/// CR 608.2k: True when `text` is a standalone object pronoun referring to
/// the trigger/spell subject. Used by effect-target parsers that need to
/// distinguish "verb + pronoun" (resolve against `ctx.subject` via
/// `resolve_it_pronoun`) from "verb + target filter" (parse via
/// `parse_target`, which defaults to `ParentTarget`).
///
/// Covers the full object-pronoun family: "it" / "itself", "him" / "himself",
/// "her" / "herself", "them" / "themselves". Caller is responsible for trimming.
pub(crate) fn is_bare_object_pronoun(text: &str) -> bool {
    matches!(
        text,
        "it" | "itself" | "him" | "himself" | "her" | "herself" | "them" | "themselves"
    )
}

/// CR 608.2k: Resolve bare pronoun ("it"/"itself"/"its") based on parser context.
/// When a triggered ability's effect refers to an untargeted object previously
/// referred to by the trigger condition, it still affects that object.
/// In trigger effects where the subject is a non-self filter (e.g. "a creature
/// you control"), "it" refers to the triggering object (TriggeringSource).
/// For self-triggers ("~ enters"), "it" stays SelfRef.
/// For AttachedTo subjects ("equipped creature"), TriggeringSource is also correct
/// because the triggering event's source IS the attached-to creature.
pub(crate) fn resolve_it_pronoun(ctx: &mut ParseContext) -> TargetFilter {
    match &ctx.subject {
        Some(subject) if !matches!(subject, TargetFilter::SelfRef | TargetFilter::Any) => {
            TargetFilter::TriggeringSource
        }
        _ => TargetFilter::SelfRef,
    }
}

fn condition_refs_source_object(condition: &AbilityCondition) -> bool {
    match condition {
        AbilityCondition::SourceMatchesFilter { .. }
        | AbilityCondition::SourceEnteredThisTurn
        | AbilityCondition::SourceIsTapped => true,
        AbilityCondition::Not { condition }
        | AbilityCondition::ConditionInstead { inner: condition } => {
            condition_refs_source_object(condition)
        }
        AbilityCondition::And { conditions } | AbilityCondition::Or { conditions } => {
            conditions.iter().any(condition_refs_source_object)
        }
        _ => false,
    }
}

fn condition_refs_cost_paid_object(condition: &AbilityCondition) -> bool {
    match condition {
        AbilityCondition::CostPaidObjectMatchesFilter { .. } => true,
        AbilityCondition::Not { condition }
        | AbilityCondition::ConditionInstead { inner: condition } => {
            condition_refs_cost_paid_object(condition)
        }
        AbilityCondition::And { conditions } | AbilityCondition::Or { conditions } => {
            conditions.iter().any(condition_refs_cost_paid_object)
        }
        _ => false,
    }
}

fn if_you_do_object_anchor(
    clauses: &[ClauseIr],
    condition: &Option<AbilityCondition>,
) -> Option<TargetFilter> {
    if !condition
        .as_ref()
        .is_some_and(AbilityCondition::is_optional_effect_performed)
    {
        return None;
    }
    clauses
        .iter()
        .rev()
        .find(|clause| !clause.absorbed_by_followup)
        .and_then(|clause| match &clause.parsed.effect {
            Effect::GenericEffect {
                static_abilities,
                target,
                ..
            } => target.clone().or_else(|| {
                static_abilities
                    .iter()
                    .find_map(|definition| definition.affected.clone())
            }),
            _ => None,
        })
}

fn merge_clause_conditions(
    outer: AbilityCondition,
    inner: Option<AbilityCondition>,
) -> AbilityCondition {
    let mut conditions = match inner {
        Some(AbilityCondition::And { conditions }) => conditions,
        Some(condition) => vec![condition],
        None => Vec::new(),
    };
    match outer {
        AbilityCondition::And {
            conditions: outer_conditions,
        } => {
            for condition in outer_conditions {
                if !conditions.contains(&condition) {
                    conditions.push(condition);
                }
            }
        }
        condition => {
            if !conditions.contains(&condition) {
                conditions.insert(0, condition);
            }
        }
    }
    match conditions.len() {
        0 => AbilityCondition::And { conditions },
        1 => conditions.pop().unwrap(),
        _ => AbilityCondition::And { conditions },
    }
}

fn apply_outer_condition_to_clause(outer: &AbilityCondition, clause: &mut ClauseIr) {
    let inner = clause
        .condition
        .take()
        .or_else(|| clause.parsed.condition.clone());
    clause.condition = Some(merge_clause_conditions(outer.clone(), inner));
}

pub(super) fn rewrite_cost_paid_object_quantities_in_definition(ability: &mut AbilityDefinition) {
    rewrite_cost_paid_object_quantities(&mut ability.effect);
    if let Some(sub_ability) = ability.sub_ability.as_mut() {
        rewrite_cost_paid_object_quantities_in_definition(sub_ability);
    }
    if let Some(else_ability) = ability.else_ability.as_mut() {
        rewrite_cost_paid_object_quantities_in_definition(else_ability);
    }
    for mode in &mut ability.mode_abilities {
        rewrite_cost_paid_object_quantities_in_definition(mode);
    }
}

fn rewrite_cost_paid_object_quantities(effect: &mut Effect) {
    if let Effect::Token { count, .. } = effect {
        if matches!(
            count,
            QuantityExpr::Ref {
                qty: QuantityRef::Toughness {
                    scope: ObjectScope::Source
                }
            }
        ) {
            *count = QuantityExpr::Ref {
                qty: QuantityRef::Toughness {
                    scope: ObjectScope::CostPaidObject,
                },
            };
        }
    }
}

/// Parse an effect clause from Oracle text into an Effect enum.
/// This handles the verb-based matching for spell effects, activated ability effects,
/// and the effect portion of triggered abilities.
///
/// For compound effects ("Gain 3 life. Draw a card."), call `parse_effect_chain`
/// which splits on sentence boundaries and chains via AbilityDefinition::sub_ability.
pub fn parse_effect(text: &str) -> Effect {
    parse_effect_clause(text, &mut ParseContext::default()).effect
}

// ── Word-boundary scanners for delayed trigger dispatch ──────────────────

/// Delayed trigger condition kinds, used by `scan_delayed_condition_kind`.
#[derive(Debug, Clone, Copy)]
enum DelayedConditionKind {
    Dies,
    PutIntoGraveyard,
    LeavesPlay,
    EntersBattlefield,
}

/// Nom combinator for delayed trigger condition keywords.
/// Ordered: longer phrases first to prevent prefix collisions
/// (e.g., "enters the battlefield" before bare "enters").
fn parse_delayed_condition_keyword(
    input: &str,
) -> nom::IResult<&str, DelayedConditionKind, OracleError<'_>> {
    alt((
        value(
            DelayedConditionKind::LeavesPlay,
            tag("leaves the battlefield"),
        ),
        value(
            DelayedConditionKind::EntersBattlefield,
            tag("enters the battlefield"),
        ),
        // CR 700.4: "is put into a graveyard" from battlefield = dies
        value(
            DelayedConditionKind::PutIntoGraveyard,
            tag("is put into a graveyard"),
        ),
        value(
            DelayedConditionKind::PutIntoGraveyard,
            tag("is put into your graveyard"),
        ),
        value(
            DelayedConditionKind::PutIntoGraveyard,
            tag("is put into their graveyard"),
        ),
        value(DelayedConditionKind::Dies, tag("dies")),
        value(DelayedConditionKind::Dies, tag("die")),
        // Bare "enters" last — least specific
        value(DelayedConditionKind::EntersBattlefield, tag("enters")),
    ))
    .parse(input)
}

/// Word-boundary scanner for delayed trigger condition keywords.
/// Delegates to the shared `scan_at_word_boundaries` primitive.
fn scan_delayed_condition_kind(text: &str) -> Option<DelayedConditionKind> {
    nom_primitives::scan_at_word_boundaries(text, parse_delayed_condition_keyword)
}

/// Nom combinator for delayed trigger subject reference phrases.
/// Returns `Some(TargetFilter)` for ParentTarget or SelfRef references.
fn parse_delayed_subject_keyword(input: &str) -> nom::IResult<&str, TargetFilter, OracleError<'_>> {
    alt((
        // ParentTarget references (longer phrases first)
        value(TargetFilter::ParentTarget, tag("an exiled ")),
        value(TargetFilter::ParentTarget, tag("the exiled ")),
        value(TargetFilter::ParentTarget, tag("the targeted ")),
        value(TargetFilter::ParentTarget, tag("the creature")),
        value(TargetFilter::ParentTarget, tag("the permanent")),
        value(TargetFilter::ParentTarget, tag("the token")),
        value(TargetFilter::ParentTarget, tag("that ")),
        value(TargetFilter::ParentTarget, tag("target ")),
        // SelfRef references — "~" is the normalized self-reference marker
        value(TargetFilter::SelfRef, tag("~ ")),
        value(TargetFilter::SelfRef, tag("this creature")),
        value(TargetFilter::SelfRef, tag("this permanent")),
        value(TargetFilter::SelfRef, tag("this artifact")),
    ))
    .parse(input)
}

/// Word-boundary scanner for delayed trigger subject references.
/// Delegates to `scan_at_word_boundaries` for typed phrases, then falls back
/// to checking for bare "it" (which can appear at end of string).
fn scan_delayed_subject(text: &str) -> Option<TargetFilter> {
    // First try typed subject references via the shared scanner
    if let Some(filter) =
        nom_primitives::scan_at_word_boundaries(text, parse_delayed_subject_keyword)
    {
        return Some(filter);
    }
    // Fallback: bare "it" at any word boundary (end of string or followed by space,
    // but NOT "its " which is possessive, not a pronoun reference)
    if nom_primitives::scan_at_word_boundaries(text, |input| {
        let (rest, _) = tag::<_, _, OracleError<'_>>("it").parse(input)?;
        // Require word boundary: end of string, space (but not "its"), or punctuation
        if rest.is_empty() || rest.starts_with(' ') && !rest.starts_with("s ") {
            Ok((rest, ()))
        } else {
            Err(nom::Err::Error(OracleError::new(
                input,
                nom::error::ErrorKind::Fail,
            )))
        }
    })
    .is_some()
    {
        return Some(TargetFilter::SelfRef);
    }
    // CR 603.7c: When the condition text doesn't start with an indefinite article
    // ("a"/"an"), it's a definite self-reference — either "~" (normalized), a card
    // name (un-normalized), or a definite noun phrase describing the source object
    // (e.g., "the pandorica becomes untapped"). Indefinite articles indicate a
    // different object class ("a creature dealt damage this way"), not the source.
    if tag::<_, _, OracleError<'_>>("a ").parse(text).is_err()
        && tag::<_, _, OracleError<'_>>("an ").parse(text).is_err()
    {
        return Some(TargetFilter::SelfRef);
    }
    None
}

/// Word-boundary scanner for tracked set references in delayed trigger conditions.
/// Checks for "that ", "the exiled ", "the targeted " at word boundaries.
fn scan_tracked_set_reference(text: &str) -> bool {
    nom_primitives::scan_at_word_boundaries(text, |input| {
        alt((
            tag::<_, _, OracleError<'_>>("that "),
            tag("an exiled "),
            tag("the exiled "),
            tag("the targeted "),
        ))
        .parse(input)
    })
    .is_some()
}

/// CR 700.4 + CR 120.1 + CR 603.7c: Parse delayed "a creature dealt damage
/// this way dies [this turn]" conditions by reusing the normal death-trigger
/// condition that checks this turn's damage ledger against the delayed
/// trigger's source.
fn parse_dealt_damage_this_way_dies_trigger(
    condition_text: &str,
    ctx: &mut ParseContext,
) -> Option<TriggerDefinition> {
    let condition_lower = condition_text.to_lowercase();
    let (rest, subject) = take_until::<_, _, OracleError<'_>>(" dealt damage this way dies")
        .parse(condition_lower.as_str())
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" dealt damage this way dies")
        .parse(rest)
        .ok()?;
    let (rest, _) = opt(tag::<_, _, OracleError<'_>>(" this turn"))
        .parse(rest)
        .ok()?;
    let (rest, _) = eof::<_, OracleError<'_>>.parse(rest).ok()?;
    debug_assert!(rest.is_empty());

    let (valid_card, rem) = parse_type_phrase(subject);
    if !rem.trim().is_empty() || matches!(valid_card, TargetFilter::Any) {
        ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
            context: "unrecognized delayed damage subject".into(),
            text: subject.trim().into(),
            line_index: 0,
        });
        return None;
    }

    let mut trigger = TriggerDefinition::new(TriggerMode::ChangesZone);
    trigger.origin = Some(Zone::Battlefield);
    trigger.destination = Some(Zone::Graveyard);
    trigger.valid_card = Some(valid_card);
    trigger.condition = Some(TriggerCondition::DealtDamageBySourceThisTurn);
    Some(trigger)
}

/// Delegates to the shared word-boundary scanning primitive in `oracle_nom::primitives`.
fn scan_contains_phrase(text: &str, phrase: &str) -> bool {
    nom_primitives::scan_contains(text, phrase)
}

/// CR 603.7c: Parse "whenever [trigger condition] this turn, [effect]" delayed triggers.
/// These create multi-fire delayed triggers that persist until end of turn.
/// Example: "whenever a creature you control deals combat damage to a player this turn, draw a card"
fn try_parse_whenever_this_turn(tp: TextPair) -> Option<ParsedEffectClause> {
    if tag::<_, _, OracleError<'_>>("whenever ")
        .parse(tp.lower)
        .is_err()
    {
        return None;
    }
    // Must contain "this turn" to distinguish from regular triggers.
    // Use rsplit_around: "this turn" terminates the condition — the last occurrence
    // is the correct split point if the condition itself contains "this turn".
    let (before, after) = tp.rsplit_around(" this turn, ")?;

    // Condition is between "whenever " and " this turn"
    let condition_text = &before.lower[9..];
    // Effect is after " this turn, "
    let effect_text = after.original;

    // Parse the condition as a trigger using the trigger parser.
    let mut inner_ctx = ParseContext::default();
    let mut trigger_def = parse_dealt_damage_this_way_dies_trigger(condition_text, &mut inner_ctx)
        .unwrap_or_else(|| {
            let (_, trigger_def) = crate::parser::oracle_trigger::parse_trigger_condition(
                condition_text,
                &mut inner_ctx,
            );
            trigger_def
        });
    trigger_def.execute = None; // Effect lives in DelayedTrigger.ability, not here

    let inner = parse_effect_chain(effect_text, AbilityKind::Spell);

    Some(ParsedEffectClause {
        effect: Effect::CreateDelayedTrigger {
            condition: DelayedTriggerCondition::WheneverEvent {
                trigger: Box::new(trigger_def),
            },
            effect: Box::new(inner),
            uses_tracked_set: false,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// Decompose the spell qualifier from `"when you next cast a <payload> this turn, ..."`
/// into a combined `TargetFilter`.
///
/// The payload must contain the word "spell". Text before " spell" is parsed as a type
/// phrase (`parse_type_phrase`); text after " spell" is parsed by
/// `oracle_trigger::parse_post_spell_modifier` (CR 107.3 + CR 202.1 — "with {X} in its
/// mana cost"). When both shapes contribute a filter, the result is an `And` composition.
///
/// Returns `None` when the payload contains unrecognized text or has no "spell" boundary.
fn extract_when_next_spell_filter(payload: &str) -> Option<TargetFilter> {
    let payload = payload.trim();
    // Bare "spell" — any spell. (Kept for completeness; this shape is not
    // common in printed card text.)
    if payload == "spell" {
        return Some(TargetFilter::Any);
    }
    // The payload is one of three shapes:
    //   (a) "<type-phrase> spell"                 — type only
    //   (b) "spell <post-modifier>"               — post-modifier only (Brass Infiniscope)
    //   (c) "<type-phrase> spell <post-modifier>" — both
    let (pre, post) = if let Some(rest) = payload.strip_prefix("spell ") {
        ("", rest.trim())
    } else {
        // Split on " spell" to isolate pre-spell type phrase from post-spell modifier.
        match crate::parser::oracle_nom::primitives::split_once_on(payload, " spell") {
            Ok((_, (pre, post))) => (pre.trim(), post.trim()),
            Err(_) => return None,
        }
    };

    let type_filter = if pre.is_empty() {
        None
    } else {
        let (filter, remainder) = super::oracle_target::parse_type_phrase(pre);
        if !remainder.trim().is_empty() {
            return None;
        }
        if matches!(filter, TargetFilter::Any) {
            None
        } else {
            Some(filter)
        }
    };

    let post_filter = if post.is_empty() {
        None
    } else {
        // Unknown post-spell modifier → reject the whole pattern rather than
        // silently dropping it. The caller falls through to other parsers.
        Some(crate::parser::oracle_trigger::parse_post_spell_modifier(
            post,
        )?)
    };

    Some(match (type_filter, post_filter) {
        (None, None) => TargetFilter::Any,
        (Some(f), None) | (None, Some(f)) => f,
        (Some(a), Some(b)) => TargetFilter::And {
            filters: vec![a, b],
        },
    })
}

/// CR 603.7: Parse "when you next cast a [type] spell [post-spell modifier] this turn, [effect]"
/// delayed triggers. Creates a one-shot delayed trigger that fires once on the next matching
/// SpellCast event.
/// Examples:
/// - "When you next cast a creature spell this turn, that creature enters with an additional +1/+1 counter on it."
/// - "When you next cast a creature spell this turn, search your library for a creature card..."
/// - "When you next cast a spell with {X} in its mana cost this turn, you draw a card and gain half X life, rounded down." (Brass Infiniscope)
fn try_parse_when_next_event(tp: TextPair) -> Option<ParsedEffectClause> {
    use crate::types::triggers::TriggerMode;

    // Must start with "when you next cast a " or "when you next cast an ".
    // Article choice depends on the payload — "a creature spell" vs "an instant or sorcery spell".
    let article_result: nom::IResult<&str, &str, OracleError<'_>> =
        alt((tag("when you next cast a "), tag("when you next cast an "))).parse(tp.lower);
    let (_, matched_prefix) = article_result.ok()?;

    // Must contain "this turn, " to delimit condition from effect
    let (before_this_turn, after) = tp.rsplit_around(" this turn, ")?;

    // Extract the spell qualifier payload from between the matched article prefix and
    // the timing tail (" this turn,"). The payload is of the shape
    //   [type-phrase]? "spell" [post-spell modifier]?
    // — e.g. "creature spell" (type only), "instant or sorcery spell" (disjunction),
    // "spell with {x} in its mana cost" (post only).
    let condition_fragment = &before_this_turn.lower[matched_prefix.len()..];
    let combined_filter = extract_when_next_spell_filter(condition_fragment)?;

    // Build a SpellCast trigger definition with the combined filter
    let mut trigger_def = crate::types::ability::TriggerDefinition::new(TriggerMode::SpellCast);
    trigger_def.valid_card = Some(combined_filter);
    // "when YOU next cast" — scope to the source's controller.
    trigger_def.valid_target = Some(TargetFilter::Controller);

    let effect_text = after.original;
    let effect_lower = after.lower;

    // Check for "that creature enters with an additional +1/+1 counter on it" pattern
    let inner = if let Some(parsed) = try_parse_enters_with_additional_counters(effect_lower) {
        parsed
    } else {
        parse_effect_chain(effect_text, AbilityKind::Spell)
    };

    Some(ParsedEffectClause {
        effect: Effect::CreateDelayedTrigger {
            condition: DelayedTriggerCondition::WhenNextEvent {
                trigger: Box::new(trigger_def),
            },
            effect: Box::new(inner),
            uses_tracked_set: false,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

pub(crate) fn try_parse_temporal_delayed_trigger_ability(
    text: &str,
    kind: AbilityKind,
) -> Option<AbilityDefinition> {
    let lower = text.to_lowercase();
    let tp = TextPair::new(text, &lower);
    let clause = try_parse_whenever_this_turn(tp).or_else(|| try_parse_when_next_event(tp))?;
    Some(ability_definition_from_clause(kind, clause))
}

/// CR 614.1a + CR 514.2: Detect "If [target_phrase] would die this turn, exile
/// it instead." damage-spell rider, returning an `AddTargetReplacement` def.
/// Returns `None` if the text doesn't match.
///
/// Covers the modal-burn class (Agate Assault, Brutal Expulsion, Suplex,
/// Touch of the Void, Bouncer's Beatdown, Betrayer's Bargain, etc.) where
/// the rider attaches to a parent damage clause and registers a one-shot,
/// EOT-scoped, target-bound replacement on the damaged creature/planeswalker.
///
/// The carried replacement uses `valid_card: SelfRef` because once it's
/// pushed onto the target object's `replacement_definitions` (by the
/// `AddTargetReplacement` resolver), SelfRef on a replacement resolves
/// against the carrying object — which IS the target.
fn try_parse_die_exile_rider(lower: &str, kind: AbilityKind) -> Option<AbilityDefinition> {
    use crate::types::ability::ReplacementDefinition;
    use crate::types::replacements::ReplacementEvent;
    use crate::types::zones::Zone;

    // Strip optional leading "if ", then the subject, then " would die this turn",
    // then ", exile <anaphor> instead" (with optional trailing period).
    let (rest, _) = nom::combinator::opt(tag::<_, _, OracleError<'_>>("if "))
        .parse(lower)
        .ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("that creature or planeswalker"),
        tag("that creature"),
        tag("that planeswalker"),
        tag("that token"),
        tag("a permanent dealt damage this way"),
        tag("a creature dealt damage this way"),
        tag("it"),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" would die this turn")
        .parse(rest)
        .ok()?;
    let (rest, _) = alt((tag::<_, _, OracleError<'_>>(", "), tag(" ")))
        .parse(rest)
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>("exile ").parse(rest).ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("that creature or planeswalker"),
        tag("that creature"),
        tag("that planeswalker"),
        tag("them"),
        tag("it"),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" instead").parse(rest).ok()?;
    let (rest, _) = nom::combinator::opt(tag::<_, _, OracleError<'_>>("."))
        .parse(rest)
        .ok()?;
    if !rest.trim().is_empty() {
        return None;
    }

    // Build: ReplacementDefinition triggered when the host moves to graveyard,
    // re-routes to exile, expires at EOT regardless of firing.
    let exile_effect = AbilityDefinition::new(
        kind,
        Effect::ChangeZone {
            origin: Some(Zone::Battlefield),
            destination: Zone::Exile,
            target: TargetFilter::SelfRef,
            owner_library: false,
            enter_transformed: false,
            enters_under: None,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        },
    );
    let mut repl = ReplacementDefinition::new(ReplacementEvent::Moved)
        .valid_card(TargetFilter::SelfRef)
        .destination_zone(Zone::Graveyard)
        .execute(exile_effect);
    repl.is_consumed = true;
    repl.expiry = Some(RestrictionExpiry::EndOfTurn);

    Some(AbilityDefinition::new(
        kind,
        Effect::AddTargetReplacement {
            replacement: Box::new(repl),
            target: TargetFilter::Any,
        },
    ))
}

fn parse_leave_battlefield_rider_ref(input: &str) -> OracleResult<'_, ()> {
    value(
        (),
        alt((
            tag("it"),
            tag("the card"),
            tag("the creature"),
            tag("the permanent"),
            tag("that card"),
            tag("that creature"),
            tag("that land"),
            tag("that permanent"),
            tag("this card"),
            tag("this creature"),
            tag("this land"),
            tag("this permanent"),
        )),
    )
    .parse(input)
}

/// CR 614.1a + CR 614.6: Detect "If it would leave the battlefield, exile it
/// instead of putting it anywhere else." riders attached to a previously
/// selected object. The carried `ReplacementDefinition` is installed on the
/// parent target, where `valid_card: SelfRef` binds to that host object.
fn try_parse_leave_battlefield_exile_replacement(lower: &str) -> Option<Effect> {
    let (rest, _) = nom::combinator::opt(tag::<_, _, OracleError<'_>>("if "))
        .parse(lower)
        .ok()?;
    let (rest, _) = parse_leave_battlefield_rider_ref(rest).ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" would leave the battlefield, ")
        .parse(rest)
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>("exile ").parse(rest).ok()?;
    let (rest, _) = parse_leave_battlefield_rider_ref(rest).ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" instead of putting ")
        .parse(rest)
        .ok()?;
    let (rest, _) = parse_leave_battlefield_rider_ref(rest).ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" anywhere else")
        .parse(rest)
        .ok()?;
    parse_optional_period_and_end(rest)?;

    let replacement = ReplacementDefinition::new(ReplacementEvent::Moved)
        .valid_card(TargetFilter::SelfRef)
        .execute(AbilityDefinition::new(
            AbilityKind::Spell,
            Effect::ChangeZone {
                origin: Some(Zone::Battlefield),
                destination: Zone::Exile,
                target: TargetFilter::SelfRef,
                owner_library: false,
                enter_transformed: false,
                enters_under: None,
                enter_tapped: crate::types::zones::EtbTapState::Unspecified,
                enters_attacking: false,
                up_to: false,
                enter_with_counters: vec![],
                face_down_profile: None,
            },
        ));

    Some(Effect::AddTargetReplacement {
        replacement: Box::new(replacement),
        target: TargetFilter::Any,
    })
}

fn parse_optional_period_and_end(input: &str) -> Option<()> {
    let (rest, _) = nom::combinator::opt(tag::<_, _, OracleError<'_>>("."))
        .parse(input)
        .ok()?;
    rest.trim().is_empty().then_some(())
}

fn parse_damage_source_subject(input: &str) -> Option<&str> {
    alt((
        tag::<_, _, OracleError<'_>>("a source"),
        tag("that source"),
        tag("it"),
    ))
    .parse(input)
    .ok()
    .map(|(rest, _)| rest)
}

fn parse_that_player_or_their_permanent(input: &str) -> Option<&str> {
    let (rest, _) = tag::<_, _, OracleError<'_>>("that player")
        .parse(input)
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" or ").parse(rest).ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>("a permanent ")
        .parse(rest)
        .ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("that player controls"),
        tag("controlled by that player"),
    ))
    .parse(rest)
    .ok()?;
    Some(rest)
}

fn parse_source_deals_double_instead(input: &str) -> Option<&str> {
    let (rest, _) = alt((tag::<_, _, OracleError<'_>>("it"), tag("that source")))
        .parse(input)
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" deals double that damage instead")
        .parse(rest)
        .ok()?;
    Some(rest)
}

fn try_parse_triggered_damage_replacement(lower: &str) -> Option<Effect> {
    let (rest, _) = nom::combinator::opt(tag::<_, _, OracleError<'_>>("if "))
        .parse(lower)
        .ok()?;
    let rest = parse_damage_source_subject(rest)?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" would deal damage to ")
        .parse(rest)
        .ok()?;
    let rest = parse_that_player_or_their_permanent(rest)?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(", ").parse(rest).ok()?;
    let rest = parse_source_deals_double_instead(rest)?;
    parse_optional_period_and_end(rest)?;

    let replacement = ReplacementDefinition::new(ReplacementEvent::DamageDone)
        .damage_modification(DamageModification::Double);

    Some(Effect::AddTargetReplacement {
        replacement: Box::new(replacement),
        target: TargetFilter::TriggeringPlayer,
    })
}

/// CR 614.1a + CR 514.2: Recognize a self-contained turn-bound damage-modification
/// replacement nested inside a triggered ability's effect chain — e.g.,
/// I Call for Slaughter's "If a source you control would deal damage this
/// turn, it deals that much damage plus 1 instead." or Rankle and Torbran's
/// "If a source would deal damage to a player or battle this turn, it deals
/// that much damage plus 2 instead."
///
/// Distinct from `try_parse_triggered_damage_replacement`, which only handles
/// the "that player or a permanent that player controls" target shape and
/// hard-binds to `TargetFilter::TriggeringPlayer`. This helper covers
/// untargeted ("any damage event matching the source filter") replacements
/// that should be pushed to the global pending_damage_replacements as-is.
///
/// Delegates source/target/scope/modification extraction to the canonical
/// `parse_replacement_line` (the same parser used for top-level static
/// replacements on permanents), then wraps the produced `ReplacementDefinition`
/// in an `Effect::AddTargetReplacement` with `target: TargetFilter::None`.
/// The "this turn" temporal qualifier is captured as
/// `expiry: Some(RestrictionExpiry::EndOfTurn)` so the cleanup step prunes
/// the replacement at end-of-turn (CR 514.2).
fn try_parse_global_damage_modification_replacement(text: &str) -> Option<Effect> {
    use super::oracle_replacement::parse_replacement_line;
    let lower = text.to_lowercase();
    // Gate: only attempt the lift when the chunk is shaped like a damage
    // modification replacement. The leading "if " check is a nom prefix
    // dispatch; the `scan_contains` body checks are structural pre-filters
    // (PATTERNS.md §5 word-boundary scan over already-classified clause
    // text) — the actual parse is delegated to `parse_replacement_line`
    // below, which uses nom combinators end-to-end.
    if tag::<_, _, OracleError<'_>>("if ")
        .parse(lower.as_str())
        .is_err()
    {
        return None;
    }
    if !nom_primitives::scan_contains(&lower, "would deal")
        || !nom_primitives::scan_contains(&lower, "this turn")
        || !nom_primitives::scan_contains(&lower, "instead")
    {
        return None;
    }
    let mut replacement = parse_replacement_line(text, "")?;
    // Only lift damage-modification replacements — other shapes (zone
    // redirection, life-gain replacements, etc.) have different runtime
    // semantics and aren't covered by this lift.
    replacement.damage_modification.as_ref()?;
    // The originating sentence carries "this turn" — bind the replacement's
    // lifetime to end-of-turn so it expires after the current turn (CR 514.2).
    if replacement.expiry.is_none() {
        replacement.expiry = Some(RestrictionExpiry::EndOfTurn);
    }
    Some(Effect::AddTargetReplacement {
        replacement: Box::new(replacement),
        target: TargetFilter::None,
    })
}

/// CR 615 + CR 614.1a + CR 514.2: Recognize the "conditional turn-bound damage
/// prevention with optional counter rider" pattern emitted as a sub-clause of a
/// chain that already chose a target. Example: Gatta and Luzzu's
/// "If damage would be dealt to that creature this turn, prevent that damage
/// and put that many +1/+1 counters on it."
///
/// The shape decomposes along four axes:
/// - antecedent: `if damage would be dealt to <target> this turn,`
/// - prevention: `prevent that damage`
/// - optional rider: `and put that many [+1/+1 | +0/+1 | …] counter[s] on <target>`
/// - terminal period
///
/// Emits `Effect::PreventDamage { amount: All, target: ParentTarget,
/// scope: AllDamage }` with `duration: UntilEndOfTurn`, and (when the rider is
/// present) a `PutCounter` sub-ability with `repeat_for: EventContextAmount`.
/// The CR 615.5 prevented-amount stash by the runtime damage applier resolves
/// the repeat count to the prevented amount per fired prevention event.
///
/// Distinct from `try_parse_next_time_source_damage_replacement` (which covers
/// "the next time X would deal damage" — a depletion-by-event-source shape).
/// This helper covers the prevent-by-recipient class where the shield persists
/// for every damage event to the chosen target for the rest of the turn.
fn try_parse_conditional_damage_prevention_with_followup(text: &str) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let lower = lower.as_str();
    let (rest, _) = tag::<_, _, OracleError<'_>>("if damage would be dealt to ")
        .parse(lower)
        .ok()?;
    // Match the target reference. Three cases for now:
    // - "that creature" / "that planeswalker" / "that player" → ParentTarget anaphor
    //   to the chosen target from the parent clause.
    // - "~" → SelfRef (the source itself).
    // - "you" → caster.
    let (rest, target) = alt((
        value(
            TargetFilter::ParentTarget,
            alt((
                tag::<_, _, OracleError<'_>>("that creature"),
                tag("that planeswalker"),
                tag("that permanent"),
                tag("that player"),
            )),
        ),
        value(TargetFilter::SelfRef, tag("~")),
        value(TargetFilter::Controller, tag("you")),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" this turn, ")
        .parse(rest)
        .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>("prevent that damage")
        .parse(rest)
        .ok()?;

    // Optional " and put that many <counter> counter(s) on <pronoun>" rider.
    let counter_followup: Option<AbilityDefinition> =
        if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>(" and put that many ").parse(rest) {
            let (rest, counter_type) = alt((
                value(
                    CounterType::Plus1Plus1,
                    tag::<_, _, OracleError<'_>>("+1/+1"),
                ),
                value(CounterType::Generic("+0/+1".to_string()), tag("+0/+1")),
                value(CounterType::Generic("+1/+0".to_string()), tag("+1/+0")),
                value(CounterType::Minus1Minus1, tag("-1/-1")),
                value(CounterType::Generic("+0/+2".to_string()), tag("+0/+2")),
                value(CounterType::Generic("+2/+0".to_string()), tag("+2/+0")),
            ))
            .parse(rest)
            .ok()?;
            let (rest, _) = alt((
                tag::<_, _, OracleError<'_>>(" counters on "),
                tag(" counter on "),
            ))
            .parse(rest)
            .ok()?;
            // CR 608.2k: the anaphor here ("it" / "that creature" / "~") binds to
            // the same target as the antecedent — the parent's chosen target.
            let (rest, counter_target) = alt((
                value(
                    TargetFilter::ParentTarget,
                    alt((
                        tag::<_, _, OracleError<'_>>("it"),
                        tag("that creature"),
                        tag("that planeswalker"),
                        tag("that permanent"),
                    )),
                ),
                value(TargetFilter::SelfRef, tag("~")),
            ))
            .parse(rest)
            .ok()?;
            parse_optional_period_and_end(rest)?;
            // CR 615.5 + CR 609.7: emit the rider as a `PutCounter` with `count: 1`
            // and `repeat_for: EventContextAmount` so the runtime invokes the
            // counter effect once per damage prevented this fire. Mirrors the
            // shape produced for Brace for Impact and other "for each 1 damage
            // prevented this way, put a counter on that creature" cards.
            Some(AbilityDefinition {
                repeat_for: Some(QuantityExpr::Ref {
                    qty: QuantityRef::EventContextAmount,
                }),
                ..AbilityDefinition::new(
                    AbilityKind::Spell,
                    Effect::PutCounter {
                        counter_type,
                        count: QuantityExpr::Fixed { value: 1 },
                        target: counter_target,
                    },
                )
            })
        } else {
            parse_optional_period_and_end(rest)?;
            None
        };

    Some(ParsedEffectClause {
        effect: Effect::PreventDamage {
            amount: PreventionAmount::All,
            amount_dynamic: None,
            target,
            scope: PreventionScope::AllDamage,
            damage_source_filter: None,
        },
        duration: Some(Duration::UntilEndOfTurn),
        sub_ability: counter_followup.map(Box::new),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 111.2 + CR 614.1a: "each token that would be created under <X> control
/// this turn is created under <Y> control instead." Builds a self-installed
/// CreateToken replacement with an opponent-token scope and a controller
/// redirect, marked to expire at end of turn. Crafty Cutpurse is the
/// canonical card; this also covers any future card with the same shape.
/// CR 111.2: "The token enters the battlefield under that player's control"
/// — the default this replacement overrides.
fn try_parse_token_controller_redirect(lower: &str) -> Option<Effect> {
    // Match "each token that would be created under " (or "any token ...") then
    // a controller phrase, then "control this turn is created under " then a
    // controller phrase, then "control instead".
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("each token that would be created under "),
        tag("any token that would be created under "),
    ))
    .parse(lower)
    .ok()?;
    let (rest, from_ctrl) = alt((
        // CR 109.4: "an opponent's" — bound to Opponent scope relative to the
        // installing source. "your opponents'" is the plural form.
        value(
            crate::types::ability::ControllerRef::Opponent,
            tag::<_, _, OracleError<'_>>("an opponent's"),
        ),
        value(
            crate::types::ability::ControllerRef::Opponent,
            tag::<_, _, OracleError<'_>>("your opponents'"),
        ),
        value(
            crate::types::ability::ControllerRef::You,
            tag::<_, _, OracleError<'_>>("your"),
        ),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" control this turn is created under ")
        .parse(rest)
        .ok()?;
    // Only `your` is supported as the redirect target. No printed card today
    // redirects to an opponent ("...created under an opponent's control
    // instead"), and the runtime in `replacement.rs` does not implement that
    // semantics (multiplayer "first non-source player" would be incorrect).
    // Restricting the parser keeps the parser/runtime contract symmetric — if
    // such a card ever prints, runtime support must land in the same change.
    let (rest, to_ctrl) = value(
        crate::types::ability::ControllerRef::You,
        tag::<_, _, OracleError<'_>>("your"),
    )
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" control instead")
        .parse(rest)
        .ok()?;
    parse_optional_period_and_end(rest)?;

    let mut replacement = ReplacementDefinition::new(ReplacementEvent::CreateToken)
        .token_owner_scope(from_ctrl)
        .token_owner_redirect(to_ctrl);
    // CR 514.2: "this turn" binds the replacement's lifetime to end of turn.
    replacement.expiry = Some(RestrictionExpiry::EndOfTurn);

    Some(Effect::AddTargetReplacement {
        replacement: Box::new(replacement),
        target: TargetFilter::SelfRef,
    })
}

fn try_parse_next_time_source_damage_replacement(lower: &str) -> Option<Effect> {
    let (rest, _) = tag::<_, _, OracleError<'_>>("the next time ")
        .parse(lower)
        .ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("that creature would deal combat damage this turn, "),
        tag("it would deal combat damage this turn, "),
    ))
    .parse(rest)
    .ok()?;

    let mut replacement = ReplacementDefinition::new(ReplacementEvent::DamageDone)
        .damage_source_filter(TargetFilter::SelfRef)
        .combat_scope(CombatDamageScope::CombatOnly);
    if let Ok((rest, _)) = alt((
        tag::<_, _, OracleError<'_>>("it deals double that damage instead"),
        tag("that creature deals double that damage instead"),
    ))
    .parse(rest)
    {
        parse_optional_period_and_end(rest)?;
        replacement = replacement.damage_modification(DamageModification::Double);
    } else if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("prevent that damage").parse(rest) {
        parse_optional_period_and_end(rest)?;
        replacement = replacement.prevention_shield(PreventionAmount::All);
    } else {
        return None;
    }

    replacement.is_consumed = true;
    replacement.expiry = Some(RestrictionExpiry::EndOfTurn);

    Some(Effect::AddTargetReplacement {
        replacement: Box::new(replacement),
        target: TargetFilter::TriggeringSource,
    })
}

/// Parse "that creature enters with an additional [N] +1/+1 counter(s) on it" into
/// an `AddPendingETBCounters` effect. Returns `None` if the text doesn't match.
fn try_parse_enters_with_additional_counters(lower: &str) -> Option<AbilityDefinition> {
    // "that creature enters with an additional +1/+1 counter on it"
    // "that creature enters with N additional +1/+1 counters on it"
    let (rest, _) = tag::<_, _, OracleError<'_>>("that creature enters with ")
        .parse(lower)
        .ok()?;

    // Parse "an additional" or "N additional"
    let (rest, count) =
        if let Ok((r, _)) = tag::<_, _, OracleError<'_>>("an additional ").parse(rest) {
            (r, 1u32)
        } else if let Ok((r, n)) = nom_primitives::parse_number(rest) {
            let (r, _) = tag::<_, _, OracleError<'_>>(" additional ").parse(r).ok()?;
            (r, n)
        } else {
            return None;
        };

    // Parse counter type: "+1/+1 counter" or "-1/-1 counter" etc.
    let (rest, counter_type) = alt((
        value(
            CounterType::Plus1Plus1,
            tag::<_, _, OracleError<'_>>("+1/+1"),
        ),
        value(CounterType::Minus1Minus1, tag("-1/-1")),
    ))
    .parse(rest)
    .ok()?;

    // Match " counter on it" or " counters on it"
    let _ = alt((
        tag::<_, _, OracleError<'_>>(" counter on it"),
        tag(" counters on it"),
    ))
    .parse(rest)
    .ok()?;

    Some(AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::AddPendingETBCounters {
            counter_type,
            count: QuantityExpr::Fixed {
                value: count as i32,
            },
        },
    ))
}

/// CR 603.7c: Parse inline delayed triggers like "when that creature dies, draw a card".
/// Returns a `CreateDelayedTrigger` wrapping the parsed inner effect.
fn try_parse_inline_delayed_trigger(
    tp: TextPair,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    if tag::<_, _, OracleError<'_>>("when ")
        .parse(tp.lower)
        .is_err()
    {
        return None;
    }

    // Find the comma separator between condition and effect
    let comma = tp.find(", ")?;
    let condition_text = &tp.lower["when ".len()..comma];
    let effect_text = &tp.original[comma + 2..];

    let condition = if let Some(trigger) =
        parse_dealt_damage_this_way_dies_trigger(condition_text, ctx)
    {
        DelayedTriggerCondition::WhenNextEvent {
            trigger: Box::new(trigger),
        }
    } else {
        match scan_delayed_condition_kind(condition_text) {
            Some(DelayedConditionKind::Dies | DelayedConditionKind::PutIntoGraveyard) => {
                DelayedTriggerCondition::WhenDies {
                    filter: parse_delayed_subject_filter(condition_text, ctx),
                }
            }
            Some(DelayedConditionKind::LeavesPlay) => {
                DelayedTriggerCondition::WhenLeavesPlayFiltered {
                    filter: parse_delayed_subject_filter(condition_text, ctx),
                }
            }
            Some(DelayedConditionKind::EntersBattlefield) => {
                if has_unconsumed_conditional(condition_text) {
                    tracing::warn!(
                    text = condition_text,
                    "Unconsumed conditional in delayed trigger 'enters' match — parser may need extension"
                );
                }
                DelayedTriggerCondition::WhenEntersBattlefield {
                    filter: parse_delayed_subject_filter(condition_text, ctx),
                }
            }
            None => return None,
        }
    };

    // "that creature/permanent/token" references the parent spell's target.
    // "the exiled creature/card" and "the targeted creature" also reference
    // the parent's tracked set.
    let uses_tracked_set = scan_tracked_set_reference(condition_text);

    let mut inner_ctx = ctx.clone();
    inner_ctx.subject = match &condition {
        DelayedTriggerCondition::WhenDies { filter }
        | DelayedTriggerCondition::WhenLeavesPlayFiltered { filter }
        | DelayedTriggerCondition::WhenEntersBattlefield { filter }
        | DelayedTriggerCondition::WhenDiesOrExiled { filter } => Some(filter.clone()),
        _ => None,
    };
    let inner = parse_effect_chain_with_context(effect_text, AbilityKind::Spell, &mut inner_ctx);

    Some(ParsedEffectClause {
        effect: Effect::CreateDelayedTrigger {
            condition,
            effect: Box::new(inner),
            uses_tracked_set,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// Map delayed trigger condition subjects to TargetFilter.
/// CR 603.7c: Delayed triggers track objects by reference.
/// "that creature"/"that permanent"/"that token"/"that card" → ParentTarget (parent spell's target).
/// "the exiled creature"/"the exiled card"/"the creature"/"the permanent" → ParentTarget (back-reference).
/// "the targeted creature" → ParentTarget.
/// "it"/"this creature"/"this permanent"/"this artifact" → SelfRef (source object).
/// "target creature" → ParentTarget (named target in the condition).
fn parse_delayed_subject_filter(condition_text: &str, ctx: &mut ParseContext) -> TargetFilter {
    scan_delayed_subject(condition_text).unwrap_or_else(|| {
        ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
            context: "unrecognized delayed subject".into(),
            text: condition_text.trim().into(),
            line_index: 0,
        });
        TargetFilter::Any
    })
}

/// CR 601.2f: Parse "the next spell you cast this turn costs {N} less to cast".
///
/// Also handles "for each counter removed this way" variants by falling back to fixed {1}.
fn try_parse_reduce_next_spell_cost(tp: TextPair) -> Option<ParsedEffectClause> {
    use nom::sequence::delimited;

    // Match prefix: "the next spell you cast this turn costs "
    let (rest, _) = tag::<_, _, OracleError<'_>>("the next spell you cast this turn costs ")
        .parse(tp.lower)
        .ok()?;

    // Extract the mana amount: "{1}", "{2}", etc.
    let (after_amount, amount) = delimited(
        tag::<_, _, OracleError<'_>>("{"),
        nom::character::complete::u32,
        tag("}"),
    )
    .parse(rest)
    .ok()?;

    // Match suffix: " less to cast" with optional trailing clause
    alt((
        tag::<_, _, OracleError<'_>>(" less to cast for each counter removed this way"),
        tag(" less to cast"),
    ))
    .parse(after_amount)
    .ok()?;

    Some(parsed_clause(Effect::ReduceNextSpellCost {
        amount,
        spell_filter: None,
    }))
}

/// CR 601.2f: Parse "the next [type] spell you cast this turn [has keyword/can't be countered/etc.]"
///
/// Handles patterns like:
/// - "the next creature spell you cast this turn can't be countered"
/// - "the next spell you cast this turn has convoke"
/// - "the next sorcery spell you cast this turn can be cast as though it had flash"
/// - "the next instant or sorcery spell you cast this turn has cascade"
/// - "the next face-down creature spell you cast this turn costs {3} less to cast"
fn try_parse_grant_next_spell_ability(tp: TextPair) -> Option<ParsedEffectClause> {
    // Must start with "the next "
    let rest = tag::<_, _, OracleError<'_>>("the next ")
        .parse(tp.lower)
        .ok()
        .map(|(r, _)| r)?;

    // Extract optional spell type filter before "spell you cast this turn"
    // Patterns: "spell you cast this turn", "creature spell you cast this turn",
    // "instant or sorcery spell you cast this turn", "noncreature spell you cast this turn",
    // "face-down creature spell you cast this turn"
    let (ability_text, filter_text) = nom::sequence::terminated(
        take_until::<_, _, OracleError<'_>>("spell"),
        alt((
            tag::<_, _, OracleError<'_>>("spell you cast this turn "),
            tag("spell of the chosen type you cast this turn "),
        )),
    )
    .parse(rest)
    .ok()?;

    let mut spell_filter = None;
    let filter_text = filter_text.trim();
    if !filter_text.is_empty() {
        // Parse the filter: "creature", "instant or sorcery", "noncreature", etc.
        let (filter, _) = parse_type_phrase(filter_text);
        if !matches!(filter, TargetFilter::Any) {
            spell_filter = Some(filter);
        }
    }

    // Now parse the ability: "can't be countered", "has convoke", "can be cast as though it had flash"
    // CR 601.2f: "can't be countered"
    if tag::<_, _, OracleError<'_>>("can't be countered")
        .parse(ability_text)
        .is_ok()
    {
        return Some(parsed_clause(Effect::GrantNextSpellAbility {
            modifier: NextSpellModifier::CantBeCountered,
            spell_filter,
        }));
    }

    // CR 601.2f: "can be cast as though it had flash"
    if tag::<_, _, OracleError<'_>>("can be cast as though it had flash")
        .parse(ability_text)
        .is_ok()
    {
        return Some(parsed_clause(Effect::GrantNextSpellAbility {
            modifier: NextSpellModifier::CastAsThoughFlash,
            spell_filter,
        }));
    }

    // CR 118.9a: "can be cast without paying its mana cost"
    if tag::<_, _, OracleError<'_>>("can be cast without paying its mana cost")
        .parse(ability_text)
        .is_ok()
    {
        return Some(parsed_clause(Effect::GrantNextSpellAbility {
            modifier: NextSpellModifier::WithoutPayingManaCost,
            spell_filter,
        }));
    }

    // CR 601.2f: "has [keyword]"
    if let Ok((_, keyword_text)) =
        preceded(tag::<_, _, OracleError<'_>>("has "), nom::combinator::rest).parse(ability_text)
    {
        // Strip trailing period/reminder text
        let keyword_text = keyword_text
            .split('.')
            .next()
            .unwrap_or(keyword_text)
            .trim();
        let keyword = match keyword_text {
            "convoke" => Some(Keyword::Convoke),
            "cascade" => Some(Keyword::Cascade),
            // CR 702.41a: "affinity for artifacts" — Affinity parameterized by artifact type
            "affinity for artifacts" => Some(Keyword::Affinity(
                crate::types::ability::TypedFilter::default()
                    .with_type(crate::types::ability::TypeFilter::Artifact),
            )),
            "improvise" => Some(Keyword::Improvise),
            _ => {
                // Try parsing as a keyword
                keyword_text.parse::<Keyword>().ok()
            }
        };
        if let Some(kw) = keyword {
            return Some(parsed_clause(Effect::GrantNextSpellAbility {
                modifier: NextSpellModifier::HasKeyword { keyword: kw },
                spell_filter,
            }));
        }
    }

    // "costs {N} less to cast" — delegate to the existing ReduceNextSpellCost for filtered variants
    // e.g., "the next face-down creature spell you cast this turn costs {3} less to cast"
    if let Ok((amount_rest, _)) = tag::<_, _, OracleError<'_>>("costs ").parse(ability_text) {
        if let Ok((after_amount, amount)) = nom::sequence::delimited(
            tag::<_, _, OracleError<'_>>("{"),
            nom::character::complete::u32,
            tag("}"),
        )
        .parse(amount_rest)
        {
            if tag::<_, _, OracleError<'_>>(" less to cast")
                .parse(after_amount)
                .is_ok()
            {
                return Some(parsed_clause(Effect::ReduceNextSpellCost {
                    amount,
                    spell_filter,
                }));
            }
        }
    }

    None
}

/// CR 614.16: Parse "Damage can't be prevented [this turn]" into Effect::AddRestriction.
///
/// Handles variants:
///   - "Damage can't be prevented this turn"
///   - "Combat damage that would be dealt by creatures you control can't be prevented"
fn try_parse_damage_prevention_disabled(tp: TextPair) -> Option<ParsedEffectClause> {
    // Guard: must contain both "damage" and a prevention-disabled phrase.
    // Use word-boundary scanning to avoid substring false positives.
    let has_prevention_disabled = scan_contains_phrase(tp.lower, "can't be prevented")
        || scan_contains_phrase(tp.lower, "cannot be prevented");
    if !has_prevention_disabled {
        return None;
    }
    if !scan_contains_phrase(tp.lower, "damage") {
        return None;
    }

    // Determine expiry: "this turn" → EndOfTurn, otherwise EndOfTurn as default
    let expiry = crate::types::ability::RestrictionExpiry::EndOfTurn;

    // Determine scope from the subject phrase
    let scope = if scan_contains_phrase(tp.lower, "creatures you control")
        || scan_contains_phrase(tp.lower, "sources you control")
    {
        Some(
            crate::types::ability::RestrictionScope::SourcesControlledBy(
                crate::types::player::PlayerId(0), // Placeholder — resolved at runtime from ability controller
            ),
        )
    } else {
        // Global: all damage prevention disabled
        None
    };

    let restriction = crate::types::ability::GameRestriction::DamagePreventionDisabled {
        source: crate::types::identifiers::ObjectId(0), // Filled in at resolution time
        expiry,
        scope,
    };

    Some(ParsedEffectClause {
        effect: Effect::AddRestriction { restriction },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_cast_only_from_zones_restriction(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let (scope_tp, expiry, duration) = if let Some(((expiry, duration), rest)) =
        nom_on_lower(tp.original, tp.lower, |input| {
            alt((
                value(
                    (
                        RestrictionExpiry::EndOfTurn,
                        Some(Duration::UntilNextTurnOf {
                            player: PlayerScope::Controller,
                        }),
                    ),
                    tag("until your next turn, "),
                ),
                value((RestrictionExpiry::EndOfTurn, None), tag("this turn, ")),
            ))
            .parse(input)
        }) {
        let rest_lower = &tp.lower[tp.lower.len() - rest.len()..];
        (TextPair::new(rest, rest_lower), expiry, duration)
    } else {
        (tp, RestrictionExpiry::EndOfTurn, None)
    };

    if !scan_contains_phrase(scope_tp.lower, "can't cast spells from anywhere other than") {
        return None;
    }

    if !scan_contains_phrase(scope_tp.lower, "their hand")
        && !scan_contains_phrase(scope_tp.lower, "their hands")
    {
        return None;
    }

    let affected_players = if alt((
        tag::<_, _, OracleError<'_>>("your opponents"),
        tag("opponents"),
    ))
    .parse(scope_tp.lower)
    .is_ok()
    {
        RestrictionPlayerScope::OpponentsOfSourceController
    } else {
        RestrictionPlayerScope::AllPlayers
    };

    Some(ParsedEffectClause {
        effect: Effect::AddRestriction {
            restriction: GameRestriction::ProhibitActivity {
                source: ObjectId(0),
                affected_players,
                expiry,
                activity: ProhibitedActivity::CastOnlyFromZones {
                    allowed_zones: vec![Zone::Hand],
                },
            },
        },
        duration,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 101.2: "Your opponents can't cast spells this turn" / "Players can't cast spells this turn."
/// Handles blanket "can't cast spells" prohibitions from instant/sorcery effects (e.g., Silence).
/// Must be called AFTER try_parse_cast_only_from_zones_restriction (which handles the more
/// specific "can't cast spells from anywhere other than" variant).
fn try_parse_cant_cast_spells_effect(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let (scope_tp, expiry, duration) = if let Some(((expiry, duration), rest_orig)) =
        nom_on_lower(tp.original, tp.lower, |input| {
            alt((
                value(
                    (
                        RestrictionExpiry::EndOfTurn,
                        Some(Duration::UntilNextTurnOf {
                            player: PlayerScope::Controller,
                        }),
                    ),
                    tag("until your next turn, "),
                ),
                value(
                    (RestrictionExpiry::EndOfTurn, Some(Duration::UntilEndOfTurn)),
                    tag("until end of turn, "),
                ),
                value((RestrictionExpiry::EndOfTurn, None), tag("this turn, ")),
            ))
            .parse(input)
        }) {
        let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
        (TextPair::new(rest_orig, rest_lower), expiry, duration)
    } else {
        (tp, RestrictionExpiry::EndOfTurn, None)
    };

    let (affected_players, rest_orig) = nom_on_lower(scope_tp.original, scope_tp.lower, |input| {
        alt((
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("your opponents"),
            ),
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("opponents"),
            ),
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("each opponent"),
            ),
            value(RestrictionPlayerScope::AllPlayers, tag("players")),
            value(RestrictionPlayerScope::AllPlayers, tag("each player")),
            value(RestrictionPlayerScope::TargetedPlayer, tag("target player")),
            value(
                RestrictionPlayerScope::ParentTargetedPlayer,
                tag("that player"),
            ),
        ))
        .parse(input)
    })?;
    let rest_lower = &scope_tp.lower[scope_tp.lower.len() - rest_orig.len()..];

    let (spell_filter_text, remaining) = nom_on_lower(rest_orig, rest_lower, |input| {
        alt((
            value(None, tag(" can't cast spells")),
            value(None, tag(" cannot cast spells")),
            map(
                preceded(
                    tag(" can't cast "),
                    nom::sequence::terminated(take_until(" spells"), tag(" spells")),
                ),
                |text: &str| Some(text.to_string()),
            ),
            map(
                preceded(
                    tag(" cannot cast "),
                    nom::sequence::terminated(take_until(" spells"), tag(" spells")),
                ),
                |text: &str| Some(text.to_string()),
            ),
        ))
        .parse(input)
    })?;
    let remaining_lower = &rest_lower[rest_lower.len() - remaining.len()..];

    if tag::<_, _, OracleError<'_>>(" from")
        .parse(remaining_lower)
        .is_ok()
    {
        return None;
    }

    let spell_filter = match spell_filter_text {
        None => None,
        Some(text) => {
            let (filter, rem) = parse_type_phrase(text.trim());
            if !rem.trim().is_empty() || matches!(filter, TargetFilter::Any) {
                return None;
            }
            Some(filter)
        }
    };

    let tail = remaining
        .trim_start()
        .trim_start_matches([',', ' '])
        .trim_start();
    let sub_ability = if tail.is_empty() {
        None
    } else {
        Some(Box::new(parse_effect_chain(tail, AbilityKind::Spell)))
    };

    Some(ParsedEffectClause {
        effect: Effect::AddRestriction {
            restriction: GameRestriction::ProhibitActivity {
                source: ObjectId(0),
                affected_players,
                expiry,
                activity: ProhibitedActivity::CastSpells { spell_filter },
            },
        },
        duration,
        sub_ability,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_cant_activate_non_mana_abilities_effect(
    tp: TextPair<'_>,
) -> Option<ParsedEffectClause> {
    let (affected_players, rest_orig) = nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("your opponents"),
            ),
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("opponents"),
            ),
            value(
                RestrictionPlayerScope::OpponentsOfSourceController,
                tag("each opponent"),
            ),
            value(RestrictionPlayerScope::AllPlayers, tag("players")),
            value(RestrictionPlayerScope::AllPlayers, tag("each player")),
            value(RestrictionPlayerScope::TargetedPlayer, tag("target player")),
            value(
                RestrictionPlayerScope::ParentTargetedPlayer,
                tag("that player"),
            ),
        ))
        .parse(input)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];

    let (_, remaining) = nom_on_lower(rest_orig, rest_lower, |input| {
        alt((
            value(
                (),
                tag(" can't activate abilities that aren't mana abilities"),
            ),
            value(
                (),
                tag(" cannot activate abilities that aren't mana abilities"),
            ),
            value(
                (),
                tag(" can't activate abilities that are not mana abilities"),
            ),
            value(
                (),
                tag(" cannot activate abilities that are not mana abilities"),
            ),
        ))
        .parse(input)
    })?;

    let remaining_lower = &rest_lower[rest_lower.len() - remaining.len()..];
    if !remaining_lower.trim().is_empty() {
        return None;
    }

    Some(ParsedEffectClause {
        effect: Effect::AddRestriction {
            restriction: GameRestriction::ProhibitActivity {
                source: ObjectId(0),
                affected_players,
                expiry: RestrictionExpiry::EndOfTurn,
                activity: ProhibitedActivity::ActivateAbilities {
                    exemption: ActivationExemption::ManaAbilities,
                },
            },
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_self_name_exile(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let card_name = ctx.card_name.as_deref()?;
    let (_, rest_orig) =
        nom_on_lower(tp.original, tp.lower, |i| value((), tag("exile ")).parse(i))?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
    let rest = TextPair::new(rest_orig, rest_lower);
    if rest.original.trim().eq_ignore_ascii_case(card_name) {
        return Some(parsed_clause(Effect::ChangeZone {
            origin: None,
            destination: Zone::Exile,
            target: TargetFilter::SelfRef,
            owner_library: false,
            enter_transformed: false,
            enters_under: None,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        }));
    }
    None
}

fn try_parse_airbend_clause(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let (_, rest_orig) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("airbend ")).parse(i)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
    let rest = TextPair::new(rest_orig, rest_lower);
    let (target_text, multi_target) = strip_optional_target_prefix(rest.original);
    let (target, after_target) = parse_target(target_text);
    let cost = parse_mana_symbols(after_target.trim_start())
        .map(|(cost, _)| cost)
        .unwrap_or(ManaCost::Cost {
            generic: 2,
            shards: vec![],
        });
    let lower_rest = rest.lower.trim_start();
    let is_mass = alt((tag::<_, _, OracleError<'_>>("all "), tag("each ")))
        .parse(lower_rest)
        .is_ok();

    let effect = if is_mass {
        let mass_target = match target {
            TargetFilter::Typed(mut typed) => {
                let had_other = typed.properties.contains(&FilterProp::Another);
                typed
                    .properties
                    .retain(|property| !matches!(property, FilterProp::Another));
                let typed_filter = TargetFilter::Typed(typed);
                if had_other {
                    TargetFilter::And {
                        filters: vec![
                            typed_filter,
                            TargetFilter::Not {
                                filter: Box::new(TargetFilter::ParentTarget),
                            },
                        ],
                    }
                } else {
                    typed_filter
                }
            }
            other => other,
        };
        Effect::ChangeZoneAll {
            origin: Some(Zone::Battlefield),
            destination: Zone::Exile,
            target: mass_target,
            enters_under: None,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            face_down_profile: None,
        }
    } else {
        Effect::ChangeZone {
            origin: Some(Zone::Battlefield),
            destination: Zone::Exile,
            target,
            owner_library: false,
            enter_transformed: false,
            enters_under: None,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        }
    };

    let register_bending = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::RegisterBending {
            kind: crate::types::events::BendingType::Air,
        },
    );

    Some(ParsedEffectClause {
        effect,
        duration: None,
        sub_ability: Some(Box::new(
            AbilityDefinition::new(
                AbilityKind::Spell,
                Effect::GrantCastingPermission {
                    permission: CastingPermission::ExileWithAltCost {
                        cost,
                        cast_transformed: false,
                        constraint: None,
                        // CR 611.2a: `grant_permission::resolve` binds this to
                        // the ability controller at grant time.
                        granted_to: None,
                        resolution_cleanup: None,
                        duration: None,
                        exile_instead_of_graveyard_on_resolve: false,
                    },
                    target: TargetFilter::TrackedSet {
                        id: TrackedSetId(0),
                    },
                    grantee: Default::default(),
                },
            )
            .sub_ability(register_bending),
        )),
        distribute: None,
        multi_target,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_earthbend_clause(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let (_, rest) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("earthbend ")).parse(i)
    })?;
    // `rest` is the original-case remainder; lowercase it for the nom-based
    // dispatcher inside `parse_earthbend_count_expr`, which expects already-lowered
    // input (matches the convention used by `parse_earthbend_params`'s sole
    // imperative caller, which passes a `rest_lower` slice).
    let lower_rest = rest.to_ascii_lowercase();
    let (target, counter_count) = imperative::parse_earthbend_count_expr(tp.original, &lower_rest);

    let register_bending = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::RegisterBending {
            kind: crate::types::events::BendingType::Earth,
        },
    );

    let return_effect = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::ChangeZone {
            origin: None,
            destination: Zone::Battlefield,
            target: TargetFilter::TriggeringSource,
            owner_library: false,
            enter_transformed: false,
            enters_under: Some(ControllerRef::You),
            enter_tapped: crate::types::zones::EtbTapState::Tapped,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        },
    );

    let delayed_return = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::CreateDelayedTrigger {
            condition: DelayedTriggerCondition::WhenDiesOrExiled {
                filter: TargetFilter::ParentTarget,
            },
            effect: Box::new(return_effect),
            uses_tracked_set: false,
        },
    )
    .sub_ability(register_bending);

    let put_counters = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::PutCounter {
            counter_type: CounterType::Plus1Plus1,
            count: counter_count,
            target: TargetFilter::ParentTarget,
        },
    )
    .sub_ability(delayed_return);

    Some(ParsedEffectClause {
        effect: Effect::Animate {
            power: Some(PtValue::Fixed(0)),
            toughness: Some(PtValue::Fixed(0)),
            types: vec!["Creature".to_string()],
            remove_types: vec![],
            target,
            keywords: vec![crate::types::keywords::Keyword::Haste],
        },
        duration: Some(Duration::Permanent),
        sub_ability: Some(Box::new(put_counters)),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 402.2 + CR 114.1: Parse "you have no maximum hand size [for the rest of the game]"
/// as an effect that creates an emblem with `NoMaximumHandSize` static.
///
/// When this text appears on a permanent as a static ability, the static parser handles it.
/// When it appears as an effect line in a spell or triggered ability (e.g., Choice of Fortunes),
/// it needs to create an emblem to produce a persistent game-state effect.
/// CR 118.12a: "[effect] unless a player has [~] deal N damage to them" — any
/// player may have the source deal damage instead of the primary effect
/// (Barbarian Bully).
fn try_parse_unless_player_have_deal_damage(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let (before_unless, _, after_unless) =
        nom_primitives::scan_preceded(tp.lower, |i| tag("unless a player has ").parse(i))?;
    let cost = parse_unless_player_have_deal_damage_cost(after_unless)?;
    let cleaned = tp.original[..before_unless.trim_end().len()].trim();
    let diagnostics_snapshot = ctx.diagnostics.len();
    let mut clause = parse_effect_clause(cleaned, ctx);
    if matches!(clause.effect, Effect::Unimplemented { .. }) {
        ctx.diagnostics.truncate(diagnostics_snapshot);
        return None;
    }
    clause.unless_pay = Some(UnlessPayModifier {
        cost,
        payer: TargetFilter::AllPlayers,
    });
    Some(clause)
}

fn parse_unless_player_have_deal_damage_cost(after_unless: &str) -> Option<AbilityCost> {
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("this creature "),
        tag::<_, _, OracleError<'_>>("~ "),
    ))
    .parse(after_unless)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>("deal ").parse(rest).ok()?;
    let (amount, tail) = super::oracle_util::parse_count_expr(rest)?;
    parse_deal_damage_to_them_tail(tail)?;
    Some(AbilityCost::EffectCost {
        effect: Box::new(Effect::DealDamage {
            amount,
            target: TargetFilter::Player,
            damage_source: None,
        }),
    })
}

/// CR 700.2 + CR 608.2d: "[DEFAULT] unless that player [A] or [B]" —
/// three-branch forced choice. The scoped player picks an avoidance option or
/// accepts the default consequence. Called before `try_parse_choose_one_of_inline`
/// to prevent the 2-branch splitter from misreading the left half.
fn try_parse_unless_three_branch_choice(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    // Nom combinator: split on the "unless" boundary (try "that player" first as
    // the most specific), then split the alternatives on exactly one top-level
    // " or ". `take_until` is bounded by the subsequent `tag`, so a match means
    // the literal boundary token was found in order — no permissive substring
    // scanning. The grammar is:
    //   <default> " unless " ("that player " | "they ") <alt1> " or " <alt2>
    use nom::Parser;
    // Try " unless that player " first (most specific); fall back to " unless they ".
    // Mirrors the original priority ordering — `split_around` matched the full
    // needle, so a "that player" form embedded after a "they" form (rare) is
    // still found via the first attempt.
    let try_split = |needle: &'static str| -> Option<(usize, usize, usize)> {
        nom_on_lower(tp.original, tp.lower, |i| {
            let (i, default) = take_until(needle).parse(i)?;
            let (i, _) = tag(needle).parse(i)?;
            let (i, alt1) = take_until(" or ").parse(i)?;
            let (i, _) = tag(" or ").parse(i)?;
            // Reject 3+ alternatives — a second " or " means the top-level
            // split was ambiguous and this isn't the binary "A or B" form.
            if nom::bytes::complete::take_until::<_, _, nom::error::Error<&str>>(" or ")
                .parse(i)
                .is_ok()
            {
                return Err(nom::Err::Error(nom::error::Error::new(
                    i,
                    nom::error::ErrorKind::Verify,
                )));
            }
            Ok((i, (default.len(), alt1.len(), i.len())))
        })
        .map(|(lens, _)| lens)
    };

    let (default_len, alt1_len, alt2_len) =
        try_split(" unless that player ").or_else(|| try_split(" unless they "))?;
    // Oracle text is ASCII so byte positions in `tp.original` and `tp.lower` match.
    let alts_start = tp.original.len() - alt2_len - " or ".len() - alt1_len;
    let alt2_start = alts_start + alt1_len + " or ".len();
    let default_orig = tp.original[..default_len].trim();
    let alt1_orig = tp.original[alts_start..alts_start + alt1_len].trim();
    let alt2_orig = tp.original[alt2_start..].trim().trim_end_matches('.');

    if default_orig.is_empty() || alt1_orig.is_empty() || alt2_orig.is_empty() {
        return None;
    }

    // Alternatives use third-person conjugation ("sacrifices", "discards") because
    // the "that player" subject was stripped. Deconjugate to imperative so effect
    // parsers recognise them.
    let alt1_deconj = subject::deconjugate_verb(alt1_orig);
    let alt2_deconj = subject::deconjugate_verb(alt2_orig);

    let diagnostics_snapshot = ctx.diagnostics.len();
    let default_clause = parse_effect_clause(default_orig, ctx);
    let alt1_clause = parse_effect_clause(&alt1_deconj, ctx);
    let alt2_clause = parse_effect_clause(&alt2_deconj, ctx);

    if matches!(default_clause.effect, Effect::Unimplemented { .. })
        || matches!(alt1_clause.effect, Effect::Unimplemented { .. })
        || matches!(alt2_clause.effect, Effect::Unimplemented { .. })
        || matches!(default_clause.effect, Effect::TargetOnly { .. })
        || matches!(alt1_clause.effect, Effect::TargetOnly { .. })
        || matches!(alt2_clause.effect, Effect::TargetOnly { .. })
    {
        ctx.diagnostics.truncate(diagnostics_snapshot);
        return None;
    }

    let mut default_def = ability_definition_from_clause(AbilityKind::Spell, default_clause);
    default_def.description = Some(default_orig.to_string());
    let mut alt1_def = ability_definition_from_clause(AbilityKind::Spell, alt1_clause);
    alt1_def.description = Some(alt1_deconj);
    let mut alt2_def = ability_definition_from_clause(AbilityKind::Spell, alt2_clause);
    alt2_def.description = Some(alt2_deconj);

    // Branch order mirrors oracle text: default consequence first, then avoidance options.
    Some(parsed_clause(Effect::ChooseOneOf {
        chooser: PlayerFilter::Controller, // Rebound to scoped opponent via player_scope
        branches: vec![default_def, alt1_def, alt2_def],
    }))
}

/// CR 111.2 + CR 608.2d: Token-choice clauses can elide the repeated verb:
/// "create a Food token or a Treasure token" means the controller chooses one
/// of two token-creation instructions as the ability resolves.
///
/// The generic `A or B` splitter intentionally requires both halves to be
/// complete imperatives. This helper handles the shared-leading-verb token
/// grammar by parsing each token noun phrase through `token::try_parse_token`
/// and wrapping the resulting normal token effects in `ChooseOneOf`.
fn try_parse_create_token_choice(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let ((), after_create_original) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("create ")).parse(i)
    })?;
    let consumed = tp.original.len() - after_create_original.len();
    let after_create = TextPair::new(after_create_original, &tp.lower[consumed..]);
    let (left, right) = after_create.split_around(" or ")?;

    if nom_primitives::split_once_on(left.lower, " or ").is_ok()
        || nom_primitives::split_once_on(right.lower, " or ").is_ok()
    {
        return None;
    }

    let left_text = left.original.trim();
    let right_text = right.original.trim();
    if left_text.is_empty() || right_text.is_empty() {
        return None;
    }

    let left_effect = token::try_parse_token(left.lower, left_text, ctx)?;
    let right_effect = token::try_parse_token(right.lower, right_text, ctx)?;

    let mut left_def = AbilityDefinition::new(AbilityKind::Spell, left_effect);
    left_def.description = Some(format!("create {left_text}"));
    let mut right_def = AbilityDefinition::new(AbilityKind::Spell, right_effect);
    right_def.description = Some(format!("create {right_text}"));

    Some(parsed_clause(Effect::ChooseOneOf {
        chooser: PlayerFilter::Controller,
        branches: vec![left_def, right_def],
    }))
}

/// CR 111.2 + CR 608.2c: Shared-verb token sequences such as "create a ...
/// token with deathtouch and a ... token with lifelink" carry two token noun
/// phrases in written order, not one token with a long keyword suffix. Parse
/// both noun phrases through the normal token grammar and chain the second.
fn try_parse_create_token_sequence(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let ((), after_create_original) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("create ")).parse(i)
    })?;
    let consumed = tp.original.len() - after_create_original.len();
    let after_create = TextPair::new(after_create_original, &tp.lower[consumed..]);

    let (left_original, left_lower, right_original, right_lower) =
        split_create_token_sequence(after_create)?;
    let left_effect = token::try_parse_token(left_lower, left_original.trim(), ctx)?;
    let right_effect = token::try_parse_token(right_lower, right_original.trim(), ctx)?;

    if !matches!(left_effect, Effect::Token { .. }) || !matches!(right_effect, Effect::Token { .. })
    {
        return None;
    }

    let mut right_def = AbilityDefinition::new(AbilityKind::Spell, right_effect);
    right_def.description = Some(format!("create {}", right_original.trim()));

    let mut clause = parsed_clause(left_effect);
    clause.sub_ability = Some(Box::new(right_def));
    Some(clause)
}

fn split_create_token_sequence<'a>(
    after_create: TextPair<'a>,
) -> Option<(&'a str, &'a str, &'a str, &'a str)> {
    let mut search_lower = after_create.lower;
    while let Some((before_lower, (), right_lower)) =
        nom_primitives::scan_preceded(search_lower, parse_token_sequence_conjunction)
    {
        let split_offset = after_create.lower.len() - search_lower.len() + before_lower.len();
        let right_offset = after_create.lower.len() - right_lower.len();
        let left_original = &after_create.original[..split_offset];
        let left_lower = &after_create.lower[..split_offset];
        let right_original = &after_create.original[right_offset..];

        if token::parse_token_description(left_original.trim()).is_some()
            && token::parse_token_description(right_original.trim()).is_some()
        {
            return Some((left_original, left_lower, right_original, right_lower));
        }

        search_lower = right_lower;
    }
    None
}

fn parse_token_sequence_conjunction(input: &str) -> OracleResult<'_, ()> {
    preceded(tag("and "), peek(parse_token_noun_start)).parse(input)
}

fn parse_token_noun_start(input: &str) -> OracleResult<'_, ()> {
    alt((
        value((), tag("a ")),
        value((), tag("an ")),
        value((), tag("one ")),
        value((), tag("x ")),
        value((), tag("that many ")),
        value((), terminated(nom_primitives::parse_number, tag(" "))),
    ))
    .parse(input)
}

/// CR 115.1 + CR 608.2d + CR 701.26a-b: "tap or untap target <object>" (and the
/// "untap or tap" ordering) declares a single target as the trigger/spell is put
/// on the stack, then the controller chooses the tap or untap instruction while
/// resolving. The choice is order-independent, so both verb orderings map to the
/// same `ChooseOneOf`.
fn try_parse_tap_or_untap_choice(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let ((), rest) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), alt((tag("tap or untap "), tag("untap or tap ")))).parse(i)
    })?;
    let (target_text, multi_target) = strip_optional_target_prefix(rest.trim_start());
    let (target, _rem) = parse_target_with_ctx(target_text, ctx);
    if matches!(target, TargetFilter::Any) {
        return None;
    }
    #[cfg(debug_assertions)]
    assert_no_compound_remainder(_rem, tp.original);

    let mut tap_branch = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::SetTapState {
            target: TargetFilter::ParentTarget,
            scope: EffectScope::Single,
            state: TapStateChange::Tap,
        },
    );
    tap_branch.description = Some("tap".to_string());
    let mut untap_branch = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::SetTapState {
            target: TargetFilter::ParentTarget,
            scope: EffectScope::Single,
            state: TapStateChange::Untap,
        },
    );
    untap_branch.description = Some("untap".to_string());

    let mut choice = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::ChooseOneOf {
            chooser: PlayerFilter::Controller,
            branches: vec![tap_branch, untap_branch],
        },
    );
    choice.description = Some("tap or untap".to_string());

    let mut clause = parsed_clause(Effect::TargetOnly { target });
    clause.multi_target = multi_target;
    clause.sub_ability = Some(Box::new(choice));
    Some(clause)
}

/// Separator combinator for disjunctive choice lists (CR 122.1 + CR 608.2d).
/// Recognizes the Oxford-comma final separators (", or " / ", and "), the bare
/// intra-list comma (", "), and the binary coordinators (" or " / " and ").
/// Longer alternatives are tried first so ", or " is not mis-split as ", " plus
/// a stray "or".
fn parse_choice_list_separator(input: &str) -> nom::IResult<&str, ()> {
    value(
        (),
        alt((
            tag(", or "),
            tag(", and "),
            tag(", "),
            tag(" or "),
            tag(" and "),
        )),
    )
    .parse(input)
}

/// Split a disjunctive choice list into its item slices using nom combinators.
/// Counter noun phrases and bare keyword names never contain a list separator,
/// so a `separated_list1` over `parse_choice_list_separator` recovers each item
/// without manual byte-offset slicing. Returns `None` unless the whole input is
/// consumed — a trailing unmatched remainder means the text was not a clean
/// list.
fn split_choice_list_items(input: &str) -> Option<Vec<&str>> {
    let item = recognize(many1(preceded(not(parse_choice_list_separator), anychar)));
    let (_, items) = all_consuming(separated_list1(parse_choice_list_separator, item))
        .parse(input)
        .ok()?;
    Some(items)
}

/// Shape of a disjunctive counter-choice list. Determines how each list item
/// is synthesized back into a `put ... on ...` branch clause.
///
/// - `Distributed`: each item is a complete counter noun phrase that already
///   ends in "counter" ("a +1/+1 counter", "two charge counters"). The item is
///   used verbatim as the choice phrase.
/// - `FromAmong`: "a counter from among X, Y, ..., and Z" — each item is a bare
///   keyword name; synthesized as "a <item> counter".
/// - `SharedNoun`: "a X, Y, ..., or Z counter" — one leading article and one
///   trailing "counter" shared across a list of bare keyword adjectives;
///   synthesized as "a <item> counter".
enum ChoiceListShape {
    Distributed,
    FromAmong,
    SharedNoun,
}

/// CR 122.1b: keyword counters distribute over a single shared noun. Recognize
/// the "shared-noun" disjunctive list shape: ONE leading article, a list of
/// bare keyword adjectives, and ONE trailing "counter" — e.g. "a menace,
/// trample, reach, or haste counter" yields `["menace", "trample", "reach",
/// "haste"]`.
///
/// The item combinator must stop at BOTH a list separator AND the trailing
/// " counter" sentinel; otherwise the final item greedily consumes
/// "haste counter" and the trailing `tag(" counter")` has nothing left to
/// match, causing `all_consuming` to fail. Excluding the sentinel from the
/// item leaves " counter" for the terminating tag.
///
/// Returns `None` unless the entire input is consumed as `a <list> counter`.
/// Per-item strict-counter-type validation is the caller's responsibility — a
/// raw match here does not yet guarantee every item names a real counter type.
fn recognize_shared_noun_counter_list(input: &str) -> Option<Vec<&str>> {
    let trailing_counter = || value((), (tag::<_, _, OracleError<'_>>(" counter"), eof));
    let item = recognize(many1(preceded(
        not(alt((parse_choice_list_separator, trailing_counter()))),
        anychar,
    )));
    let (_, items) = preceded(
        tag::<_, _, OracleError<'_>>("a "),
        all_consuming(terminated(
            separated_list1(parse_choice_list_separator, item),
            tag(" counter"),
        )),
    )
    .parse(input)
    .ok()?;
    Some(items)
}

/// CR 122.1 + CR 608.2d: Context-free classifier for a disjunctive
/// counter-choice list. Given the choices payload (the text BETWEEN
/// "your choice of " and " on TARGET"), recognize which of the three list
/// shapes it is and parse each item into a typed `(CounterType, QuantityExpr)`
/// pair.
///
/// Three list shapes (classified in priority order, mirroring
/// `try_parse_put_counter_choice`):
///   1. FromAmong  — "a counter from among X, Y, ..., and Z" (bare keywords)
///   2. SharedNoun — "a X, Y, ..., or Z counter" (one leading article + bare
///      keyword adjectives + one trailing "counter")
///   3. Distributed — "a A counter, a B counter, or a C counter" / binary,
///      each item a full counter noun phrase.
///
/// Item parsing:
///   - Distributed item ("a +1/+1 counter", "two charge counters"):
///     `parse_count_expr` then `parse_counter_type_typed` on the remainder
///     (mirrors `counter.rs::try_parse_put_counter`).
///   - FromAmong / SharedNoun bare-keyword item ("first strike"):
///     `all_consuming(parse_strict_counter_type)`, count = `Fixed { 1 }`.
///
/// Requires at least 2 items and that every item names a real counter type;
/// a non-counter list returns `None`. Nom-only — no string dispatch.
///
/// CR 122.1b: keyword counters (docs/MagicCompRules.txt:1180).
/// CR 122.1: named counters (docs/MagicCompRules.txt:1176).
pub(crate) fn classify_and_parse_counter_choice_list(
    choices_text: &str,
) -> Option<Vec<(CounterType, QuantityExpr)>> {
    let (shape, choice_items) =
        match tag::<_, _, OracleError<'_>>("a counter from among ")(choices_text) {
            Ok((rest, _)) => (ChoiceListShape::FromAmong, split_choice_list_items(rest)?),
            // CR 122.1b: keyword counters distribute over a single noun; only
            // classify as SharedNoun when the shape matches AND every item is a
            // recognized counter type — otherwise distributed lists and
            // non-counter lists leak through. Fall through to Distributed when
            // the strict guard fails.
            Err(_) => match recognize_shared_noun_counter_list(choices_text) {
                Some(items)
                    if items.len() >= 2
                        && items.iter().all(|item| {
                            all_consuming(nom_primitives::parse_strict_counter_type)
                                .parse(item.trim())
                                .is_ok()
                        }) =>
                {
                    (ChoiceListShape::SharedNoun, items)
                }
                _ => (
                    ChoiceListShape::Distributed,
                    split_choice_list_items(choices_text)?,
                ),
            },
        };

    if choice_items.len() < 2 {
        return None;
    }

    let mut entries: Vec<(CounterType, QuantityExpr)> = Vec::with_capacity(choice_items.len());
    for item in &choice_items {
        let item = item.trim();
        if item.is_empty() {
            return None;
        }
        let entry = match shape {
            // CR 122.1: full counter noun phrase ("a +1/+1 counter", "two charge
            // counters"). Parse count then counter type from the remainder.
            ChoiceListShape::Distributed => {
                let (count, rest) = parse_count_expr(item)?;
                let (_after, counter_type) = nom_primitives::parse_counter_type_typed(rest).ok()?;
                (counter_type, count)
            }
            // CR 122.1b: bare keyword name ("first strike"); count is one.
            ChoiceListShape::FromAmong | ChoiceListShape::SharedNoun => {
                let (_rest, counter_type) =
                    all_consuming(nom_primitives::parse_strict_counter_type)
                        .parse(item)
                        .ok()?;
                (counter_type, QuantityExpr::Fixed { value: 1 })
            }
        };
        entries.push(entry);
    }

    Some(entries)
}

/// CR 122.1 + CR 608.2d: Parse shared-target counter choices of the form
/// "put your choice of A counter-pattern, B counter-pattern, or C
/// counter-pattern on TARGET" (N-ary branches).
///
/// Inspirit, Flagship Vessel is the binary motivating case:
/// "put your choice of a +1/+1 counter or two charge counters on up to one
/// other target artifact".
///
/// Invoke the Ancients is the N-ary motivating case:
/// "put your choice of a vigilance counter, a reach counter, or a trample
/// counter on it".
///
/// Aragorn, Company Leader is the "from among" motivating case:
/// "put your choice of a counter from among first strike, vigilance,
/// deathtouch, and lifelink on Aragorn".
///
/// We split the shared choice payload into N items using the Oxford-comma
/// pattern (", or " as the final separator, ", " between earlier items),
/// or the "from among" pattern (", and " as the final separator with bare
/// keyword names), then reparse each branch as a full `put ... on ...`
/// clause so existing counter parsing (including multi-target extraction
/// for "up to N") stays authoritative.
fn try_parse_put_counter_choice(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let ((), after_choice_original) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("put your choice of ")).parse(i)
    })?;

    let consumed = tp.original.len() - after_choice_original.len();
    let after_choice = TextPair::new(after_choice_original, &tp.lower[consumed..]);
    let (choices_tp, target_tp) = after_choice.split_around(" on ")?;

    // Split the post-"on" choices into individual items via nom combinators.
    // Three list shapes (CR 122.1 + CR 608.2d), classified in priority order:
    //   1. FromAmong  — "a counter from among X, Y, ..., and Z" (bare keywords)
    //   2. SharedNoun — "a X, Y, ..., or Z counter" (one leading article + bare
    //      keyword adjectives + one trailing "counter")
    //   3. Distributed — "a A counter, a B counter, or a C counter" / binary
    //      ("a A counter or a B counter"), each item a full counter noun phrase.
    // CR 122.1b: both FromAmong and SharedNoun name bare keywords; each branch
    // is later synthesized as "a <keyword> counter".
    let choices_text = choices_tp.original;
    let (shape, choice_items) =
        match tag::<_, _, OracleError<'_>>("a counter from among ")(choices_text) {
            Ok((rest, _)) => (ChoiceListShape::FromAmong, split_choice_list_items(rest)?),
            // CR 122.1b: keyword counters distribute over a single noun; CR
            // 608.2d: choice made at resolution; CR 601.2c: shared target at
            // cast. Only classify as SharedNoun when the shape matches AND every
            // item is a recognized counter type — otherwise distributed lists
            // ("a +1/+1 counter, ...") and non-counter lists ("a red or blue
            // creature") would leak through. Fall through to Distributed when
            // the strict guard fails.
            Err(_) => match recognize_shared_noun_counter_list(choices_text) {
                Some(items)
                    if items.len() >= 2
                        && items.iter().all(|item| {
                            all_consuming(nom_primitives::parse_strict_counter_type)
                                .parse(item.trim())
                                .is_ok()
                        }) =>
                {
                    (ChoiceListShape::SharedNoun, items)
                }
                _ => (
                    ChoiceListShape::Distributed,
                    split_choice_list_items(choices_text)?,
                ),
            },
        };

    // Require at least 2 branches.
    if choice_items.len() < 2 {
        return None;
    }

    let target_text = target_tp.original.trim().trim_end_matches('.');
    if target_text.is_empty() {
        return None;
    }

    // Validate each choice item is non-empty.
    if choice_items.iter().any(|item| item.trim().is_empty()) {
        return None;
    }

    // Parse each branch as "put <choice> on <target>".
    let diagnostics_snapshot = ctx.diagnostics.len();
    // Parse each branch as "put <choice> on <target>" so existing counter
    // parsing (including "up to N" multi-target extraction) stays authoritative.
    // Keep the per-branch "put <choice>" description for display; the shared
    // target is lifted to the parent clause below.
    let mut branch_clauses: Vec<(ParsedEffectClause, String)> =
        Vec::with_capacity(choice_items.len());
    for item in &choice_items {
        // CR 122.1b: FromAmong and SharedNoun name bare keywords, so synthesize
        // "a <keyword> counter"; Distributed items are already full noun phrases.
        let choice_phrase = match shape {
            ChoiceListShape::Distributed => item.trim().to_string(),
            ChoiceListShape::FromAmong | ChoiceListShape::SharedNoun => {
                format!("a {} counter", item.trim())
            }
        };
        let branch_text = format!("put {choice_phrase} on {target_text}");
        let clause = parse_effect_clause(&branch_text, ctx);
        if !matches!(clause.effect, Effect::PutCounter { .. })
            || matches!(clause.effect, Effect::Unimplemented { .. })
            || matches!(clause.effect, Effect::TargetOnly { .. })
        {
            ctx.diagnostics.truncate(diagnostics_snapshot);
            return None;
        }
        branch_clauses.push((clause, format!("put {choice_phrase}")));
    }

    // CR 601.2c: the trailing "on <target>" is a single shared cast-time target
    // for the whole choice — the player chooses one permanent, then chooses which
    // counter to put on it. Every branch parsed it identically; lift it to a
    // parent `TargetOnly` clause (mirrors `try_parse_tap_or_untap_choice`) and
    // retarget each branch to `ParentTarget`. This surfaces one shared target
    // slot at cast time, instead of N per-branch targets that
    // `collect_target_slot_specs` never descends into from inside `ChooseOneOf`.
    let shared_target = match &branch_clauses[0].0.effect {
        Effect::PutCounter { target, .. } => target.clone(),
        _ => {
            ctx.diagnostics.truncate(diagnostics_snapshot);
            return None;
        }
    };
    let shared_multi_target = branch_clauses[0].0.multi_target.take();

    let mut branches: Vec<AbilityDefinition> = Vec::with_capacity(branch_clauses.len());
    for (mut clause, description) in branch_clauses {
        clause.multi_target = None;
        retarget_put_counter_to_parent(&mut clause.effect);
        let mut def = ability_definition_from_clause(AbilityKind::Spell, clause);
        def.description = Some(description);
        branches.push(def);
    }

    let mut choice = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::ChooseOneOf {
            chooser: PlayerFilter::Controller,
            branches,
        },
    );
    choice.description = Some("put your choice of counter".to_string());

    let mut clause = parsed_clause(Effect::TargetOnly {
        target: shared_target,
    });
    clause.multi_target = shared_multi_target;
    clause.sub_ability = Some(Box::new(choice));
    Some(clause)
}

/// Rewrite a `PutCounter` effect to act on the parent clause's target
/// (`TargetFilter::ParentTarget`), preserving `counter_type` and `count`.
/// Used when a shared cast-time target is lifted out of a `ChooseOneOf`.
fn retarget_put_counter_to_parent(effect: &mut Effect) {
    if let Effect::PutCounter { target, .. } = effect {
        *target = TargetFilter::ParentTarget;
    }
}

/// CR 700.2 + CR 608.2d: Detect inline binary-choice imperatives of the form
/// "A or B" where both A and B parse independently as supported effects.
/// Emits `Effect::ChooseOneOf { branches: [A, B] }` so the second branch is
/// preserved in card data rather than silently dropped by the single-verb
/// dispatch.
///
/// Highway Robbery ("discard a card or sacrifice a land") is the motivating
/// case; the same shape applies to other "you may A or B" cards where the
/// outer "you may" has already been stripped by `strip_optional_effect_prefix`.
///
/// Constraints (false-positive guards):
///   1. Reject if the clause starts with "target " — "target creature or
///      player" is a typed target, not a choice of effects.
///   2. Reject if the first token is a modal header ("choose "), reminder/
///      connector ("either"), or a non-imperative starter — this helper is
///      a last-resort detector, not a general splitter.
///   3. Reject unless BOTH halves independently parse to a non-`Unimplemented`
///      effect. A half failing to parse means this isn't a true "A or B"
///      choice — it's probably noun-phrase disjunction ("creature or land")
///      inside a larger imperative.
///   4. Only consider the FIRST `, or ` or first top-level ` or ` split. Cards
///      with 3+ branches are rare and handled by bulleted modal text instead.
fn try_parse_choose_one_of_inline(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let mut chooser = PlayerFilter::Controller;
    let mut scoped_choice_player = false;
    let mut tp = tp;
    if let Some((prefix_chooser, rest_original)) = nom_on_lower(
        tp.original,
        tp.lower,
        parse_villainous_choice_chooser_prefix,
    ) {
        let consumed = tp.original.len() - rest_original.len();
        tp = TextPair::new(rest_original, &tp.lower[consumed..]);
        chooser = prefix_chooser;
        scoped_choice_player = true;
    }

    // CR 115.1: bail on target phrases — "target creature or player" is a
    // typed-target disjunction, not a choice between effects.
    if tag::<_, _, OracleError<'_>>("target ")
        .parse(tp.lower)
        .is_ok()
    {
        return None;
    }

    // Find the first top-level " or " split. Prefer a comma-qualified ", or "
    // as the clearer form; fall back to bare " or " when the text is short
    // enough that misreading intra-phrase "or" is unlikely. Each needle
    // literal appears exactly once — the separator's length is implied by
    // what's missing between the two returned halves.
    //
    // CR 202.3 + CR 107.1c: Comparator grammar ("less than or equal to",
    // "greater than or equal to", "or fewer", "or more", "or less",
    // "or greater") wraps a bare " or " that is structurally part of the
    // comparator phrase, NOT a disjunction of imperative clauses. Splitting
    // here truncates the dynamic-quantity comparator (e.g., Beseech the
    // Queen's "with mana value less than or equal to the number of lands
    // you control") into a malformed left half, and the trial parse against
    // that half pollutes the parse_warnings buffer with spurious
    // search-filter-suffix gaps. Skip this helper entirely for any clause
    // that contains a comparator phrase — none of the false-positive cards
    // are real binary-choice clauses anyway.
    if [
        "less than or",
        "greater than or",
        " or fewer",
        " or more",
        " or less",
        " or greater",
    ]
    .iter()
    .any(|needle| tp.lower.contains(needle))
    {
        return None;
    }
    let (before_lower, after_lower) =
        split_around(tp.lower, ", or ").or_else(|| split_around(tp.lower, " or "))?;

    // CR 119.7 + CR 119.8 + CR 104.2 + CR 104.3: When the left half contains a
    // restriction-predicate marker ("can't", "cannot", "doesn't", "don't") at
    // any word boundary, the "or" coordinates predicates within a single
    // restriction — NOT two imperative choices. Everybody Lives! prints
    // "players can't lose the game or win the game this turn"; without this
    // guard, the detector mis-classifies the compound as
    // ChooseOneOf(CantLoseTheGame, WinTheGame) because both halves happen to
    // parse independently as supported effects. Restriction predicates are
    // surface-level "subject can't <verb-list>" grammar and have no chooser
    // semantic — defer to the subject+predicate path so
    // `parse_restriction_modes` can recognize the compound. A single
    // word-boundary scan with an `alt()` of the four negation forms covers
    // both the start-of-string case ("can't ...") and the mid-string case
    // ("<subject> can't ...") in one pass.
    let has_restriction = nom_primitives::scan_at_word_boundaries(before_lower, |i| {
        alt((
            tag::<_, _, OracleError<'_>>("can't "),
            tag("cannot "),
            tag("doesn't "),
            tag("don't "),
        ))
        .parse(i)
    })
    .is_some();
    if has_restriction {
        return None;
    }

    // Multi-`or` chains and inner-noun disjunctions ("discard a creature card
    // or land, or sacrifice a creature") would split here at the FIRST `or`,
    // leaving the left half's inner ` or ` to be silently dropped by
    // `parse_effect_clause` — both halves parse to non-Unimplemented but the
    // left has the wrong meaning. Reject unless the left half is unambiguously
    // a single imperative (no further top-level ` or `). This keeps the
    // 2-branch case working and conservatively declines on 3+ chains so they
    // fall through to higher-fidelity parsing rather than misread silently.
    //
    // Detection uses nom's `take_until` to scan for ` or ` in the already-
    // separated left half — a structural post-split sanity check, not parser
    // dispatch.
    if take_until::<_, _, OracleError<'_>>(" or ")
        .parse(before_lower)
        .is_ok()
    {
        return None;
    }

    let split_index = before_lower.len();
    let after_offset = tp.lower.len() - after_lower.len();

    let left_orig = tp.original[..split_index].trim();
    let right_orig = tp.original[after_offset..].trim();

    // Both halves must be non-empty and look like imperatives. The left half
    // must not end with a subject marker that would make the "or" coordinate
    // nouns (e.g., "target creature" should not split as a branch boundary).
    if left_orig.is_empty() || right_orig.is_empty() {
        return None;
    }

    // Attempt to parse each branch independently as a clause. Snapshot the
    // warnings buffer so we can roll back any side-effect warnings emitted
    // during these trial parses if the split is rejected — otherwise a
    // failed trial pollutes the committed warnings buffer with spurious
    // gaps from a malformed branch (e.g., "return a red" left half from
    // splitting "return a red or green creature" at the wrong " or ").
    let diagnostics_snapshot = ctx.diagnostics.len();
    let left_clause;
    let right_clause;
    if scoped_choice_player {
        let mut branch_ctx = ctx.clone();
        branch_ctx.relative_player_scope = Some(ControllerRef::ScopedPlayer);
        left_clause = parse_effect_clause(left_orig, &mut branch_ctx);
        right_clause = parse_effect_clause(right_orig, &mut branch_ctx);
        ctx.diagnostics = branch_ctx.diagnostics;
    } else {
        left_clause = parse_effect_clause(left_orig, ctx);
        right_clause = parse_effect_clause(right_orig, ctx);
    }

    // Reject unless BOTH branches produce non-Unimplemented effects. This
    // prevents false positives on noun-phrase disjunctions and "and/or"
    // coordinations inside larger imperatives.
    if matches!(left_clause.effect, Effect::Unimplemented { .. })
        || matches!(right_clause.effect, Effect::Unimplemented { .. })
    {
        ctx.diagnostics.truncate(diagnostics_snapshot);
        return None;
    }

    // Also reject if either branch is `TargetOnly` — that's a structural
    // wrapper, not a terminal effect. A real binary choice needs two
    // executable branches.
    if matches!(left_clause.effect, Effect::TargetOnly { .. })
        || matches!(right_clause.effect, Effect::TargetOnly { .. })
    {
        ctx.diagnostics.truncate(diagnostics_snapshot);
        return None;
    }

    let mut left_def = ability_definition_from_clause(AbilityKind::Spell, left_clause);
    left_def.description = Some(left_orig.to_string());
    let mut right_def = ability_definition_from_clause(AbilityKind::Spell, right_clause);
    right_def.description = Some(right_orig.to_string());

    Some(parsed_clause(Effect::ChooseOneOf {
        chooser,
        branches: vec![left_def, right_def],
    }))
}

fn parse_villainous_choice_chooser_prefix(input: &str) -> OracleResult<'_, PlayerFilter> {
    alt((
        value(
            PlayerFilter::DefendingPlayer,
            tag("defending player faces a villainous choice — "),
        ),
        value(
            PlayerFilter::Opponent,
            tag("target opponent faces a villainous choice — "),
        ),
        parse_life_lost_villainous_choice_chooser,
        value(PlayerFilter::Controller, tag("face a villainous choice — ")),
        value(
            PlayerFilter::Controller,
            tag("faces a villainous choice — "),
        ),
    ))
    .parse(input)
}

fn parse_life_lost_villainous_choice_chooser(input: &str) -> OracleResult<'_, PlayerFilter> {
    let (input, relation) = alt((
        value(PlayerRelation::Opponent, tag("each other player who lost ")),
        value(PlayerRelation::Opponent, tag("each opponent who lost ")),
        value(PlayerRelation::All, tag("each player who lost ")),
        value(PlayerRelation::Opponent, tag("who lost ")),
    ))
    .parse(input)?;
    let (input, threshold) = nom_primitives::parse_number(input)?;
    let (input, _) = tag(" or more life this turn faces a villainous choice — ").parse(input)?;
    let threshold = i32::try_from(threshold).unwrap_or(i32::MAX);

    Ok((
        input,
        PlayerFilter::PlayerAttribute {
            relation,
            attr: Box::new(QuantityRef::LifeLostThisTurn {
                player: PlayerScope::ScopedPlayer,
            }),
            comparator: Comparator::GE,
            value: Box::new(QuantityExpr::Fixed { value: threshold }),
        },
    ))
}

fn ability_definition_from_clause(
    kind: AbilityKind,
    clause: ParsedEffectClause,
) -> AbilityDefinition {
    let mut def = AbilityDefinition::new(kind, clause.effect);
    def.sub_ability = clause.sub_ability;
    def.duration = clause.duration;
    def.condition = clause.condition;
    def.optional = clause.optional;
    def.multi_target = clause.multi_target;
    def.distribute = clause.distribute;
    def
}

fn parse_event_context_ref_with_ctx<'a>(
    text: &'a str,
    ctx: &ParseContext,
) -> Option<(TargetFilter, &'a str)> {
    let (target, rest) = parse_event_context_ref(text)?;
    let target = match (&target, ctx.relative_player_scope.as_ref()) {
        (TargetFilter::TriggeringPlayer, Some(ControllerRef::ScopedPlayer)) => {
            TargetFilter::ScopedPlayer
        }
        (TargetFilter::TriggeringPlayer, Some(ControllerRef::SourceChosenPlayer)) => {
            TargetFilter::SourceChosenPlayer
        }
        (TargetFilter::TriggeringPlayer, Some(ControllerRef::ParentTargetController)) => {
            TargetFilter::ParentTargetController
        }
        _ => target,
    };
    Some((target, rest))
}

fn try_parse_no_max_hand_size_effect(tp: TextPair<'_>) -> Option<Effect> {
    // Strip optional "you " prefix, then match "have no maximum hand size"
    let after_you = nom_on_lower(tp.original, tp.lower, |i| value((), tag("you ")).parse(i));
    let rest = after_you.map(|(_, r)| r).unwrap_or(tp.original);
    let rest_lower = rest.to_lowercase();

    // Match "have no maximum hand size" with optional trailing "for the rest of the game"
    let matched = tag::<_, _, OracleError<'_>>("have no maximum hand size")
        .parse(rest_lower.as_str())
        .ok()?;
    let remainder = matched.0.trim().trim_end_matches('.');
    // Allow bare "have no maximum hand size" or "for the rest of the game" suffix
    if !remainder.is_empty()
        && tag::<_, _, OracleError<'_>>("for the rest of the game")
            .parse(remainder)
            .is_err()
    {
        return None;
    }

    Some(Effect::CreateEmblem {
        statics: vec![StaticDefinition::new(StaticMode::NoMaximumHandSize)
            .description("You have no maximum hand size.".to_string())],
        triggers: Vec::new(),
    })
}

/// CR 608.2d: Parse "have it [verb]" / "have you [verb]" causative constructions.
/// Used by "any opponent may" effects where the opponent causes the source or controller
/// to perform an action (e.g., "have it deal 4 damage to them").
fn try_parse_have_causative(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    // Pattern A: "have it deal N damage to them" / "have ~ deal N damage to them"
    //
    // Strictly gated to the implicit-recipient form ("to them" / "to that
    // player") because the broader "have ~ deal N damage to <X>" pattern is
    // handled by `try_parse_have_redirection` downstream, which preserves the
    // explicit recipient (e.g., Oath of Mages — "have ~ deal 1 damage to the
    // second player" must reach the anaphor-target arm, not collapse to
    // `target: Player`).
    let after_have = nom_on_lower(tp.original, tp.lower, |input| {
        value(
            (),
            alt((tag("have it "), tag("have ~ "), tag("have this artifact "))),
        )
        .parse(input)
    });
    if let Some((_, rest_orig)) = after_have {
        let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
        let rest = TextPair::new(rest_orig, rest_lower);
        // "deal N damage to them" / "deal N damage to that player"
        if let Some(after_deal) = nom_on_lower(rest.original, rest.lower, |i| {
            value((), tag("deal ")).parse(i)
        })
        .map(|(_, r)| TextPair::new(r, &rest.lower[rest.lower.len() - r.len()..]))
        {
            if let Some((amount, after_count_lower)) =
                super::oracle_util::parse_count_expr(after_deal.lower)
            {
                // After the count, require a "damage to {them|that player}"
                // tail — anything else is an explicit recipient that must
                // flow through the general redirection path.
                let after_damage = after_count_lower
                    .strip_prefix("damage to ") // allow-noncombinator: structural tail check on classified count remainder
                    .unwrap_or("");
                let recipient_implicit = after_damage
                    .trim_end_matches('.')
                    .trim_end_matches(',')
                    .trim()
                    .eq("them")
                    || after_damage.trim_end_matches('.').trim().eq("that player");
                if recipient_implicit {
                    return Some(parsed_clause(Effect::DealDamage {
                        amount,
                        target: TargetFilter::Player,
                        damage_source: None,
                    }));
                }
                // CR 608.2d: "have this artifact deal 1 damage to it" (Requiem
                // Monolith) — optional self-damage the targeted creature's
                // controller may cause the source artifact to deal.
                if after_damage.trim_end_matches('.').trim() == "it" {
                    return Some(parsed_clause(Effect::DealDamage {
                        amount,
                        target: TargetFilter::ParentTarget,
                        damage_source: None,
                    }));
                }
            }
        }
        // CR 611.2b: When the specific causative "deal damage" pattern does
        // not match, decline so the more general `try_parse_have_redirection`
        // (subject-predicate dispatch downstream of `parse_effect_clause`) can
        // take this clause. Recursing through `parse_effect_clause` here would
        // erase the subject (`~` / `it`) and reduce the remainder to a bare
        // imperative — which `try_parse_subject_become_clause` and other
        // subject-aware arms can no longer reach (Sarkhan, Soul Aflame's
        // "have ~ become a copy of it ..." class).
        return None;
    }

    // Pattern B: "have you [verb]" — controller performs an action directed by opponent
    if let Some((_, rest_orig)) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("have you ")).parse(i)
    }) {
        let clause = parse_effect_clause(rest_orig, ctx);
        return Some(clause);
    }

    None
}

fn all_core_type_categories() -> Vec<CoreType> {
    vec![
        CoreType::Artifact,
        CoreType::Battle,
        CoreType::Creature,
        CoreType::Enchantment,
        CoreType::Instant,
        CoreType::Land,
        CoreType::Planeswalker,
        CoreType::Sorcery,
    ]
}

/// CR 122.1 + CR 608.2d: Parse the body of Bribe Taker's "for each kind of
/// counter on permanents you control, you may put your choice of a +1/+1 counter
/// or a counter of that kind on this creature" into a `ChooseOneOf` between a
/// fixed-counter branch and a dynamic "counter of that kind" branch.
///
/// This runs on the body remainder AFTER `strip_for_each_prefix` has lifted the
/// `DistinctCounterKindsAmong` iteration source onto the parent ability's
/// `repeat_for` (so the body text here has the "for each … , " prefix already
/// removed). The leading "you may " is also already peeled by `peel_clause`
/// (which sets `optional`), but is accepted here as well so direct invocations
/// (tests, non-peeled paths) parse identically.
///
/// The dynamic branch is tagged `IterationKindBinding::RebindToIteratedKind`;
/// the `repeat_for` loop rewrites its placeholder counter type to each iterated
/// kind in turn (see `rebind_iterated_counter_kind` in `effects/mod.rs`). The
/// fixed counter type is parsed via `parse_counter_type_typed`, so the class
/// covers any fixed counter ("a lore counter or a counter of that kind"), not
/// just +1/+1. The placeholder counter type on the dynamic branch is a
/// don't-care — the loop overwrites every tagged branch each iteration.
fn try_parse_for_each_counter_kind_choice(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    type E<'a> = OracleError<'a>;

    let (rest, saw_you_may) = opt(tag::<_, _, E>("you may "))
        .parse(tp.lower)
        .map(|(rest, opt_match)| (rest, opt_match.is_some()))
        .ok()?;
    let (rest, _) = tag::<_, _, E>("put your choice of ").parse(rest).ok()?;
    let (rest, _) = nom_primitives::parse_article.parse(rest).ok()?;
    let (rest, fixed_counter) = nom_primitives::parse_counter_type_typed(rest).ok()?;
    let (rest, _) = tag::<_, _, E>(" counter or a counter of that kind on ")
        .parse(rest)
        .ok()?;
    // CR 109.4: self target — "this creature" is normalized to `~` upstream.
    let (rest, _) = tag::<_, _, E>("~").parse(rest).ok()?;
    if !rest.trim().trim_end_matches('.').is_empty() {
        return None;
    }

    // CR 608.2d: the controller chooses between the two branches at resolution.
    // Fixed branch: put the parsed counter on self.
    let fixed_branch = AbilityDefinition {
        description: Some(format!("put a {} counter", fixed_counter.display_phrase())),
        ..AbilityDefinition::new(
            AbilityKind::Spell,
            Effect::PutCounter {
                counter_type: fixed_counter,
                count: QuantityExpr::Fixed { value: 1 },
                target: TargetFilter::SelfRef,
            },
        )
    };
    // Dynamic branch: placeholder counter type is a don't-care — the
    // `DistinctCounterKindsAmong` loop rewrites it to the current iterated kind
    // each iteration via `rebind_iterated_counter_kind`.
    let dynamic_branch = AbilityDefinition {
        description: Some("put a counter of that kind".to_string()),
        iteration_kind_binding: Some(IterationKindBinding::RebindToIteratedKind),
        ..AbilityDefinition::new(
            AbilityKind::Spell,
            Effect::PutCounter {
                counter_type: CounterType::Plus1Plus1,
                count: QuantityExpr::Fixed { value: 1 },
                target: TargetFilter::SelfRef,
            },
        )
    };

    Some(ParsedEffectClause {
        effect: Effect::ChooseOneOf {
            chooser: PlayerFilter::Controller,
            branches: vec![fixed_branch, dynamic_branch],
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        // CR 608.2: "you may" makes the per-iteration choice optional. When this
        // body was peeled, `peel_clause` will OR its own optional flag in too.
        optional: saw_you_may,
        unless_pay: None,
    })
}

fn try_parse_distinct_card_types_from_revealed(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    type E<'a> = OracleError<'a>;

    let (rest, _) = tag::<_, _, E>("for each ").parse(tp.lower).ok()?;
    let (rest, _) = alt((tag::<_, _, E>("card type"), tag("card types")))
        .parse(rest)
        .ok()?;
    let (rest, _) = tag::<_, _, E>(", you may put ").parse(rest).ok()?;
    let (rest, _) = nom_primitives::parse_article.parse(rest).ok()?;
    let (rest, _) = tag::<_, _, E>("card of that type from among ")
        .parse(rest)
        .ok()?;
    let (rest, _) = alt((
        tag::<_, _, E>("the revealed cards"),
        tag("those revealed cards"),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, E>(" into your hand").parse(rest).ok()?;
    if !rest.trim().is_empty() {
        return None;
    }

    let categories = all_core_type_categories();
    Some(ParsedEffectClause {
        effect: Effect::ChooseFromZone {
            count: categories.len() as u32,
            zone: Zone::Library,
            additional_zones: Vec::new(),
            zone_owner: crate::types::ability::ZoneOwner::Controller,
            filter: None,
            chooser: crate::types::ability::Chooser::Controller,
            up_to: true,
            constraint: Some(ChooseFromZoneConstraint::DistinctCardTypes { categories }),
        },
        duration: None,
        sub_ability: Some(Box::new(AbilityDefinition::new(
            AbilityKind::Spell,
            Effect::ChangeZone {
                origin: Some(Zone::Library),
                destination: Zone::Hand,
                target: TargetFilter::Any,
                owner_library: false,
                enter_transformed: false,
                enters_under: None,
                enter_tapped: crate::types::zones::EtbTapState::Unspecified,
                enters_attacking: false,
                up_to: false,
                enter_with_counters: vec![],
                face_down_profile: None,
            },
        ))),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

#[tracing::instrument(level = "debug")]
fn parse_effect_clause(text: &str, ctx: &mut ParseContext) -> ParsedEffectClause {
    // Phase 2 PoC: peel structural slots off the head of the clause before
    // body parsing. The recursive shell strips slot-bearing prefixes
    // (currently just "you may " for the Optional slot) and accumulates them
    // into a `ClauseContext`. The bare imperative remainder is parsed by the
    // existing pipeline; the context is applied onto the result before
    // return so no slot is silently dropped.
    //
    // See `data/parser-swallow-progress.md` for the full architecture and
    // `crates/engine/src/parser/clause_shell.rs` for the slot machinery.
    let (peeled_text, peel_ctx) = super::clause_shell::peel_clause(text);
    if peel_ctx.is_empty() {
        return parse_effect_clause_inner(text, ctx);
    }
    if let Some(mut clause) = try_parse_for_each_effect(text, ctx) {
        peel_ctx.apply_optional(&mut clause.optional);
        if clause.condition.is_none() {
            if let Some(cond) = peel_ctx.condition().cloned() {
                clause.condition = Some(cond);
            }
        }
        return clause;
    }
    let original_lower = text.to_lowercase();
    if scan_contains_phrase(&original_lower, "this turn")
        || scan_contains_phrase(&original_lower, "until ")
    {
        if let Some(mut clause) =
            try_parse_play_from_exile(TextPair::new(text, &original_lower), ctx)
        {
            if !matches!(clause.effect, Effect::GrantCastingPermission { .. }) {
                peel_ctx.apply_optional(&mut clause.optional);
            }
            if clause.condition.is_none() {
                if let Some(cond) = peel_ctx.condition().cloned() {
                    clause.condition = Some(cond);
                }
            }
            return clause;
        }
    }
    let mut clause = parse_effect_clause_inner(&peeled_text, ctx);
    // Trial-parse fallback: peeling may have removed disambiguation signal
    // a specialized parser depends on (e.g., `the next spell you cast this
    // turn` patterns). If the peeled variant lands in `Unimplemented`,
    // retry with the original text. The shell is conservative — when in
    // doubt, leave the slot on the text and let the body parser handle it.
    if matches!(clause.effect, Effect::Unimplemented { .. }) {
        return parse_effect_clause_inner(text, ctx);
    }
    peel_ctx.apply_optional(&mut clause.optional);
    // Duration: route through `with_clause_duration` so
    // GenericEffect/GrantCastingPermission's embedded duration field
    // is patched alongside `clause.duration`. Skip when the body parser
    // already populated a non-default `clause.duration` (some specialized
    // parsers set it themselves and we must not clobber). A default
    // `Permanent` from a body parser yields to the explicit peeled duration.
    if clause.duration.is_none() || matches!(clause.duration, Some(Duration::Permanent)) {
        if let Some(duration) = peel_ctx.duration().cloned() {
            clause = with_clause_duration(clause, duration);
        }
    }
    // Condition: assign onto `clause.condition` when the inner parse
    // didn't produce one. The chunk-loop conditional handling at line
    // 6020+ runs before parse_effect_clause and may already have set
    // `condition` via its own dedicated stripper chain — don't clobber.
    if clause.condition.is_none() {
        if let Some(cond) = peel_ctx.condition().cloned() {
            clause.condition = Some(cond);
        }
    }
    clause
}

fn try_parse_for_each_copy_token_source(
    text: &str,
    lower: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let (source_filter, body) = parse_for_each_object_copy_parts(text, lower)?;
    let body_lower = body.to_lowercase();
    let Effect::CopyTokenOf {
        target,
        enters_attacking,
        tapped,
        count,
        extra_keywords,
        additional_modifications,
        ..
    } = token::try_parse_token(&body_lower, body, ctx)?
    else {
        return None;
    };
    if !matches!(target, TargetFilter::ParentTarget | TargetFilter::SelfRef) {
        return None;
    }
    Some(parsed_clause(Effect::CopyTokenOf {
        target: TargetFilter::None,
        owner: TargetFilter::Controller,
        source_filter: Some(source_filter),
        enters_attacking,
        tapped,
        count,
        extra_keywords,
        additional_modifications,
    }))
}

/// CR 603.7e + CR 118.1: Detect the compound clause
/// "choose any number of <filter> [they control] and pay <cost> for each
/// <noun> chosen this way" (Magnetic Mountain, Dream Tides, Thelon's Curse).
///
/// Emits a 2-effect head-injected chain as a single `ParsedEffectClause`:
///   head:        `Effect::ChooseObjectsIntoTrackedSet { chooser, filter, .. }`
///   sub_ability: `Effect::PayCost { cost: ScaledMana { base, times: TrackedSetSize } }`
///
/// The trailing ". If the player does, untap those creatures" sentence is a
/// separate chunk; the chunk-loop's `strip_if_you_do_conditional` + deepest-
/// sub_ability append wires it onto the `PayCost` node unchanged.
fn try_parse_choose_and_pay_per_object(
    text: &str,
    lower: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    // Selection head: [ "that player may " | "the player may " ] "choose "
    // [ "any number of " | "a " ] — nom dispatch.
    //
    // The leading subject-modal prefix ("that player may") is consumed here so
    // the detector recognizes the complete clause; `optional` is set on the
    // produced clause to encode the "may". The cardinality quantifier is
    // `opt`: when "any number of" is absent (already stripped upstream by
    // `strip_any_number_quantifier`), "any number" cardinality (`min: 0,
    // max: None`) is the correct default for this clause class.
    let ((subject_modal, (min, max)), after_choose) = nom_on_lower(text, lower, |input| {
        let (input, subject_modal) = opt(alt((
            value(true, tag("that player may ")),
            value(true, tag("the player may ")),
        )))
        .parse(input)?;
        let (input, ()) = value((), tag("choose ")).parse(input)?;
        let (input, card) = opt(alt((
            value((0u32, None), tag("any number of ")),
            value((1u32, Some(1u32)), tag("a ")),
        )))
        .parse(input)?;
        Ok((
            input,
            (subject_modal.is_some(), card.unwrap_or((0u32, None))),
        ))
    })?;
    let after_choose_lower = &lower[lower.len() - after_choose.len()..];

    // Cost tail begins at " and pay " — split structurally with the nom
    // `take_until` + `tag` combinator. The head is the filter phrase, the
    // tail is "<cost> for each <noun> chosen this way".
    let (_, (filter_text, cost_tail_lower)) =
        nom_primitives::split_once_on(after_choose_lower, " and pay ").ok()?;
    let filter_text_orig = &after_choose[..filter_text.len()];
    // Map the cost tail back to original case — `parse_mana_cost` matches
    // uppercase mana symbols (`{U}`), but `after_choose_lower` is lowercased.
    let cost_tail = &after_choose[after_choose.len() - cost_tail_lower.len()..];

    // Cost tail structure: <mana cost> " for each " <noun> " chosen this way".
    let (after_cost, base) = nom_primitives::parse_mana_cost(cost_tail).ok()?;
    // Verify (and discard) the " for each <noun> chosen this way" suffix —
    // <noun> is redundant with `filter`.
    let (suffix_rest, ()) = value((), tag::<_, _, OracleError<'_>>(" for each "))
        .parse(after_cost)
        .ok()?;
    let (chosen_rest, _noun) = take_until::<_, _, OracleError<'_>>(" chosen this way")
        .parse(suffix_rest)
        .ok()?;
    value((), tag::<_, _, OracleError<'_>>(" chosen this way"))
        .parse(chosen_rest)
        .ok()
        .filter(|(rest, ())| rest.trim().is_empty())?;

    // Parse the filter phrase ("tapped blue creatures they control"). The
    // "they control" controller constraint is folded into the TargetFilter.
    let (filter, filter_rem) = parse_target_with_ctx(filter_text_orig, ctx);
    if matches!(filter, TargetFilter::None) || !filter_rem.trim().is_empty() {
        return None;
    }

    // CR 603.7e: chooser/payer is the affected player of an "each player's
    // upkeep" trigger — "that player". Use the trigger subject when it is a
    // player-typed filter; otherwise the canonical anaphoric `TriggeringPlayer`.
    let chooser = match &ctx.subject {
        Some(TargetFilter::TriggeringPlayer) => TargetFilter::TriggeringPlayer,
        Some(TargetFilter::Player) => TargetFilter::Player,
        _ => TargetFilter::TriggeringPlayer,
    };

    // sub_ability: PayCost { ScaledMana { base, times: TrackedSetSize } }.
    // CR 608.2c: A `Spell`-kind sub-ability resolves alongside its parent —
    // the chunk-loop's deepest-sub_ability append wires the `IfYouDo`/`Untap`
    // tail onto this node.
    let pay_ability = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::PayCost {
            cost: AbilityCost::Mana { cost: base },
            scale: Some(QuantityExpr::Ref {
                qty: QuantityRef::TrackedSetSize,
            }),
            payer: chooser.clone(),
        },
    );

    let mut clause = parsed_clause(Effect::ChooseObjectsIntoTrackedSet {
        chooser,
        filter,
        min,
        max,
    });
    clause.sub_ability = Some(Box::new(pay_ability));
    // CR 603.4: The "that player may" modal makes the whole clause optional —
    // declining is equivalent to choosing zero objects.
    clause.optional = subject_modal;
    Some(clause)
}

fn parse_for_each_object_copy_parts<'a>(
    text: &'a str,
    lower: &str,
) -> Option<(TargetFilter, &'a str)> {
    let (after_prefix, _) = tag::<_, _, OracleError<'_>>("for each ")
        .parse(lower)
        .ok()?;
    let clause_start = lower.len() - after_prefix.len();
    let (after_clause, clause_lower) = take_until::<_, _, OracleError<'_>>(", ")
        .parse(after_prefix)
        .ok()?;
    let (body_lower, _) = tag::<_, _, OracleError<'_>>(", ")
        .parse(after_clause)
        .ok()?;
    if !is_copy_token_anaphor_body(body_lower.trim()) {
        return None;
    }
    let clause = &lower[clause_start..clause_start + clause_lower.len()];
    let source_filter = parse_for_each_object_filter_clause(clause)?;
    let body_start = text.len() - body_lower.len();
    Some((source_filter, text[body_start..].trim()))
}

fn is_copy_token_anaphor_body(input: &str) -> bool {
    let parsed = |i| -> OracleResult<'_, ()> {
        let (i, _) = token::parse_copy_token_entry_modifiers(i)?;
        let i = i.trim_start();
        let (i, _) = tag("it").parse(i)?;
        let (i, _) = opt(tag(".")).parse(i)?;
        let (i, _) = eof.parse(i)?;
        Ok((i, ()))
    };
    parsed(input).is_ok()
}

/// CR 608.2c + CR 109.4: "Choose a [second|third|...] player to <verb>" —
/// decompose into a `Choose(Player)` whose chosen player performs the verb.
///
/// The clause is recognized with nom combinators: `tag("choose a ")` →
/// optional ordinal (`parse_ordinal`) → `tag("player")` → optional
/// `preceded(" to ", <verb phrase>)`. The verb phrase, when present, is parsed
/// by the standard `parse_effect_clause` pipeline and attached as the
/// `Choose`'s `sub_ability`; its player-recipient field is rebound to
/// `ControllerRef::ChosenPlayer { index }` so the chosen player — not the
/// ability's controller — performs the effect.
///
/// `ctx.chosen_player_count` supplies the 0-based chain index (1st choose = 0)
/// and is incremented here; `ctx.relative_player_scope` is set to the new
/// `ChosenPlayer` so a *following* sentence ("They put counters on a creature
/// they control") binds its "they"/"that player" anaphora to this choice.
///
/// The ordinal word ("second"/"third") is a parse-time consistency hint only —
/// the engine index is derived from chain position, not the ordinal.
fn try_parse_choose_player_to_verb(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    // `choose a` prefix (the trailing space/article-`n` belongs to the
    // head-noun branch). Strip the leading "then " sequence connector when
    // present so chain entries written as ", then choose an opponent" reach
    // this helper (the chunk loop's `strip_leading_sequence_connector`
    // already covers the "Then "-cased forms, but not every chunk-splitter
    // re-trims here).
    let after_then = opt(tag::<_, _, OracleError<'_>>("then "))
        .parse(tp.lower)
        .ok()?
        .0;
    let (after_choose, _) = tag::<_, _, OracleError<'_>>("choose a")
        .parse(after_then)
        .ok()?;
    // Head noun: " player" (with optional ordinal between article and noun)
    // or "n opponent" (the article shifts from "a" to "an"; no ordinal slot
    // — multi-opponent chains aren't a printed pattern). Each axis is a
    // single `alt()` arm carrying its `ChoiceType` via `value()`.
    // CR 608.2c (issue #534): the `Opponent` arm restores Skullwinder's
    // "then choose an opponent" — pre-fix this branch only matched "player"
    // and silently dropped opponent-form choose clauses.
    let player_arm = |i| {
        let (i, _) = tag::<_, _, OracleError<'_>>(" ").parse(i)?;
        let i = super::oracle_util::parse_ordinal(i)
            .map(|(_, rest)| rest)
            .unwrap_or(i);
        let (i, _) = tag::<_, _, OracleError<'_>>("player").parse(i)?;
        Ok::<_, nom::Err<OracleError<'_>>>((i, ChoiceType::Player))
    };
    let opponent_arm = value(
        ChoiceType::Opponent,
        tag::<_, _, OracleError<'_>>("n opponent"),
    );
    let (after_player, choice_type) = alt((player_arm, opponent_arm)).parse(after_choose).ok()?;

    // The chain index is the count of `Choose(Player)` clauses already
    // finalized in this chain. The chunk loop owns the increment (once per
    // finalized clause) — this function only READS the count and is
    // side-effect-free on it, because the loop speculatively double-parses
    // each chunk (`parse_effect_clause` at the trial site + the real site).
    let index = ctx.chosen_player_count;
    let chosen_scope = ControllerRef::ChosenPlayer { index };

    // Optional verb continuation: " to <verb phrase>" — nom `tag()` dispatch
    // on the lowercase remainder.
    let verb_lower = tag::<_, _, OracleError<'_>>(" to ")
        .parse(after_player)
        .ok()
        .map(|(rest, _)| rest.trim_start());

    // Bind the relative-player scope so a later "they"/"that player controls"
    // sentence — and this clause's own verb sub-effect — resolve to this
    // chosen player. Idempotent under the loop's double-parse (set to the
    // same value each time).
    ctx.relative_player_scope = Some(chosen_scope.clone());

    let mut clause = parsed_clause(Effect::Choose {
        choice_type: choice_type.clone(),
        persist: false,
    });

    if let Some(verb_lower) = verb_lower {
        if verb_lower.is_empty() {
            return Some(clause);
        }
        // Map the lowercase verb tail back to the original-case slice so the
        // recursive parse sees unmodified text.
        let verb_orig = &tp.original[tp.original.len() - verb_lower.len()..];
        let mut verb_clause = parse_effect_clause(verb_orig, ctx);
        if matches!(verb_clause.effect, Effect::Unimplemented { .. }) {
            // The verb tail didn't parse — fall back to the bare Choose so the
            // chosen player is still recorded (no dependent effect).
            return Some(clause);
        }
        // CR 109.4: The verb's actor/recipient is the chosen player, not the
        // ability controller. Rebind the player-recipient field.
        retarget_effect_to_chosen_player(&mut verb_clause.effect, index);
        let mut sub = AbilityDefinition::new(AbilityKind::Spell, verb_clause.effect);
        sub.sub_ability = verb_clause.sub_ability;
        sub.duration = verb_clause.duration;
        clause.sub_ability = Some(Box::new(sub));
    }

    Some(clause)
}

/// CR 608.2c + CR 800.4a (issue #1504): "an opponent draws a card" — the
/// opponent is chosen during resolution, not targeted at cast (contrast with
/// "target opponent draws"). Decomposed into `Choose { Opponent }` with the
/// verb phrase as a `sub_ability`, mirroring `try_parse_choose_player_to_verb`
/// for Skullwinder's "choose an opponent" form.
fn try_parse_an_opponent_to_verb(
    tp: TextPair<'_>,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let after_then = opt(tag::<_, _, OracleError<'_>>("then "))
        .parse(tp.lower)
        .ok()?
        .0;
    let (after_opponent, _) = tag::<_, _, OracleError<'_>>("an opponent ")
        .parse(after_then)
        .ok()?;
    if tag::<_, _, OracleError<'_>>("chooses ")
        .parse(after_opponent)
        .is_ok()
    {
        return None;
    }

    let index = ctx.chosen_player_count;
    ctx.relative_player_scope = Some(ControllerRef::ChosenPlayer { index });

    let verb_lower = after_opponent.trim_start();
    if verb_lower.is_empty() {
        return None;
    }
    let verb_orig = &tp.original[tp.original.len() - verb_lower.len()..];
    let mut verb_clause = parse_effect_clause(verb_orig, ctx);
    if matches!(verb_clause.effect, Effect::Unimplemented { .. }) {
        return None;
    }
    rebind_opponent_player_recipient_to_chosen(&mut verb_clause.effect, index);
    if let Some(sub) = verb_clause.sub_ability.as_mut() {
        rebind_opponent_player_recipient_in_chain(sub, index);
    }

    let mut clause = parsed_clause(Effect::Choose {
        choice_type: ChoiceType::Opponent,
        persist: false,
    });
    let mut sub = AbilityDefinition::new(AbilityKind::Spell, verb_clause.effect);
    sub.sub_ability = verb_clause.sub_ability;
    sub.duration = verb_clause.duration;
    clause.sub_ability = Some(Box::new(sub));
    Some(clause)
}

fn filter_is_bare_opponent_player(filter: &TargetFilter) -> bool {
    matches!(
        filter,
        TargetFilter::Typed(crate::types::ability::TypedFilter {
            type_filters,
            controller: Some(ControllerRef::Opponent),
            properties,
        }) if type_filters.is_empty() && properties.is_empty()
    )
}

fn rebind_opponent_player_recipient_to_chosen(effect: &mut Effect, index: u8) {
    let chosen = TargetFilter::Typed(crate::types::ability::TypedFilter {
        controller: Some(ControllerRef::ChosenPlayer { index }),
        ..Default::default()
    });
    match effect {
        Effect::Draw { target, .. }
        | Effect::Mill { target, .. }
        | Effect::Discard { target, .. } => {
            if filter_is_bare_opponent_player(target) {
                *target = chosen;
            } else {
                retarget_effect_to_chosen_player(effect, index);
            }
        }
        Effect::GainLife { player, .. } if filter_is_bare_opponent_player(player) => {
            *player = chosen;
        }
        _ => retarget_effect_to_chosen_player(effect, index),
    }
}

fn rebind_opponent_player_recipient_in_chain(def: &mut AbilityDefinition, index: u8) {
    rebind_opponent_player_recipient_to_chosen(&mut def.effect, index);
    if let Some(sub) = def.sub_ability.as_mut() {
        rebind_opponent_player_recipient_in_chain(sub, index);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rebind_opponent_player_recipient_in_chain(else_branch, index);
    }
}

/// CR 109.4: Rebind a verb effect's player-recipient field to the Nth chosen
/// player. Covers the player-recipient effect families that follow a "choose a
/// player to <verb>" clause and carry a `Controller`-defaulted recipient
/// `TargetFilter` (`Draw`, `Token` owner, `Mill`, `Scry`, `Surveil`,
/// `LoseLife`). The recipient is encoded as a player-only `TargetFilter::Typed`
/// carrying `ControllerRef::ChosenPlayer { index }`, which
/// `resolve_player_for_context_ref` / `resolve_effect_player_ref` resolve at
/// resolution time. Effects without a `Controller`-defaulted recipient
/// `TargetFilter` are left untouched — the surrounding `relative_player_scope`
/// already binds object-controller anaphora ("a creature they control").
///
/// `GainLife` (recipient `player` is now a `TargetFilter`, but no current card
/// pairs "choose a player to gain life" with this verb, so it is not yet wired
/// into the `rebind` match below)
/// and `Discard`/`DiscardCard` (no player-recipient `TargetFilter` — `Discard`
/// is self-scoped, `DiscardCard.filter` selects *what* is discarded, not
/// *who*) are a deliberate class-boundary deferral: no current card pairs
/// "choose a player to <verb>" with those verbs. Extending to them is a
/// follow-up if such a card prints — it is not a bug in this helper.
fn retarget_effect_to_chosen_player(effect: &mut Effect, index: u8) {
    let chosen = TargetFilter::Typed(crate::types::ability::TypedFilter {
        controller: Some(ControllerRef::ChosenPlayer { index }),
        ..Default::default()
    });
    let rebind = |slot: &mut TargetFilter| {
        if matches!(slot, TargetFilter::Controller | TargetFilter::Player) {
            *slot = chosen.clone();
        }
    };
    match effect {
        Effect::Draw { target, .. } => rebind(target),
        Effect::Token { owner, .. } => rebind(owner),
        Effect::Mill { target, .. } => rebind(target),
        Effect::Scry { target, .. } => rebind(target),
        Effect::Surveil { target, .. } => rebind(target),
        Effect::LoseLife {
            target: Some(target),
            ..
        } => rebind(target),
        // CR 109.4 + CR 608.2c + CR 608.2d (issue #534): `Bounce`'s recipient
        // ("a card from THEIR graveyard to THEIR hand") is encoded inside the
        // target filter's `FilterProp::Owned { controller }` — the card is
        // *owned* (CR 109.4: graveyard cards have an owner, not a controller),
        // not a top-level player slot. Rebind the nested `Owned` property
        // (and a top-level `controller: ScopedPlayer` slot if the parser ever
        // emits one) from `ScopedPlayer` to `ChosenPlayer { index }` so the
        // chosen opponent's graveyard is enumerated at resolution time
        // (CR 608.2d — the chosen opponent announces which card returns).
        Effect::Bounce { target, .. } => rebind_owned_scope(target, index),
        _ => {}
    }
}

/// CR 109.4 (issue #534): Tree-walk a `TargetFilter` and rewrite every
/// `ScopedPlayer` ref — both the top-level `TypedFilter.controller` slot and
/// every nested `FilterProp::Owned { controller }` property — to
/// `ChosenPlayer { index }`. Used by the `Bounce` arm of
/// `retarget_effect_to_chosen_player` and by the chosen-subject post-pass in
/// `parse_subject_application`'s caller, because graveyard ownership lives
/// in a filter property, not a top-level player slot (cards in non-stack /
/// non-battlefield zones are owned, not controlled).
fn rebind_owned_scope(filter: &mut TargetFilter, index: u8) {
    use crate::types::ability::FilterProp;
    match filter {
        TargetFilter::Typed(tf) => {
            if matches!(tf.controller, Some(ControllerRef::ScopedPlayer)) {
                tf.controller = Some(ControllerRef::ChosenPlayer { index });
            }
            for prop in tf.properties.iter_mut() {
                if let FilterProp::Owned { controller } = prop {
                    if matches!(controller, ControllerRef::ScopedPlayer) {
                        *controller = ControllerRef::ChosenPlayer { index };
                    }
                }
            }
        }
        TargetFilter::And { filters } | TargetFilter::Or { filters } => {
            for f in filters.iter_mut() {
                rebind_owned_scope(f, index);
            }
        }
        TargetFilter::Not { filter } => rebind_owned_scope(filter, index),
        _ => {}
    }
}

#[tracing::instrument(level = "debug")]
fn parse_effect_clause_inner(text: &str, ctx: &mut ParseContext) -> ParsedEffectClause {
    let text = strip_leading_sequence_connector(text)
        .trim()
        .trim_end_matches('.');
    if text.is_empty() {
        return parsed_clause(Effect::Unimplemented {
            name: "empty".to_string(),
            description: None,
        });
    }
    // CR 608.2c: Self-ref continuation adverb. "also" after a self-ref subject
    // is a natural-language additive connector with no semantic weight — it
    // signals "in addition, [self-ref] [verb]…" and must reduce to plain
    // self-ref subject-predicate dispatch. Strip only when the "also" is
    // present; without it, the bare `~` / `this creature` subject carries
    // target attribution that downstream Pump/PutCounter parsers rely on.
    //
    // Example: Expressive Firedancer sub_ability "~ also gains double strike
    // until end of turn" → strip "~ also " → "gains double strike until end
    // of turn" → first-word dispatch lands on gain-keyword with SelfRef
    // target implied by the absence of an explicit target.
    let stripped_self_ref;
    let text = {
        let lower = text.to_ascii_lowercase();
        let stripped_lower = alt((
            value((), tag::<_, _, OracleError<'_>>("~ also ")),
            value((), tag("this creature also ")),
            value((), tag("this permanent also ")),
        ))
        .parse(lower.as_str())
        .ok()
        .map(|(rest, ())| {
            let consumed = lower.len() - rest.len();
            text[consumed..].trim_start().to_string()
        });
        if let Some(rest) = stripped_lower {
            stripped_self_ref = rest;
            stripped_self_ref.as_str()
        } else {
            text
        }
    };
    if text.is_empty() {
        return parsed_clause(Effect::Unimplemented {
            name: "empty".to_string(),
            description: None,
        });
    }

    // CR 608.2c: Deconjugate bare third-person verbs that appear after ", then" splits
    // where the subject carried over from the previous clause.
    // E.g., "draws seven cards" → "draw seven cards" (from "Each player discards
    // their hand, then draws seven cards.").
    // Only fires when the first word is a conjugated verb form that, after
    // deconjugation, matches a recognized imperative clause start — this avoids
    // false positives on noun phrases or subject-prefixed text.
    let deconjugated_storage;
    let text = if !sequence::starts_clause_text(text)
        && sequence::starts_clause_text_or_conjugated(text)
    {
        deconjugated_storage = subject::deconjugate_verb(text);
        &deconjugated_storage
    } else {
        text
    };

    // Single lowercase pass for all case-insensitive matching within this clause.
    let lower = text.to_lowercase();
    let tp = TextPair::new(text, &lower);

    if let Some(effect) = try_parse_triggered_damage_replacement(&lower) {
        return parsed_clause(effect);
    }
    if let Some(effect) = try_parse_next_time_source_damage_replacement(&lower) {
        return parsed_clause(effect);
    }
    if let Some(effect) = try_parse_leave_battlefield_exile_replacement(&lower) {
        return parsed_clause(effect);
    }
    // CR 614.1a + CR 608.2n + CR 607.2b: "exile it instead of putting it into a
    // graveyard as it resolves" — the resolving-spell exile rider applied by a
    // `WhenAPlayerCasts` trigger to the triggering spell (Rod of Absorption).
    // Must run before the generic exile dispatch, which would otherwise lower it
    // to a no-op `ChangeZone { origin: Graveyard }` that never finds the spell
    // (it is on the stack, not in a graveyard, when the trigger resolves).
    if try_parse_exile_resolving_spell_instead_of_graveyard(&lower) {
        return parsed_clause(Effect::ExileResolvingSpellInsteadOfGraveyard);
    }
    // CR 614.1a + CR 514.2: Global "If [source] would deal damage this turn,
    // it deals that much damage plus N instead" pattern (Rankle and Torbran,
    // I Call for Slaughter). Distinct from the targeted "If a source would
    // deal damage to that player..." form above — this lifts the entire
    // replacement to the global pending_damage_replacements with no per-target
    // binding.
    if let Some(effect) = try_parse_global_damage_modification_replacement(text) {
        return parsed_clause(effect);
    }
    // CR 111.2 + CR 614.1a: Crafty-Cutpurse-class token controller redirect.
    if let Some(effect) = try_parse_token_controller_redirect(&lower) {
        return parsed_clause(effect);
    }

    if let Some(clause) = try_parse_for_each_copy_token_source(text, &lower, ctx) {
        return clause;
    }
    // CR 603.7e + CR 118.1: "choose any number of <filter> and pay <cost> for
    // each <noun> chosen this way" — interactive selection + per-object scaled
    // cost. Must run before the generic clause dispatch, which would otherwise
    // parse only the trailing `pay <cost>` and silently drop the selection
    // step and the per-object multiplier.
    if let Some(clause) = try_parse_choose_and_pay_per_object(text, &lower, ctx) {
        return clause;
    }

    // CR 608.2c + CR 109.4: "Choose a [second|third|...] player to <verb>" —
    // a `Choose(Player)` whose chosen player then performs the trailing verb
    // phrase (Gluntch, the Bestower; the Tempt cycle). Decomposed into an
    // `Effect::Choose { choice_type: Player }` with the verb phrase as a
    // `sub_ability`; the sub's player-relative references resolve to the
    // chosen player via `ctx.relative_player_scope`. Checked before the
    // generic imperative `choose` dispatch (which would consume the prefix
    // and drop the trailing verb).
    if let Some(clause) = try_parse_choose_player_to_verb(tp, ctx) {
        return clause;
    }

    // CR 608.2c + CR 800.4a (issue #1504): "an opponent <verb>" before generic
    // subject dispatch, which would bind `ControllerRef::Opponent` as a cast-time
    // player target on Draw/Mill/etc.
    if let Some(clause) = try_parse_an_opponent_to_verb(tp, ctx) {
        return clause;
    }

    // CR 700.2 + CR 118.12a: "[DEFAULT] unless a player has ~ deal N to them".
    if let Some(clause) = try_parse_unless_player_have_deal_damage(tp, ctx) {
        return clause;
    }

    // CR 700.2 + CR 608.2d: Three-branch "[DEFAULT] unless that player A or B"
    // forced choice — checked BEFORE the two-branch splitter so the more-specific
    // "unless that player" pattern is matched before the left half is misread as
    // just the default consequence (losing the avoidance alternative).
    if let Some(clause) = try_parse_unless_three_branch_choice(tp, ctx) {
        return clause;
    }

    // CR 111.2 + CR 608.2c: Shared-verb token sequences — checked before the
    // choice splitter and single-token dispatch so the second token noun phrase
    // is preserved in the effect chain.
    if let Some(clause) = try_parse_create_token_sequence(tp, ctx) {
        return clause;
    }

    // CR 111.2 + CR 608.2d: Shared-verb token choice — must run before the
    // generic inline splitter and token dispatch so "create a Food token or a
    // Treasure token" does not collapse to the first token branch.
    if let Some(clause) = try_parse_create_token_choice(tp, ctx) {
        return clause;
    }

    // CR 115.1 + CR 608.2d + CR 701.26a-b: Shared-target tap/untap choice
    // must run before the generic "A or B" splitter and before simple `tap`
    // verb dispatch, otherwise the second instruction can be swallowed.
    if let Some(clause) = try_parse_tap_or_untap_choice(tp, ctx) {
        return clause;
    }

    // CR 122.1 + CR 608.2d: Shared-target counter choice with a shared
    // trailing target phrase (Inspirit class).
    if let Some(clause) = try_parse_put_counter_choice(tp, ctx) {
        return clause;
    }

    // CR 700.2 + CR 608.2d: Inline binary-choice imperative — "discard a card
    // or sacrifice a land" (Highway Robbery) and analogous "A or B" patterns
    // that are not bulleted `Choose one —` modals. The split happens BEFORE
    // any single-verb dispatch so the second branch isn't silently dropped
    // when the first matches ("discard ..." prefix consumes the whole text).
    // Constrained to the narrow case where (a) exactly one ` or ` appears at
    // clause top level, (b) both halves independently parse as a supported
    // imperative — prevents false positives on intra-imperative "or" like
    // "target creature or player".
    if let Some(clause) = try_parse_choose_one_of_inline(tp, ctx) {
        return clause;
    }

    // CR 402.2 + CR 114.1: "you have no maximum hand size [for the rest of the game]" —
    // as an effect, this creates an emblem with NoMaximumHandSize static.
    if let Some(effect) = try_parse_no_max_hand_size_effect(tp) {
        return parsed_clause(effect);
    }

    // CR 608.2d: "have it [verb]" / "have you [verb]" — causative construction
    // from "any opponent may" effects (e.g., "have it deal 4 damage to them").
    if let Some(clause) = try_parse_have_causative(tp, ctx) {
        return clause;
    }

    // CR 115.1d + CR 601.2c: "for each of them, [imperative]" — rhetorical
    // per-target distributor on a multi-target spell (Twinflame's strive
    // chain: "Choose any number of target creatures you control. For each of
    // them, create a token …"). The per-target iteration is intrinsic to how
    // resolvers (CopyTokenOf, Pump, etc.) iterate `ability.targets`, so we
    // strip the prefix and recurse on the inner clause. Anaphoric subjects
    // inside the inner clause ("that creature") resolve to the per-target
    // ParentTarget via `parse_target`.
    if let Some(rest) = tp
        .strip_prefix("for each of them, ")
        .or_else(|| tp.strip_prefix("for each of them "))
    {
        return parse_effect_clause(rest.original, ctx);
    }

    // CR 109.5 + CR 608.2c + CR 800.4g: "you and that player each <body>" —
    // distribute the body across two recipients (the original ability
    // controller and the iterated voter). Used by Council's-dilemma vote
    // bodies (Master of Ceremonies pattern). MUST run before the imperative
    // dispatch in `parse_clause_ast` so the bare "you" first word is not
    // matched by the imperative "you may" arm or fall through to
    // `Effect::Unimplemented`.
    if let Some(clause) = try_parse_compound_subject_each(text, ctx) {
        return clause;
    }

    // CR 122.1 + CR 608.2d: Bribe Taker — "[you may] put your choice of a
    // <fixed> counter or a counter of that kind on ~". Runs before the generic
    // for-each path; the `DistinctCounterKindsAmong` iteration source has already
    // been lifted onto the parent's `repeat_for` by `strip_for_each_prefix`.
    if let Some(clause) = try_parse_for_each_counter_kind_choice(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_distinct_card_types_from_revealed(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_random_card_perpetual_gain_quoted_ability(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_gain_energy(tp, ctx) {
        return clause;
    }

    // CR 703.4q + CR 611.2b: "[subject] don't lose [unspent] {color} mana as
    // steps and phases end" — installs a turn-scoped mana-pool retention rule
    // (The Last Agni Kai class). When this clause appears as a spell effect,
    // the duration is supplied by `with_clause_duration` from a leading
    // "Until end of turn, " or trailing duration suffix; when it appears as a
    // printed static, `oracle_static::try_parse_retain_unspent_mana_static`
    // emits it on the source object directly.
    if let Some(static_def) =
        crate::parser::oracle_static::try_parse_retain_unspent_mana_static(tp.original, tp.lower)
    {
        return parsed_clause(Effect::GenericEffect {
            static_abilities: vec![static_def],
            duration: None,
            target: None,
        });
    }

    // CR 701.54: "the ring tempts you" — Ring Tempts You effect.
    if scan_contains_phrase(tp.lower, "the ring tempts you") {
        return parsed_clause(Effect::RingTemptsYou);
    }

    // CR 101.4 + CR 701.21a: "For each player, you choose from among the permanents that
    // player controls an artifact, a creature, ..." — Tragic Arrogance pattern where
    // the spell's controller chooses for all players.
    if let Ok((after_prefix, _)) =
        tag::<_, _, OracleError<'_>>("for each player, you choose ").parse(tp.lower)
    {
        if let Some(ast) = imperative::parse_category_and_sacrifice_rest_pub(after_prefix) {
            return parsed_clause(imperative::lower_choose_ast(ast));
        }
    }

    if tp.lower == "start your engines!" || tp.lower == "start your engines" {
        return parsed_clause(Effect::StartYourEngines {
            player_scope: PlayerFilter::Controller,
        });
    }

    if tp.lower == "all players start their engines."
        || tp.lower == "all players start their engines"
        || tp.lower == "all players start their engines!"
    {
        return parsed_clause(Effect::StartYourEngines {
            player_scope: PlayerFilter::All,
        });
    }

    if let Some(amount_text) = tag::<_, _, OracleError<'_>>("increase your speed by ")
        .parse(tp.lower)
        .ok()
        .map(|(rest, _)| rest.trim())
    {
        // Delegate to nom combinator (input already lowercase from tp.lower).
        if let Ok((remainder, amount)) = nom_primitives::parse_number.parse(amount_text) {
            if remainder.trim().is_empty() {
                return parsed_clause(Effect::ChangeSpeed {
                    player_scope: PlayerFilter::Controller,
                    amount: QuantityExpr::Fixed {
                        value: amount as i32,
                    },
                    direction: crate::types::ability::SpeedDelta::Increase,
                    floor: None,
                });
            }
        }
    }

    // CR 702.179c-d: "reduce <player>'s speed by N" — directional speed
    // decrease. The player anaphor selects the `PlayerFilter`; "that
    // opponent" resolves to the parent object target's controller.
    if let Ok((rest, player_scope)) = nom::sequence::preceded(
        tag::<_, _, OracleError<'_>>("reduce "),
        alt((
            value(
                PlayerFilter::ParentObjectTargetController,
                alt((tag("that opponent's "), tag("that player's "))),
            ),
            value(PlayerFilter::Controller, tag("your ")),
        )),
    )
    .parse(tp.lower)
    {
        if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("speed by ").parse(rest) {
            if let Ok((remainder, amount)) = nom_primitives::parse_number.parse(rest) {
                if remainder.trim().is_empty() {
                    return parsed_clause(Effect::ChangeSpeed {
                        player_scope,
                        amount: QuantityExpr::Fixed {
                            value: amount as i32,
                        },
                        direction: crate::types::ability::SpeedDelta::Decrease,
                        floor: None,
                    });
                }
            }
        }
    }

    // CR 603.7c: "Whenever X this turn, Y" — multi-fire delayed trigger creation.
    if let Some(clause) = try_parse_whenever_this_turn(tp) {
        return clause;
    }

    // CR 603.7: "When you next cast a [type] spell this turn, ..." — one-shot delayed trigger.
    if let Some(clause) = try_parse_when_next_event(tp) {
        return clause;
    }

    // CR 603.7c: "When that creature dies, ..." — inline delayed trigger creation.
    if let Some(clause) = try_parse_inline_delayed_trigger(tp, ctx) {
        return clause;
    }

    if let Some(clause) = try_parse_self_name_exile(tp, ctx) {
        return clause;
    }

    // CR 601.2f: "the next spell you cast this turn costs {N} less to cast"
    if let Some(clause) = try_parse_reduce_next_spell_cost(tp) {
        return clause;
    }

    // CR 601.2f: "the next [type] spell you cast this turn [has keyword/can't be countered/etc.]"
    if let Some(clause) = try_parse_grant_next_spell_ability(tp) {
        return clause;
    }

    // CR 614.16: "Damage can't be prevented [this turn]" → Effect::AddRestriction
    if let Some(clause) = try_parse_damage_prevention_disabled(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_cast_only_from_zones_restriction(tp) {
        return clause;
    }

    // CR 101.2: "Your opponents can't cast spells this turn" — blanket temporary prohibition.
    // Must run AFTER cast_only_from_zones (more specific "from zones" check).
    if let Some(clause) = try_parse_cant_cast_spells_effect(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_cant_activate_non_mana_abilities_effect(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_earthbend_clause(tp) {
        return clause;
    }

    if let Some(clause) = try_parse_airbend_clause(tp) {
        return clause;
    }

    // CR 115.1d: "Two target creatures" / "Three target artifacts" — numeric target prefix.
    // Strip the count, recursively parse the remainder, and attach MultiTargetSpec.
    if let Some((count, rest)) = strip_exact_target_prefix(tp.lower) {
        let mut clause = parse_effect_clause(rest, ctx);
        clause.multi_target = Some(MultiTargetSpec::exact(count));
        return clause;
    }

    // CR 705: "If you win/lose the flip, [effect]" — coin flip branch.
    // Returns a FlipCoin with the appropriate branch filled in.
    // consolidate_die_and_coin_defs merges these into the preceding FlipCoin.
    if let Some((is_win, effect_text)) = imperative::try_parse_coin_flip_branch(text) {
        let branch_def = {
            let ir = parse_effect_chain_ir(effect_text, AbilityKind::Spell, ctx);
            lower_effect_chain_ir(&ir)
        };
        return if is_win {
            parsed_clause(Effect::FlipCoin {
                win_effect: Some(Box::new(branch_def)),
                lose_effect: None,
            })
        } else {
            parsed_clause(Effect::FlipCoin {
                win_effect: None,
                lose_effect: Some(Box::new(branch_def)),
            })
        };
    }

    if let Some((duration, rest)) = strip_leading_duration(text) {
        return with_clause_duration(parse_effect_clause(rest, ctx), duration);
    }

    // "it's still a/an [type]" / "that's still a/an [type]" — type-retention clause
    // CR 205.1a: Retains the original type in addition to new types from animation effects
    if let Some(clause) = try_parse_still_a_type(tp) {
        return clause;
    }

    // CR 614.10a: "you skip your next untap/draw/upkeep step" — one-shot step skip.
    if let Some(clause) = try_parse_skip_next_step(tp, ctx) {
        return clause;
    }

    // CR 614.10: "you skip your next turn" / "skip your next turn" — temporal penalty.
    if let Some(clause) = try_parse_skip_next_turn(tp) {
        return clause;
    }

    // CR 601.2d: "deal N damage divided as you choose among [targets]" /
    // "distributed among" / "divided evenly" → DealDamage with distribute.
    if scan_contains_phrase(&lower, "divided as you choose among")
        || scan_contains_phrase(&lower, "distributed among")
        || scan_contains_phrase(&lower, "divided evenly")
    {
        if let Some(clause) = try_parse_distribute_damage(&lower, text) {
            return clause;
        }
    }

    // CR 601.2d: "distribute N [type] counters among [targets]" →
    // PutCounter with distribute: Some(Counters(type)).
    if tag::<_, _, OracleError<'_>>("distribute ")
        .parse(lower.as_str())
        .is_ok()
        && scan_contains_phrase(&lower, "counter")
        && scan_contains_phrase(&lower, "among")
    {
        if let Some(clause) = try_parse_distribute_counters(&lower, text) {
            return clause;
        }
    }

    // CR 701.34a + CR 122.1: targeted proliferate — "for each kind of counter on
    // target permanent or player, give that permanent or player another counter
    // of that kind" (Skyship Plunderer, Maulfist Revolutionary). Must precede the
    // generic `for each` splitter below, which would otherwise lift "kind of
    // counter on target permanent or player" into a repeat-iteration and drop the
    // target, leaving an Unimplemented "give … counter of that kind" body.
    if let Some(effect) = try_parse_proliferate_target(text) {
        return parsed_clause(effect);
    }

    // "for each" patterns: "draw a card for each [filter]", etc.
    if let Some(clause) = try_parse_for_each_effect(text, ctx) {
        return clause;
    }

    // CR 121.1 + CR 701.17a: "{verb} cards equal to {quantity}" — dynamic count
    // from game state for draw or mill.
    if let Some(clause) = try_parse_equal_to_quantity_effect(tp) {
        return clause;
    }

    // CR 701.13a + CR 608.2c: "exile cards from the top of your library until
    // you exile a [filter] card"
    if let Some(clause) = try_parse_exile_from_top_until(tp, TargetFilter::Controller) {
        return clause;
    }

    // CR 701.20a: "reveal cards from the top of your library until you reveal a [filter]"
    // Bare imperative (no explicit subject) → activator's library (CR 109.5).
    if let Some(clause) = try_parse_reveal_until(tp, TargetFilter::Controller) {
        return clause;
    }

    // CR 701.20a: "reveal it" / "reveal them" — standalone reveal of a referenced object
    // (e.g., the card looked at via a dig effect). Maps to RevealTop { count: 1 }.
    if let Ok((rest, _)) =
        alt((tag::<_, _, OracleError<'_>>("reveal "), tag("reveals "))).parse(tp.lower)
    {
        if alt((
            value((), tag::<_, _, OracleError<'_>>("it")),
            value((), tag("them")),
        ))
        .parse(rest.trim_end_matches('.'))
        .is_ok()
        {
            return parsed_clause(Effect::RevealTop {
                player: TargetFilter::Controller,
                count: 1,
            });
        }
    }

    // CR 122.3: "cast that card by paying an amount of {E} equal to its mana value"
    // → GrantCastingPermission with ExileWithEnergyCost
    if scan_contains_phrase(tp.lower, "by paying an amount of {e}")
        && scan_contains_phrase(tp.lower, "equal to its mana value")
    {
        return parsed_clause(Effect::GrantCastingPermission {
            permission: CastingPermission::ExileWithEnergyCost,
            target: TargetFilter::ParentTarget,
            grantee: Default::default(),
        });
    }

    // CR 115.7: "change the target of" / "you may choose new targets for" —
    // must be checked before subject stripping since "you may choose" would be split.
    if let Some(effect) = try_parse_change_targets(tp.lower) {
        return parsed_clause(effect);
    }

    // CR 400.7i: "you may play/cast that card [this turn]" — impulse draw permission.
    if let Some(clause) = try_parse_play_from_exile(tp, ctx) {
        return clause;
    }

    // CR 701.57a: "discover N" / "discover X" — effect variant.
    let (discover_tp, discover_where_x) = strip_trailing_where_x(tp);
    if let Some((limit, rest_orig)) =
        super::oracle_nom::bridge::nom_on_lower(discover_tp.original, discover_tp.lower, |i| {
            let (rest, _) = tag("discover ").parse(i)?;
            let (rest, limit) = alt((
                map(nom_primitives::parse_number, |value| QuantityExpr::Fixed {
                    value: value as i32,
                }),
                value(
                    QuantityExpr::Ref {
                        qty: QuantityRef::Variable {
                            name: "X".to_string(),
                        },
                    },
                    tag("x"),
                ),
            ))
            .parse(rest)?;
            let (rest, _) = opt(tag(".")).parse(rest)?;
            Ok((rest, limit))
        })
    {
        if rest_orig.trim().is_empty() {
            let limit = apply_where_x_quantity_expression(limit, discover_where_x.as_deref());
            return parsed_clause(Effect::Discover {
                mana_value_limit: limit,
            });
        }
    }

    // "[target]'s owner puts it on their choice of the top or bottom of their library"
    if let Some(clause) = try_parse_put_on_top_or_bottom(tp, ctx) {
        return clause;
    }

    // CR 701.24a + CR 400.3: "the owner of target [filter] shuffles it into their library"
    if let Some(clause) = try_parse_owner_of_target_shuffle(tp, ctx) {
        return clause;
    }

    // CR 400.3: "the owner of target [filter] puts it into their library second from
    // the top or on the bottom"
    if let Some(clause) = try_parse_owner_of_target_put_second(tp, ctx) {
        return clause;
    }

    // CR 509.1c: "All creatures able to block [target/~] [this turn] do so" — mass forced block.
    // Semantically equivalent to "[target/~] must be blocked this turn if able".
    if let Some(clause) = try_parse_mass_forced_block(tp, ctx) {
        return clause;
    }

    // CR 611.2b: "have [subject] [predicate]" — subject redirection where "have" means
    // "cause [subject] to [predicate]". Distinct from static "have" which grants keywords
    // (e.g., "creatures you control have flying"), which is a subject-predicate pattern with
    // a plural subject before "have". Here, "have" is the first word, followed by a target/
    // anaphoric reference and a predicate.
    if let Some(redirected) = try_parse_have_redirection(text, ctx) {
        return redirected;
    }

    // Digital-only Alchemy: "[scope] intensif[y/ies] by N" - the Intensify action.
    if let Some(effect) = try_parse_intensify(tp) {
        return parsed_clause(effect);
    }

    // Digital-only Alchemy: "draft a card from [X]'s spellbook [+ destination]".
    if let Some(effect) = try_parse_spellbook_draft(tp) {
        return parsed_clause(effect);
    }

    // Digital-only: "conjure a duplicate of <reference> into/onto zone" — copies a
    // referenced card. Tried before the named form (disjoint: this requires
    // "a duplicate of", the other "named ").
    if let Some(effect) = try_parse_conjure_duplicate(tp) {
        return parsed_clause(effect);
    }

    // Digital-only: "conjure a card named X into/onto zone" — Conjure keyword action.
    if let Some(effect) = try_parse_conjure(tp) {
        return parsed_clause(effect);
    }

    let ast = parse_clause_ast(text, ctx);
    lower_clause_ast(ast, ctx)
}

/// Digital-only Alchemy keyword action: parse "intensify" clauses into
/// `Effect::Intensify`. The scope comes from the subject:
/// * self ("~ / this creature / this artifact / ... / it intensifies [by N]") ->
///   [`IntensityScope::Source`];
/// * "cards you own named [self] intensify [by N]" -> [`IntensityScope::OwnedSameName`];
/// * "all [subtype] cards you own intensify [by N]" -> [`IntensityScope::OwnedSubtype`].
///
/// The amount defaults to 1 when "by N" is absent. The clause tail must be fully
/// consumed (bare or with a sentence period) so unmodeled variants fall through
/// to `Unimplemented` instead of silently dropping riders.
fn try_parse_intensify(tp: TextPair) -> Option<Effect> {
    fn tail_done(tail: &str) -> bool {
        tail.is_empty() || tail == "."
    }

    fn verb_and_amount(rest: &str) -> Option<(QuantityExpr, &str)> {
        let (rest, _) = alt((
            tag::<_, _, OracleError<'_>>("intensifies"),
            tag::<_, _, OracleError<'_>>("intensify"),
        ))
        .parse(rest)
        .ok()?;

        if let Ok((rest, (_, n))) = (
            tag::<_, _, OracleError<'_>>(" by "),
            nom_primitives::parse_number,
        )
            .parse(rest)
        {
            return Some((QuantityExpr::Fixed { value: n as i32 }, rest));
        }

        if let Ok((after, _)) = tag::<_, _, OracleError<'_>>(" by x").parse(rest) {
            if after.is_empty()
                || after == "."
                || tag::<_, _, OracleError<'_>>(", where x is ")
                    .parse(after)
                    .is_ok()
            {
                return Some((
                    QuantityExpr::Ref {
                        qty: QuantityRef::Variable {
                            name: "X".to_string(),
                        },
                    },
                    "",
                ));
            }
            return None;
        }

        Some((QuantityExpr::Fixed { value: 1 }, rest))
    }

    let lower = tp.lower;

    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("cards you own named ").parse(lower) {
        let (rest, _) = take_until::<_, _, OracleError<'_>>("intensif")
            .parse(rest)
            .ok()?;
        let (amount, rest) = verb_and_amount(rest)?;
        return tail_done(rest).then_some(Effect::Intensify {
            scope: IntensityScope::OwnedSameName,
            amount,
        });
    }

    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("all ").parse(lower) {
        if let Ok((after, subtype_lower)) =
            take_until::<_, _, OracleError<'_>>(" cards you own intensif").parse(rest)
        {
            let (after, _) = tag::<_, _, OracleError<'_>>(" cards you own ")
                .parse(after)
                .ok()?;
            let (amount, after) = verb_and_amount(after)?;
            if tail_done(after) {
                return Some(Effect::Intensify {
                    scope: IntensityScope::OwnedSubtype {
                        subtype: crate::parser::oracle_quantity::capitalize_first(
                            subtype_lower.trim(),
                        ),
                    },
                    amount,
                });
            }
            return None;
        }
    }

    let after_subject = [
        "~ ",
        "it ",
        "this creature ",
        "this artifact ",
        "this enchantment ",
        "this equipment ",
        "this card ",
    ]
    .iter()
    .find_map(|subject| {
        tag::<_, _, OracleError<'_>>(*subject)
            .parse(lower)
            .ok()
            .map(|(rest, _)| rest)
    })?;
    let (amount, rest) = verb_and_amount(after_subject)?;
    tail_done(rest).then_some(Effect::Intensify {
        scope: IntensityScope::Source,
        amount,
    })
}

/// Digital-only Alchemy keyword action: parse "draft a card from [X]'s spellbook"
/// with its destination. The source name between "from " and "spellbook" is the
/// card's own name (or "this creature/artifact/…") and is irrelevant to the
/// effect — the resolver reads the spellbook list from the source object.
///
/// To avoid silently dropping unmodeled riders (which the coverage tooling
/// counts as swallowed clauses), the clause tail must be **fully consumed**:
/// the bare draft goes to the hand; "and put it onto the battlefield[ tapped]"
/// goes to the battlefield (honouring the tapped rider); "and exile it" goes to
/// exile. Anything else — "and exile it face down", "twice, then …", or a
/// trailing "then …" continuation not split off by the effect chain — returns
/// `None` so the card falls through to `Unimplemented` rather than parsing to a
/// subtly wrong effect.
fn try_parse_spellbook_draft(tp: TextPair) -> Option<Effect> {
    /// The clause tail is fully consumed when nothing (or just a sentence
    /// period) remains.
    fn tail_done(tail: &str) -> bool {
        tail.is_empty() || tail == "."
    }

    let (rest, _) = tag::<_, _, OracleError<'_>>("draft a card from ")
        .parse(tp.lower)
        .ok()?;
    // Consume the (irrelevant) source-card name up to "spellbook".
    let (after_book, _src) = take_until::<_, _, OracleError<'_>>("spellbook")
        .parse(rest)
        .ok()?;
    let (after_book, _) = tag::<_, _, OracleError<'_>>("spellbook")
        .parse(after_book)
        .ok()?;

    // Default: a bare "draft a card from X's spellbook" creates it in hand.
    if tail_done(after_book) {
        return Some(Effect::DraftFromSpellbook {
            destination: Zone::Hand,
            tapped: false,
        });
    }

    // "… and put it onto the battlefield[ tapped]".
    if let Ok((tail, _)) =
        tag::<_, _, OracleError<'_>>(" and put it onto the battlefield").parse(after_book)
    {
        let (tail, tapped) = match tag::<_, _, OracleError<'_>>(" tapped").parse(tail) {
            Ok((tail, _)) => (tail, true),
            Err(_) => (tail, false),
        };
        return tail_done(tail).then_some(Effect::DraftFromSpellbook {
            destination: Zone::Battlefield,
            tapped,
        });
    }

    // "… and exile it" — but not "and exile it face down" (face-down exile is
    // not modeled yet), which leaves an unconsumed tail and is rejected.
    if let Ok((tail, _)) = tag::<_, _, OracleError<'_>>(" and exile it").parse(after_book) {
        return tail_done(tail).then_some(Effect::DraftFromSpellbook {
            destination: Zone::Exile,
            tapped: false,
        });
    }

    // Unmodeled tail ("twice, then …", a trailing chained clause, …) — leave it
    // to `Unimplemented` rather than dropping the rider.
    None
}

/// Digital-only keyword action: Parse "conjure [quantity] card(s) named {Name} into/onto {zone}"
/// patterns. Handles:
/// - "conjure a card named X onto the battlefield"
/// - "conjure a card named X into your hand"
/// - "conjure three cards named X into your graveyard"
/// - "conjure a card named X onto the battlefield tapped"
/// - "conjure a card named X and a card named Y into your hand"
/// - "conjure X cards named Y onto the battlefield"
///
/// Uses nom combinators exclusively for dispatch and structure recognition.
fn try_parse_conjure(tp: TextPair) -> Option<Effect> {
    // Gate: must start with "conjure " (nom tag dispatch).
    let (rest, _) = tag::<_, _, OracleError<'_>>("conjure ")
        .parse(tp.lower)
        .ok()?;
    let rest_orig = &tp.original[tp.original.len() - rest.len()..];

    // Parse the first "a card named X" / "N cards named X" entry.
    let mut cards = Vec::new();
    let (count, after_count, _) = parse_conjure_quantity(rest, rest_orig)?;

    // Expect "named " after the quantity phrase.
    let (after_named, _) = tag::<_, _, OracleError<'_>>("named ")
        .parse(after_count)
        .ok()?;
    let after_named_orig = &rest_orig[rest_orig.len() - after_named.len()..];

    // Extract card name: take until " onto ", " into ", or " and a card" separator.
    let (card_name_lower, zone_rest) = parse_conjure_card_name(after_named)?;
    let card_name = &after_named_orig[..card_name_lower.len()];

    cards.push(ConjureCard {
        source: ConjureSource::Named {
            name: card_name.to_string(),
        },
        count,
    });

    // Check for " and a card named " continuation (multi-card pattern).
    // e.g., "conjure a card named X and a card named Y into your hand"
    let zone_rest = if let Ok((after_and, _)) =
        tag::<_, _, OracleError<'_>>(" and a card named ").parse(zone_rest)
    {
        let after_and_orig = &rest_orig[rest_orig.len() - after_and.len()..];
        let (next_name_lower, next_zone_rest) = parse_conjure_card_name(after_and)?;
        let next_name = &after_and_orig[..next_name_lower.len()];
        cards.push(ConjureCard {
            source: ConjureSource::Named {
                name: next_name.to_string(),
            },
            count: QuantityExpr::Fixed { value: 1 },
        });
        next_zone_rest
    } else {
        zone_rest
    };

    // Parse destination zone.
    let (destination, zone_rest) = parse_conjure_zone(zone_rest)?;

    // Parse optional "tapped" suffix.
    let tapped = tag::<_, _, OracleError<'_>>(" tapped")
        .parse(zone_rest)
        .is_ok();

    Some(Effect::Conjure {
        cards,
        destination,
        tapped,
    })
}

/// Digital-only keyword action: Parse "conjure a duplicate of {reference} into/onto {zone}".
/// The reference is either an explicit target ("target creature card exiled with ~")
/// or an anaphoric pronoun ("it" / "that card") resolving to the parent target.
/// The conjured card copies the referenced card's copiable characteristics (CR 707.2).
fn try_parse_conjure_duplicate(tp: TextPair) -> Option<Effect> {
    // Gate: must start with "conjure a duplicate of " (nom tag dispatch).
    let (rest, _) = tag::<_, _, OracleError<'_>>("conjure a duplicate of ")
        .parse(tp.lower)
        .ok()?;

    // Split the reference text (before) from the trailing zone clause (the
    // remaining text starting at the " into "/" onto " connector).
    let (zone_rest, reference_lower) = alt((
        take_until::<_, _, OracleError<'_>>(" into "),
        take_until(" onto "),
    ))
    .parse(rest)
    .ok()?;

    // Resolve the reference, but only CLAIM the clause when it is *fully*
    // modeled — otherwise return None so the card stays a loud
    // `Effect::Unimplemented` rather than silently dropping a qualifier (a
    // "swallowed clause", which the coverage-honesty gate rightly rejects).
    //
    // "target … card" → an explicit target filter, accepted only if `parse_target`
    // consumes the entire reference (so e.g. "exiled with ~" can't be dropped).
    // A bare anaphor ("it" / "that card" / "this card") → the inherited parent
    // target. Anything else is left loud.
    let duplicate_of = if tag::<_, _, OracleError<'_>>("target ")
        .parse(reference_lower)
        .is_ok()
    {
        let (filter, ref_rest) = parse_target(reference_lower);
        if !ref_rest.trim().is_empty() || matches!(filter, TargetFilter::Any) {
            return None;
        }
        filter
    } else {
        // CR 707.2: demonstrative anaphors referring to the object the enclosing
        // ability just established (the triggering / chosen / exiled object) all
        // resolve to the inherited parent target. "that creature" (Goblin Morale
        // Sergeant, Vodalian Tide Mage), "that spell" (Spellchain Scatter) and
        // "that permanent" (Vona de Iedo) join the existing card-noun anaphors.
        match reference_lower.trim() {
            "it" | "that card" | "this card" | "that creature" | "that spell"
            | "that permanent" => TargetFilter::ParentTarget,
            _ => return None,
        }
    };

    // Parse destination zone and optional "tapped" suffix, then require the
    // clause to be fully consumed — trailing text would be silently dropped.
    let (destination, zone_rest) = parse_conjure_zone(zone_rest)?;
    let (zone_rest, tapped) = match tag::<_, _, OracleError<'_>>(" tapped").parse(zone_rest) {
        Ok((after, _)) => (after, true),
        Err(_) => (zone_rest, false),
    };
    if !zone_rest.trim().trim_end_matches('.').trim().is_empty() {
        return None;
    }

    Some(Effect::Conjure {
        cards: vec![ConjureCard {
            source: ConjureSource::Duplicate { duplicate_of },
            count: QuantityExpr::Fixed { value: 1 },
        }],
        destination,
        tapped,
    })
}

/// Parse the quantity portion of a conjure clause.
/// Consumes the quantity and "card(s) " but NOT "named " — the caller handles "named ".
/// Returns (QuantityExpr, remaining_lower, remaining_orig).
fn parse_conjure_quantity<'a>(
    lower: &'a str,
    orig: &'a str,
) -> Option<(QuantityExpr, &'a str, &'a str)> {
    // "a card " → quantity 1
    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("a card ").parse(lower) {
        let rest_orig = &orig[orig.len() - rest.len()..];
        return Some((QuantityExpr::Fixed { value: 1 }, rest, rest_orig));
    }

    // Try numeric: "three cards ", "four cards ", "X cards "
    // First try nom parse_number for English words and digits.
    if let Ok((after_num, n)) = nom_primitives::parse_number.parse(lower) {
        let after_num = after_num.trim_start();
        if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("cards ").parse(after_num) {
            let rest_orig = &orig[orig.len() - rest.len()..];
            return Some((QuantityExpr::Fixed { value: n as i32 }, rest, rest_orig));
        }
    }

    None
}

/// Extract the card name from conjure text. The name extends until we hit
/// a zone destination (" onto " or " into ") or an " and a card" separator.
/// Uses nom `take_until` combinators for structured extraction.
///
/// " and a card" is checked first because multi-card patterns like
/// "X and a card named Y into your hand" contain both " and a card" and " into ",
/// and we want the shortest (first occurring) separator.
fn parse_conjure_card_name(lower: &str) -> Option<(&str, &str)> {
    alt((
        take_until::<_, _, OracleError<'_>>(" and a card"),
        take_until(" onto "),
        take_until(" into "),
    ))
    .parse(lower)
    .ok()
    .map(|(rest, name)| (name, rest))
}

/// Parse the destination zone from conjure text using nom combinators.
fn parse_conjure_zone(lower: &str) -> Option<(Zone, &str)> {
    alt((
        value(
            Zone::Battlefield,
            tag::<_, _, OracleError<'_>>(" onto the battlefield"),
        ),
        value(Zone::Hand, tag(" into your hand")),
        value(Zone::Graveyard, tag(" into your graveyard")),
        value(Zone::Library, tag(" into your library")),
        // Third-person variants: "into their hand/graveyard/library"
        value(Zone::Hand, tag(" into their hand")),
        value(Zone::Graveyard, tag(" into their graveyard")),
        value(Zone::Library, tag(" into their library")),
    ))
    .parse(lower)
    .ok()
    .map(|(rest, zone)| (zone, rest))
}

/// CR 611.2: Parse "have [subject] [predicate]" subject redirection.
///
/// In imperative Oracle text, "have" followed by a target reference or anaphoric pronoun
/// means "cause [subject] to [predicate]". Examples:
/// - "have target creature get +3/+3" → Pump with target creature
/// - "have it gain flying" → keyword grant with anaphoric "it"
/// - "have it fight target creature" → fight with redirected subject
///
/// Distinguished from static "have" (e.g., "creatures you control have flying") by position:
/// imperative "have" starts the clause; static "have" follows a subject.
fn try_parse_have_redirection(text: &str, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let (after_have, _) = tag::<_, _, OracleError<'_>>("have ")
        .parse(lower.as_str())
        .ok()?;

    // CR 603.2 + CR 113.3a + CR 111.10: "have its controller <predicate>" —
    // rebinds the acting player of the redirected sub-effect from the ability
    // controller (default per CR 113.3a) to the triggering source's controller.
    // "Its" refers to the triggering object (e.g., for Najeela, the attacking
    // Warrior). At resolution, the redirected effect's player-scoped filter
    // auto-resolves via `TargetFilter::TriggeringSource` (see
    // `extract_event_context_filter` + `resolve_token_owner`).
    if let Some(clause) = try_parse_have_its_controller(text, after_have, ctx) {
        return Some(clause);
    }

    let self_named_redirected;
    if let Some(card_name) = ctx.card_name.as_deref() {
        let card_name_lower = card_name.to_lowercase();
        let parsed_name = tag::<_, _, OracleError<'_>>(card_name_lower.as_str()).parse(after_have);
        if let Ok((after_name, _)) = parsed_name {
            if after_name.starts_with(char::is_whitespace) {
                let consumed = lower.len() - after_name.len();
                self_named_redirected = format!("~ {}", text[consumed..].trim_start());
                if let Some(ast) =
                    subject::try_parse_subject_predicate_ast(&self_named_redirected, ctx)
                {
                    return Some(lower_clause_ast(ast, ctx));
                }
            }
        }
    }

    // Strip "have " from the original text (preserving original casing).
    let redirected_text = text["have ".len()..].trim();

    // CR 113.1a + CR 608.2c + CR 611.1: A successful subject-predicate parse
    // on the post-"have" text is unambiguous evidence that this is the
    // causative-grant form. CR 113.1a explicitly names "has"/"have"/"gains"/
    // "gain" as the granted-ability terminology; CR 608.2c is the in-order
    // instruction-following step where the controller of the resolving
    // ability applies the grant; CR 611.1 is the continuous-effect that
    // results. Delegate the "is this a valid subject + predicate?" question
    // to the existing AST parser rather than gating on a hardcoded word
    // allowlist. This unlocks the filter-subject class ("have Ally creatures
    // you control gain first strike", "have creatures you control gain
    // trample", "have Spirit creatures you control gain flying", etc.) that
    // the prior allowlist (`target | it | that | each | all | them | another
    // | this | ~ | enchanted | equipped`) rejected.
    if let Some(ast) = subject::try_parse_subject_predicate_ast(redirected_text, ctx) {
        return Some(lower_clause_ast(ast, ctx));
    }

    // Guard: for the recursive `parse_effect_clause` fallback below (handles
    // "have it fight target creature", "have it deal damage", etc. where the
    // predicate verb is a non-subject-predicate verb), restrict to recognizable
    // anaphoric / target subject references so a bare imperative recursion
    // does not silently convert non-redirection text into a redirection.
    // Subject references covered here: "target", "it", "that", "each", "all",
    // "them", "another target", "this", "~", "enchanted", "equipped".
    let first_word = after_have.split_whitespace().next().unwrap_or("");
    let is_subject_ref = matches!(
        first_word,
        "target"
            | "it"
            | "that"
            | "each"
            | "all"
            | "them"
            | "another"
            | "this"
            | "~"
            | "enchanted"
            | "equipped"
    );
    if !is_subject_ref {
        return None;
    }

    // Fallback: if subject-predicate doesn't match, try parsing the redirected text
    // through the full parse_effect_clause pipeline (handles fight, damage, etc.).
    // This recursion is safe because "have" has been stripped — no infinite loop.
    let clause = parse_effect_clause(redirected_text, ctx);
    if !matches!(clause.effect, Effect::Unimplemented { .. }) {
        return Some(clause);
    }

    None
}

/// CR 603.2 + CR 111.10: Parse "have its controller <predicate>" — controller
/// rebinding for token creation (and other player-scoped sub-effects) on a
/// triggered ability. Najeela, the Blade-Blossom is the canonical case:
/// "Whenever a Warrior attacks, you may have its controller create a 1/1
/// white Warrior creature token that's tapped and attacking."
///
/// At resolution, `Effect::Token.owner` = `TargetFilter::TriggeringSource`
/// causes `extract_event_context_filter` to populate `ability.targets` with
/// the attacker's ObjectRef, and `resolve_token_owner`'s fallback arm reads
/// the controller from that object — yielding the Warrior's controller,
/// exactly as CR 111.10 requires.
fn try_parse_have_its_controller(
    original: &str,
    after_have_lower: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    // Nom dispatch: must match "its controller " exactly.
    let (rest_lower, _) = tag::<_, _, OracleError<'_>>("its controller ")
        .parse(after_have_lower)
        .ok()?;

    // Recover the original-case remainder using the canonical `len - rest.len()`
    // offset idiom. `after_have_lower` starts at the same offset in both slices
    // (case-insensitive prefix "have " has no case-varying chars), so the offset
    // into `original` is `original.len() - rest_lower.len()`.
    let offset = original.len().checked_sub(rest_lower.len())?;
    let redirected_text = original[offset..].trim();

    // Parse the sub-effect through the full effect pipeline.
    let clause = parse_effect_clause(redirected_text, ctx);
    if matches!(clause.effect, Effect::Unimplemented { .. }) {
        return None;
    }

    // Rebind the acting player of player-scoped sub-effects to the triggering
    // source's controller. Mirrors the original Token-only rebind across the
    // common player-scoped sub-effects so cards in the same class (Captive
    // Audience-style "have its controller draw/discard/lose life") resolve
    // their player field to the *acting* player rather than the static
    // ability's controller.
    let rebound = rebind_controller_to_triggering_source(clause);
    Some(rebound)
}

/// Rebind the player-facing filter of a parsed effect clause to
/// `TargetFilter::TriggeringSource` so token owners (and similar "acting
/// player" fields) resolve to the controller of the triggering object at
/// runtime. Only effects whose player-scope field is currently the default
/// `Controller` are touched — an explicit target/filter is preserved.
///
/// Covers the player-scoped sub-effects that the "have its controller [verb]"
/// pattern can produce: Token (creation), Draw, DiscardCard, LoseLife, Mill.
/// Each receives the same defaulted-Controller-only guard so a parser arm
/// that wired an explicit target (e.g. "have its controller mill target
/// player's library") survives unchanged.
fn rebind_controller_to_triggering_source(mut clause: ParsedEffectClause) -> ParsedEffectClause {
    let rebind = |target: &mut TargetFilter| {
        if matches!(target, TargetFilter::Controller) {
            *target = TargetFilter::TriggeringSource;
        }
    };
    match &mut clause.effect {
        Effect::Token { owner, .. } => rebind(owner),
        Effect::Draw { target, .. } => rebind(target),
        Effect::DiscardCard { target, .. } => rebind(target),
        Effect::Mill { target, .. } => rebind(target),
        // CR 119.3: `LoseLife.target` is `Option<TargetFilter>` — only rebind
        // the populated `Controller` case; `None` means "the controller of
        // the resolving ability" and that semantic is preserved by leaving it.
        Effect::LoseLife {
            target: Some(t), ..
        } => rebind(t),
        _ => {}
    }
    clause
}

/// Parse "it's still a/an [type]" and "that's still a/an [type]" type-retention clauses.
///
/// These appear as separate sentences after animation effects (e.g., "This land becomes
/// a 3/3 creature with vigilance. It's still a land."). The clause ensures the original
/// type is retained as a permanent continuous effect.
///
/// CR 205.1a: An object retains types explicitly stated by the effect.
/// CR 509.1c: "All creatures able to block [target/~] [this turn] do so."
///
/// This is the "lure" requirement: *every* creature able to block the referenced
/// object must block it, not merely one. It is therefore NOT equivalent to
/// "[target/~] must be blocked if able" (which `MustBeBlocked` models, satisfied
/// by a single blocker). Produces a GenericEffect with the stronger
/// `MustBeBlockedByAll` AddStaticMode on the referenced object.
///
/// Patterns:
/// - "all creatures able to block target creature this turn do so"
/// - "all creatures able to block ~ do so"
/// - "all creatures able to block ~ this turn do so"
fn try_parse_mass_forced_block(tp: TextPair, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let (_, rest_orig) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("all creatures able to block ")).parse(i)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
    let rest = TextPair::new(rest_orig, rest_lower);

    // The text must end with "do so" (the mass-block imperative)
    let rest_lower = rest.lower.trim_end_matches('.');
    if !rest_lower.ends_with("do so") {
        return None;
    }

    // Strip "do so" suffix, then optional "this turn " / "this combat " before it
    let before_do_so = rest_lower[..rest_lower.len() - "do so".len()].trim();
    let before_temporal = before_do_so
        .strip_suffix("this turn")
        .or_else(|| before_do_so.strip_suffix("this combat"))
        .unwrap_or(before_do_so)
        .trim();

    // Remaining text is the block target: "target creature", "~", "it", etc.
    // May be compound: "~ or enchanted creature" → Or union.
    let target_text = &rest.original[..before_temporal.len()];
    let (target, remainder) = parse_target(target_text);
    let (target, remainder) = refine_damage_target_remainder(target, remainder);
    if !remainder.trim().is_empty() {
        ctx.push_diagnostic(OracleDiagnostic::IgnoredRemainder {
            text: remainder.trim().into(),
            parser: "must-block".into(),
            line_index: 0,
        });
    }

    Some(ParsedEffectClause {
        effect: Effect::GenericEffect {
            static_abilities: vec![StaticDefinition::new(StaticMode::MustBeBlockedByAll)
                .affected(target.clone())
                .modifications(vec![ContinuousModification::AddStaticMode {
                    mode: StaticMode::MustBeBlockedByAll,
                }])],
            duration: Some(Duration::UntilEndOfTurn),
            target: Some(target),
        },
        distribute: None,
        multi_target: None,
        condition: None,
        duration: Some(Duration::UntilEndOfTurn),
        sub_ability: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_still_a_type(tp: TextPair) -> Option<ParsedEffectClause> {
    // Match singular "it's still a/an [type]" / "that's still a/an [type]"
    // or plural "they're still [type]s" — CR 205.1a type retention after animation.
    let (is_plural, rest_orig) = nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value(false, alt((tag("it's still "), tag("that's still ")))),
            value(true, tag("they're still ")),
        ))
        .parse(input)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];

    let type_name_lower = if is_plural {
        // Plural: "they're still lands" — no article, strip trailing 's'
        rest_lower
    } else {
        // Singular: strip article "a " / "an "
        let ((), after_article) = nom_on_lower(rest_orig, rest_lower, |input| {
            nom_primitives::parse_article(input)
        })?;
        &rest_lower[rest_lower.len() - after_article.len()..]
    };

    // Strip plural 's' if present (e.g., "lands" → "land", "creatures" → "creature")
    let singular = type_name_lower.strip_suffix('s').unwrap_or(type_name_lower);
    let core_type = CoreType::from_str(&capitalize(singular)).ok()?;

    Some(ParsedEffectClause {
        effect: Effect::GenericEffect {
            static_abilities: vec![StaticDefinition::continuous()
                .affected(TargetFilter::SelfRef)
                .modifications(vec![ContinuousModification::AddType { core_type }])
                .description(tp.original.to_string())],
            duration: Some(Duration::Permanent),
            target: None,
        },
        duration: Some(Duration::Permanent),
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 614.10a: Parse "[subject] skip[s] [their|your] next [step] step[s]" —
/// one-shot step skips. Handles controller and target-player forms.
fn try_parse_skip_next_step(tp: TextPair, ctx: &ParseContext) -> Option<ParsedEffectClause> {
    if let Some((step, rest)) = nom_on_lower(tp.original, tp.lower, |input| {
        let (input, _) = alt((
            tag::<_, _, OracleError<'_>>("you skip your next "),
            tag("skip your next "),
        ))
        .parse(input)?;
        let (input, step) = parse_skip_step_name(input)?;
        Ok((input, step))
    }) {
        if rest.trim().trim_end_matches('.').is_empty() {
            return Some(parsed_clause(Effect::SkipNextStep {
                target: TargetFilter::Controller,
                step,
                count: QuantityExpr::Fixed { value: 1 },
            }));
        }
    }

    if let Some((target, after_verb_orig)) = nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value(
                TargetFilter::DefendingPlayer,
                tag("defending player skips "),
            ),
            value(TargetFilter::TriggeringPlayer, tag("that player skips ")),
            value(TargetFilter::TriggeringPlayer, tag("the player skips ")),
        ))
        .parse(input)
    }) {
        let target = if matches!(target, TargetFilter::TriggeringPlayer) && ctx.subject.is_none() {
            TargetFilter::ParentTarget
        } else {
            target
        };
        let after_verb_lower = &tp.lower[tp.lower.len() - after_verb_orig.len()..];
        let (after_next_lower, _) = alt((
            tag::<_, _, OracleError<'_>>("their next "),
            tag("your next "),
        ))
        .parse(after_verb_lower)
        .ok()?;
        let (rest, step) = parse_skip_step_name(after_next_lower).ok()?;
        if rest.trim().trim_end_matches('.').is_empty() {
            return Some(parsed_clause(Effect::SkipNextStep {
                target,
                step,
                count: QuantityExpr::Fixed { value: 1 },
            }));
        }
    }

    nom::combinator::peek(alt((
        tag::<_, _, OracleError<'_>>("target opponent "),
        tag("target player "),
    )))
    .parse(tp.lower)
    .ok()?;

    let (target, after_target_orig) = super::oracle_target::parse_target(tp.original);
    let after_target_lower = &tp.lower[tp.lower.len() - after_target_orig.len()..];
    let (after_verb_lower, _) = alt((tag::<_, _, OracleError<'_>>(" skips "), tag(" skip ")))
        .parse(after_target_lower)
        .ok()?;
    let (after_next_lower, _) = alt((
        tag::<_, _, OracleError<'_>>("their next "),
        tag("your next "),
    ))
    .parse(after_verb_lower)
    .ok()?;
    let (rest, step) = parse_skip_step_name(after_next_lower).ok()?;
    if !rest.trim().trim_end_matches('.').is_empty() {
        return None;
    }

    Some(parsed_clause(Effect::SkipNextStep {
        target,
        step,
        count: QuantityExpr::Fixed { value: 1 },
    }))
}

fn parse_skip_step_name(input: &str) -> OracleResult<'_, StepSkipTarget> {
    alt((
        value(StepSkipTarget::Step(Phase::Untap), tag("untap step")),
        value(StepSkipTarget::Step(Phase::Upkeep), tag("upkeep step")),
        value(StepSkipTarget::Step(Phase::Draw), tag("draw step")),
        // CR 500.11: Skipping a phase skips all steps within it.
        value(StepSkipTarget::CombatPhase, tag("combat phase")),
    ))
    .parse(input)
}

/// CR 614.10: Parse "[subject] skip[s] [their|your] next [N] turn[s]" — temporal
/// penalty effect. Handles:
///   - "you skip your next turn" / "skip your next turn" → Controller, 1
///   - "target opponent skips their next turn" → Opponent-target, 1
///   - "target player skips their next turn" → Player-target, 1
///   - "target opponent skips their next N turns" → Opponent-target, N
///   - "target opponent skips their next X turns, where X is the number of
///     coins that came up heads" → Opponent-target, 1 (the heads-count
///     multiplier is supplied by the outer `Effect::FlipCoins` loop, which
///     invokes this handler once per heads).
fn try_parse_skip_next_turn(tp: TextPair) -> Option<ParsedEffectClause> {
    // Bare subjectless form (controller skips).
    if nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value((), tag::<_, _, OracleError<'_>>("you skip your next turn")),
            value((), tag("skip your next turn")),
        ))
        .parse(input)
    })
    .is_some()
    {
        return Some(parsed_clause(Effect::SkipNextTurn {
            target: TargetFilter::Controller,
            count: QuantityExpr::Fixed { value: 1 },
        }));
    }

    // Targeted form: "target {opponent|player} skips their next [N|X] turn[s]".
    // Guard on the lowercase prefix before delegating to `parse_target`.
    nom::combinator::peek(alt((
        tag::<_, _, OracleError<'_>>("target opponent "),
        tag("target player "),
    )))
    .parse(tp.lower)
    .ok()?;

    // Delegate the target extraction to the canonical parser so any future
    // target shape ("target opponent of your choice", etc.) picks it up.
    let (target, after_target_orig) = super::oracle_target::parse_target(tp.original);
    let after_target_lower = &tp.lower[tp.lower.len() - after_target_orig.len()..];

    // Verb: " skips " / " skip " (surrounding spaces keep word boundary safe).
    let (after_verb_lower, _) = alt((tag::<_, _, OracleError<'_>>(" skips "), tag(" skip ")))
        .parse(after_target_lower)
        .ok()?;

    // Possessive: "their next " / "your next ".
    let (after_next_lower, _) = alt((
        tag::<_, _, OracleError<'_>>("their next "),
        tag("your next "),
    ))
    .parse(after_verb_lower)
    .ok()?;

    // Optional count between "next " and "turn[s]". Default to 1 if the very
    // next token is "turn"/"turns" (e.g. "skips their next turn"). When
    // `parse_count_expr` succeeds it trims leading whitespace on the remainder,
    // so match "turn[s]" without a leading-space prefix below.
    let after_next_orig = &tp.original[tp.lower.len() - after_next_lower.len()..];
    let (count, after_count_orig) = if let Some((expr, after_num_orig)) =
        super::oracle_util::parse_count_expr(after_next_orig)
    {
        (expr, after_num_orig)
    } else {
        (QuantityExpr::Fixed { value: 1 }, after_next_orig)
    };
    let after_count_lower = &tp.lower[tp.lower.len() - after_count_orig.len()..];

    // Require "turn[s]" with word-boundary termination.
    let (after_turn_lower, _) = alt((tag::<_, _, OracleError<'_>>("turns"), tag("turn")))
        .parse(after_count_lower)
        .ok()?;
    if after_turn_lower
        .chars()
        .next()
        .is_some_and(|c| c.is_alphanumeric())
    {
        return None;
    }

    // CR 705: "where X is the number of coins that came up heads" — the heads
    // multiplier is supplied by the outer `Effect::FlipCoins` loop (one
    // invocation per heads), so normalize the count to 1.
    let trailing = after_turn_lower.trim_start_matches(|c: char| c == ',' || c.is_whitespace());
    let is_heads_tail =
        tag::<_, _, OracleError<'_>>("where x is the number of coins that came up heads")
            .parse(trailing)
            .is_ok();
    let count = if matches!(
        count,
        QuantityExpr::Ref {
            qty: QuantityRef::Variable { ref name },
        } if name == "X"
    ) && is_heads_tail
    {
        QuantityExpr::Fixed { value: 1 }
    } else {
        count
    };

    Some(parsed_clause(Effect::SkipNextTurn { target, count }))
}

/// Verb discriminant for `try_parse_equal_to_quantity_effect`. Using a typed
/// enum instead of a matched `&str` keeps all dispatch inside the nom `alt()`
/// combinator — the match arms below are exhaustive Rust enum arms, not
/// string-literal dispatch (CLAUDE.md nom-combinator mandate).
#[derive(Clone, Copy)]
enum EqualToQtyVerb {
    Mill,
    Draw,
}

/// Parse "{verb} cards equal to {quantity_ref}" patterns (CR 121.1 + CR 701.17a).
///
/// Handles verbs whose count field is `QuantityExpr` (mill, draw).
fn try_parse_equal_to_quantity_effect(tp: TextPair) -> Option<ParsedEffectClause> {
    // Try matching "mill cards equal to " or "draw cards equal to " using nom.
    let (verb, rest_orig) = nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value(EqualToQtyVerb::Mill, tag("mill cards equal to ")),
            value(EqualToQtyVerb::Draw, tag("draw cards equal to ")),
        ))
        .parse(input)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
    let rest = rest_lower.trim().trim_end_matches('.');
    // CR 603.7c: Prefer event context quantity for triggered effects.
    let qty = super::oracle_quantity::parse_event_context_quantity(rest)?;
    match verb {
        EqualToQtyVerb::Mill => Some(parsed_clause(Effect::Mill {
            count: qty,
            // CR 701.17a: No subject → controller mills.
            target: TargetFilter::Controller,
            destination: Zone::Graveyard,
        })),
        // CR 121.1 + CR 601.2c: Default Controller target — `inject_subject_target`
        // upgrades to `TargetFilter::Player` for "target player draws ..." subjects.
        EqualToQtyVerb::Draw => Some(parsed_clause(Effect::Draw {
            count: qty,
            target: TargetFilter::Controller,
        })),
    }
}

/// Parse "owner puts it on their choice of the top or bottom of their library".
///
/// Two Oracle patterns:
/// - "Target creature's owner puts it on their choice of the top or bottom of their library"
/// - "The owner of target nonland permanent puts it on their choice of the top or bottom of their library"
fn try_parse_put_on_top_or_bottom(
    tp: TextPair,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let tp = tp.trim_end_matches('.');

    // Pattern 0: "its owner puts it ..." (anaphoric continuation from prior target clause).
    if super::oracle_nom::bridge::nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = tag("its owner puts it on ").parse(i)?;
        let (i, _) = alt((
            tag("the top or bottom of their library"),
            tag("their choice of the top or bottom of their library"),
        ))
        .parse(i)?;
        value((), eof).parse(i)
    })
    .is_some()
    {
        return Some(parsed_clause(Effect::PutOnTopOrBottom {
            target: TargetFilter::ParentTarget,
        }));
    }

    // Pattern 1: "target [filter]'s owner puts it ..."
    if super::oracle_nom::bridge::nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = take_until("'s owner puts it on ").parse(i)?;
        let (i, _) = tag("'s owner puts it on ").parse(i)?;
        let (i, _) = alt((
            tag("the top or bottom of their library"),
            tag("their choice of the top or bottom of their library"),
        ))
        .parse(i)?;
        value((), eof).parse(i)
    })
    .is_some()
    {
        let target_text = tp
            // allow-noncombinator: TextPair structural extraction after nom-dispatch confirmation.
            .strip_suffix("'s owner puts it on the top or bottom of their library")
            .or_else(|| {
                // allow-noncombinator: TextPair structural extraction after nom-dispatch confirmation.
                tp.strip_suffix(
                    "'s owner puts it on their choice of the top or bottom of their library",
                )
            })
            .map(|pair| pair.original)?;
        let (filter, remainder) = parse_target(target_text);
        if !remainder.trim().is_empty() {
            ctx.push_diagnostic(OracleDiagnostic::IgnoredRemainder {
                text: remainder.trim().into(),
                parser: "owner-puts-it".into(),
                line_index: 0,
            });
        }
        return Some(parsed_clause(Effect::PutOnTopOrBottom { target: filter }));
    }

    // Pattern 2: "the owner of target [filter] puts it ..."
    if super::oracle_nom::bridge::nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = tag("the owner of ").parse(i)?;
        let (i, _) = take_until(" puts it on ").parse(i)?;
        let (i, _) = tag(" puts it on ").parse(i)?;
        let (i, _) = alt((
            tag("the top or bottom of their library"),
            tag("their choice of the top or bottom of their library"),
        ))
        .parse(i)?;
        value((), eof).parse(i)
    })
    .is_some()
    {
        let target_text = tp
            // allow-noncombinator: TextPair structural extraction after nom-dispatch confirmation.
            .strip_prefix("the owner of ")
            .and_then(|pair| {
                // allow-noncombinator: TextPair structural extraction after nom-dispatch confirmation.
                pair.strip_suffix(" puts it on the top or bottom of their library")
                    .or_else(|| {
                        // allow-noncombinator: TextPair structural extraction after nom-dispatch confirmation.
                        pair.strip_suffix(
                            " puts it on their choice of the top or bottom of their library",
                        )
                    })
            })
            .map(|pair| pair.original)?;
        let (filter, remainder) = parse_target(target_text);
        if !remainder.trim().is_empty() {
            ctx.push_diagnostic(OracleDiagnostic::IgnoredRemainder {
                text: remainder.trim().into(),
                parser: "owner-puts-it".into(),
                line_index: 0,
            });
        }
        return Some(parsed_clause(Effect::PutOnTopOrBottom { target: filter }));
    }

    None
}

/// CR 701.24a + CR 400.3: Parse "the owner of target [filter] shuffles it into their library".
///
/// Handles both subject forms:
/// - "The owner of target permanent shuffles it into their library" (Chaos Warp)
/// - "Target permanent's owner shuffles it into their library"
///
/// Produces a `ChangeZone` to Library with `owner_library: true` + a `Shuffle` sub_ability.
fn try_parse_owner_of_target_shuffle(
    tp: TextPair,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let tp = tp.trim_end_matches('.');

    // Must contain both "shuffle" and "library" to be a shuffle-into-library pattern
    if !nom_primitives::scan_contains(tp.lower, "shuffle")
        || !nom_primitives::scan_contains(tp.lower, "library")
    {
        return None;
    }

    let target = extract_owner_of_target(tp, ctx)?;

    Some(imperative::with_shuffle_sub_ability(Effect::ChangeZone {
        origin: None,
        destination: Zone::Library,
        target,
        owner_library: true,
        enter_transformed: false,
        enters_under: None,
        enter_tapped: crate::types::zones::EtbTapState::Unspecified,
        enters_attacking: false,
        up_to: false,
        enter_with_counters: vec![],
        face_down_profile: None,
    }))
}

/// CR 400.3: Parse "the owner of target [filter] puts it into their library
/// second from the top or on the bottom".
///
/// Handles:
/// - "The owner of target nonland permanent puts it into their library second from the top or on the bottom"
/// - "The owner of target creature or enchantment puts it into their library second from the top or on the bottom"
///
/// The "second from the top or on the bottom" pattern is semantically PutOnTopOrBottom (the
/// player chooses). We map it to the same `PutOnTopOrBottom` effect.
fn try_parse_owner_of_target_put_second(
    tp: TextPair,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let tp = tp.trim_end_matches('.');

    // Must contain the signature suffix
    if !nom_primitives::scan_contains(tp.lower, "second from the top or on the bottom") {
        return None;
    }

    let target = extract_owner_of_target(tp, ctx)?;

    Some(parsed_clause(Effect::PutOnTopOrBottom { target }))
}

/// Shared helper: extract the target filter from "the owner of target [filter] [verb]s it ..."
/// or "target [filter]'s owner [verb]s it ..." subject patterns.
///
/// Returns `Some(target_filter)` if the pattern matches, `None` otherwise.
fn extract_owner_of_target(tp: TextPair, ctx: &mut ParseContext) -> Option<TargetFilter> {
    // Pattern 1: "target [filter]'s owner [verb]s it ..."
    if let Some(idx) = tp.find("'s owner ") {
        let target_text = &tp.original[..idx];
        let (filter, remainder) = parse_target(target_text);
        if !remainder.trim().is_empty() {
            ctx.push_diagnostic(OracleDiagnostic::IgnoredRemainder {
                text: remainder.trim().into(),
                parser: "owner-of-target".into(),
                line_index: 0,
            });
        }
        return Some(filter);
    }

    // Pattern 2: "the owner of target [filter] [verb]s it ..."
    if let Some((_, rest_orig)) = nom_on_lower(tp.original, tp.lower, |i| {
        value((), tag("the owner of ")).parse(i)
    }) {
        let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
        let rest = TextPair::new(rest_orig, rest_lower);
        // Find the verb boundary: " shuffles ", " puts ", " draws "
        for verb in [" shuffles ", " puts ", " draws "] {
            if let Some(idx) = rest.find(verb) {
                let target_text = &rest.original[..idx];
                let (filter, remainder) = parse_target(target_text);
                if !remainder.trim().is_empty() {
                    ctx.push_diagnostic(OracleDiagnostic::IgnoredRemainder {
                        text: remainder.trim().into(),
                        parser: "owner-of-target".into(),
                        line_index: 0,
                    });
                }
                return Some(filter);
            }
        }
    }

    None
}

fn try_parse_exile_from_top_until(
    tp: TextPair,
    player: TargetFilter,
) -> Option<ParsedEffectClause> {
    // CR 701.13a + CR 701.57a + CR 702.85a + CR 202.3 + CR 107.3e: Parse the
    // unified `exile cards from the top of <possessive> library until <until>`
    // pattern. The `until` clause is dispatched into a typed
    // [`UntilCondition`] so the same parser arm handles both stop-condition
    // families:
    //
    // * `NextMatches` (CR 701.57a / CR 702.85a) — Discover / Cascade /
    //   Etali-shape: "until <pronoun> exile[s] a/an {filter} card". Stops on
    //   the first hit; the hit card is exposed to the sub_ability chain.
    //
    // * `CumulativeThreshold` (CR 202.3 + CR 107.3e) — Tasha's Hideous
    //   Laughter / Dream Harvest / Improvisation Capstone: "until <subject>
    //   <verb> exiled cards with total mana value N or greater". Stops once
    //   the running sum reaches the threshold.
    //
    // CR 400.7: each exiled card is a new object; tracked by `ExileLink` in
    // the resolver so downstream `TargetFilter::ExiledBySource` lookups
    // resolve correctly for both stop-condition kinds.
    //
    // Subject normalization — both second-person ("exile … your library
    // until you exile …") and third-person ("exile … their library until
    // they exile …") possessives are accepted. The "each player " /
    // "each opponent " subject is stripped upstream by
    // `strip_each_player_subject`, which deconjugates "exiles" → "exile";
    // by the time this combinator runs Tasha's body reads
    //   "exile cards from the top of their library until that player has
    //    exiled cards with total mana value 20 or greater"
    // — same prefix as Etali, different until-clause shape.
    //
    // Mirrors the analogous sub-combinator pattern in
    // `parse_reveal_until_prefix` (oracle_effect/mod.rs:2433).
    let (_, rest_orig) = nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = alt((tag("exile "), tag("exiles "))).parse(i)?;
        let (i, _) = tag("cards from the top of ").parse(i)?;
        let (i, _) = alt((
            tag("your "),
            tag("their "),
            tag("his "),
            tag("her "),
            tag("its "),
        ))
        .parse(i)?;
        value::<_, _, OracleError<'_>, _>((), tag("library until ")).parse(i)
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];

    let until = parse_until_condition(rest_lower)?;
    Some(parsed_clause(Effect::ExileFromTopUntil { player, until }))
}

/// CR 701.13a + CR 701.57a + CR 702.85a + CR 202.3 + CR 107.3e: Dispatch the
/// until-clause of an `exile cards from the top of <library> until …` body
/// into a typed [`UntilCondition`]. The two recognised shapes are:
///
/// * `NextMatches` — `<pronoun> exile[s] a/an {filter} card`
///   (e.g. "you exile a nonland card", "they exile a creature card").
///
/// * `CumulativeThreshold` — `<subject> <verb> exiled cards with total mana
///   value N <comparator>` (e.g. "you exile cards with total mana value 4 or
///   greater", "that player has exiled cards with total mana value 20 or
///   greater", "they have exiled cards with total mana value 5 or greater
///   this way"). The trailing `this way` qualifier is informational — it
///   refers to the per-resolution exile-link channel which the runtime
///   already tracks via `ExileLinkKind::TrackedBySource`.
///
/// Returns `None` if the clause matches neither shape so the caller can
/// fall through to the generic dispatcher.
fn parse_until_condition(input: &str) -> Option<UntilCondition> {
    // First, try the cumulative form: it carries a richer leading subject
    // ("that player has exiled" / "they have exiled" / "you exile") that
    // precedes the "exiled cards with total mana value" tail. Try this branch
    // first because the NextMatches branch's leading "you exile " /
    // "they exile " prefix is a left-anchored substring of one of the
    // cumulative-clause subjects.
    if let Some(cond) = try_parse_cumulative_until(input) {
        return Some(cond);
    }
    try_parse_next_matches_until(input)
}

/// CR 701.57a / CR 702.85a: Parse `<pronoun> exile[s] a/an {filter} card.`
/// Returns the typed `UntilCondition::NextMatches { filter }`.
fn try_parse_next_matches_until(input: &str) -> Option<UntilCondition> {
    let (_, rest) = nom_on_lower(input, input, |i| {
        let (i, _) = alt((
            tag("you exile "),
            tag("they exile "),
            tag("he exiles "),
            tag("she exiles "),
            tag("it exiles "),
        ))
        .parse(i)?;
        nom_primitives::parse_article(i)
    })?;

    // Extract the filter from "nonland card", "creature card", etc. The
    // downstream `parse_target` call does the actual filter parsing with
    // combinators; this is just punctuation/suffix cleanup on the chunk.
    let filter_text = rest.trim_end_matches('.').trim_end_matches(" card"); // allow-noncombinator: structural punctuation cleanup on isolated filter chunk

    let filter = if filter_text == "nonland" {
        TargetFilter::Typed(
            TypedFilter::default().with_type(TypeFilter::Non(Box::new(TypeFilter::Land))),
        )
    } else {
        // Delegate to existing target parsing for other filter types
        let (parsed, _) = parse_target(filter_text);
        parsed
    };

    Some(UntilCondition::NextMatches { filter })
}

/// CR 202.3 + CR 107.3e: Parse the cumulative-threshold until-clause shape.
/// Recognises every documented subject/verb form for this family:
///
///   <subject> [has|have] exiled cards with total mana value N <comparator>[ this way]
///
/// where `<subject>` is `that player`, `they`, `you`, `it`, `he`, `she`, or
/// the bare deconjugated `<pronoun> exile` (the "each opponent" → "exile"
/// path that `strip_each_player_subject` produces, e.g. Improvisation
/// Capstone's "you exile cards with total mana value 4 or greater").
fn try_parse_cumulative_until(input: &str) -> Option<UntilCondition> {
    let (_, rest) = nom_on_lower(input, input, |i| {
        // Subject + verb. Two grammatical shapes appear in printed cards:
        //
        //   * Perfect aspect: "that player has exiled" / "they have exiled" /
        //     "you have exiled" — the "this way" qualifier is typically present.
        //   * Imperative deconjugation: "you exile" / "they exile" — produced
        //     by the upstream "each opponent" stripper for cards whose printed
        //     text was "Each opponent exiles cards … until they exile cards …".
        //
        // Compose subject + verb as a single combinator alternation.
        let (i, _) = alt((
            tag("that player has exiled "),
            tag("they have exiled "),
            tag("you have exiled "),
            tag("it has exiled "),
            tag("he has exiled "),
            tag("she has exiled "),
            tag("they exile "),
            tag("you exile "),
            tag("it exiles "),
            tag("he exiles "),
            tag("she exiles "),
        ))
        .parse(i)?;
        value::<_, _, OracleError<'_>, _>((), tag("cards with total ")).parse(i)
    })?;

    // Property axis: "mana value", "power", or "toughness". Power/toughness
    // are speculative for printed cards but cost zero to wire — the runtime
    // resolver already handles all three via `ObjectProperty`.
    let (property, after_prop) = parse_property_axis(rest)?;

    // Threshold: "N or greater" / "N or more" / "N or less" / "N or fewer".
    // Fixed integer threshold; X-thresholds for this clause shape don't appear
    // in printed cards but the typed enum already supports `QuantityExpr::X`
    // upstream if needed.
    let (after_n, n) = nom_primitives::parse_number(after_prop).ok()?;
    let comparator = parse_threshold_comparator(after_n.trim_start())?;

    // Trailing qualifiers ("this way", ".") are informational; the
    // per-resolution exile-link tracking is already enforced at runtime.
    Some(UntilCondition::CumulativeThreshold {
        property,
        comparator,
        threshold: QuantityExpr::Fixed {
            value: i32::try_from(n).unwrap_or(i32::MAX),
        },
    })
}

/// CR 202.3 / CR 208 / CR 209: Recognise the property axis of a cumulative
/// threshold clause. Returns the property and the remaining input.
fn parse_property_axis(input: &str) -> Option<(ObjectProperty, &str)> {
    nom_on_lower(input, input, |i| {
        alt((
            value(ObjectProperty::ManaValue, tag("mana value ")),
            value(ObjectProperty::Power, tag("power ")),
            value(ObjectProperty::Toughness, tag("toughness ")),
        ))
        .parse(i)
    })
}

/// Recognise the comparator suffix of a cumulative threshold clause:
/// "or greater" / "or more" → `GE`, "or less" / "or fewer" → `LE`.
fn parse_threshold_comparator(input: &str) -> Option<Comparator> {
    nom_on_lower(input, input, |i| {
        alt((
            value(Comparator::GE, tag("or greater")),
            value(Comparator::GE, tag("or more")),
            value(Comparator::LE, tag("or less")),
            value(Comparator::LE, tag("or fewer")),
        ))
        .parse(i)
    })
    .map(|(c, _)| c)
}

/// CR 701.20a: Shared prefix `"reveal[s] cards from the top of <possessive> library until "`.
/// Returns the input positioned at the first token after `"until "`.
/// Used by both the active-form and passive-form `RevealUntil` parsers so that
/// any future possessive arm addition only needs to be made in one place.
fn parse_reveal_cards_from_library_until(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
    // CR 701.20a: verb form — bare imperative ("reveal") or third-person ("reveals")
    let (input, _) = alt((tag("reveals "), tag("reveal "))).parse(input)?;
    let (input, _) = tag("cards from the top of ").parse(input)?;
    // CR 109.5: possessive determiner identifying the library owner. Both English
    // possessive forms ("your"/"their"/"his"/"her"/"its") map to the same parsed
    // structure; the actual player is supplied by the caller via subject context.
    let (input, _) = alt((
        tag("your "),
        tag("their "),
        tag("his "),
        tag("her "),
        tag("its "),
        // CR 109.5: "top of that library" — Mirror-Mad Phantasm class
        tag("that "),
    ))
    .parse(input)?;
    value((), tag("library until ")).parse(input)
}

fn parse_reveal_until_prefix(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
    let (input, _) = parse_reveal_cards_from_library_until(input)?;
    // Active-voice pronoun + matching verb form.
    let (input, _) = alt((
        tag("you reveal "),
        tag("they reveal "),
        tag("he reveals "),
        tag("she reveals "),
        tag("it reveals "),
    ))
    .parse(input)?;
    let (input, _) = nom_primitives::parse_article(input)?;
    Ok((input, ()))
}

/// CR 701.20a: Parse the **passive-voice** prefix `"reveal[s] cards from the top of
/// <possessive> library until "`, returning `()`.
/// Stops before the article — the caller (`try_parse_reveal_until`) extracts the
/// article, filter phrase, and optional exile suffix using nom combinators in
/// the function body.
///
/// Covers: Indomitable Creativity, Blessed Reincarnation, Tunnel Vision.
fn parse_reveal_until_passive_prefix(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
    parse_reveal_cards_from_library_until(input)
}

fn parse_reveal_until_active_filter_text(input: &str) -> OracleResult<'_, &str> {
    all_consuming(alt((
        terminated(take_until(" card"), (tag(" card"), opt(tag(".")))),
        terminated(take_until("."), tag(".")),
        rest,
    )))
    .parse(input)
}

fn parse_reveal_until_passive_filter_text(input: &str) -> OracleResult<'_, &str> {
    all_consuming(alt((terminated(take_until(" card"), tag(" card")), rest))).parse(input)
}

/// Build a [`TargetFilter`] from the bare filter phrase extracted from a `RevealUntil`
/// until-clause (caller has already stripped the article and trailing `" card"` suffix).
fn build_reveal_until_filter(filter_text: &str) -> TargetFilter {
    // CR 701.20a: "with the chosen name" — active form (e.g. Abundance)
    if nom_primitives::scan_contains(filter_text, "with the chosen name") {
        return TargetFilter::HasChosenName;
    }
    // CR 701.20a: "with that name" — passive form (Tunnel Vision)
    if nom_primitives::scan_contains(filter_text, "with that name") {
        return TargetFilter::HasChosenName;
    }
    if filter_text == "nonland" {
        return TargetFilter::Typed(
            TypedFilter::default().with_type(TypeFilter::Non(Box::new(TypeFilter::Land))),
        );
    }
    if let Some(filter) = try_parse_chosen_kind_filter(filter_text) {
        return filter;
    }
    let (parsed, _) = parse_target(filter_text);
    parsed
}

/// CR 701.20a: Parse `"reveal[s] cards from the top of <possessive> library until …"`
/// in both active voice (`"until <pronoun> reveal[s] a <filter>"`) and
/// passive voice (`"until a/an <filter> [card] is revealed [and exiles that card]"`).
/// Builds [`Effect::RevealUntil`] with `player` identifying whose library is revealed.
fn try_parse_reveal_until(tp: TextPair, player: TargetFilter) -> Option<ParsedEffectClause> {
    // CR 701.20a: Active-voice form — "…until they reveal a <filter>".
    let active_result = nom_on_lower(tp.original, tp.lower, parse_reveal_until_prefix);
    if let Some((_, rest_orig)) = active_result {
        let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
        let (_, filter_text) = parse_reveal_until_active_filter_text(rest_lower).ok()?;
        let filter = build_reveal_until_filter(filter_text);
        return Some(parsed_clause(Effect::RevealUntil {
            player,
            filter,
            kept_destination: Zone::Hand,
            rest_destination: Zone::Library,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            enters_attacking: false,
            kept_optional_to: None,
        }));
    }

    // CR 701.20a: Passive-voice form — "…until a/an <filter> [card] is revealed
    // [and exiles that card]" (Indomitable Creativity, Blessed Reincarnation,
    // Tunnel Vision). Passive prefix stops before the article; extract article,
    // filter phrase, and optional exile suffix here.
    let (_, rest_orig) = nom_on_lower(tp.original, tp.lower, parse_reveal_until_passive_prefix)?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];

    // Consume the article ("a" / "an").
    let (_, after_article_orig) =
        nom_on_lower(rest_orig, rest_lower, nom_primitives::parse_article)?;
    let after_article_lower = &rest_lower[rest_lower.len() - after_article_orig.len()..];

    // Capture everything up to " is revealed" — this is the filter phrase.
    let (remainder, captured) = take_until::<_, _, OracleError<'_>>(" is revealed")
        .parse(after_article_lower)
        .ok()?;

    // Strip trailing " card" if present ("artifact or creature card" → "artifact or creature").
    // Tunnel Vision's captured = "card with that name" (no " card" suffix — handled by HasChosenName).
    let (_, filter_text) = parse_reveal_until_passive_filter_text(captured).ok()?;

    let filter = build_reveal_until_filter(filter_text);

    // CR 406.2: Detect inline "and exiles that card" suffix. When present, the kept
    // card goes directly to Exile. Consume " is revealed" via nom tag, then check
    // the optional exile clause with a tag probe (.is_ok() since opt is infallible anyway).
    let (after_is_revealed, _) = tag::<_, _, OracleError<'_>>(" is revealed")
        .parse(remainder)
        .ok()?;
    let inline_exile = tag::<_, _, OracleError<'_>>(" and exiles that card")
        .parse(after_is_revealed)
        .is_ok();
    let kept_destination = if inline_exile {
        Zone::Exile
    } else {
        Zone::Hand
    };

    Some(parsed_clause(Effect::RevealUntil {
        player,
        filter,
        kept_destination,
        rest_destination: Zone::Library,
        enter_tapped: crate::types::zones::EtbTapState::Unspecified,
        enters_attacking: false,
        kept_optional_to: None,
    }))
}

/// CR 614.11 + CR 701.20a: Detect a "card of the chosen kind" reveal-until
/// filter by delegating to `parse_search_filter` and inspecting the result
/// for `FilterProp::IsChosenLandOrNonlandKind`. The search-filter parser is
/// the canonical detector for this phrase (consumed by the Seek-of-the-
/// chosen-kind family); reusing it here avoids a parallel string match and
/// inherits any future "permanent card of the chosen kind" extensions.
fn try_parse_chosen_kind_filter(filter_text: &str) -> Option<TargetFilter> {
    let mut ctx = ParseContext::default();
    let parsed = parse_search_filter(filter_text, &mut ctx);
    let TargetFilter::Typed(ref tf) = parsed else {
        return None;
    };
    tf.properties
        .iter()
        .any(|p| matches!(p, FilterProp::IsChosenLandOrNonlandKind))
        .then_some(parsed)
}

/// CR 611.2a + CR 108.3: Parse per-grantee grant clauses that follow a
/// compound-exile effect. These clauses bind the resulting `PlayFromExile`
/// permission to a player OTHER than the ability's controller — the exiled
/// object's owner, or the parent effect's player target — via
/// [`PermissionGrantee`]. The target is `TrackedSet` — the most recently
/// published tracked set (i.e., the exiled cards).
///
/// Patterns:
/// - `for each of those cards, its owner may play it [until the end of their next turn]`
///   → [`PermissionGrantee::ObjectOwner`] (Suspend Aggression). The
///   "for each of those cards" prefix is rhetorical — the resolver already
///   iterates the target set object-by-object.
/// - `they may play those cards [until the end of their next turn]`
///   → [`PermissionGrantee::ParentTargetController`] (Expedited Inheritance).
///   The pronoun "they" refers to the parent effect's player target.
fn try_parse_per_grantee_play_grant(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let lower = tp.lower;

    let grantee = if alt((
        tag::<_, _, OracleError<'_>>("for each of those cards, its owner may play it"),
        tag("for each of those cards, its owner may cast it"),
        tag("its owner may play it"),
        tag("its owner may cast it"),
        // CR 611.2a + CR 108.3 + CR 400.7i + CR 400.7j: Rocco-class
        // "each player may play the card they exiled this way" —
        // multi-player owner-binding grant. The "they exiled this way"
        // anaphor refers to the per-iteration tracked set published by
        // the parent player_scope iteration in `resolve_ability_chain`;
        // the resolver binds `granted_to` to each card's owner via
        // `PermissionGrantee::ObjectOwner`.
        tag("each player may play the card they exiled this way"),
        tag("each player may cast the card they exiled this way"),
        tag("each player may play the cards they exiled this way"),
        tag("each player may cast the cards they exiled this way"),
    ))
    .parse(lower)
    .is_ok()
    {
        crate::types::ability::PermissionGrantee::ObjectOwner
    } else if alt((
        tag::<_, _, OracleError<'_>>("they may play those cards"),
        tag("they may cast those cards"),
        tag("they may play them"),
        tag("they may cast them"),
    ))
    .parse(lower)
    .is_ok()
    {
        crate::types::ability::PermissionGrantee::ParentTargetController
    } else {
        return None;
    };

    // Duration: default to UntilEndOfTurn if unspecified (matches impulse-draw default).
    let (_, dur) = strip_trailing_duration(tp.original);
    let duration = dur.unwrap_or(Duration::UntilEndOfTurn);

    Some(parsed_clause(Effect::GrantCastingPermission {
        permission: CastingPermission::PlayFromExile {
            duration,
            // Placeholder — `grant_permission::resolve` normalizes per-iteration.
            granted_to: crate::types::player::PlayerId(0),
            frequency: CastFrequency::Unlimited,
            source_id: None,
            exiled_by_ability_controller: None,
            mana_spend_permission: None,
        },
        target: TargetFilter::TrackedSet {
            id: TrackedSetId(0),
        },
        grantee,
    }))
}

/// CR 400.7i + CR 609.4b: Persistent duration-scoped cast permission for the
/// "exile, then until [duration] you may cast spells from among those exiled
/// cards" anaphor (Nassari Dean of Expression, Stolen Strategy, and similar
/// cast-from-tracked-exile patterns).
///
/// Distinguishes from the single-resolution sibling
/// [`Effect::CastFromZone { target: ExiledBySource }`] (Etali, Apex of Power,
/// Improvisation Capstone) by the presence of a duration scope on the cast
/// permission rather than an inline cast. The persistent variant grants
/// [`CastingPermission::PlayFromExile`] to the tracked-set members and lets
/// the controller cast across the duration window; the single-resolution
/// variant casts inline during the same resolution.
///
/// The grant binds to [`TargetFilter::TrackedSet { id: TrackedSetId(0) }`] —
/// `grant_permission::resolve` normalizes the sentinel to the most recently
/// published tracked set, and only objects in that set receive the
/// permission. Cards exiled by other sources do not have this permission
/// attached and are correctly excluded from `has_exile_cast_permission`'s
/// surfacing. No new variant needed — the existing primitives compose.
///
/// The optional ", and you may spend mana as though it were mana of any
/// color to cast those spells" conjunct folds into the same permission via
/// `mana_spend_permission: Some(ManaSpendPermission::AnyTypeOrColor)`,
/// matching the wire-up used by `try_parse_exile_play_grant_with_any_mana`.
fn try_parse_cast_from_tracked_exile_grant(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    // Prefix: "you may cast spells from among [those|the] exiled cards"
    let ((), rest_orig) = nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = tag("you may cast spells from among ").parse(i)?;
        let (i, _) = alt((tag("those exiled cards"), tag("the exiled cards"))).parse(i)?;
        Ok((i, ()))
    })?;
    let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];

    // Optional any-color mana conjunct: ", and you may spend mana as though
    // it were mana of any color to cast those spells" (or "...any type...").
    let mana_spend_permission = if rest_lower.is_empty() {
        None
    } else {
        // Trailing text that is not the recognized conjunct — reject so the
        // catch-all SpendManaAsAnyColor parse does not consume an unrelated
        // suffix and silently drop the cast-permission half.
        nom_on_lower(rest_orig, rest_lower, |i| {
            let (i, _) = tag(", and you may spend mana as though it were mana of any ").parse(i)?;
            let (i, _) = alt((tag("color"), tag("type"))).parse(i)?;
            let (i, _) = tag(" to cast those spells").parse(i)?;
            let (i, _) = eof.parse(i)?;
            Ok((i, ()))
        })?;
        Some(ManaSpendPermission::AnyTypeOrColor)
    };

    Some(parsed_clause(Effect::GrantCastingPermission {
        permission: CastingPermission::PlayFromExile {
            // Duration is a placeholder; `with_clause_duration` patches this
            // when a leading "Until end of turn, " or trailing "... this turn"
            // is stripped. CR 611.2a + CR 514.2: the duration governs prune
            // timing in `layers.rs::prune_play_from_exile_at_cleanup`.
            duration: Duration::Permanent,
            // CR 611.2a/b: placeholder — `grant_permission::resolve` rewrites
            // this to the concrete grantee at grant time.
            granted_to: crate::types::player::PlayerId(0),
            frequency: CastFrequency::Unlimited,
            source_id: None,
            exiled_by_ability_controller: None,
            mana_spend_permission,
        },
        // CR 603.7 + CR 608.2c: TrackedSet sentinel — the runtime resolver
        // normalizes `TrackedSetId(0)` to the most recently published set
        // (the cards exiled by the parent effect in this resolution chain).
        // Only those objects receive the permission; cards exiled by other
        // sources do not, scoping the cast surface to the correct exile set.
        target: TargetFilter::TrackedSet {
            id: TrackedSetId(0),
        },
        grantee: Default::default(),
    }))
}

fn try_parse_exile_play_grant_with_any_mana(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("you may look at and play "),
        tag("you may play "),
        tag("you may cast "),
        tag("look at and play "),
        tag("play "),
        tag("cast "),
    ))
    .parse(tp.lower)
    .ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("that card"),
        tag("that spell"),
        tag("those cards"),
        tag("it"),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(" for as long as ")
        .parse(rest)
        .ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("it remains exiled"),
        tag("that card remains exiled"),
        tag("those cards remain exiled"),
    ))
    .parse(rest)
    .ok()?;
    let (rest, _) = tag::<_, _, OracleError<'_>>(", and ").parse(rest).ok()?;
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("mana of any type can be spent to cast that spell"),
        tag("mana of any color can be spent to cast that spell"),
    ))
    .parse(rest)
    .ok()?;
    eof::<_, OracleError<'_>>(rest).ok()?;

    Some(parsed_clause(Effect::GrantCastingPermission {
        permission: CastingPermission::PlayFromExile {
            duration: Duration::Permanent,
            granted_to: crate::types::player::PlayerId(0),
            frequency: CastFrequency::Unlimited,
            source_id: None,
            exiled_by_ability_controller: None,
            mana_spend_permission: Some(ManaSpendPermission::AnyTypeOrColor),
        },
        target: TargetFilter::Any,
        grantee: Default::default(),
    }))
}

/// CR 400.7i: Parse "you may play/cast that card [this turn]" — impulse draw permission.
fn try_parse_play_from_exile(tp: TextPair, ctx: &ParseContext) -> Option<ParsedEffectClause> {
    let tp = tp.trim_end_matches('.');

    // CR 611.2a + CR 108.3: Per-object grant clauses from compound-exile chains.
    // These bind the grant to a player OTHER than the ability's controller via
    // Theme D's `granted_to` field, resolved per-iteration by
    // `grant_permission::resolve`. The target is `TrackedSet` — the most
    // recently published set (the exiled cards from the parent effect).
    if let Some(clause) = try_parse_per_grantee_play_grant(tp) {
        return Some(clause);
    }
    if let Some(clause) = try_parse_exile_play_grant_with_any_mana(tp) {
        return Some(clause);
    }
    // CR 400.7i + CR 609.4b: Persistent duration-scoped variant —
    // "you may cast spells from among those exiled cards[, and you may spend
    // mana as though it were mana of any color to cast those spells]".
    // Must run before the catch-all SpendManaAsAnyColor branch so the
    // GrantCastingPermission half is not silently dropped (Nassari, Stolen
    // Strategy, and similar exile-then-cast-permission patterns).
    if let Some(clause) = try_parse_cast_from_tracked_exile_grant(tp) {
        return Some(clause);
    }

    if let Some(clause) = try_parse_play_the_exiled_card_grant(tp) {
        return Some(clause);
    }

    // Try full forms first: "you may play/cast that card/it/those cards ..."
    // Then bare forms (after "you may" has been stripped): "play that card ..."
    let full_rest = nom_on_lower(tp.original, tp.lower, |input| {
        value((), alt((tag("you may play "), tag("you may cast ")))).parse(input)
    })
    .map(|((), rest_orig)| {
        let rest_lower = &tp.lower[tp.lower.len() - rest_orig.len()..];
        TextPair::new(rest_orig, rest_lower)
    });

    if let Some(rest) = full_rest {
        // Full form: rest must start with a card reference
        if alt((
            tag::<_, _, OracleError<'_>>("that card"),
            tag("that spell"),
            tag("those cards"),
            tag("it "),
        ))
        .parse(rest.lower)
        .is_err()
            && rest.lower != "it"
        {
            return None;
        }
        // CR 118.5 + CR 118.9 + CR 118.9a + CR 118.9b: "without paying [its|their]
        // mana cost(s)" is a *free-cast alternative cost*, not a PlayFromExile
        // permission. Defer to `try_parse_cast_effect`, which emits
        // `CastFromZone { without_paying_mana_cost: true }` — the correct
        // free-cast shape. Mirrors the bare-form guard below. Fallen Shinobi
        // ("you may play those cards without paying their mana costs") and
        // similar cards depend on this branch.
        if scan_contains_phrase(tp.lower, "without paying") {
            return None;
        }
    } else {
        // Bare form (after "you may" was stripped by parse_effect_chain):
        // Only match when temporal context exists ("this turn", "until"),
        // otherwise it's a CastFromZone, not impulse draw permission.
        let has_temporal =
            scan_contains_phrase(tp.lower, "this turn") || scan_contains_phrase(tp.lower, "until ");
        if !has_temporal {
            return None;
        }
        if scan_contains_phrase(tp.lower, "without paying") {
            return None;
        }
        if alt((
            tag::<_, _, OracleError<'_>>("play that card"),
            tag("cast that card"),
            tag("play it"),
            tag("cast it"),
        ))
        .parse(tp.lower)
        .is_err()
        {
            return None;
        }
    }

    // CR 601.2a + CR 608.2c: Distinguish a targeted graveyard grant from an
    // impulse-draw grant by the anaphor's referent, not by the clause's wording.
    // When an earlier clause in this chain SELECTED a target (Emry's "Choose
    // target artifact card in your graveyard" → `Effect::TargetOnly`), the
    // "that card"/"that spell" anaphor binds to that chosen card — defer to
    // `try_parse_cast_effect` → `CastFromZone { target: ParentTarget }`. When the
    // referent is an exile/impulse publisher instead (`Exile the top card... you
    // may play that card this turn`, or `ExileFromTopUntil` as in Territorial
    // Bruntar), the anaphor is the tracked exile set — fall through to the
    // `PlayFromExile { TrackedSet }` grant below. `parent_target_is_chosen` is a
    // strict subset of `parent_target_available` set by the chain loop via
    // `chain_prior_referent_is_chosen_target`, so the two classes split here
    // without inspecting clause text (a lexical "that card this turn" guard would
    // misroute the entire impulse class and silently drop its `PlayFromExile`
    // shape).
    if ctx.parent_target_is_chosen {
        return None;
    }

    // Duration: extract from trailing text, defaulting to UntilEndOfTurn for impulse draw
    let (_, dur) = strip_trailing_duration(tp.original);
    let duration = dur.unwrap_or(Duration::UntilEndOfTurn);

    Some(parsed_clause(Effect::GrantCastingPermission {
        permission: CastingPermission::PlayFromExile {
            duration,
            // Placeholder — `grant_permission::resolve` rewrites this to the
            // ability's controller at grant time (CR 611.2a/b).
            granted_to: crate::types::player::PlayerId(0),
            frequency: CastFrequency::Unlimited,
            source_id: None,
            exiled_by_ability_controller: None,
            mana_spend_permission: None,
        },
        // CR 603.7 + CR 611.2a: The grant must reach the tracked exile set
        // (the cards exiled by the prior clause) rather than fall back to the
        // source object. `TargetFilter::Any` causes `grant_permission::resolve`
        // to attach the permission to the source itself, which is wrong for
        // impulse-draw chains like Act on Impulse, Light Up the Stage, etc.
        target: tracked_set_filter(),
        grantee: Default::default(),
    }))
}

fn try_parse_play_the_exiled_card_grant(tp: TextPair) -> Option<ParsedEffectClause> {
    let (duration, rest_orig) = nom_on_lower(tp.original, tp.lower, |input| {
        let (input, _) = opt(alt((tag("you may "), tag("may ")))).parse(input)?;
        let (input, _) = alt((tag("play "), tag("cast "))).parse(input)?;
        let (input, _) = tag("the exiled card").parse(input)?;
        let (input, duration) = alt((
            value(Duration::UntilEndOfTurn, tag(" this turn")),
            value(Duration::UntilEndOfTurn, tag(" until end of turn")),
            value(Duration::UntilEndOfTurn, tag(" until the end of turn")),
        ))
        .parse(input)?;
        Ok((input, duration))
    })?;
    if !rest_orig.trim().is_empty() {
        return None;
    }

    Some(parsed_clause(Effect::GrantCastingPermission {
        permission: CastingPermission::PlayFromExile {
            duration,
            granted_to: crate::types::player::PlayerId(0),
            frequency: CastFrequency::Unlimited,
            source_id: None,
            exiled_by_ability_controller: None,
            mana_spend_permission: None,
        },
        target: tracked_set_filter(),
        grantee: Default::default(),
    }))
}

pub(crate) fn try_parse_exile_top_each_library_with_collection_counter(
    text: &str,
    kind: AbilityKind,
) -> Option<AbilityDefinition> {
    let lower = text.to_lowercase();
    let ((), _) = nom_on_lower(text, &lower, |input| {
        let (input, _) = tag("exile the top card of each player's library").parse(input)?;
        let (input, _) = tag(" with a collection counter on it").parse(input)?;
        let (input, _) = opt(tag(".")).parse(input)?;
        let (input, _) = eof.parse(input)?;
        Ok((input, ()))
    })?;

    let grant = AbilityDefinition::new(
        kind,
        Effect::GrantCastingPermission {
            permission: CastingPermission::PlayFromExile {
                duration: Duration::Permanent,
                granted_to: crate::types::player::PlayerId(0),
                frequency: CastFrequency::OncePerTurn,
                source_id: None,
                exiled_by_ability_controller: None,
                mana_spend_permission: Some(ManaSpendPermission::AnyTypeOrColor),
            },
            target: TargetFilter::TrackedSet {
                id: TrackedSetId(0),
            },
            grantee: Default::default(),
        },
    );
    let put_counter = AbilityDefinition::new(
        kind,
        Effect::PutCounterAll {
            counter_type: CounterType::Generic("collection".to_string()),
            count: QuantityExpr::Fixed { value: 1 },
            target: TargetFilter::TrackedSet {
                id: TrackedSetId(0),
            },
        },
    )
    .sub_ability(grant);

    let mut def = AbilityDefinition::new(
        kind,
        Effect::ExileTop {
            player: TargetFilter::Controller,
            count: QuantityExpr::Fixed { value: 1 },
            face_down: false,
        },
    );
    def.player_scope = Some(PlayerFilter::All);
    def.sub_ability = Some(Box::new(put_counter));
    Some(def)
}

/// The two equalization verbs Balance / Restore Balance / Balancing Act use.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EqualizeVerb {
    Sacrifice,
    Discard,
}

/// CR 107.1b: Build the "keep N, dispose the rest" effect for one Balance
/// clause. "Each player keeps the minimum, disposes the rest" is identically
/// "each player disposes (their own count − the minimum)". Operand order is
/// load-bearing: `left` MUST be the per-player count and `right` MUST be the
/// cross-player minimum. The `Difference` resolver takes `.abs()`, which masks
/// a `left >= right` invariant — `left >= right` always holds here because the
/// per-player count includes the minimizing player, and the §8 clause-local
/// snapshot freezes `right` so an earlier APNAP player's sacrifices cannot
/// shrink it below a later player's `left`. A swapped pair (or an unsnapshot
/// minimum) would mis-clamp a positive disposal count instead of yielding 0.
fn balance_clause_effect(verb: EqualizeVerb, filter: TargetFilter) -> Effect {
    match verb {
        // CR 701.21a: battlefield clause — "lands they control" / "creatures
        // they control". `filter` carries `controller: You`. The sacrifice
        // `target` and the RIGHT `ControlledByEachPlayer` Min keep `You`; the
        // LEFT per-player count is re-scoped to `ScopedPlayer` so it reads the
        // iterating player at the `resolve_ref` seam (CR 109.5) rather than the
        // caster. See `balance_filter_scoped_player`.
        EqualizeVerb::Sacrifice => {
            let left = QuantityExpr::Ref {
                qty: QuantityRef::ObjectCount {
                    filter: balance_filter_scoped_player(&filter),
                },
            };
            let right = QuantityExpr::Ref {
                qty: QuantityRef::ControlledByEachPlayer {
                    filter: filter.clone(),
                    aggregate: AggregateFunction::Min,
                },
            };
            Effect::Sacrifice {
                target: filter,
                // CR 107.1b: left = per-player count, right = minimum.
                count: QuantityExpr::Difference {
                    left: Box::new(left),
                    right: Box::new(right),
                },
                min_count: 0,
            }
        }
        // CR 701.9a: hand clause — "cards they control" in hand. No battlefield
        // filter: `HandSize { ScopedPlayer }` is the iterating player's hand
        // size, `HandSize { AllPlayers { Min } }` the cross-player minimum.
        EqualizeVerb::Discard => {
            let left = QuantityExpr::Ref {
                qty: QuantityRef::HandSize {
                    player: PlayerScope::ScopedPlayer,
                },
            };
            let right = QuantityExpr::Ref {
                qty: QuantityRef::HandSize {
                    player: PlayerScope::AllPlayers {
                        aggregate: AggregateFunction::Min,
                        exclude: None,
                    },
                },
            };
            Effect::Discard {
                // CR 107.1b: left = per-player count, right = minimum.
                count: QuantityExpr::Difference {
                    left: Box::new(left),
                    right: Box::new(right),
                },
                target: TargetFilter::Controller,
                selection: crate::types::ability::CardSelectionMode::Chosen,
                unless_filter: None,
                filter: None,
            }
        }
    }
}

/// Force a type-phrase filter's controller clause to "you control" so the
/// `player_scope` driver scopes it to the iterating player. Balance's "lands
/// they control" has the "they control" consumed by an outer `tag()`, so the
/// inner `parse_type_phrase` sees only the bare type word.
fn balance_filter_you_control(filter: TargetFilter) -> TargetFilter {
    match filter {
        TargetFilter::Typed(tf) => TargetFilter::Typed(TypedFilter {
            controller: Some(ControllerRef::You),
            ..tf
        }),
        other => other,
    }
}

/// CR 109.5 + CR 608.2c: Re-scope a Balance battlefield filter's controller to
/// `ScopedPlayer` for the per-player LEFT count operand. "Lands/creatures they
/// control" names the iterating player, but a quantity sub-expression is read
/// against the *printed* controller at the `resolve_ref` seam (CR 109.5) — so a
/// `controller: You` LEFT operand counts the caster's permanents, not the
/// iterating player's. `ScopedPlayer` resolves via `scoped_player_or_controller`
/// (reads `ability.scoped_player`, bound per-iteration by the `player_scope`
/// driver) and is immune to that seam, mirroring the hand clause's already-
/// correct `HandSize { ScopedPlayer }`. Only the LEFT operand is re-scoped: the
/// sacrifice `target` keeps `You` (its scope follows `ability.controller`, which
/// the driver rebinds per player) and the RIGHT `ControlledByEachPlayer` Min
/// operand keeps `You` (it builds its own per-player context and gates on
/// `obj.controller == p.id` — `ScopedPlayer` there would collapse to the
/// iterating player and zero the minimum).
fn balance_filter_scoped_player(filter: &TargetFilter) -> TargetFilter {
    match filter {
        TargetFilter::Typed(tf) => TargetFilter::Typed(TypedFilter {
            controller: Some(ControllerRef::ScopedPlayer),
            ..tf.clone()
        }),
        other => other.clone(),
    }
}

/// Arm B — Balance's first sentence: "each player chooses a number of
/// [type-phrase] they control equal to [min-quantity], then
/// sacrifices/discards the rest". The verb branch determines the clause type;
/// the `[type-phrase]` is consumed by the nom-typed `parse_type_phrase`.
fn parse_balance_arm_b(input: &str) -> OracleResult<'_, (EqualizeVerb, TargetFilter)> {
    let (input, _) = tag("each player chooses a number of ").parse(input)?;
    let (input, filter) = super::oracle_nom::target::parse_type_phrase(input)?;
    let (input, _) = tag(" they control equal to ").parse(input)?;
    // CR 107.1b: the min-quantity phrase MUST parse to the equalization shape
    // (`ControlledByEachPlayer { aggregate: Min, .. }` — "the number of [type]
    // controlled by the player who controls the fewest"). The parsed ref is
    // not retained because the verb branch substitutes the zone-correct
    // minimum directly, but its STRUCTURE is load-bearing: accepting any other
    // quantity here would mis-intercept superficially similar text (e.g.,
    // "equal to the number of cards in their hand") and emit a Balance chain
    // that mis-clamps disposal counts. If the inner ref doesn't match the
    // equalization shape, fail so the parser falls through to its normal path.
    let saved = input;
    let (input, parsed_qty) = nom_quantity::parse_quantity_ref.parse(input)?;
    if !matches!(
        parsed_qty,
        QuantityRef::ControlledByEachPlayer {
            aggregate: AggregateFunction::Min,
            ..
        }
    ) {
        return Err(nom::Err::Error(OracleError::new(
            saved,
            nom::error::ErrorKind::Verify,
        )));
    }
    let (input, _) = tag(", then ").parse(input)?;
    let (input, verb) = alt((
        value(EqualizeVerb::Sacrifice, tag("sacrifices")),
        value(EqualizeVerb::Discard, tag("discards")),
    ))
    .parse(input)?;
    let (input, _) = tag(" the rest").parse(input)?;
    Ok((input, (verb, filter)))
}

/// Arm C — Balance's "the same way" continuation: "players / each player
/// [verb]s [type-phrase] ... the same way". Subject is an `alt()`; the clause
/// list is 1-or-2 `(verb, filter)` pairs joined by " and ". The verb wraps
/// `opt(tag("s"))` to accept both the bare ("Players discard") and `-s`
/// ("Each player discards") inflections. The `alt()` over the verb makes the
/// Balance-vs-Restore-Balance clause-order reversal a non-issue.
fn parse_balance_arm_c(input: &str) -> OracleResult<'_, Vec<(EqualizeVerb, TargetFilter)>> {
    use nom::character::complete::space1;
    use nom::multi::separated_list1;

    let (input, _) = alt((tag("players "), tag("each player "))).parse(input)?;
    let (input, pairs) = separated_list1(
        tag(" and "),
        (
            terminated(
                alt((
                    value(EqualizeVerb::Discard, tag("discard")),
                    value(EqualizeVerb::Sacrifice, tag("sacrifice")),
                )),
                opt(tag("s")),
            ),
            preceded(space1, super::oracle_nom::target::parse_type_phrase),
        ),
    )
    .parse(input)?;
    let (input, _) = tag(" the same way").parse(input)?;
    Ok((input, pairs))
}

/// CR 107.1 + CR 608.2e: Whole-line interceptor for the Balance equalization
/// class (Balance, Restore Balance, Balancing Act).
///
/// Arm B parses the first sentence and Arm C parses the "the same way"
/// continuation. Each clause lowers to a `player_scope: All`
/// `Effect::Sacrifice` / `Effect::Discard` with a `QuantityExpr::Difference`
/// count; the clauses are chained via `sub_ability` as three independent steps
/// (CR 608.2e — each clause computes its own minimum at its own resolution
/// time, guaranteed by the §8 per-link clause-minimum snapshot).
pub(crate) fn try_parse_balance_equalization(
    text: &str,
    kind: AbilityKind,
) -> Option<AbilityDefinition> {
    let lower = text.to_lowercase();

    let parsed = nom_on_lower(text, &lower, |input| {
        let (input, first) = parse_balance_arm_b(input)?;
        let (input, _) = tag(". ").parse(input)?;
        let (input, rest) = parse_balance_arm_c(input)?;
        let (input, _) = opt(tag(".")).parse(input)?;
        let (input, _) = eof.parse(input)?;
        Ok((input, (first, rest)))
    });
    let ((first, rest), _) = parsed?;

    // Build the clause list: the Arm B clause followed by the Arm C clauses.
    let mut clauses: Vec<(EqualizeVerb, TargetFilter)> = Vec::with_capacity(1 + rest.len());
    clauses.push(first);
    clauses.extend(rest);

    // Lower each (verb, filter) into a `player_scope: All` link, chained via
    // `sub_ability` (CR 608.2e — three independent steps).
    let mut links: Vec<AbilityDefinition> = clauses
        .into_iter()
        .map(|(verb, filter)| {
            let filter = balance_filter_you_control(filter);
            let mut def = AbilityDefinition::new(kind, balance_clause_effect(verb, filter));
            def.player_scope = Some(PlayerFilter::All);
            def.sub_link = SubAbilityLink::SequentialSibling;
            def
        })
        .collect();

    // Fold the chain back-to-front so each link's `sub_ability` is the next.
    let mut chain = links.pop()?;
    while let Some(mut prev) = links.pop() {
        prev.sub_ability = Some(Box::new(chain));
        chain = prev;
    }
    Some(chain)
}

/// Parse "for each" quantity patterns on draw/life/damage/mill effects.
///
/// Handles patterns like:
/// - "draw a card for each opponent who lost life this turn"
/// - "draw a card for each creature you control"
/// - "gain 1 life for each creature you control"
/// - "mill a card for each [counter type] counter on ~"
fn try_parse_for_each_effect(text: &str, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let tp = TextPair::new(text, &lower);

    // Find "for each" in the text
    let for_each_idx = tp.find("for each ")?;
    let (base_tp, _) = tp.split_at(for_each_idx);
    let base_tp = base_tp.trim_end();
    let for_each_clause = &tp.lower[for_each_idx + "for each ".len()..];
    let (base_no_duration, base_duration) = strip_trailing_duration(base_tp.original);
    let quantity_ctx = for_each_quantity_context(base_no_duration, ctx);

    // Parse the "for each" clause into a QuantityExpr. Try the full clause
    // before stripping duration-like suffixes: "this turn" is part of
    // counter-history quantities, not an effect duration.
    let for_each_full = for_each_clause.trim_end_matches('.');
    let (for_each_no_duration, stripped_for_each_duration) =
        strip_trailing_duration(for_each_clause);
    let for_each_stripped = for_each_no_duration.trim_end_matches('.');
    let (quantity, for_each_duration, reference_clause) = if let Some(quantity) =
        parse_for_each_clause_expr_with_context(for_each_full, &quantity_ctx)
    {
        (quantity, None, for_each_full)
    } else {
        (
            parse_for_each_clause_expr_with_context(for_each_stripped, &quantity_ctx)?,
            stripped_for_each_duration,
            for_each_stripped,
        )
    };
    let reference_target = for_each_clause_target_controller_filter(reference_clause);

    // Strip trailing duration from the base text (e.g., "gets +2/+0 until end of turn"
    // → "gets +2/+0" with duration=UntilEndOfTurn). Duration often appears between
    // the base effect and the "for each" clause.
    let duration = base_duration.or(for_each_duration);
    let numeric_base_storage = subject::strip_subject_clause(base_no_duration);
    let numeric_base = numeric_base_storage.as_deref().unwrap_or(base_no_duration);
    let numeric_base_lower = numeric_base.to_lowercase();

    if let Some(effect) = parse_energy_gain_base(&numeric_base_lower, quantity.clone()) {
        return Some(ParsedEffectClause {
            effect,
            duration,
            sub_ability: None,
            distribute: None,
            multi_target: None,
            condition: None,
            optional: false,
            unless_pay: None,
        });
    }

    // Delegate to parse_numeric_imperative_ast — it already handles draw, gain/lose life,
    // pump, scry, surveil, mill. Replace fixed counts with the for-each quantity, then
    // thread subject through for effects that carry a target.
    if let Some(ast) = imperative::parse_numeric_imperative_ast(numeric_base, &numeric_base_lower) {
        let effect = imperative::lower_numeric_imperative_ast(ast.with_for_each_quantity(quantity));
        let effect = thread_for_each_subject(effect, base_no_duration, ctx);
        return Some(parsed_for_each_quantity_effect(
            effect,
            duration,
            reference_target,
        ));
    }

    let targeted_base_storage = subject::strip_subject_clause(base_no_duration);
    let targeted_base = targeted_base_storage.as_deref().unwrap_or(base_no_duration);
    let targeted_base_lower = targeted_base.to_lowercase();
    if let Some(ast) = imperative::parse_targeted_action_ast(
        targeted_base,
        &targeted_base_lower,
        &mut ParseContext::default(),
    ) {
        if matches!(
            ast,
            TargetedImperativeAst::Sacrifice { .. } | TargetedImperativeAst::Discard { .. }
        ) {
            let effect =
                imperative::lower_targeted_action_ast(ast.with_for_each_quantity(quantity.clone()));
            let effect = thread_for_each_subject(effect, base_no_duration, ctx);
            return Some(ParsedEffectClause {
                effect,
                duration,
                sub_ability: None,
                distribute: None,
                multi_target: None,
                condition: None,
                optional: false,
                unless_pay: None,
            });
        }
    }

    // CR 120.1: "[subject] deals N damage to [target] for each X" → DealDamage.
    // Delegates to try_parse_damage, which already handles amount extraction, target parsing,
    // and damage source variants. Replace the fixed amount with the for-each quantity.
    if let Some(effect) = try_parse_damage(base_tp.lower, base_tp.original, ctx) {
        let effect = match effect {
            Effect::DealDamage {
                amount,
                target,
                damage_source,
            } => Effect::DealDamage {
                amount: replace_fixed_quantity(amount, quantity.clone()),
                target,
                damage_source,
            },
            Effect::DamageEachPlayer {
                amount,
                player_filter,
            } => Effect::DamageEachPlayer {
                amount: replace_fixed_quantity(amount, quantity.clone()),
                player_filter,
            },
            Effect::DamageAll {
                amount,
                target,
                player_filter,
                damage_source: None,
            } => Effect::DamageAll {
                amount: replace_fixed_quantity(amount, quantity),
                target,
                player_filter,
                damage_source: None,
            },
            other => other,
        };
        return Some(parsed_clause(effect));
    }

    // CR 111.11: "create [token description] for each X" → Token with dynamic count.
    // Delegates to try_parse_token, which handles token description parsing (name, P/T,
    // types, colors, keywords). Replace the embedded count with the for-each quantity.
    if let Some(effect) = token::try_parse_token(base_tp.lower, base_tp.original, ctx) {
        let effect = match effect {
            Effect::Token {
                name,
                power,
                toughness,
                types,
                colors,
                keywords,
                tapped,
                owner,
                attach_to,
                enters_attacking,
                supertypes,
                static_abilities,
                enter_with_counters,
                count: _,
            } => Effect::Token {
                name,
                power,
                toughness,
                types,
                colors,
                keywords,
                tapped,
                owner,
                attach_to,
                enters_attacking,
                supertypes,
                static_abilities,
                enter_with_counters,
                // CR 109.4: a "their <zone>" possessive in the for-each clause
                // binds to the player creating the token. Stamp ScopedPlayer
                // so an "each player creates … for each … in their graveyard"
                // iteration counts each player's OWN zone.
                count: token::scope_token_for_each_to_iterating_player(quantity),
            },
            other => other,
        };
        return Some(parsed_clause(effect));
    }

    // "put a [counter type] counter on [target] for each X" → PutCounter with dynamic count.
    // Not a NumericImperativeAst — counter placement has its own structure.
    if let Ok((_, before)) = take_until::<_, _, OracleError<'_>>("counter on").parse(base_tp.lower)
    {
        // before = "put a +1/+1 " — strip "put a[n] " prefix then parse counter type.
        let ct_start = alt((
            value((), tag::<_, _, OracleError<'_>>("put a ")),
            value((), tag("put an ")),
            value((), tag("put ")),
        ))
        .parse(before)
        .map(|(rest, _)| rest)
        .unwrap_or(before)
        .trim();
        let (_, counter_type) = nom_primitives::parse_counter_type_typed
            .parse(ct_start)
            .ok()?;
        let counter_on_end = before.len() + "counter on ".len();
        let after_counter_on = base_tp.original[counter_on_end..].trim();
        // Strip clause separators (", then") that leak into the counter target text.
        let after_counter_on_lower = after_counter_on.to_lowercase();
        let counter_target_text = if let Ok((_, before_sep)) =
            take_until::<_, _, OracleError<'_>>(", then").parse(after_counter_on_lower.as_str())
        {
            &after_counter_on[..before_sep.len()]
        } else {
            after_counter_on
        };
        // CR 608.2c: "put a counter on that <type> for each X" — when the
        // counter target is an anaphoric back-reference (`that creature`,
        // `that permanent`, etc.), `parse_subject_application` signals it
        // with `inherits_parent: true` and returns the type filter as a
        // suggestion. The contract documented inside `parse_subject_application`
        // is that the call site must lower this to `TargetFilter::ParentTarget`
        // so the counter lands on the inherited parent target (or, in passive
        // contexts where there is no parent, on the post-replacement event
        // recipient via the caller's post-parse rewrite). Without this, the
        // typed `Creature` filter leaks through and the counter is placed on
        // an unrelated creature.
        let target = parse_subject_application(counter_target_text, &mut ParseContext::default())
            .map(|app| {
                if app.inherits_parent {
                    TargetFilter::ParentTarget
                } else {
                    app.affected
                }
            })
            .unwrap_or_else(|| {
                ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
                    context: "unrecognized counter target".into(),
                    text: after_counter_on.trim().into(),
                    line_index: 0,
                });
                TargetFilter::Any
            });
        return Some(parsed_clause(Effect::PutCounter {
            counter_type,
            count: quantity,
            target,
        }));
    }

    None
}

fn for_each_clause_target_controller_filter(for_each_clause: &str) -> Option<TargetFilter> {
    nom_primitives::scan_at_word_boundaries(for_each_clause, |input| {
        alt((
            value(
                TargetFilter::Typed(TypedFilter::default().controller(ControllerRef::Opponent)),
                tag("target opponent controls"),
            ),
            value(
                TargetFilter::Typed(TypedFilter::default()),
                tag("target player controls"),
            ),
        ))
        .parse(input)
    })
}

fn parsed_for_each_quantity_effect(
    mut effect: Effect,
    duration: Option<Duration>,
    reference_target: Option<TargetFilter>,
) -> ParsedEffectClause {
    if let Some(target) = reference_target {
        bind_search_library_for_each_antecedent(&mut effect, &target, "");
        if matches!(
            effect,
            Effect::Draw {
                target: TargetFilter::Controller,
                ..
            }
        ) {
            let mut sub_ability = AbilityDefinition::new(AbilityKind::Spell, effect);
            sub_ability.duration = duration;
            return ParsedEffectClause {
                effect: Effect::TargetOnly { target },
                duration: None,
                sub_ability: Some(Box::new(sub_ability)),
                distribute: None,
                multi_target: None,
                condition: None,
                optional: false,
                unless_pay: None,
            };
        }
    }

    ParsedEffectClause {
        effect,
        duration,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    }
}

fn bind_search_library_for_each_antecedent(
    effect: &mut Effect,
    target: &TargetFilter,
    text_lower: &str,
) {
    if let Effect::SearchLibrary { target_player, .. } = effect {
        if target_player
            .as_ref()
            .is_some_and(search_library_target_player_is_for_each_antecedent)
            || (target_player.is_none()
                && nom_primitives::scan_contains(text_lower, "search that player's "))
        {
            *target_player = Some(target.clone());
        }
    }
}

fn search_library_target_player_is_for_each_antecedent(target: &TargetFilter) -> bool {
    let TargetFilter::Typed(typed) = target else {
        return false;
    };
    typed.type_filters.is_empty()
        && typed.properties.is_empty()
        && typed.controller == Some(ControllerRef::TargetPlayer)
}

fn try_parse_gain_energy(tp: TextPair<'_>, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let (rest, _) = alt((tag::<_, _, OracleError<'_>>("you get "), tag("get ")))
        .parse(tp.lower)
        .ok()?;
    let rest = rest.trim_start();

    if let Ok((qty_text, _)) = (
        tag::<_, _, OracleError<'_>>("an amount of {e}"),
        multispace1,
        tag("equal to "),
    )
        .parse(rest)
    {
        let qty_text = qty_text.trim().trim_end_matches('.');
        let amount = crate::parser::oracle_quantity::parse_event_context_quantity(qty_text)
            .or_else(|| {
                crate::parser::oracle_quantity::parse_quantity_ref(qty_text)
                    .map(|qty| QuantityExpr::Ref { qty })
            })?;
        return Some(parsed_clause(Effect::GainEnergy { amount }));
    }

    let (rest, effect) =
        parse_energy_symbols_gain_with_rest(rest, QuantityExpr::Fixed { value: 1 })?;
    let mut clause = parsed_clause(effect);
    let rest = rest.trim();
    if rest.is_empty() || rest == "." {
        return Some(clause);
    }
    if let Some(continuation) = parse_energy_gain_continuation(rest) {
        clause.sub_ability = Some(Box::new({
            let ir = parse_effect_chain_ir(continuation, AbilityKind::Spell, ctx);
            lower_effect_chain_ir(&ir)
        }));
        return Some(clause);
    }
    None
}

fn parse_energy_gain_base(input: &str, multiplier: QuantityExpr) -> Option<Effect> {
    let (rest, _) = alt((tag::<_, _, OracleError<'_>>("you get "), tag("get ")))
        .parse(input)
        .ok()?;
    parse_energy_symbols_gain(rest, multiplier)
}

fn nonland_card_in_hand_filter(controller: Option<ControllerRef>) -> TargetFilter {
    let mut filter = TypedFilter::card()
        .with_type(TypeFilter::Non(Box::new(TypeFilter::Land)))
        .properties(vec![FilterProp::InZone { zone: Zone::Hand }]);
    filter.controller = controller;
    TargetFilter::Typed(filter)
}

fn try_parse_random_card_perpetual_gain_quoted_ability(
    tp: TextPair<'_>,
) -> Option<ParsedEffectClause> {
    let parsed = nom_on_lower(tp.original, tp.lower, |input| {
        alt((
            value(
                Some(ControllerRef::You),
                tag("a random nonland card in your hand perpetually gains "),
            ),
            value(
                None,
                tag("a random nonland card in that player's hand perpetually gains "),
            ),
        ))
        .parse(input)
    })?;
    let (controller, quoted_text) = parsed;
    let modifications =
        crate::parser::oracle_static::parse_quoted_ability_modifications(quoted_text);
    if modifications.is_empty() {
        return None;
    }

    Some(ParsedEffectClause {
        effect: Effect::GenericEffect {
            static_abilities: vec![StaticDefinition::continuous()
                .affected(nonland_card_in_hand_filter(controller))
                .affected_zone(Zone::Hand)
                .modifications(modifications)
                .description(tp.original.to_string())],
            duration: Some(Duration::Permanent),
            target: None,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn parse_energy_symbols_gain(input: &str, multiplier: QuantityExpr) -> Option<Effect> {
    let (rest, effect) = parse_energy_symbols_gain_with_rest(input, multiplier)?;
    let rest = rest.trim().trim_end_matches('.');
    rest.is_empty().then_some(effect)
}

fn parse_energy_symbols_gain_with_rest(
    input: &str,
    multiplier: QuantityExpr,
) -> Option<(&str, Effect)> {
    let input = input.trim_start();

    if let Ok((after_that_many, _)) = (
        tag::<_, _, OracleError<'_>>("that many"),
        multispace1,
        tag("{e}"),
    )
        .parse(input)
    {
        return Some((
            after_that_many,
            Effect::GainEnergy {
                amount: QuantityExpr::Ref {
                    qty: QuantityRef::EventContextAmount,
                },
            },
        ));
    }

    if let Ok((after_x, _)) =
        (tag::<_, _, OracleError<'_>>("x"), multispace1, tag("{e}")).parse(input)
    {
        return Some((
            after_x,
            Effect::GainEnergy {
                amount: QuantityExpr::Ref {
                    qty: QuantityRef::Variable {
                        name: "X".to_string(),
                    },
                },
            },
        ));
    }

    if let Ok((after_number, value)) = nom_primitives::parse_number.parse(input) {
        if let Ok((after_energy, _)) =
            (multispace1, tag::<_, _, OracleError<'_>>("{e}")).parse(after_number)
        {
            return Some((
                after_energy,
                Effect::GainEnergy {
                    amount: QuantityExpr::Fixed {
                        value: value as i32,
                    },
                },
            ));
        }
    }

    let (after_symbols, symbols) = many1(tag::<_, _, OracleError<'_>>("{e}"))
        .parse(input)
        .ok()?;
    let symbol_count = symbols.len() as i32;
    let amount = match (symbol_count, multiplier) {
        (count, QuantityExpr::Fixed { value: 1 }) => QuantityExpr::Fixed { value: count },
        (1, multiplier) => multiplier,
        (count, multiplier) => QuantityExpr::Multiply {
            factor: count,
            inner: Box::new(multiplier),
        },
    };
    Some((after_symbols, Effect::GainEnergy { amount }))
}

fn parse_energy_gain_continuation(rest: &str) -> Option<&str> {
    let rest = rest.trim();
    let (continuation, _) = alt((
        tag::<_, _, OracleError<'_>>(", then "),
        tag("then "),
        tag(", and "),
        tag("and "),
    ))
    .parse(rest)
    .ok()?;
    let continuation = continuation.trim();
    (!continuation.is_empty()).then_some(continuation)
}

/// Thread subject through for-each effects that carry a `target` field.
/// Locates the predicate verb, extracts subject text before it, and replaces
/// default targets (Any/Controller) with the parsed subject filter.
fn for_each_subject_application(
    original: &str,
    ctx: &mut ParseContext,
) -> Option<SubjectApplication> {
    let lower = original.to_lowercase();
    // Predicate verbs that the for-each base parsers recognize — find the earliest one.
    // Note: uses str::find (not nom) because this is positional splitting on already-dispatched
    // text (base_tp from try_parse_for_each_effect), not parsing dispatch on raw Oracle text.
    // The input is short and constrained, so substring false positives are not a concern.
    // Find the predicate verb. Must check for space-before-verb boundary to avoid
    // substring matches inside other words (e.g., "target" contains "get").
    // The first verb may appear at position 0 (no preceding space) for bare imperatives.
    let verb_pos = [
        " gets ",
        " get ",
        " gains ",
        " gain ",
        " loses ",
        " lose ",
        " draws ",
        " draw ",
        " mills ",
        " mill ",
        " discards ",
        " discard ",
        " scries ",
        " scry ",
        " surveils ",
        " surveil ",
    ]
    .iter()
    .filter_map(|verb| lower.find(verb).map(|pos| pos + 1)) // +1 to skip the leading space
    .min();

    let subject_text = match verb_pos {
        Some(pos) if pos > 0 => original[..pos].trim(),
        _ => return None,
    };
    if subject_text.is_empty() {
        return None;
    }

    parse_subject_application(subject_text, ctx)
}

fn for_each_quantity_context(original: &str, ctx: &ParseContext) -> ParseContext {
    let mut quantity_ctx = ctx.clone();
    let mut subject_ctx = ctx.clone();
    if quantity_ctx.third_person_player_controller_ref().is_none()
        && for_each_subject_application(original, &mut subject_ctx)
            .is_some_and(|app| app.target.is_some() && is_player_filter(&app.affected))
    {
        quantity_ctx.relative_player_scope = Some(ControllerRef::TargetPlayer);
    }
    quantity_ctx
}

fn is_player_filter(filter: &TargetFilter) -> bool {
    matches!(filter, TargetFilter::Player)
        || matches!(
            filter,
            TargetFilter::Typed(TypedFilter {
                type_filters,
                controller: Some(_),
                ..
            }) if type_filters.is_empty()
        )
}

fn thread_for_each_subject(effect: Effect, original: &str, ctx: &mut ParseContext) -> Effect {
    let application = match for_each_subject_application(original, ctx) {
        Some(application) => application,
        None => return effect,
    };
    let target = application.affected;
    let is_targeted = application.target.is_some();
    let pump_target = if application.inherits_parent {
        TargetFilter::ParentTarget
    } else {
        target.clone()
    };

    // Only replace default/placeholder targets — leave already-resolved targets alone.
    match effect {
        // CR 609 + CR 611.2: "All creatures get -1/-1 until end of turn for each Swamp
        // you control" (Mutilate). When the subject filter identifies a class of
        // permanents (not a single targeted object or single-object ref), lower to
        // `Effect::PumpAll` so the continuous effect applies to every matching
        // permanent — not a single target. Mirrors `subject::build_pump_effect`.
        Effect::Pump {
            power,
            toughness,
            target: TargetFilter::Any,
        } => {
            if application.inherits_parent || is_targeted || subject::is_single_object_ref(&target)
            {
                Effect::Pump {
                    power,
                    toughness,
                    target: pump_target,
                }
            } else {
                Effect::PumpAll {
                    power,
                    toughness,
                    target,
                }
            }
        }
        Effect::Mill {
            count,
            target: TargetFilter::Controller,
            destination,
        } => Effect::Mill {
            count,
            target,
            destination,
        },
        Effect::Draw {
            count,
            target: TargetFilter::Controller,
        } => Effect::Draw { count, target },
        Effect::Discard {
            count,
            target: TargetFilter::Controller,
            selection,
            unless_filter,
            filter,
        } => Effect::Discard {
            count,
            target,
            selection,
            unless_filter,
            filter,
        },
        Effect::GainLife {
            amount,
            player: TargetFilter::Controller,
        } if is_targeted && target_filter_can_target_player(&target) => Effect::GainLife {
            amount,
            player: target,
        },
        other => other,
    }
}

#[tracing::instrument(level = "trace")]
fn parse_clause_ast(text: &str, ctx: &mut ParseContext) -> ClauseAst {
    let text = text.trim();

    // Mirror the CubeArtisan grammar's high-level sentence shapes:
    // 1) conditionals ("if X, Y"), 2) subject + verb phrase, 3) bare imperative.
    if let Some((condition_text, remainder)) = split_leading_conditional(text) {
        // CR 608.2c: Parse the leading conditional guard through the nom condition pipeline.
        // Strip "if " prefix before passing to the condition parser.
        let condition_lower = condition_text.to_lowercase();
        let cond_body = nom_on_lower(&condition_text, &condition_lower, |i| {
            value(
                (),
                alt((tag("if "), tag("during any turn "), tag("during a turn "))),
            )
            .parse(i)
        })
        .map(|((), rest)| rest)
        .unwrap_or(&condition_text)
        .trim();
        let condition = try_nom_condition_as_ability_condition(cond_body, ctx);
        return ClauseAst::Conditional {
            condition,
            clause: Box::new(parse_clause_ast(&remainder, ctx)),
        };
    }

    // CR 701.24b: "each player who searched their library this way shuffles" —
    // redundant shuffle after a search effect (search already includes a shuffle).
    // Parse as a bare shuffle to avoid Unimplemented.
    {
        let lower = text.to_lowercase();
        if nom_primitives::scan_contains(&lower, "who searched") && lower.ends_with("shuffles") {
            return ClauseAst::Imperative {
                text: "shuffle".to_string(),
            };
        }
    }

    // CR 114.1: Emblem text is quoted rules text, not part of the enclosing
    // sentence grammar. Route emblem creation to the imperative parser before
    // subject-predicate classification so quoted trigger text like "Whenever an
    // opponent is dealt ... they lose ..." cannot be mistaken for the outer
    // effect.
    {
        let lower = text.to_lowercase();
        if try_parse_emblem_creation(&lower, text).is_some() {
            return ClauseAst::Imperative {
                text: text.to_string(),
            };
        }
    }

    if let Some(ast) = try_parse_subject_predicate_ast(text, ctx) {
        return ast;
    }

    ClauseAst::Imperative {
        text: text.to_string(),
    }
}

/// Peel an optional cardinality prefix from the noun phrase that precedes a
/// positional placement terminator ("on top of" / "on the bottom of" / "into").
///
/// Returns `Some((Some(count), remainder))` when an explicit cardinality is
/// recognized (e.g. "two cards from your hand" → `Fixed(2)` + "cards from your
/// hand"), or `Some((None, input))` when the noun phrase has no leading
/// quantity (the patcher leaves the existing `count: Fixed(1)` untouched).
///
/// Recognized prefixes for positional library placement:
///   - `"x "` (with X-cost)     → `QuantityExpr::Ref { Variable("X") }`
///   - numeric word/digit + " " → `QuantityExpr::Fixed { value: N }`
///
/// Cards like "put it on top" / "put that card on top" / "put target X on top"
/// have no leading numeral and fall through to the `None` arm — the existing
/// `count: Fixed(1)` is preserved. "Any number of …" forms are out of scope
/// here; they involve a player-choice cardinality that is paired with a
/// matching `MultiTargetSpec` and currently route through other effect
/// paths (Brainstorm-class effects are handled at the trigger / sub-clause
/// level, not by this patcher).
fn peel_put_at_library_count(input: &str) -> Option<(Option<QuantityExpr>, &str)> {
    // "x " — variable quantity bound to the spell's chosen X.
    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("x ").parse(input) {
        return Some((
            Some(QuantityExpr::Ref {
                qty: QuantityRef::Variable {
                    name: "X".to_string(),
                },
            }),
            rest,
        ));
    }
    // Numeric ("two ", "three ", "1 ", …). `parse_number` accepts both English
    // number words and digits per the oracle-parser SKILL.
    if let Ok((after_num, n)) = nom_primitives::parse_number.parse(input) {
        if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>(" ").parse(after_num) {
            return Some((Some(QuantityExpr::Fixed { value: n as i32 }), rest));
        }
    }
    Some((None, input))
}

fn parse_exiled_cards_not_cast_cleanup(input: &str) -> Option<()> {
    let (input, _) = tag::<_, _, OracleError<'_>>("put the exiled cards")
        .parse(input)
        .ok()?;
    let (input, _) = opt(tag::<_, _, OracleError<'_>>(" that weren't cast this way"))
        .parse(input)
        .ok()?;
    let (input, _) = tag::<_, _, OracleError<'_>>(" on the bottom of ")
        .parse(input)
        .ok()?;
    let (input, _) = alt((
        tag::<_, _, OracleError<'_>>("that library"),
        tag("their library"),
        tag("your library"),
        tag("its owner's library"),
    ))
    .parse(input)
    .ok()?;
    let (input, _) = opt(tag::<_, _, OracleError<'_>>(" in a random order"))
        .parse(input)
        .ok()?;
    let (input, _) = opt(tag::<_, _, OracleError<'_>>(".")).parse(input).ok()?;
    input.is_empty().then_some(())
}

fn lower_clause_ast(ast: ClauseAst, ctx: &mut ParseContext) -> ParsedEffectClause {
    match ast {
        ClauseAst::Imperative { text } => {
            let mut clause = lower_imperative_clause(&text, ctx);
            // "put [N] [type] on top/bottom of library" — the imperative parser
            // returns PutAtLibraryPosition { target: Any, count: Fixed(1) }
            // because it dispatches on the positional suffix without extracting
            // the noun phrase. This patch re-inspects the imperative text and
            // assigns both the target filter and the cardinality. Covers:
            //   - "put target X on top of Y's library"           (count = 1)
            //   - "put target X on the bottom of Y's library"    (count = 1)
            //   - "put target X into Y's library Nth from top"   (count = 1)
            //   - "put two cards from your hand on top of your library in any order"
            //     (Cavalier of Gales / Brainstorm class — count = N, filter = Card+InZone:Hand)
            if let Effect::PutAtLibraryPosition {
                ref mut target,
                ref mut count,
                ..
            } = clause.effect
            {
                if parse_exiled_cards_not_cast_cleanup(&text.to_lowercase()).is_some() {
                    *target = TargetFilter::ExiledBySource;
                    *count = QuantityExpr::Fixed { value: 0 };
                    return clause;
                }
                let lower_put = text.to_lowercase();
                if matches!(*target, TargetFilter::Any | TargetFilter::ParentTarget)
                    && (nom_primitives::scan_contains(&lower_put, "put them on top")
                        || nom_primitives::scan_contains(&lower_put, "put the exiled cards on top")
                        || nom_primitives::scan_contains(&lower_put, "cards exiled this way"))
                {
                    *target = TargetFilter::ExiledBySource;
                    if matches!(*count, QuantityExpr::Fixed { value: 1 }) {
                        *count = QuantityExpr::Ref {
                            qty: QuantityRef::CardsExiledBySource,
                        };
                    }
                }
                let extracted = (|| -> Option<(Option<TargetFilter>, Option<QuantityExpr>)> {
                    let lower = text.to_lowercase();
                    let (after_put, _) = tag::<_, _, OracleError<'_>>("put ")
                        .parse(lower.as_str())
                        .ok()?;
                    // Isolate the noun phrase before the first positional terminator.
                    let before = [" on top of", " on the bottom of", " into "]
                        .iter()
                        .find_map(|term| {
                            take_until::<_, _, OracleError<'_>>(*term)
                                .parse(after_put)
                                .ok()
                                .map(|(_, before)| before)
                        })?;
                    // Peel a leading cardinality, if present. Recognized forms:
                    //   - "two cards ..."          → Fixed(2)
                    //   - "x cards ..."            → Variable("X")
                    //   - "any number of cards"   → AnyNumberOf
                    // The remainder (e.g. "cards from your hand") is then handed to
                    // `parse_target` for filter extraction. If no quantity prefix
                    // matches, the noun phrase is fed to `parse_target` unchanged
                    // (covers "target X" / "it" / "that card" — count stays 1).
                    let (count_expr, after_count) =
                        peel_put_at_library_count(before).unwrap_or((None, before));
                    let (filter, _) = parse_target(after_count);
                    let new_target = if matches!(filter, TargetFilter::Any) {
                        None
                    } else {
                        Some(filter)
                    };
                    Some((new_target, count_expr))
                })();
                if let Some((maybe_filter, maybe_count)) = extracted {
                    if *target == TargetFilter::Any {
                        if let Some(filter) = maybe_filter {
                            *target = filter;
                        }
                    }
                    if let Some(c) = maybe_count {
                        *count = c;
                    }
                }
            }
            clause
        }
        ClauseAst::SubjectPredicate { subject, predicate } => {
            lower_subject_predicate_ast(*subject, *predicate, ctx)
        }
        ClauseAst::Conditional { condition, clause } => {
            // CR 608.2c: Thread the leading conditional into the lowered clause's condition field.
            let mut result = lower_clause_ast(*clause, ctx);
            if let Some(cond) = condition {
                result.condition = Some(cond);
            }
            result
        }
    }
}

#[tracing::instrument(level = "debug")]
/// CR 701.34a (operation) + CR 122.1: "For each kind of counter on target
/// permanent or player, give that permanent or player another counter of that
/// kind." — the proliferate counter-add forced on a single chosen target
/// (Skyship Plunderer, Maulfist Revolutionary). The card
/// spells out the operation rather than using the proliferate keyword, and it
/// always targets exactly one permanent-or-player, so it lowers to the targeted
/// `Effect::ProliferateTarget` (not `Effect::Proliferate`, which prompts a
/// chooser and fires "whenever you proliferate" triggers).
fn try_parse_proliferate_target(text: &str) -> Option<Effect> {
    type E<'a> = OracleError<'a>;
    let lower = text.to_lowercase();

    // Consume the leading "for each kind of counter on " phrase, then read the
    // target with the shared target parser ("target permanent or player").
    let (_, after_on) = nom_on_lower(text, &lower, |i| {
        value((), tag::<_, _, E>("for each kind of counter on ")).parse(i)
    })?;
    let (target, remainder) = parse_target(after_on);

    // The tail re-states the target as an anaphor and adds one counter of each
    // kind it already has: "give that permanent or player another counter of
    // that kind".
    let rem_lower = remainder
        .trim_start_matches([',', ' '])
        .to_lowercase()
        .trim_end_matches(['.', ' '])
        .to_string();
    let (rem, _) = tag::<_, _, E>("give ").parse(rem_lower.as_str()).ok()?;
    let (rem, _) = alt((
        tag::<_, _, E>("that permanent or player"),
        tag("that permanent"),
        tag("that player"),
        tag("them"),
        tag("it"),
    ))
    .parse(rem)
    .ok()?;
    let (rem, _) = tag::<_, _, E>(" another counter of that kind")
        .parse(rem)
        .ok()?;
    if !rem.is_empty() {
        return None;
    }

    Some(Effect::ProliferateTarget { target })
}

fn lower_imperative_clause(text: &str, ctx: &mut ParseContext) -> ParsedEffectClause {
    if let Some(effect) = try_parse_drawn_this_turn_choice(text) {
        return parsed_clause(effect);
    }

    if let Some(clause) = try_parse_return_opponent_choice_from_graveyard(text) {
        return clause;
    }

    // CR 106.1 + CR 109.1: "For each color among [X], add one mana of that color"
    // (Faeburrow Elder). Must run before the generic for-each-prefix strip path,
    // because "that color" anaphors a per-iteration color rather than the
    // source's `ChosenAttribute::Color`. Emits a single mana ability producing
    // one mana per distinct color among matching permanents.
    if let Some(effect) = super::oracle_effect::mana::try_parse_for_each_color_mana_public(text) {
        return parsed_clause(effect);
    }

    // "Its controller gains life equal to its power/toughness" — subject must be preserved
    // because the life recipient is not the caster but the targeted permanent's controller.
    if let Some(clause) = try_parse_targeted_controller_gain_life(text) {
        return clause;
    }

    // CR 121.1 + CR 615.5: "{verb} cards equal to {quantity}" inside a
    // subject-aware predicate (e.g. "the source's controller draws cards equal
    // to the damage prevented this way" — Swans of Bryn Argoll). Mirrors the
    // bare-imperative arm at `parse_effect_clause`: must run BEFORE the
    // simpler "draw cards" matchers to avoid being dropped to a default
    // count of 1.
    {
        let lower = text.to_lowercase();
        let tp = TextPair::new(text, lower.as_str());
        if let Some(clause) = try_parse_equal_to_quantity_effect(tp) {
            return clause;
        }
    }

    // Compound shuffle subjects: "shuffle ~ and target creature ... into their owners' libraries"
    // Must come before try_split_targeted_compound because "shuffle" is the verb, not the subject.
    if let Some(clause) = try_parse_compound_shuffle(text) {
        return clause;
    }

    // Compound targeted actions: "tap target creature and put a stun counter on it"
    // Split on " and " when the primary clause is a targeted verb.
    if let Some(clause) = try_parse_tap_goad_compound(text, ctx) {
        return clause;
    }
    if let Some(clause) = try_parse_multi_target_counter_chain(text, ctx) {
        return clause;
    }
    if let Some(clause) = try_split_targeted_compound(text, ctx) {
        return clause;
    }

    // CR 608.2c: Compound damage actions: "~ deals 3 damage to any target and you gain 3 life"
    if let Some(clause) = try_split_damage_compound(text, ctx) {
        return clause;
    }

    // CR 609.4b: "spend mana as though it were mana of any color to cast ..." /
    // "mana of any type can be spent to cast ..." — grants any-color mana permission
    // for a cast-from-exile card. Produce a GenericEffect with SpendManaAsAnyColor static.
    // Variants: "spend colorless mana as though..." / "mana of any color to cast..."
    {
        let lower = text.to_lowercase();
        if nom_primitives::scan_contains(&lower, "as though it were mana of any color")
            || nom_primitives::scan_contains(&lower, "mana of any type can be spent to cast")
        {
            return parsed_clause(Effect::GenericEffect {
                static_abilities: vec![StaticDefinition::new(StaticMode::SpendManaAsAnyColor)
                    .description(text.to_string())],
                duration: None,
                target: Some(TargetFilter::Controller),
            });
        }
    }

    let (stripped, duration) = strip_trailing_duration(text);
    let mut clause = parse_imperative_effect(stripped, ctx);
    if clause.duration.is_none() {
        clause.duration = duration;
    }
    // CR 115.1d: Post-parse fixup for PutCounter "up to N" multi_target.
    // The multi_target is lost in the AST→Effect lowering chain, so we re-extract it
    // from the original text when the effect is PutCounter with a targeted filter.
    if matches!(clause.effect, Effect::PutCounter { .. }) && clause.multi_target.is_none() {
        clause.multi_target = extract_put_counter_multi_target(text);
    }
    // CR 601.2c: Post-parse fixup for exact-count multi-target text. The
    // imperative parser lowers "destroy X target ..." to the target filter but
    // the target count lives outside that filter, so recover it from the full
    // source sentence here.
    if clause.multi_target.is_none()
        && triggers::extract_target_filter_from_effect(&clause.effect).is_some()
    {
        clause.multi_target = extract_exact_target_multi_target(text)
            .or_else(|| extract_bounded_target_multi_target(text));
    }
    if matches!(clause.effect, Effect::DealDamage { .. }) && clause.multi_target.is_none() {
        clause.multi_target = extract_deal_damage_multi_target(text);
    }
    // CR 115.1d: Post-parse fixup for SwitchPT prepositional form. The
    // imperative parser strips "any number of" / "each of" to keep `parse_target`
    // bare, so the MultiTargetSpec is rebuilt from the original text here
    // (parallel to the DealDamage / Double counter fixups above).
    if matches!(clause.effect, Effect::SwitchPT { .. }) && clause.multi_target.is_none() {
        clause.multi_target = extract_switch_pt_multi_target(text);
    }
    if matches!(
        clause.effect,
        Effect::Double {
            target_kind: DoubleTarget::Counters { .. },
            ..
        }
    ) && clause.multi_target.is_none()
    {
        clause.multi_target = extract_double_counter_multi_target(text);
    }
    clause
}

fn try_parse_return_opponent_choice_from_graveyard(text: &str) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let (_, filter_text) =
        parse_return_opponent_choice_from_graveyard_filter(lower.as_str()).ok()?;
    let (target, _) = parse_target(filter_text);
    if matches!(target, TargetFilter::Any) {
        return None;
    }
    // CR 400.7: The chosen card changes zones from its owner's graveyard to hand.
    // CR 608.2d: "of an opponent's choice" is a resolution-time card choice.
    let filter = add_inferred_origin_constraints_to_target(target, Some(Zone::Graveyard), &lower);
    let mut clause = parsed_clause(Effect::ChooseFromZone {
        count: 1,
        zone: Zone::Graveyard,
        additional_zones: Vec::new(),
        zone_owner: ZoneOwner::Controller,
        filter: Some(filter),
        chooser: Chooser::Opponent,
        up_to: false,
        constraint: None,
    });
    clause.sub_ability = Some(Box::new(AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::ChangeZone {
            origin: None,
            destination: Zone::Hand,
            target: TargetFilter::Any,
            owner_library: false,
            enter_transformed: false,
            enters_under: None,
            enter_tapped: crate::types::zones::EtbTapState::Unspecified,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        },
    )));
    Some(clause)
}

fn parse_return_opponent_choice_from_graveyard_filter(input: &str) -> OracleResult<'_, &str> {
    all_consuming(preceded(
        tag("return "),
        terminated(
            take_until(" of an opponent's choice"),
            tag(" of an opponent's choice from your graveyard to your hand"),
        ),
    ))
    .parse(input)
}

fn try_parse_drawn_this_turn_choice(text: &str) -> Option<Effect> {
    let lower = text.to_lowercase();
    let count = nom_on_lower(text, &lower, |input| {
        let (input, _) = tag("choose ").parse(input)?;
        let (input, count) = nom_primitives::parse_number(input)?;
        let (input, _) = tag(" card").parse(input)?;
        let (input, _) = opt(tag("s")).parse(input)?;
        let (input, _) = tag(" in your hand drawn this turn").parse(input)?;
        let (input, _) = eof.parse(input)?;
        Ok((input, count))
    })
    .map(|(count, _)| count)?;
    Some(Effect::ChooseDrawnThisTurnPayOrTopdeck {
        count: QuantityExpr::Fixed {
            value: count as i32,
        },
        life_payment: QuantityExpr::Fixed { value: 4 },
        player: TargetFilter::Controller,
    })
}

fn try_parse_drawn_this_turn_pay_or_topdeck_followup(text: &str) -> Option<QuantityExpr> {
    let lower = text.to_lowercase();
    nom_on_lower(text, &lower, |input| {
        let (input, _) = tag("for each of those cards, pay ").parse(input)?;
        let (input, life_payment) = nom_primitives::parse_number(input)?;
        let (input, _) = tag(" life or put the card on top of your library").parse(input)?;
        let (input, _) = eof.parse(input)?;
        Ok((input, life_payment))
    })
    .map(|(life_payment, _)| QuantityExpr::Fixed {
        value: life_payment as i32,
    })
}

/// Parse a verb prefix and its target, returning the AST and `parse_target`'s unconsumed
/// remainder. Used by `try_split_targeted_compound` to determine compound boundaries
/// semantically — `parse_target` correctly consumes compound filter phrases like
/// "you own and control", so its remainder reveals whether " and " is a true compound
/// connector or part of the target filter.
///
/// CR 608.2c: The instructions in a spell or ability are followed in order; this helper
/// identifies the boundary between the first instruction and any subsequent compound action.
///
/// NOTE: Shares verb prefixes with `parse_targeted_action_ast` in `imperative.rs`.
/// When adding a new targeted verb here, check if it also needs to be added there.
fn try_parse_verb_and_target<'a>(
    text: &'a str,
    lower: &str,
    ctx: &mut ParseContext,
) -> Option<(TargetedImperativeAst, &'a str)> {
    // CR 701.26a/b: Tap/untap all — mass variants must be checked before single-target
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("tap all "), tag("tap each ")))).parse(i)
    }) {
        let (target, rem) = parse_target_with_ctx(rest, ctx);
        return Some((TargetedImperativeAst::TapAll { target }, rem));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("untap all "), tag("untap each ")))).parse(i)
    }) {
        let (target, rem) = parse_target_with_ctx(rest, ctx);
        return Some((TargetedImperativeAst::UntapAll { target }, rem));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("goad all "), tag("goad each ")))).parse(i)
    }) {
        let (target, rem) = parse_target_with_ctx(rest, ctx);
        return Some((TargetedImperativeAst::GoadAll { target }, rem));
    }
    // Simple targeted verbs: parse_target on text after the verb prefix
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("tap ")).parse(i)) {
        let (target_text, _) = strip_optional_target_prefix(rest);
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        return Some((TargetedImperativeAst::Tap { target }, rem));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("untap ")).parse(i)) {
        let (target_text, _) = strip_optional_target_prefix(rest);
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        return Some((TargetedImperativeAst::Untap { target }, rem));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("goad ")).parse(i)) {
        let (target_text, _) = strip_optional_target_prefix(rest);
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        return Some((TargetedImperativeAst::Goad { target }, rem));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("sacrifice ")).parse(i)) {
        if let Some((count, target, rem)) = imperative::parse_all_sacrifice(rest, ctx) {
            return Some((
                TargetedImperativeAst::Sacrifice {
                    target,
                    count,
                    min_count: 0,
                },
                rem,
            ));
        }
        // CR 107.1c + CR 701.21a: "sacrifice one or more / any number of
        // <filter>" — delegate to the single variable-count-sacrifice
        // authority so the dynamic `UpTo(ObjectCount)` ceiling and the
        // matched `min_count` (1 vs 0) are produced consistently with the
        // single-imperative path in `parse_targeted_action_ast`.
        if let Some((count, target, min_count)) = imperative::parse_one_or_more_sacrifice(rest, ctx)
        {
            return Some((
                TargetedImperativeAst::Sacrifice {
                    target,
                    count,
                    min_count,
                },
                "",
            ));
        }
        let (count, after_count) = super::oracle_util::parse_count_expr(rest).unwrap_or((
            crate::types::ability::QuantityExpr::Fixed { value: 1 },
            rest,
        ));
        let (target_text, _) = strip_optional_target_prefix(after_count.trim_start());
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        return Some((
            TargetedImperativeAst::Sacrifice {
                target,
                count,
                min_count: 0,
            },
            rem,
        ));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("fight ")).parse(i)) {
        let (target_text, _) = strip_optional_target_prefix(rest);
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        return Some((TargetedImperativeAst::Fight { target }, rem));
    }
    if let Some((_, rest)) =
        nom_on_lower(text, lower, |i| value((), tag("gain control of ")).parse(i))
    {
        // CR 613.1b: untargeted mass form "gain control of all/each <filter>"
        // (Hellkite Tyrant) lowers to `Effect::GainControlAll`.
        let rest_lower = rest.to_ascii_lowercase();
        let all = alt((tag::<_, _, OracleError<'_>>("all "), tag("each ")))
            .parse(rest_lower.as_str())
            .is_ok();
        let (target_text, _) = strip_optional_target_prefix(rest);
        let (target, rem) = parse_target_with_ctx(target_text, ctx);
        let rem_lower = rem.to_ascii_lowercase();
        if tag::<_, _, OracleError<'_>>(" during that player's next turn")
            .parse(rem_lower.as_str())
            .is_ok()
        {
            let rem = &rem[" during that player's next turn".len()..];
            let rem_lower = rem.to_ascii_lowercase();
            let (rem, grant_extra_turn_after) = if let Ok((rest, _)) = alt((
                tag::<_, _, OracleError<'_>>(". after that turn, that player takes an extra turn"),
                tag(" after that turn, that player takes an extra turn"),
                tag("after that turn, that player takes an extra turn"),
            ))
            .parse(rem_lower.as_str())
            {
                (&rem[rem.len() - rest.len()..], true)
            } else {
                (rem, false)
            };
            return Some((
                TargetedImperativeAst::ControlNextTurn {
                    target,
                    grant_extra_turn_after,
                },
                rem,
            ));
        }
        return Some((TargetedImperativeAst::GainControl { target, all }, rem));
    }
    // Earthbend: "earthbend [N] [target <type>]"
    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("earthbend ").parse(lower) {
        let (target, power, toughness) = imperative::parse_earthbend_params(text, rest);
        return Some((
            TargetedImperativeAst::Earthbend {
                target,
                power,
                toughness,
            },
            "", // remainder is consumed by parse_earthbend_params
        ));
    }
    // Airbend: "airbend target <type> <mana_cost>" → GrantCastingPermission(ExileWithAltCost)
    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("airbend ").parse(lower) {
        let original_rest = &text[text.len() - rest.len()..];
        let (target_text, _) = strip_optional_target_prefix(original_rest);
        let (target, after_target) = parse_target_with_ctx(target_text, ctx);
        let (cost, rem) = parse_mana_symbols(after_target.trim_start()).unwrap_or((
            crate::types::mana::ManaCost::Cost {
                generic: 2,
                shards: vec![],
            },
            after_target,
        ));
        return Some((TargetedImperativeAst::Airbend { target, cost }, rem));
    }

    // Destroy: check "all"/"each" prefix for mass destruction
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("destroy all "), tag("destroy each ")))).parse(i)
    }) {
        let (target, rem) = parse_target_with_ctx(rest, ctx);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Destroy {
                target,
                all: true,
            })),
            rem,
        ));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("destroy ")).parse(i)) {
        let (target, rem) = parse_target_with_ctx(rest, ctx);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Destroy {
                target,
                all: false,
            })),
            rem,
        ));
    }

    // Exile: infer origin zone from the full post-verb text (NOT the remainder,
    // since parse_zone_suffix inside parse_type_phrase consumes zone phrases).
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("exile all "), tag("exile each ")))).parse(i)
    }) {
        let rest_lower = &lower[lower.len() - rest.len()..];
        let (parsed_target, rem) = parse_target_with_ctx(rest, ctx);
        // CR 701.5a: "exile all spells" must constrain to the stack.
        let target = if scan_contains_phrase(rest_lower, "spell") {
            constrain_filter_to_stack(parsed_target)
        } else {
            parsed_target
        };
        let origin = infer_origin_zone(rest_lower);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Exile {
                origin,
                target,
                all: true,
                enter_with_counters: vec![],
            })),
            rem,
        ));
    }
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("exile ")).parse(i)) {
        let rest_lower = &lower[lower.len() - rest.len()..];
        let (parsed_target, rem) = parse_target_with_ctx(rest, ctx);
        // CR 701.5a: "exile target spell" must constrain targeting to the stack,
        // mirroring the counter-spell parser at line 1036-1037.
        let target = if scan_contains_phrase(rest_lower, "spell") {
            constrain_filter_to_stack(parsed_target)
        } else {
            parsed_target
        };
        let origin = infer_origin_zone(rest_lower);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Exile {
                origin,
                target,
                all: false,
                enter_with_counters: vec![],
            })),
            rem,
        ));
    }

    // CR 701.6 + CR 405.1: "Counter all/each [filter] spells/abilities" mass-
    // counter precheck — must run before the bare `tag("counter ")` arm so a
    // compound-clause head like "Counter all spells your opponents control
    // and ..." promotes to `Effect::CounterAll` instead of falling through to
    // single-target. Mirrors the imperative.rs `parse_counter_ast` precheck.
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| {
        value((), alt((tag("counter all "), tag("counter each ")))).parse(i)
    }) {
        let rest_lower = &lower[lower.len() - rest.len()..];
        let (parsed_target, rem) = parse_target_with_ctx(rest, ctx);
        // CR 113.3: Bare "abilities" (no intervening type phrase) ⇒ stack-
        // ability filter. Mass mode is loose enough to accept this form
        // because the mass keyword has already disambiguated the verb sense.
        // Bare "abilities" head: nom tag-match (skipping leading whitespace)
        // so the dispatch is a combinator, not a string starts_with.
        fn abilities_head(i: &str) -> nom::IResult<&str, &str, OracleError<'_>> {
            preceded(nom::character::complete::multispace0, tag("abilities")).parse(i)
        }
        let target = if scan_contains_phrase(rest_lower, "activated or triggered ability")
            || abilities_head(rest_lower).is_ok()
        {
            imperative::stack_ability_filter_from_text(rest_lower)
        } else if scan_contains_phrase(rest_lower, "spell") {
            constrain_filter_to_stack(parsed_target)
        } else {
            parsed_target
        };
        let unless_pay = parse_unless_payment(rest_lower).map(counter_unless_pay_modifier);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Counter {
                target,
                source_rider: None,
                unless_pay,
                all: true,
            })),
            rem,
        ));
    }

    // CR 701.6: Counter a spell or ability on the stack.
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("counter ")).parse(i)) {
        let rest_lower = &lower[lower.len() - rest.len()..];
        let (parsed_target, rem) = parse_target_with_ctx(rest, ctx);
        let target = if scan_contains_phrase(rest_lower, "activated or triggered ability") {
            // CR 701.6: "activated or triggered ability" is a special-case target
            // that maps to StackAbility. We still use parse_target's remainder to
            // preserve the compound-detection contract.
            imperative::stack_ability_filter_from_text(rest_lower)
        } else if scan_contains_phrase(rest_lower, "spell") {
            constrain_filter_to_stack(parsed_target)
        } else {
            parsed_target
        };
        // CR 118.12: Parse "unless its controller pays {X}" for conditional counters
        let unless_pay = parse_unless_payment(rest_lower).map(counter_unless_pay_modifier);
        return Some((
            TargetedImperativeAst::ZoneCounterProxy(Box::new(ZoneCounterImperativeAst::Counter {
                target,
                source_rider: None,
                unless_pay,
                all: false,
            })),
            rem,
        ));
    }

    // Return: determine destination separately, use parse_target remainder for compound detection
    if let Some((_, rest)) = nom_on_lower(text, lower, |i| value((), tag("return ")).parse(i)) {
        let rest_lower = &lower[lower.len() - rest.len()..];
        let (trailing_target_text, trailing_dest, trailing_dest_remainder) =
            strip_return_destination_ext_with_remainder(rest);
        let (leading_target_text, leading_dest) = strip_leading_return_destination_ext(rest);
        let (target_text, dest, dest_remainder) = if leading_dest.is_some() {
            (leading_target_text, leading_dest, "")
        } else {
            (trailing_target_text, trailing_dest, trailing_dest_remainder)
        };
        let (is_mass, target_text) = if let Some((_, stripped)) =
            nom_on_lower(target_text, &target_text.to_ascii_lowercase(), |i| {
                value((), alt((tag("all "), tag("each ")))).parse(i)
            }) {
            (true, stripped)
        } else {
            (false, target_text)
        };
        // CR 115.1 + Whitemane Lion ruling: Use `parse_target_with_syntax` so
        // the "target"-keyword vs descriptor discriminator flows back from
        // this parse alone, with no cross-clause residue to clear.
        let (target, mut rem, target_syntax) = parse_target_with_syntax(target_text, ctx);
        if rem.is_empty() {
            rem = dest_remainder;
        }
        let origin = infer_origin_zone(rest_lower);
        let target = add_inferred_origin_constraints_to_target(target, origin, rest_lower);
        // CR 115.1: A bounce resolves at-resolution iff the Oracle text omitted
        // the word "target" AND the filter has a controller scope to enumerate
        // against. Computed here so both Hand-destined and default-None
        // branches below can stamp it onto the AST.
        let selection = if matches!(target_syntax, TargetSyntax::Descriptor)
            && imperative::filter_has_controller_scope(&target)
        {
            BounceSelection::AtResolution
        } else {
            BounceSelection::Targeted
        };
        return match dest {
            Some(d) if d.zone == Zone::Battlefield => {
                if is_mass && d.enter_with_counters.is_empty() {
                    Some((
                        TargetedImperativeAst::ReturnAllToZone {
                            target,
                            origin,
                            destination: Zone::Battlefield,
                            enters_under: d.enters_under,
                            enter_tapped: d.enter_tapped,
                        },
                        rem,
                    ))
                } else {
                    Some((
                        TargetedImperativeAst::ReturnToBattlefield {
                            target,
                            origin,
                            enter_transformed: d.transformed,
                            enters_under: d.enters_under,
                            enter_tapped: d.enter_tapped,
                            enters_attacking: d.enters_attacking,
                            enter_with_counters: d.enter_with_counters,
                        },
                        rem,
                    ))
                }
            }
            Some(d) if d.zone == Zone::Hand => {
                if is_mass && origin.is_some() {
                    Some((
                        TargetedImperativeAst::ReturnAllToZone {
                            target,
                            origin,
                            destination: Zone::Hand,
                            enters_under: None,
                            enter_tapped: false,
                        },
                        rem,
                    ))
                } else {
                    Some((TargetedImperativeAst::Return { target, selection }, rem))
                }
            }
            Some(d) => {
                if is_mass {
                    Some((
                        TargetedImperativeAst::ReturnAllToZone {
                            target,
                            origin,
                            destination: d.zone,
                            enters_under: None,
                            enter_tapped: false,
                        },
                        rem,
                    ))
                } else {
                    Some((
                        TargetedImperativeAst::ReturnToZone {
                            target,
                            origin,
                            destination: d.zone,
                        },
                        rem,
                    ))
                }
            }
            None => Some((TargetedImperativeAst::Return { target, selection }, rem)),
        };
    }

    // Put counter: use refactored try_parse_put_counter that returns remainder
    if tag::<_, _, OracleError<'_>>("put ").parse(lower).is_ok()
        && scan_contains_phrase(lower, "counter")
    {
        if let Some((
            Effect::PutCounter {
                counter_type,
                count,
                target,
            },
            rem,
            multi_target,
        )) = counter::try_parse_put_counter(lower, text, ctx)
        {
            // CR 122.1: Run mass detection against ONLY the primary clause — the slice
            // try_parse_put_counter consumed (`text` minus `rem`) — never the full
            // compound `lower`. A trailing "on each" conjunct in `lower` would otherwise
            // wrongly promote a targeted primary clause. `rem` is a suffix-slice of the
            // same `text` buffer, so `text.len() - rem.len()` always lands on a valid
            // UTF-8 char boundary and `text[..text.len() - rem.len()]` is sound.
            let primary_clause = &text[..text.len() - rem.len()];
            let primary_clause_lower = primary_clause.to_ascii_lowercase();
            let ast = if imperative::counter_placement_is_mass(&primary_clause_lower)
                && multi_target.is_none()
            {
                ZoneCounterImperativeAst::PutCounterAll {
                    counter_type,
                    count,
                    target,
                }
            } else {
                ZoneCounterImperativeAst::PutCounter {
                    counter_type,
                    count,
                    target,
                }
            };
            return Some((TargetedImperativeAst::ZoneCounterProxy(Box::new(ast)), rem));
        }
    }

    None
}

/// CR 608.2c: Split compound targeted actions like "tap target creature and put a stun
/// counter on it" into a primary effect (Tap) with a sub_ability chain (PutCounter with
/// ParentTarget). Instructions in a spell are followed in order; each " and "-connected
/// action becomes a chained sub_ability.
///
/// Uses `parse_target`'s unconsumed remainder as the compound boundary oracle — this correctly
/// handles compound filter phrases like "you own and control" because `parse_target` consumes
/// them as part of the target filter, leaving no " and " in the remainder.
///
/// When the remainder references "it"/"that creature"/"them" (via `contains_object_pronoun`),
/// the sub_ability's target is set to `TargetFilter::ParentTarget` so it inherits the
/// parent's resolved targets at resolution time.
fn try_split_targeted_compound(text: &str, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();

    // Quick bail: no "and" means no compound connector possible
    if !scan_contains_phrase(&lower, "and") {
        return None;
    }

    // Use parse_target's remainder to determine the compound split point
    let (primary_ast, remainder) = try_parse_verb_and_target(text, &lower, ctx)?;

    // If parse_target consumed everything, there's no compound action
    // (e.g. "exile any number of other nonland permanents you own and control")
    if remainder.is_empty() {
        return None;
    }

    // The remainder must start with " and " to be a compound connector.
    // Do NOT trim — the leading space is the boundary marker.
    let (after_and, _) = tag::<_, _, OracleError<'_>>(" and ")
        .parse(remainder)
        .ok()?;

    let sub_text = after_and.trim();
    if sub_text.is_empty() {
        return None;
    }

    // Lower the primary AST to an Effect
    let primary_effect = match primary_ast {
        TargetedImperativeAst::ZoneCounterProxy(ast) => lower_zone_counter_ast(*ast),
        other => lower_targeted_action_ast(other),
    };

    let sub_lower = sub_text.to_lowercase();
    let uses_parent_target_reference = has_anaphoric_reference(&sub_lower);
    let mut continuation_ctx = if uses_parent_target_reference {
        ParseContext {
            card_name: ctx.card_name.clone(),
            // CR 303.4 + CR 702.103: keep the enclosing card's typed host
            // self-reference so a `"that creature"` copy-token anaphor in the
            // continuation chunk still remaps to the enchanted host.
            host_self_reference: ctx.host_self_reference.clone(),
            ..Default::default()
        }
    } else {
        ctx.clone()
    };

    // Parse the sub-effect
    let mut sub_clause = parse_imperative_effect(sub_text, &mut continuation_ctx);

    // CR 608.2c: Verb carry-forward for bare "target X" clauses in compound actions.
    // When the sub-text starts with "target" and parsed as Unimplemented or
    // the structural TargetOnly wrapper, prepend the verb from the primary
    // effect and re-parse. Handles "exile target creature and target artifact"
    // where "target artifact" lacks a verb.
    // Only this branch accepts TargetOnly: bare "target ..." is the only
    // verbless head that lowers structurally to TargetOnly; the other
    // carry-forward prefixes below ("up to", "all/each", "~", possessives)
    // fall back as Unimplemented when the verb is omitted.
    if (matches!(sub_clause.effect, Effect::Unimplemented { .. })
        || matches!(sub_clause.effect, Effect::TargetOnly { .. }))
        && tag::<_, _, OracleError<'_>>("target ")
            .parse(sub_lower.as_str())
            .is_ok()
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // CR 122.1 + CR 115.6: Counter-clause carry-forward for a second targeted
    // PutCounter conjunct. "put an everything counter on each of up to one
    // target land and up to one target creature" (Omo, Queen of Vesuva) splits
    // on " and " into the verbless sub-text "up to one target creature". The
    // generic verb-only carry-forward below would reparse "put up to one target
    // creature" — which has no counter phrase and stays Unimplemented. Instead,
    // when the primary effect is a PutCounter, reuse its counter_type/count and
    // build the second PutCounter sibling directly against the trailing target,
    // carrying its own "up to N" multi_target. Mirrors `try_parse_tap_goad_compound`'s
    // direct sub-effect construction.
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && tag::<_, _, OracleError<'_>>("up to ")
            .parse(sub_lower.as_str())
            .is_ok()
    {
        if let Effect::PutCounter {
            counter_type,
            count,
            ..
        } = &primary_effect
        {
            // CR 115.1d: strip the "up to N" / "each of up to N" cardinality from
            // the sub-text and emit the corresponding MultiTargetSpec, mirroring
            // `resolve_counter_placement_target`'s own up-to handling.
            let (target_text, up_to_spec): (&str, Option<MultiTargetSpec>) =
                if let Some(((), after_up_to)) =
                    super::oracle_nom::bridge::nom_on_lower(sub_text, sub_lower.as_str(), |i| {
                        value((), alt((tag("each of up to "), tag("up to ")))).parse(i)
                    })
                {
                    match parse_multi_target_count_expr(
                        &sub_lower[sub_lower.len() - after_up_to.len()..],
                    ) {
                        Ok((after_qty, max)) => (
                            &sub_text[sub_text.len() - after_qty.len()..],
                            Some(MultiTargetSpec::up_to(max)),
                        ),
                        Err(_) => (sub_text, None),
                    }
                } else {
                    (sub_text, None)
                };
            let (sub_target, sub_rem) =
                parse_target_with_ctx(target_text.trim_start(), &mut continuation_ctx);
            if sub_rem.trim().is_empty() && !matches!(sub_target, TargetFilter::Any) {
                sub_clause = ParsedEffectClause {
                    effect: Effect::PutCounter {
                        counter_type: counter_type.clone(),
                        count: count.clone(),
                        target: sub_target,
                    },
                    duration: None,
                    sub_ability: None,
                    distribute: None,
                    multi_target: up_to_spec,
                    condition: None,
                    optional: false,
                    unless_pay: None,
                };
            }
        }
    }
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && tag::<_, _, OracleError<'_>>("up to ")
            .parse(sub_lower.as_str())
            .is_ok()
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            // CR 115.6: Extract "up to N" cardinality before reparsing so it
            // survives the verb+target pipeline (which discards it internally).
            let (_, up_to_spec) = strip_any_number_quantifier(&reparsed_text);
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
                if sub_clause.multi_target.is_none() {
                    sub_clause.multi_target = up_to_spec;
                }
            }
        }
    }

    // CR 608.2c: Verb carry-forward for mass-object continuations.
    // "untap it and all Samurai you control" splits into sub-text
    // "all Samurai you control"; prepend the primary verb so the existing
    // mass parser sees "untap all Samurai you control".
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && alt((
            tag::<_, _, OracleError<'_>>("all "),
            tag::<_, _, OracleError<'_>>("each "),
        ))
        .parse(sub_lower.as_str())
        .is_ok()
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // CR 608.2c + CR 701.8a: Self-reference carry-forward for compound actions.
    // "destroy that creature and ~" splits on " and " into sub-text "~" which
    // lacks a verb. Prepend the primary verb so it becomes "destroy ~" — parsed
    // as Destroy { target: SelfRef }. Handles Loyal Sentry, etc.
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && all_consuming(tag::<_, _, OracleError<'_>>("~"))
            .parse(sub_lower.as_str())
            .is_ok()
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // CR 608.2c: Possessive zone carry-forward for compound actions.
    // "exiles a creature they control and their graveyard" → sub-text "their graveyard"
    // lacks a verb. Prepend the primary verb so it becomes "exile their graveyard".
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && (starts_with_possessive(&sub_lower, "", "graveyard")
            || starts_with_possessive(&sub_lower, "", "library")
            || starts_with_possessive(&sub_lower, "", "hand"))
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // CR 608.2c: Top-of-library carry-forward for compound actions.
    // "Exile target nonland permanent and the top card of your library"
    // (Suspend Aggression) splits on " and " into sub-text "the top card of
    // your library" which lacks a verb. Prepend the primary verb so it
    // becomes "exile the top card of your library" — parsed as ExileTop.
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && tag::<_, _, OracleError<'_>>("the top ")
            .parse(sub_lower.as_str())
            .is_ok()
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // CR 608.2c: Article-led counter carry-forward for compound actions.
    // "put a +1/+1 counter on each creature you control and a loyalty counter
    // on each planeswalker you control" splits on " and " into sub-text
    // "a loyalty counter on each planeswalker you control" — a verbless counter
    // clause starting with an article. Prepend the primary verb so it becomes
    // "put a loyalty counter on each planeswalker you control".
    if matches!(sub_clause.effect, Effect::Unimplemented { .. })
        && alt((
            tag::<_, _, OracleError<'_>>("a "),
            tag::<_, _, OracleError<'_>>("an "),
        ))
        .parse(sub_lower.as_str())
        .is_ok()
        && nom_primitives::scan_contains(&sub_lower, "counter on")
    {
        if let Some(verb) = extract_effect_verb(&primary_effect) {
            let reparsed_text = format!("{verb} {sub_text}");
            let reparsed = parse_imperative_effect(&reparsed_text, &mut continuation_ctx);
            if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                sub_clause = reparsed;
            }
        }
    }

    // If the remainder contains anaphoric references ("it", "that creature", "them"),
    // replace the sub_effect's target with ParentTarget so it inherits the parent's targets.
    // CR 608.2k carve-out (issue #319): in typed-trigger-subject context the
    // pronoun has already been correctly resolved to TriggeringSource by
    // `resolve_pronoun_target` — preserve that binding instead of clobbering.
    if uses_parent_target_reference && !ctx_has_typed_trigger_subject(ctx) {
        replace_target_with_parent(&mut sub_clause.effect);
    }

    let mut sub_ability = AbilityDefinition::new(AbilityKind::Spell, sub_clause.effect);
    sub_ability.sub_ability = sub_clause.sub_ability;
    // CR 115.6: Propagate "up to N" cardinality so the sub-clause target
    // remains optional (e.g. "up to one other target artifact or enchantment").
    sub_ability.multi_target = sub_clause.multi_target;

    // CR 115.1d: Recover the PRIMARY clause's "up to N" cardinality, which
    // `try_parse_verb_and_target` discards when it lowers a PutCounter to a
    // `ZoneCounterProxy`. Without this the primary target of e.g. Omo, Queen of
    // Vesuva ("...on each of up to one target land and up to one target
    // creature") would be wrongly mandatory. Re-derive it from the consumed
    // primary-clause prefix via the same building block that produced it.
    let primary_multi_target = if matches!(&primary_effect, Effect::PutCounter { .. }) {
        let primary_clause = &text[..text.len() - remainder.len()];
        let primary_lower = primary_clause.to_ascii_lowercase();
        counter::try_parse_put_counter(&primary_lower, primary_clause, &mut ctx.clone())
            .and_then(|(_, _, multi)| multi)
    } else {
        None
    };

    Some(ParsedEffectClause {
        effect: primary_effect,
        duration: None,
        sub_ability: Some(Box::new(sub_ability)),
        distribute: None,
        multi_target: primary_multi_target,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn try_parse_tap_goad_compound(text: &str, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let (target_lower, untap) = alt((
        value(false, tag::<_, _, OracleError<'_>>("tap and goad ")),
        value(true, tag("untap and goad ")),
    ))
    .parse(lower.as_str())
    .ok()?;
    let target_text = &text[text.len() - target_lower.len()..];
    let (target, rem) = parse_target_with_ctx(target_text, ctx);
    if !rem.trim().is_empty() {
        return None;
    }

    let primary = Effect::SetTapState {
        target: target.clone(),
        scope: EffectScope::Single,
        state: if untap {
            TapStateChange::Untap
        } else {
            TapStateChange::Tap
        },
    };
    let sub_ability = AbilityDefinition::new(AbilityKind::Spell, Effect::Goad { target });

    Some(ParsedEffectClause {
        effect: primary,
        duration: None,
        sub_ability: Some(Box::new(sub_ability)),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 608.2c: Split compound damage actions like "~ deals 3 damage to any target
/// and you gain 3 life" into a primary DealDamage effect with a sub_ability chain
/// for the remainder clause. Instructions within a single spell or ability are
/// followed in order; each " and "-connected clause becomes a chained sub_ability.
///
/// Uses `parse_target`'s unconsumed remainder as the compound boundary oracle —
/// this correctly handles compound filter phrases like "you own and control"
/// because `parse_target` consumes them as part of the target filter.
/// Detect "deals N damage to each [opponent/player] and each [type] they control".
///
/// CR 120.3 + CR 609.7: This compound target pattern deals damage to BOTH players
/// and objects from a single source as one simultaneous damage event. Producing
/// two chained effects (DamageEachPlayer + DamageAll sub_ability) would split
/// the event in two, breaking replacement/prevention shields like Awe Strike
/// ("the next time a source would deal damage ... prevent that damage"), which
/// must observe the full batch as one event from one source.
///
/// Emits a single `Effect::DamageAll` carrying both the object `target` filter
/// and a `player_filter` populated — the resolver iterates the combined
/// recipient set under one `DamageContext`.
///
/// Cards: Goblin Chainwhirler, Kumano Faces Kakkazan, etc.
fn try_parse_compound_player_object_damage(lower: &str) -> Option<ParsedEffectClause> {
    // Extract the damage verb + amount using the same entry logic as try_parse_damage_with_remainder.
    // structural: not dispatch — positional search for verb in variable-length subject prefix
    let pos = lower.find("deals ").or_else(|| lower.find("deal "))?;
    let verb_len = if tag::<_, _, OracleError<'_>>("deals ")
        .parse(&lower[pos..])
        .is_ok()
    {
        6
    } else {
        5
    };
    let after_lower = &lower[pos + verb_len..];

    // Parse amount: "N damage to "
    let (qty, after_amount) =
        super::oracle_util::parse_count_expr(after_lower).and_then(|(qty, rest)| {
            let (rest, _) = tag::<_, _, OracleError<'_>>("damage").parse(rest).ok()?;
            let rest = rest.trim_start();
            let (rest, _) = tag::<_, _, OracleError<'_>>("to ").parse(rest).ok()?;
            Some((qty, rest))
        })?;

    // Match: "each [opponent/player] and each [type phrase] {they control | you don't control | your opponents control}"
    let (after_each, _) = tag::<_, _, OracleError<'_>>("each ")
        .parse(after_amount)
        .ok()?;
    let (after_player, player_filter) = parse_damage_player_scope(after_each).ok()?;

    // " and each " connector
    let (after_and_each, _) = tag::<_, _, OracleError<'_>>(" and each ")
        .parse(after_player)
        .ok()?;

    // Trim a trailing period so suffix-anchored controller phrases match cleanly.
    let after_and_each = after_and_each.trim_end_matches('.').trim_end();
    if after_and_each.is_empty() {
        return None;
    }

    // CR 109.4 + CR 109.5: Probe for one of the three controller-suffix variants
    // this compound class uses. All three resolve to ControllerRef::Opponent for
    // the object filter — "they" anaphors the opponent set named in the first
    // half; "you don't control" and "your opponents control" are direct opponent
    // refs. The suffix presence is the gate for the compound shape — without it
    // the " and " is part of an unrelated clause and falls through to general
    // split. `take_until` + an anchored controller-tag alt() is the single-pass
    // gate; the take_until result (the type-phrase prefix) is unused here because
    // we hand the full slice to parse_target below for native consumption.
    let mut probe = alt((
        preceded(
            take_until::<_, _, OracleError<'_>>(" they control"),
            tag(" they control"),
        ),
        preceded(
            take_until::<_, _, OracleError<'_>>(" you don't control"),
            tag(" you don't control"),
        ),
        preceded(
            take_until::<_, _, OracleError<'_>>(" your opponents control"),
            tag(" your opponents control"),
        ),
    ));
    let (gate_rest, _) = probe.parse(after_and_each).ok()?;
    if !gate_rest.is_empty() {
        return None;
    }

    // Use parse_target on "each [type phrase + controller suffix]" so the controller
    // suffix is consumed natively by the parser pipeline. parse_target returns the
    // typed filter with controller already populated (Opponent for "you don't control"
    // / "your opponents control"; You for "they control" — we rewrite that below).
    let target_text = format!("each {after_and_each}");
    let (mut object_filter, _rem) = parse_target(&target_text);

    // CR 109.5: "they" in this compound damage context anaphors back to the
    // opponent set in the first half of the conjunction, NOT to the controller.
    // Rewrite ControllerRef::You (parse_target's default for "they control") to
    // Opponent so the runtime targets the same opponent set as `player_filter`.
    // "you don't control" and "your opponents control" already resolve to
    // Opponent via `parse_zone_controller` and are left unchanged.
    fn set_opponent_controller(filter: &mut TargetFilter) {
        match filter {
            TargetFilter::Typed(tf) => {
                tf.controller = Some(ControllerRef::Opponent);
            }
            TargetFilter::Or { filters } => {
                for f in filters.iter_mut() {
                    set_opponent_controller(f);
                }
            }
            _ => {}
        }
    }
    set_opponent_controller(&mut object_filter);

    // CR 120.3: Single effect, one damage source, simultaneous batch across both
    // the player set and the object set. Replacement effects observe this as one
    // coherent damage event — see `resolve_all` in game/effects/deal_damage.rs.
    Some(ParsedEffectClause {
        effect: Effect::DamageAll {
            amount: qty,
            target: object_filter,
            player_filter: Some(player_filter),
            damage_source: None,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 120.3 + CR 119.3a: Compound object+player damage — type-first variant.
/// Detects "deals N damage to each [type-phrase] and each player" and emits a
/// single `Effect::DamageAll` carrying both the object filter and a
/// `player_filter: Some(PlayerFilter::All)` so the resolver damages every
/// matching creature AND every player from one batch (preserving simultaneous
/// damage event semantics for replacement/prevention shields).
///
/// Mirrors `try_parse_compound_player_object_damage` but with the conjunction
/// reversed: the first half names the object filter (with optional property
/// suffix like "with flying" / "without flying" / "with horsemanship"), the
/// second half is the player scope ("each player"). Without this gate the
/// general compound splitter parses "each [type]" and silently drops the
/// "and each player" continuation.
///
/// Cards: Pyrohemia, Pestilence, Earthquake, Hurricane, Inferno, Famine,
/// Fire Tempest, Cave-In, Crypt Rats, Cloudthresher, Flamebreak, Devastate,
/// Dakmor Plague, Dry Spell, Festering Evil, etc. (~30 cards).
fn try_parse_compound_object_player_damage(lower: &str) -> Option<ParsedEffectClause> {
    // Reuse the same verb+amount entry logic as the player-first variant.
    let pos = lower.find("deals ").or_else(|| lower.find("deal "))?; // allow-noncombinator: positional verb search inside a variable-length subject prefix; tag("deals ") below is the actual dispatch.
    let verb_len = if tag::<_, _, OracleError<'_>>("deals ")
        .parse(&lower[pos..])
        .is_ok()
    {
        6
    } else {
        5
    };
    let after_lower = &lower[pos + verb_len..];

    // Parse amount: "N damage to "
    let (qty, after_amount) =
        super::oracle_util::parse_count_expr(after_lower).and_then(|(qty, rest)| {
            let (rest, _) = tag::<_, _, OracleError<'_>>("damage").parse(rest).ok()?;
            let rest = rest.trim_start();
            let (rest, _) = tag::<_, _, OracleError<'_>>("to ").parse(rest).ok()?;
            Some((qty, rest))
        })?;

    // Must start with "each " (the object half of the conjunction).
    let (after_each, _) = tag::<_, _, OracleError<'_>>("each ")
        .parse(after_amount)
        .ok()?;

    // Locate the " and each player" connector. take_until isolates the type-phrase
    // prefix; the player suffix gates the compound shape and may carry a trailing
    // period, comma, or independent continuation clause (e.g., Flamebreak:
    // "and each player. Creatures dealt damage this way..."). After consuming the
    // tag, the next char must be a clause boundary — anything else (e.g.,
    // " who controls a white creature" on Disorder, " equal to ..." on Pompeii)
    // means "each player" is a QUALIFIED player set, not the universal scope.
    let (after_player, type_phrase) = take_until::<_, _, OracleError<'_>>(" and each player")
        .parse(after_each)
        .ok()?;
    let (after_player_tag, _) = tag::<_, _, OracleError<'_>>(" and each player")
        .parse(after_player)
        .ok()?;

    // CR 109.5: Reject qualified player phrases. Only accept clause-boundary
    // characters (whitespace + punctuation) or end-of-string after "each player".
    // " who", " equal", " that", " whose", and similar word continuations indicate
    // a relative clause that restricts the player set — those cards are not part
    // of this class.
    if let Some(c) = after_player_tag.chars().next() {
        if !(c.is_ascii_punctuation() || c == ' ') {
            return None;
        }
        // Whitespace alone isn't enough — peek at the next word.
        if c == ' ' {
            let next = after_player_tag.trim_start();
            // A bare trailing space + period/comma is fine (already covered by punctuation
            // peek above), but " who/equal/that/whose/with..." is a qualifier.
            // The only acceptable post-space content is another sentence (capitalized,
            // started by punctuation), or the empty tail. We approximate with a tag
            // probe over the known qualifier words.
            let mut qualifier = alt((
                tag::<_, _, OracleError<'_>>("who "),
                tag("whose "),
                tag("that "),
                tag("equal "),
                tag("with "),
                tag("without "),
            ));
            if qualifier.parse(next).is_ok() {
                return None;
            }
        }
    }

    if type_phrase.is_empty() {
        return None;
    }

    // Reject if the type-phrase itself contains a stray "and each " — that
    // suggests a more complex N-way conjunction we don't yet handle.
    if scan_contains_phrase(type_phrase, "and each") {
        return None;
    }

    // Hand the "each [type-phrase]" slice to parse_target so property suffixes
    // ("with flying", "without flying", "with horsemanship") are consumed
    // natively. The full lower-case slice is fine because parse_target is
    // case-insensitive and we only use the resulting filter, not the remainder.
    let target_text = format!("each {type_phrase}");
    let (object_filter, _rem) = parse_target(&target_text);

    // Sanity: the parsed filter must reference at least one object type.
    // If parse_target returned an empty filter, bail out so the general
    // compound splitter gets a chance.
    if matches!(&object_filter, TargetFilter::None) {
        return None;
    }

    Some(ParsedEffectClause {
        effect: Effect::DamageAll {
            amount: qty,
            target: object_filter,
            player_filter: Some(PlayerFilter::All),
            damage_source: None,
        },
        duration: None,
        sub_ability: None,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 120.2b + CR 608.2c: Multi-target damage split (Cone of Flame, Banshee,
/// Serpentine Spike, Spinal Embrace class). One source emits N independent
/// `DealDamage` events whose amounts and targets vary. Segments are separated
/// either by commas (with `and` introducing the final segment) or — for the
/// two-segment case — by a bare `and` with no comma (Char: "deals 4 damage to
/// any target and 2 damage to you"). Each segment after the first is bare-form
/// — `"M damage to T2"` without a leading "deals" verb — and inherits the
/// source object from the printed sentence.
///
/// Build shape:
///   primary = `DealDamage { amount_1, target_1 }`
///   primary.sub_ability = `DealDamage { amount_2, target_2 }`
///   primary.sub_ability.sub_ability = `DealDamage { amount_3, target_3 }`
///
/// Each segment is parsed via [`parse_bare_damage_continuation`] and chained
/// as a `sub_ability`. A non-damage continuation aborts the whole chain (the
/// bare-damage parser returns `None`, propagated by `?`), so single-`and`
/// compounds like "deals 3 damage to any target and you gain 3 life" fall
/// through to the caller's compound splitter unharmed. Returns `None` (and
/// does not mutate `ctx`) if the text is not a multi-segment damage line.
fn try_parse_multi_target_damage_chain(
    text: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let (primary_effect, remainder) = try_parse_damage_with_remainder(text, &lower, ctx)?;
    let trimmed = remainder.trim_start();
    let trimmed_lower = trimmed.to_lowercase();
    // A comma-delimited list ("..., M damage to T2, and K ...") or a bare
    // two-segment "and" ("... and 2 damage to you", Char). Non-damage "and"
    // continuations still reach the loop but abort it at the bare-damage parse,
    // so they fall through to the caller's compound splitter.
    if alt((
        tag::<_, _, OracleError<'_>>(", "),
        tag::<_, _, OracleError<'_>>("and "),
    ))
    .parse(trimmed_lower.as_str())
    .is_err()
    {
        return None;
    }

    // Walk the comma-delimited continuation list. Each iteration either
    // consumes one bare-damage segment (returning the next AbilityDefinition)
    // or aborts the entire chain — partial parses are not committed.
    let mut segments: Vec<Effect> = Vec::new();
    let mut cursor = remainder.trim_start();
    while !cursor.is_empty() {
        let cursor_lower = cursor.to_lowercase();
        let after_separator = if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>(", and ").parse(cursor_lower.as_str())
        {
            &cursor[cursor_lower.len() - rest.len()..]
        } else if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>(", ").parse(cursor_lower.as_str())
        {
            &cursor[cursor_lower.len() - rest.len()..]
        } else if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>("and ").parse(cursor_lower.as_str())
        {
            // Bare two-segment "and" (Char) — `cursor` was trimmed of its
            // leading space, so the connector is "and " with no comma.
            &cursor[cursor_lower.len() - rest.len()..]
        } else {
            // Trailing punctuation only — clean end of chain.
            let rest_trimmed = cursor.trim_end_matches('.').trim();
            if rest_trimmed.is_empty() {
                break;
            }
            return None;
        };

        let (segment_effect, leftover) = parse_bare_damage_continuation(after_separator, ctx)?;
        segments.push(segment_effect);
        cursor = leftover.trim_start();
    }

    if segments.is_empty() {
        return None;
    }

    // Build the chain bottom-up so each segment becomes the `sub_ability` of
    // the previous one. Effects beyond the primary share the primary's
    // damage-source semantics by construction (each is a `DealDamage` with
    // `damage_source: None`).
    let mut chain_tail: Option<Box<AbilityDefinition>> = None;
    for effect in segments.into_iter().rev() {
        let mut def = AbilityDefinition::new(AbilityKind::Spell, effect);
        def.sub_ability = chain_tail.take();
        chain_tail = Some(Box::new(def));
    }

    Some(ParsedEffectClause {
        effect: primary_effect,
        duration: None,
        sub_ability: chain_tail,
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 122.1 + CR 608.2c: Multi-target counter placement split. A single
/// instruction may put different counter counts on different targets using
/// comma-separated bare continuations:
///
/// `put N <counter> counter(s) on T1, M <counter> counter(s) on T2[, and K ...]`.
///
/// Each bare continuation inherits the `put` verb and is parsed by the same
/// counter-placement building block as the primary segment.
fn try_parse_multi_target_counter_chain(
    text: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    let (primary_effect, remainder, primary_multi_target) =
        counter::try_parse_put_counter(&lower, text, ctx)?;

    let trimmed = remainder.trim_start();
    let trimmed_lower = trimmed.to_lowercase();
    if tag::<_, _, OracleError<'_>>(", ")
        .parse(trimmed_lower.as_str())
        .is_err()
    {
        return None;
    }

    let mut segments: Vec<(Effect, Option<MultiTargetSpec>)> = Vec::new();
    let mut cursor = remainder.trim_start();
    while !cursor.is_empty() {
        let cursor_lower = cursor.to_lowercase();
        let after_separator = if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>(", and ").parse(cursor_lower.as_str())
        {
            &cursor[cursor_lower.len() - rest.len()..]
        } else if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>(", ").parse(cursor_lower.as_str())
        {
            &cursor[cursor_lower.len() - rest.len()..]
        } else {
            // allow-noncombinator: structural punctuation cleanup after all
            // comma-separated counter segments are parsed, not parser dispatch.
            let rest_trimmed = cursor.trim_end_matches('.').trim();
            if rest_trimmed.is_empty() {
                break;
            }
            return None;
        };

        let (segment_effect, segment_remainder, segment_multi_target) =
            parse_bare_counter_continuation(after_separator, ctx)?;
        segments.push((segment_effect, segment_multi_target));
        cursor = segment_remainder.trim_start();
    }

    if segments.is_empty() {
        return None;
    }

    let mut chain_tail: Option<Box<AbilityDefinition>> = None;
    for (effect, multi_target) in segments.into_iter().rev() {
        let mut def = AbilityDefinition::new(AbilityKind::Spell, effect);
        def.multi_target = multi_target;
        def.sub_ability = chain_tail.take();
        chain_tail = Some(Box::new(def));
    }

    Some(ParsedEffectClause {
        effect: primary_effect,
        duration: None,
        sub_ability: chain_tail,
        distribute: None,
        multi_target: primary_multi_target,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

fn parse_bare_counter_continuation<'a>(
    text: &'a str,
    ctx: &mut ParseContext,
) -> Option<(Effect, &'a str, Option<MultiTargetSpec>)> {
    let reparsed_text = format!("put {text}");
    let reparsed_lower = reparsed_text.to_lowercase();
    let (effect, remainder, multi_target) =
        counter::try_parse_put_counter(&reparsed_lower, &reparsed_text, ctx)?;
    let consumed = reparsed_text.len().checked_sub(remainder.len())?;
    let text_consumed = consumed.checked_sub("put ".len())?;
    Some((effect, &text[text_consumed..], multi_target))
}

/// Parse one bare-form damage continuation: `"N damage to T"` (no leading
/// "deals" verb), with optional `, rounded up/down` qualifier and required
/// `to <target>` recipient. Returns the parsed `DealDamage` effect and the
/// post-recipient remainder.
///
/// Accepts the same amount shapes as [`try_parse_damage_with_remainder`]
/// (fixed numbers, `half X`, `that much`, `twice that much`, etc.) by
/// delegating to [`oracle_util::parse_count_expr`]. The recipient is parsed
/// through [`parse_target_with_ctx`], same as the primary segment.
fn parse_bare_damage_continuation<'a>(
    text: &'a str,
    ctx: &mut ParseContext,
) -> Option<(Effect, &'a str)> {
    let lower = text.to_lowercase();
    let (amount, after_damage_offset) =
        if let Some((qty, rest)) = super::oracle_util::parse_count_expr(&lower) {
            if tag::<_, _, OracleError<'_>>("damage").parse(rest).is_ok() {
                // Compute the byte offset of the post-`damage` slice in the
                // original-case string. Both `text` and `lower` share the same
                // ASCII byte length.
                let after_amount = text.len() - rest.len();
                let after_damage = after_amount + "damage".len();
                (qty, after_damage)
            } else {
                return None;
            }
        } else if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>("twice that much damage").parse(lower.as_str())
        {
            let consumed = lower.len() - rest.len();
            (
                QuantityExpr::Multiply {
                    factor: 2,
                    inner: Box::new(QuantityExpr::Ref {
                        qty: QuantityRef::EventContextAmount,
                    }),
                },
                consumed,
            )
        } else if let Ok((rest, _)) =
            tag::<_, _, OracleError<'_>>("that much damage").parse(lower.as_str())
        {
            let consumed = lower.len() - rest.len();
            (
                QuantityExpr::Ref {
                    qty: QuantityRef::EventContextAmount,
                },
                consumed,
            )
        } else {
            return None;
        };

    let after_damage = &text[after_damage_offset..];
    let (amount, after_target) = absorb_trailing_rounding_suffix(amount, after_damage);
    let trimmed = after_target.trim();
    let trimmed_lower = trimmed.to_lowercase();
    let after_to = match opt(tag::<_, _, OracleError<'_>>("to ")).parse(trimmed_lower.as_str()) {
        Ok((rest_lower, _)) => trimmed[trimmed_lower.len() - rest_lower.len()..].trim(),
        Err(_) => trimmed,
    };
    if after_to.is_empty() {
        // Bare segment with inherited target ("deals 1 damage, then 2 more
        // damage" — vanishingly rare, but no recipient means ParentTarget).
        return Some((
            Effect::DealDamage {
                amount,
                target: TargetFilter::ParentTarget,
                damage_source: None,
            },
            "",
        ));
    }
    let (target, rem) = parse_target_with_ctx(after_to, ctx);
    let (target, rem) = refine_damage_target_remainder(target, rem);
    let rem = trim_dangling_target_word(rem);
    Some((
        Effect::DealDamage {
            amount,
            target,
            damage_source: None,
        },
        rem,
    ))
}

fn try_split_damage_compound(text: &str, ctx: &mut ParseContext) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    if !scan_contains_phrase(&lower, "and") {
        return None;
    }

    // CR 120.2a: Compound player+object damage — "each opponent and each [type] they control"
    // must be detected before the general compound splitter, because the "and" here connects
    // two damage targets (not two independent effects).
    if let Some(clause) = try_parse_compound_player_object_damage(&lower) {
        return Some(clause);
    }

    // CR 120.3 + CR 119.3a: Same shape, type-first ordering — "each creature
    // [with X | without X] and each player" (Pyrohemia / Earthquake / Hurricane
    // class). Must run before the general split so the player half isn't dropped.
    if let Some(clause) = try_parse_compound_object_player_damage(&lower) {
        return Some(clause);
    }

    // CR 120.2b + CR 608.2c: Multi-target damage split — "deals N damage to T1,
    // M damage to T2[, and K damage to T3]". A single source emits multiple
    // DealDamage events with shared source-of-damage but distinct
    // amount/target pairs (Cone of Flame, Banshee, Serpentine Spike). Must
    // run before the general single-and split so the comma-separated chain
    // isn't bisected by the "and" connector at the final segment.
    if let Some(clause) = try_parse_multi_target_damage_chain(text, ctx) {
        return Some(clause);
    }

    let (primary_effect, remainder) = try_parse_damage_with_remainder(text, &lower, ctx)?;

    if remainder.is_empty() {
        return None;
    }

    // The remainder must start with " and " to be a compound connector.
    // Do NOT trim — the leading space is the boundary marker.
    let (after_and, _) = tag::<_, _, OracleError<'_>>(" and ")
        .parse(remainder)
        .ok()?;
    let sub_text = after_and.trim();
    if sub_text.is_empty() {
        return None;
    }

    // Parse the sub-effect through the full clause pipeline (not just imperative),
    // because the sub-text may have a subject prefix like "you gain 3 life".
    let mut sub_clause = parse_effect_clause(sub_text, ctx);

    // Guard: if the sub-text parsed to Unimplemented, it's likely a target phrase
    // continuation ("each creature and planeswalker they control") rather than an
    // independent clause. Bail out and let the damage parser handle the full text.
    if matches!(sub_clause.effect, Effect::Unimplemented { .. }) {
        return None;
    }

    // If the remainder contains anaphoric references ("it", "that creature", "them"),
    // replace the sub_effect's target with ParentTarget so it inherits the parent's targets.
    // CR 608.2k carve-out (issue #319): preserve TriggeringSource bindings
    // produced by `resolve_pronoun_target` in typed-trigger-subject context.
    let sub_lower = sub_text.to_lowercase();
    if has_anaphoric_reference(&sub_lower) && !ctx_has_typed_trigger_subject(ctx) {
        replace_target_with_parent(&mut sub_clause.effect);
    }

    let mut sub_ability = AbilityDefinition::new(AbilityKind::Spell, sub_clause.effect);
    sub_ability.sub_ability = sub_clause.sub_ability;

    Some(ParsedEffectClause {
        effect: primary_effect,
        duration: None,
        sub_ability: Some(Box::new(sub_ability)),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// Verb-agnostic compound subject splitter.
/// Splits "X and Y [remainder]" into two subjects + the verb phrase.
/// X and Y are each parsed via `parse_target` or SelfRef detection.
/// Returns None if no compound subject detected.
///
/// Examples:
///   "~ and target creature with a stun counter on it into their owners' libraries"
///   → (SelfRef, Typed(Creature+Counters{OfType(Stun),GE,1}), "into their owners' libraries")
fn try_split_compound_subject(text: &str) -> Option<(TargetFilter, TargetFilter, &str)> {
    // Find " and " that separates subjects
    let (_, (first_text, after_and)) = nom_primitives::split_once_on(text, " and ").ok()?;
    let first_text = first_text.trim();
    let after_and = after_and.trim();

    // Parse first subject
    let first_filter = if first_text == "~"
        || first_text.eq_ignore_ascii_case("this creature")
        || first_text.eq_ignore_ascii_case("this permanent")
    {
        TargetFilter::SelfRef
    } else {
        let (filter, _rest) = parse_target(first_text);
        if matches!(filter, TargetFilter::None) {
            return None;
        }
        filter
    };

    // Parse second subject — consume until we hit a preposition that starts the verb phrase
    // Look for "into " or "from " as the boundary between the second subject and remainder
    let after_and_lower = after_and.to_lowercase();
    // Positional find for preposition boundary — position used to slice both
    // original-case and lowercase strings, so find() is kept for dual-string slicing.
    let remainder_start = after_and_lower
        .find(" into ")
        .or_else(|| after_and_lower.find(" from "))
        .or_else(|| after_and_lower.find(" onto "));

    let (second_text, remainder) = if let Some(pos) = remainder_start {
        (after_and[..pos].trim(), after_and[pos..].trim())
    } else {
        // No remainder phrase found — entire after_and is the second subject
        (after_and, "")
    };

    let (second_filter, extra_rest) = parse_target(second_text);
    if matches!(second_filter, TargetFilter::None) {
        return None;
    }

    // If parse_target consumed less than the full second_text, combine leftovers with remainder
    let extra_rest = extra_rest.trim();
    let final_remainder = if !extra_rest.is_empty() && !remainder.is_empty() {
        // extra_rest comes before the remainder preposition — just use remainder
        remainder
    } else if !extra_rest.is_empty() {
        extra_rest
    } else {
        remainder
    };

    Some((first_filter, second_filter, final_remainder))
}

/// Parse "shuffle X and Y into their owners' libraries" as a compound ChangeZone chain.
/// Returns a ParsedEffectClause with a ChangeZone for the first subject and a sub_ability
/// for the second subject, both with owner_library: true.
fn try_parse_compound_shuffle(text: &str) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    tag::<_, _, OracleError<'_>>("shuffle ")
        .parse(lower.as_str())
        .ok()?;

    if let Some(ShuffleImperativeAst::ChangeZoneAllToLibrary { origins }) =
        parse_shuffle_ast(text, &lower)
    {
        return Some(lower_shuffle_ast(
            ShuffleImperativeAst::ChangeZoneAllToLibrary { origins },
        ));
    }

    // Try to split compound subject from the text after "shuffle "
    let text_after = &text["shuffle ".len()..];
    let (first, second, remainder) = try_split_compound_subject(text_after)?;

    // The remainder must indicate library destination
    let remainder_lower = remainder.to_lowercase();
    let is_owner_library = scan_contains_phrase(&remainder_lower, "owner")
        || scan_contains_phrase(&remainder_lower, "their")
        || scan_contains_phrase(&remainder_lower, "its");

    if !scan_contains_phrase(&remainder_lower, "librar") {
        return None;
    }

    let owner_library = is_owner_library;

    // CR 701.24a: Compound shuffle is ChangeZone(first) → ChangeZone(second) → Shuffle.
    let shuffle_def = AbilityDefinition::new(
        AbilityKind::Spell,
        Effect::Shuffle {
            target: TargetFilter::Controller,
        },
    );

    // Build ChangeZone for the second subject, chained to the Shuffle
    let sub_effect = Effect::ChangeZone {
        origin: None,
        destination: Zone::Library,
        target: second,
        owner_library,
        enter_transformed: false,
        enters_under: None,
        enter_tapped: crate::types::zones::EtbTapState::Unspecified,
        enters_attacking: false,
        up_to: false,
        enter_with_counters: vec![],
        face_down_profile: None,
    };
    let mut sub_def = AbilityDefinition::new(AbilityKind::Spell, sub_effect);
    sub_def.sub_ability = Some(Box::new(shuffle_def));

    // Build ChangeZone for the first subject as the primary effect
    let primary_effect = Effect::ChangeZone {
        origin: None,
        destination: Zone::Library,
        target: first,
        owner_library,
        enter_transformed: false,
        enters_under: None,
        enter_tapped: crate::types::zones::EtbTapState::Unspecified,
        enters_attacking: false,
        up_to: false,
        enter_with_counters: vec![],
        face_down_profile: None,
    };

    Some(ParsedEffectClause {
        effect: primary_effect,
        duration: None,
        sub_ability: Some(Box::new(sub_def)),
        distribute: None,
        multi_target: None,
        condition: None,
        optional: false,
        unless_pay: None,
    })
}

/// CR 109.5 + CR 115.1 + CR 608.2c + CR 611.2c: Distribute "<subject-A> and
/// <subject-B> each <body>" into an AbilityDefinition chain whose halves apply
/// `<body>` to two different recipients.
///
/// Recognized static subject axes (each is one `alt()` call; permutations are
/// never enumerated):
/// - First subject: `you` → `OriginalController` (player axis), or `~` →
///   `SelfRef` (object axis — the ability source, e.g. Gogo).
/// - Second subject: `that player` → `ScopedPlayer` (the iterated voter for
///   `PlayerFilter::VotedFor`); `target opponent` / `target player` → `Player`
///   (the chosen target player, Bloodroot Apothecary class); or `that creature`
///   → `ParentTarget` (CR 115.1: the parent-ability target slot, e.g. the
///   creature Gogo copied).
///
/// Player-axis exemplar: "For each player who chose <choice>, you and that
/// player each <body>" (Council's-dilemma vote effects, Master of Ceremonies).
/// `OriginalController` is the printed ability controller (fixed even when
/// `player_scope` iteration rebinds the acting controller per-voter).
///
/// Object-axis exemplar: Gogo, Mysterious Mime — "Gogo and that creature each
/// get +2/+0 and gain haste until end of turn and attack this turn if able".
/// CR 611.2c: the pump+haste are a single continuous effect; the body is a
/// multi-link chain (pump+keyword link + MustAttack rider) distributed to both
/// `SelfRef` and `ParentTarget`. The two halves resolve in printed order via
/// the `sub_ability` chain, with half B appended at the tail of half A's chain.
///
/// Generality: the parser shape is parameterized to accept any body whose links
/// have a recognized `TargetFilter`-typed recipient slot (Token's `owner`,
/// Draw/Discard/Mill/Pump's `target`, GenericEffect's `Option<target>`). Bodies
/// with any link lacking a recipient slot are not supported — `None` is
/// returned and the caller falls through to Unimplemented.
/// CR 109.5 + CR 608.2c: Parse the compound-subject distribution prefix
/// (`"<A> and <B> each "`), returning the two authoritatively-bound recipient
/// filters and the remaining body text offset. Static dimensions are composed
/// from independent `alt()` axes; the dynamic controlled-creature subject is a
/// fallback for type phrases such as "Drakes you control each".
///
/// Shared by `try_parse_compound_subject_each` (which builds the distributed
/// chain) and `text_is_compound_subject_distribution` (the chunk-loop guard
/// that protects the bound recipients from post-distribution anaphoric
/// re-targeting). Keeping the prefix grammar in one place ensures the guard
/// and the distributor never drift.
/// Second-subject axis: "{type phrase} you control each " (Alandra, Sky Dreamer:
/// "~ and Drakes you control each get +X/+X until end of turn").
fn parse_controlled_creature_each_second_subject(rest: &str) -> Option<(usize, TargetFilter)> {
    const SUFFIX: &str = " you control each ";
    let (remaining, type_phrase) = terminated(
        take_until::<_, _, OracleError<'_>>(SUFFIX),
        tag::<_, _, OracleError<'_>>(SUFFIX),
    )
    .parse(rest)
    .ok()?;
    let type_phrase = type_phrase.trim();
    if type_phrase.is_empty() || type_phrase_has_compound_conjunction(type_phrase) {
        return None;
    }
    let normalized = format!("all {type_phrase} you control");
    let (filter, remainder) = parse_target(&normalized);
    if !remainder.trim().is_empty() || matches!(filter, TargetFilter::None) {
        return None;
    }
    Some((rest.len() - remaining.len(), filter))
}

fn type_phrase_has_compound_conjunction(type_phrase: &str) -> bool {
    take_until::<_, _, OracleError<'_>>(" and ")
        .parse(type_phrase)
        .is_ok()
}

fn parse_static_compound_subject_prefix(
    lower: &str,
) -> Option<(usize, TargetFilter, TargetFilter)> {
    let (remaining, (first_filter, second_filter)) = (
        alt((
            value(
                TargetFilter::OriginalController,
                tag::<_, _, OracleError<'_>>("you and "),
            ),
            value(TargetFilter::SelfRef, tag("~ and ")),
        )),
        alt((
            value(
                TargetFilter::ScopedPlayer,
                tag::<_, _, OracleError<'_>>("that player each "),
            ),
            value(TargetFilter::Player, tag("target opponent each ")),
            value(TargetFilter::Player, tag("target player each ")),
            value(TargetFilter::ParentTarget, tag("that creature each ")),
        )),
    )
        .parse(lower)
        .ok()?;
    Some((lower.len() - remaining.len(), first_filter, second_filter))
}

fn parse_dynamic_compound_subject_prefix(
    lower: &str,
) -> Option<(usize, TargetFilter, TargetFilter)> {
    let (remaining, first_filter) = alt((
        value(
            TargetFilter::OriginalController,
            tag::<_, _, OracleError<'_>>("you and "),
        ),
        value(TargetFilter::SelfRef, tag("~ and ")),
    ))
    .parse(lower)
    .ok()?;
    let (second_consumed, second_filter) =
        parse_controlled_creature_each_second_subject(remaining)?;
    Some((
        lower.len() - remaining.len() + second_consumed,
        first_filter,
        second_filter,
    ))
}

fn parse_compound_subject_prefix(lower: &str) -> Option<(usize, TargetFilter, TargetFilter)> {
    parse_static_compound_subject_prefix(lower)
        .or_else(|| parse_dynamic_compound_subject_prefix(lower))
}

/// CR 109.5 + CR 608.2c: True when `text` opens with a compound-subject
/// distribution prefix. The distributor binds an explicit recipient on EVERY
/// link of the chain it produces, so the chunk-loop anaphoric rewriter
/// (`replace_target_with_parent`) must NOT re-target the head — that would
/// clobber the distributor's authoritative binding (e.g. Gogo's leading
/// `SelfRef` link flipped to `ParentTarget`). This guard lets the finalize
/// path skip anaphoric re-targeting for distributed chains.
fn text_is_compound_subject_distribution(text: &str) -> bool {
    parse_compound_subject_prefix(&text.to_lowercase()).is_some()
}

fn try_parse_compound_subject_each(
    text: &str,
    ctx: &mut ParseContext,
) -> Option<ParsedEffectClause> {
    let lower = text.to_lowercase();
    // Compose the prefix through the shared grammar in
    // `parse_compound_subject_prefix` (kept in lockstep with the chunk-loop guard
    // `text_is_compound_subject_distribution`).
    let (consumed_prefix, first_filter, second_filter) =
        parse_compound_subject_prefix(lower.as_str())?;

    // Slice the original-case body text using the consumed offset.
    let body_text = text[consumed_prefix..].trim();
    if body_text.is_empty() {
        return None;
    }

    // Parse the body once. Re-using `parse_effect_chain_with_context`
    // composes the existing body parser surface (Token, Draw, etc.).
    let mut body_ctx = ctx.clone();
    let parsed_body = parse_effect_chain_with_context(body_text, AbilityKind::Spell, &mut body_ctx);

    // Reject Unimplemented bodies — distribution is meaningless when the body
    // didn't parse, and the caller's fallback (Unimplemented + diagnostic)
    // is more informative than silently emitting two Unimplemented halves.
    if matches!(*parsed_body.effect, Effect::Unimplemented { .. }) {
        return None;
    }

    // Build the two halves. Each half is a clone of the parsed body with its
    // recipient field rewritten. Effects without a `TargetFilter`-typed
    // recipient are unsupported — return None to fall through to Unimplemented.
    let mut half_a = parsed_body.clone();
    if !rewrite_recipient_chain(&mut half_a, &first_filter) {
        return None;
    }
    let mut half_b = parsed_body;
    if !rewrite_recipient_chain(&mut half_b, &second_filter) {
        return None;
    }

    // Compose: Half A is the top-level effect; Half B is its sub_ability.
    // The runtime `resolve_ability_chain` walks parent → sub_ability in
    // printed order, matching the "you ..., then that player ..." reading.
    //
    // CR 608.2c: distribution over a multi-link body — half B's chain attaches
    // at the TAIL of half A's chain so half A's own deeper links (e.g. a
    // MustAttack rider) survive. A plain overwrite would clobber them.
    let mut tail = &mut half_a;
    while tail.sub_ability.is_some() {
        tail = tail.sub_ability.as_mut().unwrap();
    }
    tail.sub_ability = Some(Box::new(half_b));

    Some(ParsedEffectClause {
        effect: *half_a.effect,
        duration: half_a.duration,
        sub_ability: half_a.sub_ability,
        distribute: None,
        multi_target: None,
        condition: half_a.condition,
        optional: false,
        unless_pay: None,
    })
}

/// CR 109.5 + CR 115.1: Rewrite the recipient slot on EVERY link of an
/// ability chain to `filter`. Walks parent -> sub_ability so a multi-link
/// body (e.g. GenericEffect[pump+haste] -> GenericEffect[MustAttack]) has
/// every link retargeted, not just the head. Returns `false` if ANY link
/// has no recognized recipient slot, in which case the caller drops the
/// (freshly-cloned) definition and falls through to Unimplemented.
///
/// Atomic-mutation contract: callers MUST pass a freshly-cloned
/// `AbilityDefinition`; partial mutation on a `false` return is dropped
/// with the clone.
fn rewrite_recipient_chain(def: &mut AbilityDefinition, filter: &TargetFilter) -> bool {
    let mut cursor: Option<&mut AbilityDefinition> = Some(def);
    while let Some(node) = cursor {
        if !rewrite_recipient_on_link(node, filter) {
            return false;
        }
        cursor = node.sub_ability.as_deref_mut();
    }
    true
}

/// CR 109.5 + CR 115.1: Rewrite one link's recipient (`TargetFilter`-typed
/// slot) to `filter`. Returns `false` when the link's effect has no
/// recognized recipient slot.
///
/// Covers the recipient-bearing effects produced by parsing "<A> and <B>
/// each Y" bodies — Token (`owner`), Draw/Discard/Mill (`target`), Pump
/// (`target`), GenericEffect (`Option<target>`). Extending to a new effect
/// family is one match arm per family.
fn rewrite_recipient_on_link(def: &mut AbilityDefinition, filter: &TargetFilter) -> bool {
    match def.effect.as_mut() {
        Effect::Token { owner, .. } => {
            *owner = filter.clone();
            true
        }
        Effect::Draw { target, .. }
        | Effect::Discard { target, .. }
        | Effect::Mill { target, .. } => {
            *target = filter.clone();
            true
        }
        // CR 611.2c: continuous P/T + keyword effect — recipient is a plain TargetFilter.
        Effect::Pump { target, .. } => {
            *target = filter.clone();
            true
        }
        // GenericEffect carries the unified pump+haste mods AND the MustAttack
        // rider; its recipient is Option<TargetFilter>. The top-level `target`
        // is dispositive at the runtime register_transient_effect catch-all, but
        // each static ability's `affected` set (the continuous-effect subject)
        // must agree per CR 611.2c so the distributed continuous effect applies
        // to the SAME object as its link recipient. Only an unbound / self /
        // anaphoric default (`None` or `SelfRef`) is rebound — an explicit
        // typed `affected` (e.g. "creatures you control") is preserved.
        Effect::GenericEffect {
            target,
            static_abilities,
            ..
        } => {
            *target = Some(filter.clone());
            for static_def in static_abilities.iter_mut() {
                match &static_def.affected {
                    None | Some(TargetFilter::SelfRef) => {
                        static_def.affected = Some(filter.clone());
                    }
                    Some(_) => {}
                }
            }
            true
        }
        // Any other effect family is out of scope for compound-subject
        // distribution at this entry point. Returning false keeps the
        // detector tight and prevents silent misparse on bodies whose
        // recipient binding is encoded differently (e.g. nested filter props).
        _ => false,
    }
}

/// CR 614.1a + CR 701.5 + CR 608.2c: Detect the "exile-after-cast/counter rider"
/// structural pattern — "if that spell would be put into [a/the/its owner's]
/// graveyard, exile it instead". This is the trailing rider clause that
/// follows a `CastFromZone` or `Counter` effect (Toshiro Umezawa,
/// Defabricate-class, Snapcaster sibling cards).
///
/// In compound triggers with a typed subject ("Whenever a creature an opponent
/// controls dies, you may cast target instant card from your graveyard. If
/// that spell would be put into a graveyard, exile it instead.") the bare
/// "it" in the rider clause must bind to the cast spell (the parent target),
/// not to the triggering source (the dying creature). This detector relaxes
/// the `typed_trigger_subject` guard for that specific rider shape so the
/// pronoun-rewrite can lift "it" → `ParentTarget` and the rider matches the
/// established `def_tree_has_exile_parent_rider` shape that
/// `swallow_check.rs` already recognises.
fn is_exile_after_spell_rider_clause(lower: &str) -> bool {
    // Single nom combinator chain over the rider pattern. Independent
    // dimensions (graveyard determiner, "exile it" / "exile that spell"
    // anaphor) are composed via inner alts; no string heuristics.
    use nom::branch::alt;
    use nom::bytes::complete::tag;
    use nom::combinator::all_consuming;
    use nom::Parser;
    let trimmed = lower.trim().trim_end_matches('.').trim();
    all_consuming((
        tag::<_, _, OracleError<'_>>("if that spell would be put into "),
        alt((
            tag::<_, _, OracleError<'_>>("a graveyard"),
            tag("the graveyard"),
            tag("its owner's graveyard"),
            tag("your graveyard"),
            tag("an opponent's graveyard"),
        )),
        tag(", "),
        alt((
            tag::<_, _, OracleError<'_>>("exile it instead"),
            tag("exile that card instead"),
            tag("exile that spell instead"),
        )),
    ))
    .parse(trimmed)
    .is_ok()
}

/// CR 614.1a + CR 608.2n + CR 607.2b: Detect the resolving-spell exile rider —
/// "exile it instead of putting it into a graveyard as it resolves". This is the
/// trigger BODY of a `WhenAPlayerCasts` trigger (Rod of Absorption), distinct
/// from the post-cast rider clause `is_exile_after_spell_rider_clause` ("if that
/// spell would be put into a graveyard, exile it instead") that trails a
/// `CastFromZone`/`Counter` effect.
///
/// Composed as a single nom chain over the independent axes: the bare anaphor
/// ("it" / "that spell") and the graveyard determiner. "a graveyard" /
/// "its owner's graveyard" / "a player's graveyard" are leaf variants of the
/// same slot. The trailing "as it resolves" is the resolution-timing marker that
/// distinguishes this from the immediate "exile it" zone-move.
fn try_parse_exile_resolving_spell_instead_of_graveyard(lower: &str) -> bool {
    use nom::branch::alt;
    use nom::bytes::complete::tag;
    use nom::combinator::all_consuming;
    use nom::Parser;
    let trimmed = lower.trim().trim_end_matches('.').trim();
    all_consuming((
        tag::<_, _, OracleError<'_>>("exile "),
        alt((tag("it"), tag("that spell"), tag("that card"))),
        tag(" instead of putting it into "),
        alt((
            tag("a graveyard"),
            tag("the graveyard"),
            tag("its owner's graveyard"),
            tag("a player's graveyard"),
            tag("their graveyard"),
        )),
        tag(" as it resolves"),
    ))
    .parse(trimmed)
    .is_ok()
}

/// Check if text contains anaphoric pronouns referencing a previously mentioned object.
/// Unlike `contains_object_pronoun`, this handles word boundaries at end-of-string
/// (e.g., "counter on it" where "it" is the last word).
///
/// CR 608.2c: bare anaphoric pronouns binding to a prior clause. Detection runs on
/// the `parse_word_bounded` combinator scanned at every word boundary — no `find()`
/// heuristic. The bare-object-pronoun set is sourced from `is_bare_object_pronoun`
/// so it has a single authority; the demonstratives are matched as two-word phrases.
fn has_anaphoric_reference(lower: &str) -> bool {
    // Single-word object pronouns (it/itself/him/himself/her/herself/them/themselves).
    const PRONOUNS: [&str; 8] = [
        "it",
        "itself",
        "him",
        "himself",
        "her",
        "herself",
        "them",
        "themselves",
    ];
    // Two-word demonstrative anaphors ("that creature", "those cards", ...).
    const DEMONSTRATIVES: [&str; 4] = [
        "that creature",
        "that card",
        "those cards",
        "that permanent",
    ];
    debug_assert!(
        PRONOUNS.iter().all(|p| is_bare_object_pronoun(p)),
        "PRONOUNS must stay in sync with is_bare_object_pronoun"
    );

    let mut remaining = lower;
    while !remaining.is_empty() {
        let matched = PRONOUNS
            .iter()
            .chain(DEMONSTRATIVES.iter())
            .any(|w| super::oracle_target::parse_word_bounded(remaining, w).is_ok());
        if matched {
            return true;
        }
        // structural: not dispatch — advance to the next word boundary so the
        // `parse_word_bounded` combinator can be retried at each position
        // (the `scan_timing_restrictions` scan-loop idiom).
        remaining = match remaining.find(' ') {
            Some(i) => remaining[i + 1..].trim_start(),
            None => "",
        };
    }
    false
}

/// CR 608.2c: "that player" / "the player" after an earlier explicit player
/// target binds to that chosen player, not to the triggering-event player and
/// not to the controller of an object target.
fn has_player_anaphoric_reference(lower: &str) -> bool {
    nom_primitives::scan_at_word_boundaries(lower, |input| {
        alt((
            tag::<_, _, OracleError<'_>>("that player"),
            tag("the player"),
        ))
        .parse(input)
    })
    .is_some()
}

fn explicit_any_target_clause(effect: &Effect, lower: &str) -> bool {
    matches!(effect.target_filter(), Some(TargetFilter::Any))
        && nom_primitives::scan_contains(lower, "any target")
}

fn rewrite_triggering_spell_controller_to_parent_target_controller(effect: &mut Effect) {
    each_target_filter_mut(effect, &mut |filter| {
        if matches!(filter, TargetFilter::TriggeringSpellController) {
            *filter = TargetFilter::ParentTargetController;
        }
    });
}

fn replace_definition_targets_with_parent(def: &mut AbilityDefinition) {
    replace_target_with_parent(&mut def.effect);
    if let Some(sub) = def.sub_ability.as_mut() {
        replace_definition_targets_with_parent(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        replace_definition_targets_with_parent(else_branch);
    }
    for mode in &mut def.mode_abilities {
        replace_definition_targets_with_parent(mode);
    }
}

/// Replace the target filter on an effect with ParentTarget.
/// Used for anaphoric "it"/"that creature" references in compound sub-effects.
fn replace_target_with_parent(effect: &mut Effect) {
    // CR 115.10a: a target carrying the `Another` property excludes the
    // referenced object by definition, so it is never the parent target — an
    // anaphor rewrite must not collapse it to ParentTarget (Fumble: "…attach
    // them to another creature", where the attach destination is a fresh,
    // distinct choice, not the bounced creature).
    if let Some(TargetFilter::Typed(tf)) = effect.target_filter() {
        if tf
            .properties
            .iter()
            .any(|p| matches!(p, FilterProp::Another))
        {
            return;
        }
    }
    match effect {
        Effect::Sacrifice { target, .. }
            if target_filter_controller_ref(target)
                == Some(ControllerRef::ParentTargetController) => {}
        Effect::Sacrifice { target, .. } if matches!(target, TargetFilter::SelfRef) => {
            *target = TargetFilter::ParentTarget;
        }
        // CR 701.26a/b: only single-target tap/untap carries a rewritable target.
        Effect::SetTapState {
            scope: EffectScope::Single,
            target,
            ..
        }
        | Effect::Destroy { target, .. }
        | Effect::GainControl { target }
        | Effect::Fight { target, .. }
        | Effect::Bounce { target, .. }
        | Effect::DealDamage { target, .. }
        | Effect::Pump { target, .. }
        | Effect::Counter { target, .. }
        | Effect::Transform { target, .. }
        | Effect::Connive { target, .. }
        | Effect::PhaseOut { target }
        | Effect::ForceBlock { target }
        | Effect::ForceAttack { target, .. }
            if !matches!(target, TargetFilter::ParentTargetController) =>
        {
            *target = TargetFilter::ParentTarget;
        }
        Effect::Attach { target, .. } if !matches!(target, TargetFilter::LastCreated) => {
            *target = TargetFilter::ParentTarget;
        }
        Effect::UnattachAll { target, .. } if !matches!(target, TargetFilter::LastCreated) => {
            *target = TargetFilter::ParentTarget;
        }
        Effect::PutCounter { target, .. } | Effect::RemoveCounter { target, .. } => {
            *target = TargetFilter::ParentTarget;
        }
        // CR 608.2c: a self-referential zone change ("Exile Venture Forth with
        // three time counters on it") names the source via `~` (SelfRef); the
        // "on it" anaphor is a trailing counter modifier, not the moved object.
        // Leave SelfRef intact so the source still moves itself.
        Effect::ChangeZone { target, .. } | Effect::ChangeZoneAll { target, .. }
            if !matches!(target, TargetFilter::SelfRef) =>
        {
            *target = TargetFilter::ParentTarget;
        }
        // CR 608.2c (issue #327): A `GenericEffect` carries both an outer
        // `target` slot (used by the runtime as the broadcast filter) AND
        // per-static `affected` slots (used by the layer system to decide
        // which objects receive each modification). When this rewriter is
        // invoked for an anaphoric "It" clause that follows a typed earlier
        // clause, the parser-emitted `affected: SelfRef` on inner static
        // definitions is the same pronoun-resolution mistake as the outer
        // `target: None` — both must rewrite to ParentTarget so the granted
        // modifications attach to the same chosen object. Without this,
        // chained "Choose → grant → grant" abilities (Skrelv, Defector Mite;
        // similar siblings) emit a static_def pinned to SelfRef that the
        // runtime applies to the source rather than the chosen target.
        Effect::GenericEffect {
            target,
            static_abilities,
            ..
        } => {
            *target = Some(TargetFilter::ParentTarget);
            for static_def in static_abilities {
                if matches!(static_def.affected, Some(TargetFilter::SelfRef)) {
                    static_def.affected = Some(TargetFilter::ParentTarget);
                }
            }
        }
        Effect::CreateDelayedTrigger { effect, .. } => {
            replace_definition_targets_with_parent(effect);
        }
        _ => {
            // Effects without a target field (Draw, GainLife, etc.) stay as-is.
            // ParentTarget is handled by the sub_ability chain's target propagation.
        }
    }
}

/// CR 608.2c: rebind an anaphoric pronoun to the source object when a preceding
/// clause named it via `~` (parsed as a `SelfRef`-targeted effect — e.g.
/// "exile ~, then return him to the battlefield transformed"). Sibling of
/// `replace_target_with_parent`, but assigns `TargetFilter::SelfRef`.
///
/// Only the effect arms reachable for the "name ~ then refer back" class are
/// populated: zone changes (the issue card) and `Transform` for the DFC family.
/// Arms with `ParentTargetController`/`LastCreated` guards (`Sacrifice`,
/// `Attach`) are intentionally omitted — those guards are meaningless for a
/// `SelfRef` rebind, and no card in this class reaches them.
fn replace_target_with_self(effect: &mut Effect) {
    match effect {
        Effect::ChangeZone { target, .. } | Effect::ChangeZoneAll { target, .. } => {
            *target = TargetFilter::SelfRef;
        }
        Effect::Transform { target, .. } => {
            *target = TargetFilter::SelfRef;
        }
        _ => {
            // Effects without a target field, or outside this anaphor class,
            // stay as-is.
        }
    }
}

fn replace_player_anaphor_with_parent_target(effect: &mut Effect) {
    each_target_filter_mut(effect, &mut |filter| {
        if matches!(
            filter,
            TargetFilter::TriggeringPlayer | TargetFilter::ParentTargetController
        ) {
            *filter = TargetFilter::ParentTarget;
        }
    });
}

/// CR 608.2k (issue #319): True when `ctx` carries a *typed* trigger subject
/// (a non-source object the trigger condition explicitly named, e.g.
/// `Typed{Subtype:Elf}` from "Whenever an Elf you control dies"). In this
/// context, bare pronouns "it"/"them"/etc. correctly resolve to
/// `TriggeringSource` via `resolve_pronoun_target` — the chunk-level
/// `replace_target_with_parent` rewriter must NOT clobber them back to
/// `ParentTarget`. SelfRef/Any/None subjects fall through to the legacy
/// rewrite path so spell-context anaphors (Dispatch, kicker-instead chains)
/// still inherit the parent target.
fn ctx_has_typed_trigger_subject(ctx: &ParseContext) -> bool {
    fn is_player_subject(subject: &TargetFilter) -> bool {
        matches!(
            subject,
            TargetFilter::Player
                | TargetFilter::Controller
                | TargetFilter::AllPlayers
                | TargetFilter::SpecificPlayer { .. }
                | TargetFilter::ScopedPlayer
        ) || matches!(
            subject,
            TargetFilter::Typed(TypedFilter {
                type_filters,
                controller: Some(_),
                properties,
            }) if type_filters.is_empty() && properties.is_empty()
        )
    }

    matches!(
        &ctx.subject,
        Some(subject)
            if !matches!(subject, TargetFilter::SelfRef | TargetFilter::Any)
                && !is_player_subject(subject)
    )
}

fn replace_fight_subject_with_parent_if_anaphoric_subject(
    lower: &str,
    effect: &mut Effect,
) -> bool {
    let is_anaphoric_subject = alt((
        tag::<_, _, OracleError<'_>>("it fights "),
        tag("that creature fights "),
        tag("that permanent fights "),
    ))
    .parse(lower)
    .is_ok();
    if !is_anaphoric_subject {
        return false;
    }

    if let Effect::Fight { subject, .. } = effect {
        *subject = TargetFilter::ParentTarget;
        true
    } else {
        false
    }
}

/// Check if an effect has a `Typed(...)` target filter (not SelfRef/ParentTarget/Any).
/// Used to guard anaphoric replacement scope — prevents false positives when a
/// pronoun clause follows a conditional effect without a typed target.
///
/// CR 608.2k: An anaphor in a later clause of a multi-step ability binds to the
/// typed target chosen for an earlier clause. The predicate gates the rebinding
/// so non-targeting prior clauses (e.g. `Effect::Draw`, untargeted `LoseLife`)
/// don't capture a later "it" reference. `Effect::GenericEffect` carries an
/// `Option<TargetFilter>` (becomes/animate/transform-class clauses such as
/// "Target legendary creature becomes a God"); when populated with a typed
/// filter, a following anaphor refers to the same chosen object.
fn has_typed_target(effect: &Effect) -> bool {
    matches!(
        effect,
        Effect::PutCounter {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::Pump {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::DealDamage {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::Destroy {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::SetTapState {
            // CR 701.26a/b: only single-target tap/untap exposes a typed target.
            scope: EffectScope::Single,
            target: TargetFilter::Typed(_),
            ..
        } | Effect::Bounce {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::GainControl {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::Attach {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::UnattachAll {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::ChangeZone {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::ChangeZoneAll {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::GenericEffect {
            target: Some(TargetFilter::Typed(_)),
            ..
        } | Effect::TargetOnly {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::CastFromZone {
            target: TargetFilter::Typed(_),
            ..
        } | Effect::Counter {
            target: TargetFilter::Typed(_),
            ..
        }
        // CR 608.2c + CR 701.57a / CR 702.85a: An `ExileFromTopUntil { NextMatches }`
        // introduces a single object (the just-exiled matching card) that the resolver
        // threads into the sub-ability chain (exile_from_top_until.rs sub_clone.targets).
        // A following sibling clause's bare anaphor "it" ("Put three time counters on it")
        // binds to that object, so this prior clause counts as object-introducing for the
        // chunk-loop `replace_target_with_parent` rewrite. CumulativeThreshold is excluded
        // — it introduces a card *set*, not a single referent.
        | Effect::ExileFromTopUntil {
            until: UntilCondition::NextMatches { .. },
            ..
        }
    )
}

fn target_filter_is_explicit_player_target(filter: &TargetFilter) -> bool {
    if filter.is_context_ref() {
        return false;
    }
    match filter {
        TargetFilter::Player | TargetFilter::SpecificPlayer { .. } => true,
        TargetFilter::Typed(tf) => tf.type_filters.is_empty(),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().any(target_filter_is_explicit_player_target)
        }
        TargetFilter::Not { filter } => target_filter_is_explicit_player_target(filter),
        _ => false,
    }
}

/// CR 608.2c: An earlier clause whose target filter is a compound shape
/// (`And` / `Or` wrapping a `Typed` branch) still introduces a typed object
/// referent for a sibling bare-"it" anaphor.
///
/// The leaf `TargetFilter::Typed` check used by `has_typed_target` doesn't
/// see compound shapes — so a chain whose originating clause selects a
/// creature via `And[Typed(Creature), ExiledBySource]` (Emperor of Bones'
/// "put a creature card exiled with this creature onto the battlefield")
/// would fall back to `SelfRef` for the trailing "it gains haste. sacrifice
/// it." This helper recognizes those compound filters.
///
/// Quantifier semantics: `And` uses `.any()` — one `Typed` branch suffices
/// because every And-branch must hold during resolution, so a Typed branch
/// pins the referent kind. `Or` uses `.all()` — every branch must be typed
/// for a bare "it" to have a single referent kind across the player's
/// choice. `Not` introduces no positive referent.
fn filter_introduces_typed_object(filter: &TargetFilter) -> bool {
    match filter {
        TargetFilter::Typed(_) => true,
        TargetFilter::And { filters } => filters.iter().any(filter_introduces_typed_object),
        TargetFilter::Or { filters } => filters.iter().all(filter_introduces_typed_object),
        TargetFilter::Not { .. } => false,
        _ => false,
    }
}

fn has_explicit_player_target(effect: &Effect) -> bool {
    effect
        .target_filter()
        .is_some_and(target_filter_is_explicit_player_target)
}

/// CR 608.2c: Variant of `has_typed_target` that accepts compound filter
/// shapes (`And` / `Or` wrapping a `Typed`). Effect-kind whitelist mirrors
/// `has_typed_target` exactly — only the filter-shape recognition is
/// widened. Used by the chain walk so a `ChangeZone` whose target is
/// `And[Typed(Creature), ExiledBySource]` (Emperor of Bones) counts as
/// introducing the moved card as the anaphor referent.
///
/// `has_typed_target` is kept as the leaf check; its other call sites
/// (e.g., the immediate-prior-clause anaphor rewrite) depend on the
/// leaf-only semantics.
fn has_typed_target_widened(effect: &Effect) -> bool {
    let target = match effect {
        Effect::PutCounter { target, .. }
        | Effect::Pump { target, .. }
        | Effect::DealDamage { target, .. }
        | Effect::Destroy { target, .. }
        // CR 701.26a/b: only single-target tap/untap exposes a widenable target.
        | Effect::SetTapState {
            scope: EffectScope::Single,
            target,
            ..
        }
        | Effect::Bounce { target, .. }
        | Effect::GainControl { target, .. }
        | Effect::Attach { target, .. }
        | Effect::UnattachAll { target, .. }
        | Effect::ChangeZone { target, .. }
        | Effect::ChangeZoneAll { target, .. }
        | Effect::TargetOnly { target, .. }
        | Effect::CastFromZone { target, .. }
        | Effect::Counter { target, .. } => target,
        Effect::GenericEffect {
            target: Some(target),
            ..
        } => target,
        // ExileFromTopUntil { NextMatches } has no compound-filter axis to
        // widen — the referent is the just-exiled card, not a TargetFilter.
        Effect::ExileFromTopUntil {
            until: UntilCondition::NextMatches { .. },
            ..
        } => return true,
        _ => return false,
    };
    filter_introduces_typed_object(target)
}

/// CR 608.2c: Does an earlier clause in the chain establish a typed (chosen)
/// object referent that the current anaphor binds to — looking PAST intermediate
/// clauses that merely carry that referent forward via `ParentTarget`?
///
/// `has_typed_target` alone only inspects the immediately-preceding clause, which
/// breaks the "target X. <do something to it>. <grant on it>" shape when the
/// middle clause is itself an anaphor: Nissa, Who Shakes the World — "Put three
/// +1/+1 counters on up to one target land you control. Untap it. It becomes a
/// 0/0 Elemental …" — has the typed land two clauses back, with the `Untap it`
/// (`ParentTarget`) clause in between. The scan walks back, skipping
/// `ParentTarget`-carrier clauses (they continue the same chosen referent), and
/// succeeds at the originating typed clause. It stops at the first clause that is
/// conditional or is neither typed nor a `ParentTarget` carrier, so it never
/// reaches across an unrelated referent.
fn chain_has_prior_typed_referent(clauses: &[ClauseIr]) -> bool {
    for prev in clauses.iter().rev() {
        if prev.condition.is_some() {
            return false;
        }
        // CR 608.2c: Chain clauses resolve in written order; an earlier typed referent is visible to a later anaphor.
        // `has_typed_target_widened` mirrors `has_typed_target`'s effect-kind
        // whitelist but also accepts a compound (`And` / `Or` over `Typed`)
        // filter as a typed-referent introducer (Emperor of Bones'
        // `And[Typed(Creature), ExiledBySource]`). The narrower
        // `has_typed_target` is still used at its other call sites
        // (immediate-prior-clause anaphor rewrite) because they depend on
        // the leaf-only semantics.
        if has_typed_target_widened(&prev.parsed.effect) {
            return true;
        }
        if matches!(
            prev.parsed.effect.target_filter(),
            Some(TargetFilter::ParentTarget)
        ) {
            continue;
        }
        return false;
    }
    false
}

/// CR 608.2c + CR 601.2a: Does the chain's prior referent come from an explicit
/// target SELECTION (`Effect::TargetOnly`) rather than an exile/impulse publisher
/// (`ExileTop`, `ExileFromTopUntil`, `ChangeZone`, token creation)? Emry, Lurker
/// in the Loch — "Choose target artifact card in your graveyard. You may cast
/// that card this turn." — selects its referent, so the anaphor binds to that
/// chosen card (`CastFromZone { ParentTarget }`). An impulse publisher's anaphor
/// is the tracked exile set and must stay a `PlayFromExile { TrackedSet }` grant
/// (Territorial Bruntar's `ExileFromTopUntil` referent is whitelisted by
/// `has_typed_target_widened`, so this stricter check is what excludes it). The
/// walk mirrors `chain_has_prior_typed_referent`: it skips `ParentTarget`-carrier
/// clauses (which continue the same chosen referent) and stops at the first
/// conditional clause or non-carrier referent.
fn chain_prior_referent_is_chosen_target(clauses: &[ClauseIr]) -> bool {
    for prev in clauses.iter().rev() {
        if prev.condition.is_some() {
            return false;
        }
        if matches!(prev.parsed.effect, Effect::TargetOnly { .. }) {
            return true;
        }
        if has_typed_target_widened(&prev.parsed.effect) {
            // A typed referent that is not a bare target selection (an exile/
            // zone publisher, or pump/destroy/etc. of a target) is not an
            // Emry-style chosen graveyard pick — its "that card" anaphor keeps
            // the impulse/tracked-set grant.
            return false;
        }
        if matches!(
            prev.parsed.effect.target_filter(),
            Some(TargetFilter::ParentTarget)
        ) {
            continue;
        }
        return false;
    }
    false
}

fn chain_has_prior_player_target_referent(clauses: &[ClauseIr]) -> bool {
    for prev in clauses.iter().rev() {
        if prev.condition.is_some() {
            return false;
        }
        if has_explicit_player_target(&prev.parsed.effect) {
            return true;
        }
        if matches!(
            prev.parsed.effect.target_filter(),
            Some(TargetFilter::ParentTarget | TargetFilter::ParentTargetController)
        ) {
            continue;
        }
        return false;
    }
    false
}

fn lower_subject_predicate_ast(
    subject: SubjectPhraseAst,
    predicate: PredicateAst,
    ctx: &mut ParseContext,
) -> ParsedEffectClause {
    // CR 115.1d: Propagate multi_target from the subject phrase (e.g., "any number of
    // target creatures", "up to two target artifacts") into the lowered clause so the
    // targeting system creates the correct number of target slots at cast time.
    let multi_target = subject.multi_target.clone();

    match predicate {
        PredicateAst::Continuous {
            effect,
            duration,
            sub_ability,
        } => ParsedEffectClause {
            effect,
            duration,
            sub_ability,
            distribute: None,
            multi_target,
            condition: None,
            optional: subject.is_optional,
            unless_pay: None,
        },
        PredicateAst::Become {
            effect,
            duration,
            sub_ability,
        } => ParsedEffectClause {
            effect,
            duration,
            sub_ability,
            distribute: None,
            multi_target,
            condition: None,
            optional: subject.is_optional,
            unless_pay: None,
        },
        PredicateAst::Restriction { effect, duration } => ParsedEffectClause {
            effect,
            duration,
            sub_ability: None,
            distribute: None,
            multi_target,
            condition: None,
            optional: subject.is_optional,
            unless_pay: None,
        },
        PredicateAst::ImperativeFallback { text } => {
            let pred_lower = text.to_lowercase();
            if matches!(pred_lower.as_str(), "shuffle" | "shuffles")
                && matches!(
                    subject.affected,
                    TargetFilter::Player | TargetFilter::Controller
                )
            {
                return parsed_clause(Effect::Shuffle {
                    target: subject.affected,
                });
            }
            // CR 701.20a: "<player> reveals cards from the top of their library
            // until they reveal a [filter]" — third-person form. The subject
            // (e.g., "its controller", "that player", "target opponent") was
            // extracted into `subject.affected` and identifies whose library is
            // revealed. Must be checked BEFORE the RevealTop fallback below,
            // which would otherwise greedy-match the "reveals/top/library" verbs.
            {
                let pred_tp = TextPair::new(text.as_str(), pred_lower.as_str());
                if let Some(clause) =
                    try_parse_exile_from_top_until(pred_tp, subject.affected.clone())
                {
                    return clause;
                }
                if let Some(clause) = try_parse_reveal_until(pred_tp, subject.affected.clone()) {
                    return clause;
                }
            }
            // CR 701.20a: "<player> reveals the top [N] card(s) of their library"
            if alt((tag::<_, _, OracleError<'_>>("reveal "), tag("reveals ")))
                .parse(pred_lower.as_str())
                .is_ok()
                && scan_contains_phrase(&pred_lower, "top")
                && scan_contains_phrase(&pred_lower, "library")
            {
                // Delegate to nom combinator (input already lowercase from pred_lower).
                let count = if let Some(after_top) = strip_after(&pred_lower, "top ") {
                    nom_primitives::parse_number
                        .parse(after_top)
                        .map(|(_, n)| n)
                        .unwrap_or(1)
                } else {
                    1
                };
                return parsed_clause(Effect::RevealTop {
                    player: subject.affected,
                    count,
                });
            }
            // CR 701.10a: "<player> exiles the top [N] card(s) of their library"
            if alt((tag::<_, _, OracleError<'_>>("exile "), tag("exiles ")))
                .parse(pred_lower.as_str())
                .is_ok()
                && scan_contains_phrase(&pred_lower, "top")
                && scan_contains_phrase(&pred_lower, "library")
            {
                let count = parse_subject_exile_top_count(&pred_lower);
                return parsed_clause(Effect::ExileTop {
                    player: subject.affected,
                    count,
                    face_down: false,
                });
            }
            // CR 701.40a + CR 608.2c: "<player> manifests the top [N] card(s) of
            // their library" — Reality Shift's "its controller manifests the top
            // card of their library" routes through this arm so the acting
            // player is bound to `subject.affected` (e.g., ParentTargetController)
            // rather than the default Controller.
            if alt((tag::<_, _, OracleError<'_>>("manifest "), tag("manifests ")))
                .parse(pred_lower.as_str())
                .is_ok()
                && scan_contains_phrase(&pred_lower, "top")
                && scan_contains_phrase(&pred_lower, "library")
            {
                let count = if let Some(after_top) = strip_after(&pred_lower, "top ") {
                    let n = nom_primitives::parse_number
                        .parse(after_top)
                        .map(|(_, n)| n as i32)
                        .unwrap_or(1);
                    QuantityExpr::Fixed { value: n }
                } else {
                    QuantityExpr::Fixed { value: 1 }
                };
                return parsed_clause(Effect::Manifest {
                    target: subject.affected,
                    count,
                });
            }
            let mut clause = lower_imperative_clause(&text, ctx);
            if matches!(
                &clause.effect,
                Effect::ChooseFromZone {
                    filter: Some(_),
                    ..
                }
            ) && !matches!(
                subject.affected,
                TargetFilter::Controller | TargetFilter::SelfRef
            ) {
                return parsed_clause(Effect::Unimplemented {
                    name: "choose".to_string(),
                    description: Some(text.clone()),
                });
            }
            if let Some(player_target) = subject
                .target
                .as_ref()
                .filter(|filter| target_filter_can_target_player(filter))
            {
                if matches!(
                    clause.effect,
                    Effect::ChangeZone { .. } | Effect::ChangeZoneAll { .. }
                ) {
                    let mut sub_ability =
                        AbilityDefinition::new(AbilityKind::Spell, clause.effect.clone());
                    sub_ability.sub_ability = clause.sub_ability;
                    return ParsedEffectClause {
                        effect: Effect::TargetOnly {
                            target: player_target.clone(),
                        },
                        duration: clause.duration,
                        sub_ability: Some(Box::new(sub_ability)),
                        distribute: None,
                        multi_target: subject.multi_target,
                        condition: None,
                        optional: subject.is_optional,
                        unless_pay: None,
                    };
                }
            }
            if matches!(clause.effect, Effect::Explore) {
                let subject_filter = if subject.inherits_parent {
                    TargetFilter::ParentTarget
                } else {
                    subject.target.as_ref().unwrap_or(&subject.affected).clone()
                };

                if subject.target.is_some()
                    || matches!(subject.affected, TargetFilter::TriggeringSource)
                {
                    let mut explore = AbilityDefinition::new(AbilityKind::Spell, Effect::Explore);
                    explore.sub_ability = clause.sub_ability;
                    return ParsedEffectClause {
                        effect: Effect::TargetOnly {
                            target: subject_filter,
                        },
                        duration: clause.duration,
                        sub_ability: Some(Box::new(explore)),
                        distribute: None,
                        multi_target: subject.multi_target,
                        condition: None,
                        optional: subject.is_optional,
                        unless_pay: None,
                    };
                }
                if subject.inherits_parent {
                    return clause;
                }

                if !matches!(subject.affected, TargetFilter::SelfRef) {
                    return ParsedEffectClause {
                        effect: Effect::ExploreAll {
                            filter: subject_filter,
                        },
                        duration: clause.duration,
                        sub_ability: clause.sub_ability,
                        distribute: None,
                        multi_target: subject.multi_target,
                        condition: None,
                        optional: subject.is_optional,
                        unless_pay: None,
                    };
                }
            }
            // CR 608.2c: Inject the subject's target into targeted effects that were
            // parsed via the imperative path (connive, phase out, force block, suspect).
            if let Some(wrapped) = wrap_target_subject_damage(clause.clone(), &subject) {
                return wrapped;
            }
            inject_subject_target(&mut clause.effect, &subject);
            // CR 109.4 + CR 608.2c (issue #534): When the subject phrase
            // resolved to the chosen player ("That player" after a
            // `Choose(Opponent)`/`Choose(Player)`), the predicate's possessive
            // "their" parses as `Owned { ScopedPlayer }` because `parse_target`
            // is scope-agnostic. Rebind those nested `ScopedPlayer` refs to
            // the chosen-player index so the effect's filter enumerates the
            // chosen player's zone at resolution time. Skullwinder exercises
            // this for `Effect::Bounce`; the rebind tree-walks the filter and
            // is a no-op when the filter has no `ScopedPlayer` ref.
            if let TargetFilter::Typed(tf) = &subject.affected {
                if let Some(ControllerRef::ChosenPlayer { index }) = tf.controller {
                    if let Effect::Bounce { target, .. } = &mut clause.effect {
                        rebind_owned_scope(target, index);
                    }
                }
            }
            if let Effect::PayCost { payer, .. } = &mut clause.effect {
                if matches!(
                    subject.affected,
                    TargetFilter::Controller
                        | TargetFilter::Player
                        | TargetFilter::ParentTargetController
                        | TargetFilter::ParentTargetOwner
                        | TargetFilter::TriggeringPlayer
                        | TargetFilter::TriggeringSpellController
                        | TargetFilter::TriggeringSpellOwner
                        | TargetFilter::DefendingPlayer
                        | TargetFilter::PostReplacementSourceController
                        | TargetFilter::PostReplacementDamageTarget
                        | TargetFilter::Owner
                        | TargetFilter::SpecificPlayer { .. }
                ) {
                    *payer = subject.affected.clone();
                }
            }
            // CR 113.10 + CR 702.16j: When the subject is a player-scope filter
            // ("you" → Controller) and the predicate produced a keyword grant
            // whose keywords are all player-applicable (currently only
            // Protection), retarget the static's `affected` from SelfRef (the
            // spell object) to the subject filter so the keyword is granted to
            // the player. This is the Teferi's-Protection-clause-2 hook.
            retarget_player_scoped_keyword_grant(&mut clause.effect, &subject.affected);
            if clause.multi_target.is_none() {
                clause.multi_target = subject.multi_target;
            }
            // CR 608.2c + CR 117.3a: Propagate the subject phrase's "may" modal
            // so the lowered ability is marked optional (e.g., "its controller
            // may search their library").
            if subject.is_optional {
                clause.optional = true;
            }
            clause
        }
    }
}

/// CR 113.10 + CR 702.16j: If `effect` is a `GenericEffect` whose static
/// modifications are all player-applicable AddKeyword grants and whose
/// `affected` is the default `SelfRef`, rewrite `affected` to `subject_filter`.
///
/// Only player-applicable keywords are rerouted; the list is intentionally
/// narrow because the overwhelming majority of "gain [keyword]" patterns target
/// a creature subject (and therefore belong on the object, not the controller).
/// Today only `Keyword::Protection(_)` qualifies — extend as other keywords
/// become legal on players.
fn retarget_player_scoped_keyword_grant(effect: &mut Effect, subject_filter: &TargetFilter) {
    let Effect::GenericEffect {
        static_abilities, ..
    } = effect
    else {
        return;
    };
    if !matches!(
        subject_filter,
        TargetFilter::Controller | TargetFilter::Player
    ) {
        return;
    }
    for sd in static_abilities.iter_mut() {
        if sd.affected != Some(TargetFilter::SelfRef) {
            continue;
        }
        if sd.modifications.is_empty() {
            continue;
        }
        let all_player_applicable = sd.modifications.iter().all(|m| match m {
            ContinuousModification::AddKeyword { keyword }
            | ContinuousModification::RemoveKeyword { keyword } => {
                is_player_applicable_keyword(keyword)
            }
            _ => false,
        });
        if all_player_applicable {
            sd.affected = Some(subject_filter.clone());
        }
    }
}

/// CR 113.10 + CR 702.16j: Keywords that can be granted to a player.
/// Today only Protection (per CR 702.16b/j). Extend as new player-granted
/// keyword qualities are implemented — always via typed enum variants, never
/// via string comparison.
fn is_player_applicable_keyword(keyword: &crate::types::keywords::Keyword) -> bool {
    matches!(keyword, crate::types::keywords::Keyword::Protection(_))
}

/// CR 608.2c + CR 117.3a: Extract a non-caster player anchor from an effect's
/// own subject. Used by `parse_effect_chain_ir` to remember "who is acting"
/// when a later clause in the same chain has a caster-defaulted player target
/// that should inherit the earlier subject (Assassin's Trophy's "then
/// shuffle" inheriting "its controller" from the preceding search clause).
///
/// Returns None for caster-defaulted or object-scoped effects — these do not
/// establish an acting-player anchor.
fn extract_player_anchor(effect: &Effect) -> Option<TargetFilter> {
    let candidate = match effect {
        Effect::SearchLibrary {
            target_player: Some(filter),
            ..
        } => filter,
        Effect::Shuffle { target } => target,
        Effect::ChangeZoneAll { target, .. } => target,
        _ => return None,
    };
    if !target_filter_can_target_player(candidate) {
        return None;
    }
    if matches!(candidate, TargetFilter::Controller | TargetFilter::Any) {
        return None;
    }
    Some(candidate.clone())
}

/// CR 608.2c + CR 117.3a: Apply an anchor subject (tracked by the chain parser)
/// to a caster-defaulted player-scope effect, so chained instructions like
/// "then shuffle" inherit the earlier subject ("its controller").
///
/// Only overwrites effects whose player target is the caster default
/// (`Controller`) and only when the anchor is a player-scope filter. Does not
/// touch effects that already carry an explicit non-caster subject.
fn apply_anchor_subject(effect: &mut Effect, anchor: &TargetFilter) {
    if !target_filter_can_target_player(anchor) {
        return;
    }
    match effect {
        Effect::Shuffle { target } if *target == TargetFilter::Controller => {
            *target = anchor.clone();
        }
        Effect::SearchLibrary {
            target_player: tp @ None,
            ..
        } => {
            *tp = Some(anchor.clone());
        }
        Effect::ChangeZoneAll { target, .. } if *target == TargetFilter::Controller => {
            *target = anchor.clone();
        }
        _ => {}
    }
}

/// CR 109.4: Map a player-reference `TargetFilter` to the `ControllerRef`
/// variant a typed object filter should adopt to match "permanents that player
/// controls". `TriggeringPlayer` is event-contextual and must not create a
/// target slot; explicit targeted subjects still use `TargetPlayer` in
/// `inject_subject_target` below. Caster-scoped filters (`Controller`, `You`)
/// should not rewrite an object filter because they reference the ability
/// controller, not an acting player target.
fn player_filter_as_controller_ref(filter: &TargetFilter) -> Option<ControllerRef> {
    match filter {
        TargetFilter::ScopedPlayer => Some(ControllerRef::ScopedPlayer),
        TargetFilter::TriggeringPlayer => Some(ControllerRef::ScopedPlayer),
        TargetFilter::ParentTargetController => Some(ControllerRef::ParentTargetController),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().find_map(player_filter_as_controller_ref)
        }
        TargetFilter::Not { filter } => player_filter_as_controller_ref(filter),
        TargetFilter::Typed(tf)
            if tf.type_filters.is_empty()
                && tf.controller.is_some()
                && tf.properties.is_empty() =>
        {
            tf.controller.clone()
        }
        // CR 115.1 + CR 701.21a: A bare "target player" subject ("target player
        // sacrifices a creature" — Diabolic Edict, Chainer's Edict, Geth's
        // Verdict, Liliana of the Veil −2) is a player target. "target opponent"
        // lowers to a typed filter with `controller: Opponent` (matched above),
        // but "target player" lowers to the unit `TargetFilter::Player`, which
        // otherwise fell through to `None` and dropped the controller scope. The
        // Sacrifice injection arm promotes this to `TargetPlayer` so the engine
        // surfaces a player target slot and `resolve_sacrifice_scope` reads the
        // chosen player at resolution — identical to the "target opponent" path.
        TargetFilter::Player => Some(ControllerRef::TargetPlayer),
        _ => None,
    }
}

fn target_filter_controller_ref(filter: &TargetFilter) -> Option<ControllerRef> {
    match filter {
        TargetFilter::Typed(tf) => tf.controller.clone(),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().find_map(target_filter_controller_ref)
        }
        TargetFilter::Not { filter } => target_filter_controller_ref(filter),
        _ => None,
    }
}

/// CR 701.16a + CR 115.1: Unconditionally set the controller constraint on a
/// typed object filter, overwriting any existing value. Used when a targeted
/// subject ("target opponent sacrifices...") must override a pre-parsed "they
/// control" → `ControllerRef::You` with `ControllerRef::TargetPlayer`.
fn force_controller(filter: &mut TargetFilter, ctrl: ControllerRef) {
    match filter {
        TargetFilter::Typed(tf) => {
            tf.controller = Some(ctrl);
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for inner in filters.iter_mut() {
                force_controller(inner, ctrl.clone());
            }
        }
        TargetFilter::Not { filter } => force_controller(filter, ctrl),
        _ => {}
    }
}

/// Rewrite all occurrences of `from` controller inside a `QuantityExpr`'s
/// embedded filters to `to`. Walks DivideRounded/Multiply/Offset/Sum wrappers
/// and rewrites ObjectCount filter controllers.
fn rewrite_quantity_controller(expr: &mut QuantityExpr, from: ControllerRef, to: ControllerRef) {
    match expr {
        QuantityExpr::Ref { qty } => {
            if let QuantityRef::ObjectCount { filter } = qty {
                rewrite_filter_controller(filter, &from, &to);
            }
        }
        QuantityExpr::DivideRounded { inner, .. }
        | QuantityExpr::Multiply { inner, .. }
        | QuantityExpr::ClampMin { inner, .. }
        | QuantityExpr::Offset { inner, .. }
        | QuantityExpr::UpTo { max: inner }
        | QuantityExpr::Power {
            exponent: inner, ..
        } => {
            rewrite_quantity_controller(inner, from, to);
        }
        QuantityExpr::Sum { exprs } => {
            for inner in exprs {
                rewrite_quantity_controller(inner, from.clone(), to.clone());
            }
        }
        QuantityExpr::Difference { left, right } => {
            rewrite_quantity_controller(left, from.clone(), to.clone());
            rewrite_quantity_controller(right, from, to);
        }
        QuantityExpr::Fixed { .. } => {}
    }
}

/// Rebind a deferred anaphoric **pronoun** referent ("its power", "its
/// toughness", "its mana value", …) — parsed as `ObjectScope::Anaphoric` per
/// CR 608.2k — to a concrete `ObjectScope` once the surrounding clause
/// establishes the antecedent (a damage clause whose subject is the source,
/// the first target object, or the triggering object).
///
/// CR 113.6 + CR 208/209/202: the pronoun names *one* object; this rewrite
/// retargets *which* object (the `scope` field), never *which* characteristic
/// (the `QuantityRef` variant), so it stays within each property's CR section
/// and applies uniformly across power, toughness, mana value, color/word/
/// mana-symbol counts, and counters. An explicit participle-possessive ("the
/// sacrificed creature's power", `CostPaidObject`) and a demonstrative ("that
/// creature's toughness", `Demonstrative`) are deliberately NOT matched — both
/// have antecedents fixed by the Oracle text and must not be clobbered.
fn rebind_anaphoric_object_scope(expr: &mut QuantityExpr, scope: ObjectScope) {
    match expr {
        QuantityExpr::Ref { qty } => rebind_anaphoric_ref(qty, scope),
        QuantityExpr::DivideRounded { inner, .. }
        | QuantityExpr::Multiply { inner, .. }
        | QuantityExpr::ClampMin { inner, .. }
        | QuantityExpr::Offset { inner, .. }
        | QuantityExpr::UpTo { max: inner }
        | QuantityExpr::Power {
            exponent: inner, ..
        } => {
            rebind_anaphoric_object_scope(inner, scope);
        }
        QuantityExpr::Sum { exprs } => {
            for inner in exprs {
                rebind_anaphoric_object_scope(inner, scope);
            }
        }
        QuantityExpr::Difference { left, right } => {
            rebind_anaphoric_object_scope(left, scope);
            rebind_anaphoric_object_scope(right, scope);
        }
        QuantityExpr::Fixed { .. } => {}
    }
}

/// Retarget a single per-object `QuantityRef` whose scope is the deferred
/// pronoun `ObjectScope::Anaphoric` to `target`. Leaves every other scope
/// (including the fixed `Demonstrative` / `CostPaidObject` referents) and every
/// non-per-object `QuantityRef` untouched.
fn rebind_anaphoric_ref(qty: &mut QuantityRef, target: ObjectScope) {
    let scope = match qty {
        QuantityRef::Power { scope }
        | QuantityRef::Toughness { scope }
        | QuantityRef::ObjectManaValue { scope }
        | QuantityRef::ObjectColorCount { scope }
        | QuantityRef::ObjectNameWordCount { scope }
        | QuantityRef::ObjectTypelineComponentCount { scope }
        | QuantityRef::ManaSymbolsInManaCost { scope, .. }
        | QuantityRef::CountersOn { scope, .. } => scope,
        _ => return,
    };
    if *scope == ObjectScope::Anaphoric {
        *scope = target;
    }
}

fn bind_damage_clause_source(
    effect: &mut Effect,
    damage_source_ref: DamageSource,
    power_scope: ObjectScope,
) -> bool {
    match effect {
        Effect::DealDamage {
            amount,
            damage_source,
            ..
        }
        | Effect::DamageAll {
            amount,
            damage_source,
            ..
        } => {
            rebind_anaphoric_object_scope(amount, power_scope);
            *damage_source = Some(damage_source_ref);
            true
        }
        _ => false,
    }
}

fn rewrite_filter_controller(filter: &mut TargetFilter, from: &ControllerRef, to: &ControllerRef) {
    match filter {
        TargetFilter::Typed(tf) if tf.controller.as_ref() == Some(from) => {
            tf.controller = Some(to.clone());
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for inner in filters.iter_mut() {
                rewrite_filter_controller(inner, from, to);
            }
        }
        TargetFilter::Not { filter } => rewrite_filter_controller(filter, from, to),
        _ => {}
    }
}

/// CR 109.4 + CR 115.7: Attach a controller constraint to a typed object
/// filter that does not yet have one. Walks into `Or`/`And`/`Not` to cover
/// compound filters like "target creature or planeswalker". Filters that
/// already carry a controller constraint are left untouched so an explicit
/// "creature you control" clause is never silently rewritten.
pub(super) fn attach_controller_if_absent(filter: &mut TargetFilter, ctrl: ControllerRef) {
    match filter {
        TargetFilter::Typed(tf) if tf.controller.is_none() => {
            tf.controller = Some(ctrl);
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for inner in filters.iter_mut() {
                attach_controller_if_absent(inner, ctrl.clone());
            }
        }
        TargetFilter::Not { filter } => attach_controller_if_absent(filter, ctrl),
        _ => {}
    }
}

fn target_filter_can_target_player(filter: &TargetFilter) -> bool {
    match filter {
        TargetFilter::Player
        | TargetFilter::Controller
        | TargetFilter::ScopedPlayer
        | TargetFilter::TriggeringSpellController
        | TargetFilter::TriggeringSpellOwner
        | TargetFilter::TriggeringPlayer
        | TargetFilter::DefendingPlayer
        | TargetFilter::ParentTargetController
        | TargetFilter::ParentTargetOwner => true,
        TargetFilter::Typed(tf) => tf.type_filters.is_empty(),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().any(target_filter_can_target_player)
        }
        TargetFilter::Not { filter } => target_filter_can_target_player(filter),
        _ => false,
    }
}

fn wrap_target_subject_damage(
    mut clause: ParsedEffectClause,
    subject: &SubjectPhraseAst,
) -> Option<ParsedEffectClause> {
    let subject_target = subject.target.as_ref()?;
    if matches!(subject_target, TargetFilter::TriggeringSource) {
        // CR 603.6 + CR 120.1: "that creature deals damage equal to its
        // power" in a zone-change trigger binds both the damage source and
        // anaphoric power reference to the moved object.
        if bind_damage_clause_source(
            &mut clause.effect,
            DamageSource::TriggeringSource,
            ObjectScope::EventSource,
        ) {
            return Some(clause);
        }
        return None;
    }

    // CR 608.2c + CR 120.1: "target creature deals damage equal to its
    // power..." makes the chosen source object, not the spell card, deal the
    // damage. "Its power" is therefore the first target's current power.
    // Both `DealDamage` (single recipient) and `DamageAll` (multi-recipient
    // batch) carry this shape uniformly — `damage_source = Some(Target)` is
    // honored by the resolver in `game/effects/deal_damage.rs` for protection
    // (CR 702.16), wither/infect (CR 120.3b/d), and damage-source replacements
    // (CR 614). The 2015-06-22 Chandra's Ignition rulings codify this for
    // the multi-recipient case (DamageAll).
    if !bind_damage_clause_source(
        &mut clause.effect,
        DamageSource::Target,
        ObjectScope::Target,
    ) {
        return None;
    }

    let mut damage_ability = AbilityDefinition::new(AbilityKind::Spell, clause.effect);
    damage_ability.sub_ability = clause.sub_ability;
    damage_ability.duration = clause.duration.clone();
    damage_ability.condition = clause.condition.clone();
    damage_ability.optional = clause.optional;
    damage_ability.multi_target = clause.multi_target;
    damage_ability.distribute = clause.distribute;

    Some(ParsedEffectClause {
        effect: Effect::TargetOnly {
            target: subject_target.clone(),
        },
        duration: clause.duration,
        sub_ability: Some(Box::new(damage_ability)),
        distribute: None,
        multi_target: subject.multi_target.clone(),
        condition: None,
        optional: subject.is_optional,
        unless_pay: None,
    })
}

fn parse_subject_exile_top_count(pred_lower: &str) -> QuantityExpr {
    if let Ok((_, qty_text)) = preceded(
        alt((tag::<_, _, OracleError<'_>>("exile "), tag("exiles "))),
        take_until(" from the top"),
    )
    .parse(pred_lower)
    {
        if let Some(expr) = parse_event_context_quantity(qty_text.trim()) {
            return expr;
        }
    }

    if let Some(after_top) = strip_after(pred_lower, "top ") {
        // CR 107.1a: "half of their library, rounded up/down" composes over
        // `TargetZoneCardCount` via the shared quantity combinator.
        if let Ok((_, expr)) = super::oracle_nom::quantity::parse_half_rounded(after_top) {
            expr
        } else {
            let n = nom_primitives::parse_number
                .parse(after_top)
                .map(|(_, n)| n as i32)
                .unwrap_or(1);
            QuantityExpr::Fixed { value: n }
        }
    } else {
        QuantityExpr::Fixed { value: 1 }
    }
}

/// Inject a subject phrase's target filter into an effect that was parsed through
/// the imperative fallback path, where the subject was stripped before parsing.
/// Only applies to effects with a sentinel `TargetFilter::Any` that should inherit
/// the subject's targeting information.
fn inject_subject_target(effect: &mut Effect, subject: &SubjectPhraseAst) {
    let subject_filter = subject.target.as_ref().unwrap_or(&subject.affected).clone();
    // CR 603.6 + CR 120.1: "that creature/permanent deals damage equal to
    // its power..." in an ETB trigger makes the triggering object, not the
    // trigger source permanent, the damage source. Keep the parsed damage
    // recipient target intact ("to any target") while rebinding both the
    // source metadata and anaphoric "its power" to the triggering source.
    if matches!(subject_filter, TargetFilter::TriggeringSource)
        && bind_damage_clause_source(
            effect,
            DamageSource::TriggeringSource,
            ObjectScope::EventSource,
        )
    {
        return;
    }

    match effect {
        // CR 601.2c + CR 121.1: "Target player draws ..." — each Draw mode of a
        // modal spell is its own targeting instance. The imperative path emits
        // `target: TargetFilter::Controller` (the no-subject default); when a
        // player-subject is parsed we promote that to the subject filter so
        // `collect_target_slots` surfaces an independent slot per Draw mode.
        Effect::Connive { target, .. }
        | Effect::PhaseOut { target }
        | Effect::PhaseIn { target }
        | Effect::ForceBlock { target }
        | Effect::ForceAttack { target, .. }
        | Effect::Suspect { target }
        | Effect::Goad { target }
        | Effect::Mill { target, .. }
        | Effect::Discard { target, .. }
        | Effect::Draw { target, .. }
        | Effect::Scry { target, .. }
        | Effect::Surveil { target, .. }
        | Effect::PutAtLibraryPosition { target, .. }
            if *target == TargetFilter::Any || *target == TargetFilter::Controller =>
        {
            *target = subject_filter;
        }
        // CR 500.7: "target player takes an extra turn" — inject subject target
        Effect::ExtraTurn { target } if *target == TargetFilter::Controller => {
            *target = subject_filter;
        }
        // CR 104.3e + CR 603.7c: "that player loses the game" / "target player
        // loses the game" — bind the named player into the effect's
        // optional target field. The subject parser ("subject.rs") maps "that
        // player" → `TargetFilter::TriggeringPlayer` (a context ref resolved
        // at effect-resolution time against `state.current_trigger_event`)
        // and "target player" → `TargetFilter::Player` (declared at cast/
        // stack-push time). Guard on `is_none()` so an already-parsed target
        // (no current call site, kept defensively) is preserved. Canonical
        // cards: Ezio Auditore da Firenze's reflexive "that player loses the
        // game" sub-ability (CR 104.3e); the WinTheGame arm is the symmetric
        // CR 104.2b counterpart for any future "that player wins the game"
        // wording.
        Effect::LoseTheGame { ref mut target } | Effect::WinTheGame { ref mut target }
            if target.is_none() =>
        {
            *target = Some(subject_filter);
        }
        // CR 122.1: "target player gets a poison counter" — inject subject target
        Effect::GivePlayerCounter { target, .. } if *target == TargetFilter::Controller => {
            *target = subject_filter;
        }
        // CR 122.1: "target opponent loses all counters" — inject subject target
        Effect::LoseAllPlayerCounters { target } if *target == TargetFilter::Controller => {
            *target = subject_filter;
        }
        // CR 500.8: "target player gets an additional combat phase" — inject subject target
        Effect::AdditionalPhase { target, .. } if *target == TargetFilter::Controller => {
            *target = subject_filter;
        }
        // CR 400.7: "shuffle [subject]'s graveyard into their library" — inject
        // subject target for zone-wide changes and shuffles.
        Effect::ChangeZoneAll { ref mut target, .. }
            if *target == TargetFilter::Any || *target == TargetFilter::Controller =>
        {
            *target = subject_filter;
        }
        Effect::Shuffle { ref mut target }
            if *target == TargetFilter::Any || *target == TargetFilter::Controller =>
        {
            *target = subject_filter;
        }
        Effect::Token { ref mut owner, .. } if *owner == TargetFilter::Controller => {
            *owner = subject_filter;
        }
        // CR 109.4 + CR 707.2: "target opponent creates a token that's a copy
        // of it" — the chosen player is the token's creator/controller, not the
        // copy source. Inject the subject into `owner` (mirrors `Effect::Token`
        // above); `target` is left untouched so it keeps the copy *source*
        // (SelfRef/ParentTarget). Placed before the object-targeting group so
        // the `owner` channel wins over the `target == Any` injection.
        Effect::CopyTokenOf { ref mut owner, .. } if *owner == TargetFilter::Controller => {
            *owner = subject_filter;
        }
        // CR 701.14a: "enchanted creature fights target creature" — the subject
        // of the fight is the enchanted/equipped creature, not the Aura/Equipment.
        Effect::Fight {
            subject: fight_subject,
            ..
        } if *fight_subject == TargetFilter::SelfRef => {
            *fight_subject = subject_filter;
        }
        // CR 613.1b + CR 110.2: "[Player] gains control of [object]" — when the
        // acting subject is a non-controller player (e.g. "an opponent of your
        // choice gains control of it"), the semantics are GIVE (the current
        // controller transfers the object to that player), not TAKE (the
        // current controller steals). Rewrite GainControl → GiveControl with
        // the subject as the recipient and keep the original target intact.
        // This covers Khârn the Betrayer's damage replacement and any other
        // "opponent/player gains control of [target]" oracle text.
        Effect::GainControl { target }
            if !matches!(
                subject_filter,
                TargetFilter::Controller | TargetFilter::SelfRef
            ) =>
        {
            *effect = Effect::GiveControl {
                target: target.clone(),
                recipient: subject_filter,
            };
        }
        // Object-targeting effects: inject subject filter only when the sentinel
        // is `TargetFilter::Any` (not Controller — these target objects, not players).
        // Note: DealDamage is intentionally excluded — the damage parser always parses
        // its own target from the "to [target]" clause. Injecting the subject into
        // DealDamage would overwrite explicitly-parsed "any target" with SelfRef,
        // causing "It deals 5 damage to any target" to target itself instead of the opponent.
        Effect::Pump { target, .. }
        | Effect::Destroy { target, .. }
        | Effect::Regenerate { target, .. }
        | Effect::Counter { target, .. }
        // CR 701.26a/b: only single-target tap/untap carries an `Any` target to
        // rewrite into the subject filter.
        | Effect::SetTapState {
            scope: EffectScope::Single,
            target,
            ..
        }
        | Effect::RemoveCounter { target, .. }
        | Effect::Sacrifice { target, .. }
        | Effect::DiscardCard { target, .. }
        | Effect::ChangeZone { target, .. }
        | Effect::ControlNextTurn { target, .. }
        | Effect::Attach { target, .. }
        | Effect::UnattachAll { target, .. }
        | Effect::Bounce { target, .. }
        | Effect::SwitchPT { target, .. }
        | Effect::CopySpell { target, .. }
        | Effect::CopyTokenOf { target, .. }
        | Effect::BecomeCopy { target, .. }
        | Effect::ChooseCard { target, .. }
        | Effect::PutCounter { target, .. }
        | Effect::MultiplyCounter { target, .. }
        | Effect::DoublePT { target, .. }
        | Effect::MoveCounters { target, .. }
        | Effect::Animate { target, .. }
        | Effect::Transform { target, .. }
        | Effect::RevealHand { target, .. }
        | Effect::TargetOnly { target, .. }
        | Effect::PreventDamage { target, .. }
        | Effect::Exploit { target, .. }
        | Effect::CastFromZone { target, .. }
        | Effect::PutOnTopOrBottom { target, .. }
        | Effect::Double { target, .. }
            if *target == TargetFilter::Any =>
        {
            *target = subject_filter;
        }
        // CR 608.2k + CR 109.4: "that player sacrifices a non-Elf creature" /
        // "each opponent sacrifices a creature they control". When the subject
        // is a player reference (TriggeringPlayer / TargetPlayer / etc.) and
        // CR 115.1 + CR 701.21a: Sacrifice with a typed object filter —
        // inject the subject's controller constraint. For non-targeted subjects
        // ("each player sacrifices a non-Elf creature"), this scopes the filter
        // to the acting player's permanents. For targeted subjects ("target
        // opponent sacrifices..."), use ControllerRef::TargetPlayer so the
        // engine surfaces a player target slot and resolve_sacrifice_scope
        // reads the chosen player from ability.targets at resolution time.
        // Also rewrite "they control" refs inside the count expression so
        // the dynamic count resolves against the targeted player's board.
        Effect::Sacrifice { target, count, .. }
            if player_filter_as_controller_ref(&subject_filter).is_some() =>
        {
            if let Some(ctrl) = player_filter_as_controller_ref(&subject_filter) {
                let effective_ctrl = if subject.target.is_some() {
                    ControllerRef::TargetPlayer
                } else {
                    ctrl
                };
                force_controller(target, effective_ctrl.clone());
                if subject.target.is_some() {
                    rewrite_quantity_controller(count, ControllerRef::ScopedPlayer, effective_ctrl);
                }
            }
        }
        // CR 608.2c + CR 608.2d (issue #1535): "that player may put a [typed]
        // card from their hand onto the battlefield" (Braids, Conjurer Adept) /
        // "each player puts a [typed] card from their graveyard ...". When the
        // subject is a player reference and the `ChangeZone` target is a *typed*
        // filter, the `Any`-guarded injection in the object-targeting group above
        // was skipped, leaving the moved-object filter with no owner constraint —
        // so at resolution it draws from every player's zone and the choice is
        // mis-routed to the controller. Stamp the subject's controller onto the
        // filter (mirroring the `Sacrifice` arm) so the card is taken from, and
        // the choice presented to, the acting (per-iteration) player.
        Effect::ChangeZone { target, .. }
            if player_filter_as_controller_ref(&subject_filter).is_some() =>
        {
            if let Some(ctrl) = player_filter_as_controller_ref(&subject_filter) {
                let effective_ctrl = if subject.target.is_some() {
                    ControllerRef::TargetPlayer
                } else {
                    ctrl
                };
                force_controller(target, effective_ctrl);
            }
        }
        // CR 115.1c / CR 602.2b + CR 601.2c / CR 119.3: "Target player gains
        // N life" / "target opponent gains N life" announces a player target;
        // the chosen player, not the source controller, gains the life.
        Effect::GainLife {
            player: player @ TargetFilter::Controller,
            ..
        } if subject.target.is_some() && target_filter_can_target_player(&subject_filter) => {
            *player = subject_filter;
        }
        // CR 119.3 + CR 115.1d: "they lose N life" — inject subject's player reference.
        // LoseLife.target is Option<TargetFilter>, unlike other effects' non-optional targets.
        // Guard on is_none() to only inject when no target was explicitly parsed.
        Effect::LoseLife { ref mut target, .. } if target.is_none() => {
            *target = Some(subject_filter);
        }
        // CR 106.4 + CR 505.1 + CR 608.2c: "<player> adds {mana}" — subject-predicate
        // classification deconjugates "adds" → "add" and routes through the imperative
        // mana parser with `target: None`. Stamp the stripped subject ("that player",
        // "the active player") as the mana recipient (Blinkmoth Urn, issue #2900).
        Effect::Mana { ref mut target, .. }
            if target.is_none() && target_filter_can_target_player(&subject_filter) =>
        {
            *target = Some(subject_filter);
        }
        // CR 608.2c + CR 113.7a + CR 120.3: When the stripped subject is the
        // source object ("~ deals damage equal to its toughness/power/mana
        // value..."), an anaphoric "its <characteristic>" reads the ability
        // source's current value — via LKI (CR 113.7a) if the source has since
        // left the battlefield (Steadfast Armasaur destroyed in response to its
        // own activated ability). Only the pronoun `ObjectScope::Anaphoric` is
        // rebound; an explicit possessive ("the sacrificed creature's power",
        // `CostPaidObject`) or a demonstrative ("that creature's toughness",
        // `Demonstrative`) keeps its parser-fixed referent.
        Effect::DealDamage { amount, .. } | Effect::DamageEachPlayer { amount, .. }
            if subject_filter == TargetFilter::SelfRef =>
        {
            rebind_anaphoric_object_scope(amount, ObjectScope::Source);
        }
        // CR 701.23a: "Its controller may search their library..." — the subject
        // names the library owner (and, when the subject is a context-ref, the
        // searcher). Only inject when the subject is a player-scope filter and
        // no target_player has already been extracted from "search target X's
        // library" earlier in the pipeline.
        Effect::SearchLibrary {
            target_player: target_player @ None,
            ..
        } if target_filter_can_target_player(&subject_filter)
            && subject_filter != TargetFilter::Controller =>
        {
            *target_player = Some(subject_filter);
        }
        // CR 508.1d / CR 509.1c + CR 611.2c: "<set-scoped subject> attack(s) this
        // combat if able" / "... must be blocked ...". A non-targeted set subject
        // ("all Revelers") is threaded onto the `GenericEffect` produced by the
        // standalone combat-requirement parsers — both the per-static `affected`
        // (which objects the layer system grants the requirement to) and the
        // outer broadcast `target`. Only inject when the parser left the default
        // sentinel (`None`/`SelfRef`); a targeted subject never reaches here
        // (the conjunction splitter prepends the anaphor "it" instead, which the
        // chunk loop rewrites to `ParentTarget`).
        Effect::GenericEffect {
            ref mut static_abilities,
            ref mut target,
            ..
        } if subject.target.is_none() => {
            for static_def in static_abilities.iter_mut() {
                if matches!(static_def.affected, None | Some(TargetFilter::SelfRef)) {
                    static_def.affected = Some(subject_filter.clone());
                }
            }
            if target.is_none() {
                *target = Some(subject_filter);
            }
        }
        _ => {}
    }
}

/// Strip a single matching pair of outer quotes (`"…"`, `'…'`, or curly
/// `“…”`) from `s`, if present. Only ONE pair is removed so that quotes nested
/// inside the body survive — an emblem's granted ability is itself quoted one
/// level deeper (`"… have '{T}: …'"`), and the old
/// `trim_matches('"').trim_matches('\'')` over-stripped the granted ability's
/// closing quote, leaving it unbalanced and unparseable.
fn strip_balanced_outer_quotes(s: &str) -> &str {
    let s = s.trim();
    const PAIRS: [(char, char); 3] = [('"', '"'), ('\'', '\''), ('\u{201c}', '\u{201d}')];
    let mut chars = s.chars();
    let Some(first) = chars.next() else {
        return s;
    };
    // `next_back` returns `None` when only one char remained (already consumed
    // by `next`), so this also guards against a degenerate single-quote string.
    let Some(last) = chars.next_back() else {
        return s;
    };
    for (open, close) in PAIRS {
        if first == open && last == close {
            return &s[open.len_utf8()..s.len() - close.len_utf8()];
        }
    }
    s
}

/// An emblem grants its ability one quote-nesting level deep, so a granted
/// ability is single-quoted (Koth of the Hammer: `Mountains you control have
/// '{T}: ~ deals 1 damage to any target.'`). Every downstream grant parser
/// (`parse_static_line`, `parse_quoted_ability_modifications`) recognises only
/// double-quoted ability bodies — single quotes are ambiguous with
/// apostrophes — so promote the nested pair to double quotes. The opening
/// quote is anchored on a grant verb
/// (`have '` / `has '` / `gain '` / `gains '`) so a possessive apostrophe in
/// the subject phrase is never mistaken for the delimiter; the closing quote is
/// the final `'` in the body. Bodies without a nested single-quoted ability are
/// returned unchanged.
fn promote_nested_ability_quotes(body: &str) -> String {
    const OPEN_ANCHORS: [&str; 4] = [" have '", " has '", " gain '", " gains '"];
    // Grant verbs are mid-sentence and therefore lowercase in Oracle text, so
    // they can be matched against `body` directly without lowercasing.
    let open_quote = OPEN_ANCHORS
        .iter()
        .filter_map(|anchor| body.find(anchor).map(|pos| pos + anchor.len() - 1))
        .min();
    let (Some(open_quote), Some(close_quote)) = (open_quote, body.rfind('\'')) else {
        return body.to_string();
    };
    if close_quote <= open_quote {
        return body.to_string();
    }
    let mut promoted = String::with_capacity(body.len());
    promoted.push_str(&body[..open_quote]);
    promoted.push('"');
    promoted.push_str(&body[open_quote + 1..close_quote]);
    promoted.push('"');
    promoted.push_str(&body[close_quote + 1..]);
    promoted
}

/// CR 114.1: Parse emblem creation from Oracle text.
/// Handles both full form "you get an emblem with \"[text]\"" and
/// subject-stripped form "get an emblem with \"[text]\"".
fn try_parse_emblem_creation(lower: &str, original: &str) -> Option<Effect> {
    // Use nom to strip the prefix and get original-case remainder
    let (_, rest) = nom_on_lower(original, lower, |i| {
        value(
            (),
            alt((tag("you get an emblem with "), tag("get an emblem with "))),
        )
        .parse(i)
    })?;

    // Remove only the emblem's OUTER quote wrapper, then promote any nested
    // single-quoted granted ability to double quotes so the standard grant
    // parsers recognise it (Koth of the Hammer's "Mountains you control have
    // '{T}: ~ deals 1 damage to any target.'").
    let body = strip_balanced_outer_quotes(rest);
    let promoted = promote_nested_ability_quotes(body);
    let inner = promoted.trim().trim_end_matches('.').trim();

    if inner.is_empty() {
        return None;
    }

    // CR 113.1c + CR 114.4: An emblem's ability may be a triggered ability
    // ("Whenever ...", "At the beginning of ..."), a static ability, or the
    // Unknown fallback. Try the triggered-ability parser first; fall through
    // to the static-ability parser only if `parse_trigger_lines` does not
    // recognise a trigger phrase (returns `TriggerMode::Unknown`). Both
    // detectors ARE the parsers — no string heuristics.
    let trig_defs = super::oracle_trigger::parse_trigger_lines(inner, "~");
    let all_known = !trig_defs.is_empty()
        && trig_defs
            .iter()
            .all(|t| !matches!(t.mode, TriggerMode::Unknown(_)));
    if all_known {
        // CR 114.4: An emblem's triggers function in the command zone, so the
        // `collect_matching_triggers` zone guard must admit them. Declare
        // `trigger_zones = [Zone::Command]` explicitly (the default empty
        // vector is interpreted as battlefield-only by the scanner).
        let mut triggers: Vec<TriggerDefinition> = trig_defs
            .into_iter()
            .map(|t| t.trigger_zones(vec![Zone::Command]))
            .collect();
        // CR 114: retain the emblem's granted rules text so the display layer
        // can show "what it does" in the emblem tooltip. Attach to the first
        // trigger only — the joined display text would otherwise repeat the
        // clause for multi-trigger emblems.
        if let Some(first) = triggers.first_mut() {
            first.description = Some(inner.to_string());
        }
        return Some(Effect::CreateEmblem {
            statics: Vec::new(),
            triggers,
        });
    }

    // Try to parse the emblem text as a static ability line.
    if let Some(mut static_def) = super::oracle_static::parse_static_line(inner) {
        // CR 114: retain the emblem's granted rules text for the display
        // tooltip, mirroring the trigger and fallback branches.
        static_def.description = Some(inner.to_string());
        Some(Effect::CreateEmblem {
            statics: vec![static_def],
            triggers: Vec::new(),
        })
    } else {
        // Fallback: create an emblem with an unimplemented static.
        Some(Effect::CreateEmblem {
            statics: vec![
                StaticDefinition::new(StaticMode::EmblemStatic).description(inner.to_string())
            ],
            triggers: Vec::new(),
        })
    }
}

/// CR 601.2a + CR 118.9: Parse "cast it/that card [without paying its mana cost]".
///
/// Three branches:
/// CR 205.2 + CR 108.1: Parse a leading core-type disjunction with the
/// "spell" / "card" informational suffix — "an instant or sorcery spell",
/// "target instant or sorcery card". Returns a `TypedFilter` whose type atom
/// is the disjunctive set.
///
/// `parse_type_phrase` handles single core types and adjective-conjunction
/// ("artifact creature") but not " or " between bare core-type words. This
/// helper covers the common cast-effect surface that needs the disjunctive
/// form (Jeleva, Past in Flames, Mizzix's Mastery, Wandering Mind, and the
/// wider "cast instant or sorcery from <zone>" class).
fn parse_cast_type_disjunction(rest: &str) -> Option<TypedFilter> {
    type E<'a> = OracleError<'a>;
    fn parse_core(i: &str) -> nom::IResult<&str, TypeFilter, OracleError<'_>> {
        alt((
            value(TypeFilter::Instant, tag::<_, _, E>("instant")),
            value(TypeFilter::Sorcery, tag("sorcery")),
            value(TypeFilter::Creature, tag("creature")),
            value(TypeFilter::Artifact, tag("artifact")),
            value(TypeFilter::Enchantment, tag("enchantment")),
            value(TypeFilter::Planeswalker, tag("planeswalker")),
            value(TypeFilter::Land, tag("land")),
            value(TypeFilter::Battle, tag("battle")),
        ))
        .parse(i)
    }
    let (rest, _) = opt(tag::<_, _, E>("target ")).parse(rest).ok()?;
    // Strip optional "a "/"an " article.
    let (rest, _) = opt(alt((tag::<_, _, E>("an "), tag("a "))))
        .parse(rest)
        .ok()?;
    let (rest, first) = parse_core(rest).ok()?;
    let (rest, _) = tag::<_, _, E>(" or ").parse(rest).ok()?;
    let (rest, second) = parse_core(rest).ok()?;
    // Require the informational "spell"/"card" suffix so we don't over-match
    // bare disjunctions ("instant or sorcery" alone falls through to the
    // normal parser path).
    let (_rest, _) = alt((
        tag::<_, _, E>(" spell"),
        tag(" card"),
        tag(" spells"),
        tag(" cards"),
    ))
    .parse(rest)
    .ok()?;
    Some(TypedFilter {
        type_filters: vec![TypeFilter::AnyOf(vec![first, second])],
        controller: None,
        properties: Vec::new(),
    })
}

fn strip_cast_target_prefix(rest: &str) -> &str {
    opt(tag::<_, _, OracleError<'_>>("target "))
        .parse(rest)
        .map(|(after, _)| after)
        .unwrap_or(rest)
}

fn cast_filter_has_typed_leaf(filter: &TargetFilter) -> bool {
    match filter {
        TargetFilter::Typed(tf) => {
            !tf.type_filters.is_empty() || tf.controller.is_some() || !tf.properties.is_empty()
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().any(cast_filter_has_typed_leaf)
        }
        TargetFilter::Not { filter } => cast_filter_has_typed_leaf(filter),
        _ => false,
    }
}

fn cast_filter_has_meaningful_typed_leaf(filter: &TargetFilter) -> bool {
    match filter {
        TargetFilter::Typed(tf) => tf.has_meaningful_type_constraint(),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            filters.iter().any(cast_filter_has_meaningful_typed_leaf)
        }
        TargetFilter::Not { filter } => cast_filter_has_meaningful_typed_leaf(filter),
        _ => false,
    }
}

fn add_cast_target_props(
    filter: &mut TargetFilter,
    props: &[FilterProp],
    controller: Option<ControllerRef>,
) {
    match filter {
        TargetFilter::Typed(tf) => {
            if tf.controller.is_none() {
                tf.controller = controller;
            }
            for prop in props {
                let already_present = match prop {
                    FilterProp::Cmc { .. } => tf
                        .properties
                        .iter()
                        .any(|existing| matches!(existing, FilterProp::Cmc { .. })),
                    _ => tf.properties.contains(prop),
                };
                if !already_present {
                    tf.properties.push(prop.clone());
                }
            }
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for inner in filters {
                add_cast_target_props(inner, props, controller.clone());
            }
        }
        TargetFilter::Not { filter } => add_cast_target_props(filter, props, controller),
        _ => {}
    }
}

fn apply_cast_target_suffixes(filter: &mut TargetFilter, rest: &str) {
    type E<'a> = OracleError<'a>;

    if let Some((_zone, controller, props)) = super::oracle_target::scan_zone_phrase(rest) {
        add_cast_target_props(filter, &props, controller);
    } else if let Some(zone) = infer_origin_zone(rest) {
        add_cast_target_props(filter, &[FilterProp::InZone { zone }], None);
    }

    if let Ok((after_take, _)) = take_until::<_, _, E>("with mana value ").parse(rest) {
        if let Some((prop, _)) =
            super::oracle_target::parse_mana_value_suffix(after_take, &mut ParseContext::default())
        {
            add_cast_target_props(filter, &[prop], None);
        }
    }
}

/// CR 610.3 + CR 608.2c: Parse the `"from among (the|those) [TYPED]
/// (card|cards) exiled this way"` anchor and lift its optional typed leg
/// into a `TargetFilter`.
///
/// Returns:
/// * `Some(And { ExiledBySource, Typed(tf) })` — typed leg present
///   (Etali: "the nonland cards exiled this way" → AND with Non(Land)).
/// * `Some(ExiledBySource)` — bare "the cards exiled this way".
/// * `None` — anchor or "exiled this way" suffix not present.
///
/// Composition mirrors `has_from_among_cards_exiled_with_self` (anchor
/// strip) and `parse_cast_type_disjunction` / `parse_type_phrase` (typed
/// leg extraction).
fn parse_from_among_exiled_this_way(rest: &str) -> Option<TargetFilter> {
    type E<'a> = OracleError<'a>;
    let (after_anchor, _) = take_until::<_, _, E>("from among ").parse(rest).ok()?;
    let (after_anchor, _) = tag::<_, _, E>("from among ").parse(after_anchor).ok()?;
    let (after_article, _) = opt(alt((tag::<_, _, E>("the "), tag("those "))))
        .parse(after_anchor)
        .ok()?;

    // Require the literal suffix anchor before lifting anything so we
    // don't shadow the bare anaphor arm below.
    if !scan_contains_phrase(after_article, "cards exiled this way")
        && !scan_contains_phrase(after_article, "card exiled this way")
    {
        return None;
    }

    // Try disjunctive typed leg first ("instant or sorcery cards"); fall
    // back to parse_type_phrase ("nonland cards", "creature cards").
    let typed_filter = parse_cast_type_disjunction(after_article)
        .map(TargetFilter::Typed)
        .unwrap_or_else(|| super::oracle_target::parse_type_phrase(after_article).0);

    // "the cards exiled this way" lifts a bare `Typed(Card)` leaf with no
    // further constraint — that's the structural "cards" anchor, not a
    // meaningful type filter, so degrade to bare `ExiledBySource`.
    // `cast_filter_has_typed_leaf` would treat `[Card]` as non-empty;
    // `TypedFilter::has_meaningful_type_constraint` is the canonical
    // accessor that excludes Card/Any noise.
    let meaningful = cast_filter_has_meaningful_typed_leaf(&typed_filter);

    Some(if !meaningful {
        TargetFilter::ExiledBySource
    } else if typed_filter.references_exiled_by_source() {
        typed_filter.normalized()
    } else {
        TargetFilter::And {
            filters: vec![TargetFilter::ExiledBySource, typed_filter],
        }
        .normalized()
    })
}

/// CR 406.6 + CR 603.10a: Detect the `"from among cards exiled with [self-ref]"`
/// anchor — the persistent per-source exile-link anaphor used by cards that
/// reference their own tracked exile set from a later, independent ability
/// (Jeleva, Nephalia's Scourge attack trigger reading from Jeleva's ETB exile
/// set; Mizzix's Mastery sacrifice reference; and the wider class).
///
/// Composed via nom alternation over the self-reference variants the rest of
/// the parser already accepts at the SelfObject scope: `~` (the normalized
/// card name), `this creature`, `it`, `this spell`. The trailing-word matcher
/// uses `tag()` rather than a leaf-level enum because the variants are
/// orthographic spellings of the same `SelfRef` referent — parameterizing this
/// would only proliferate `alt()` arms with no semantic difference.
fn has_from_among_cards_exiled_with_self(rest: &str) -> bool {
    type E<'a> = OracleError<'a>;
    let Ok((after_anchor, _)) = take_until::<_, _, E>("from among cards exiled with ").parse(rest)
    else {
        return false;
    };
    let Ok((after_anchor, _)) = tag::<_, _, E>("from among cards exiled with ").parse(after_anchor)
    else {
        return false;
    };
    alt((
        tag::<_, _, E>("~"),
        tag("this creature"),
        tag("this artifact"),
        tag("this permanent"),
        tag("this card"),
        tag("this spell"),
        tag("it"),
    ))
    .parse(after_anchor)
    .is_ok()
}

/// CR 601.3b + CR 702.8a: "you may cast [type] spells as though they had flash"
/// — a duration-scoped flash-timing grant (Teferi, Time Raveler +1 class;
/// Emergence Zone sacrifice ability), not a `CastFromZone` card-selection
/// permission. Must dispatch before `try_parse_cast_effect`, which
/// misclassifies the spell-type filter as an activation-time target and blocks
/// loyalty activation (issue #878).
fn try_parse_cast_as_though_flash_permission(tp: TextPair<'_>) -> Option<ParsedEffectClause> {
    let ((type_text_orig, flash_duration), _) = nom_on_lower(tp.original, tp.lower, |i| {
        let (i, _) = opt(tag::<_, _, OracleError<'_>>("you may ")).parse(i)?;
        let (i, _) = tag("cast ").parse(i)?;
        let (i, (type_part, duration)) = alt((
            map(tag("spells this turn as though they had flash"), |_| {
                ("", Duration::UntilEndOfTurn)
            }),
            map(
                terminated(
                    take_until(" spells this turn as though they had flash"),
                    tag(" spells this turn as though they had flash"),
                ),
                |type_part: &str| (type_part.trim(), Duration::UntilEndOfTurn),
            ),
            map(tag("spells as though they had flash"), |_| {
                (
                    "",
                    Duration::UntilNextTurnOf {
                        player: PlayerScope::Controller,
                    },
                )
            }),
            map(
                terminated(
                    take_until(" spells as though they had flash"),
                    tag(" spells as though they had flash"),
                ),
                |type_part: &str| {
                    (
                        type_part.trim(),
                        Duration::UntilNextTurnOf {
                            player: PlayerScope::Controller,
                        },
                    )
                },
            ),
        ))
        .parse(i)?;
        let (i, _) = eof.parse(i)?;
        Ok((i, (type_part.to_string(), duration)))
    })?;

    let mut spell_filter = if type_text_orig.is_empty() {
        TargetFilter::Any
    } else {
        let phrase = format!("{type_text_orig} spells");
        parse_type_phrase(&phrase).0
    };
    if let TargetFilter::Typed(ref mut tf) = spell_filter {
        if tf.controller.is_none() {
            tf.controller = Some(ControllerRef::You);
        }
    }

    let granted_static = StaticDefinition::new(StaticMode::CastWithKeyword {
        keyword: Keyword::Flash,
    })
    .affected(spell_filter);

    // CR 611.2c + CR 601.3b + CR 702.8a: This grant modifies the rules of the game
    // for its CONTROLLER (the player gains permission to cast matching spells at
    // instant speed), not the characteristics of an object. Store it as a
    // player-scoped transient continuous effect: `target: Controller` resolves at
    // effect.rs (the `Some(TargetFilter::Controller)` arm) to a
    // `SpecificPlayer { id: controller }` binding, read by `granted_spell_keywords`
    // (casting.rs). Binding it to the source object (`SelfRef` → `SpecificObject`)
    // was the wrong seam — `prune_affected_object_left_effects` (layers.rs) drops it
    // the instant Teferi leaves, violating CR 611.2a/c (the effect's DURATION, not
    // its source's presence, governs its lifetime).
    Some(parsed_clause(Effect::GenericEffect {
        static_abilities: vec![StaticDefinition::continuous().modifications(vec![
            ContinuousModification::GrantStaticAbility {
                definition: Box::new(granted_static),
            },
        ])],
        duration: Some(flash_duration),
        target: Some(TargetFilter::Controller),
    }))
}

/// CR 608.2g + CR 601.2 + CR 118.9 + CR 202.3: Parse the free-cast window class —
/// "you may cast up to N [instant and/or sorcery] spells [with total mana value
/// M or less] from your graveyard and/or hand without paying their mana costs".
///
/// Lowers to `Effect::FreeCastFromZones`, the interactive multi-cast window with
/// a shared running-MV budget. The separate "If those spells would be put into
/// your graveyard, exile them instead" rider (CR 614.1a) is absorbed by
/// `parse_effect_chain_ir` so this parser stays at the per-clause seam.
///
/// Built from composed nom combinators: a fixed "you may cast up to " / "cast up
/// to " prefix, `parse_number` for the count, an `alt()` over the candidate type
/// phrase, an optional "with total mana value M or less" budget, and the
/// graveyard-and/or-hand zone tail. Distinct from `try_parse_cast_effect` (which
/// grants a `CastFromZone` permission on a single targeted/anaphoric card).
fn try_parse_free_cast_from_zones(lower: &str) -> Option<Effect> {
    type E<'a> = OracleError<'a>;

    // CR 601.2: "[you may] cast up to N " — fixed prefix + count. The chain
    // parser strips a leading optional "you may" before imperative dispatch, so
    // the per-clause parser accepts both the printed and stripped forms here.
    let (rest, _) = alt((tag::<_, _, E>("you may cast up to "), tag("cast up to ")))
        .parse(lower)
        .ok()?;
    let (rest, count) = nom_primitives::parse_number.parse(rest).ok()?;
    let count = count as u8;
    // `parse_number` leaves the trailing word boundary; consume the space
    // before the candidate type phrase.
    let (rest, _) = tag::<_, _, E>(" ").parse(rest).ok()?;

    // CR 601.2a: candidate type phrase. Compose the union over the published
    // surface forms ("instant and/or sorcery", "instant or sorcery") plus the
    // single-type variants, so the class covers more than Invoke Calamity.
    let (rest, filter) = parse_free_cast_candidate_filter(rest)?;

    // CR 601.2a: " spell"/" spells" noun, then the optional MV budget.
    let rest = alt((
        tag::<_, _, E>(" spells"),
        tag(" spell"),
        tag(" cards"),
        tag(" card"),
    ))
    .parse(rest)
    .map(|(r, _)| r)
    .unwrap_or(rest);

    // CR 202.3: optional "with total mana value M or less" running-total budget.
    let (rest, max_total_mv) = match tag::<_, _, E>(" with total mana value ").parse(rest) {
        Ok((after, _)) => {
            let (after, (comparator, value)) =
                search::parse_total_mana_value_comparator(after).ok()?;
            // CR 202.3: only the "or less" (LE) budget form is meaningful for a
            // free-cast cap; reject the "or greater" shape rather than mis-parse.
            if comparator != Comparator::LE {
                return None;
            }
            (after, Some(value.max(0) as u32))
        }
        Err(_) => (rest, None),
    };

    // CR 601.2a: zone tail — "from your graveyard and/or hand" (either order) or
    // a single-zone variant. Parse the zone set from the remainder.
    let zones = parse_free_cast_zone_tail(rest)?;

    // CR 118.9: `Effect::FreeCastFromZones` is a *free* cast — only lower a
    // "cast up to N ... from graveyard/hand" clause to it when the spell actually
    // grants the cast without its mana cost. A hypothetical pay-required
    // "cast up to N from your graveyard" (the controller still pays) must NOT be
    // treated as free, so require the "without paying their mana cost(s)" clause
    // (singular for a single-cast variant, plural for "up to N") in this clause.
    if !nom_primitives::scan_contains(rest, "without paying their mana cost")
        && !nom_primitives::scan_contains(rest, "without paying its mana cost")
    {
        return None;
    }

    Some(Effect::FreeCastFromZones {
        count,
        max_total_mv,
        filter,
        zones,
        exile_instead_of_graveyard: false,
    })
}

/// CR 601.2a: Candidate filter for the free-cast window — the spell types the
/// controller may cast this way. A single `alt()` composes the union surface
/// forms (longest-first so the two-type unions win over the single types) so the
/// class is not Invoke-Calamity-only.
fn parse_free_cast_candidate_filter(input: &str) -> Option<(&str, TargetFilter)> {
    type E<'a> = OracleError<'a>;
    let instant = || TargetFilter::Typed(TypedFilter::new(TypeFilter::Instant));
    let sorcery = || TargetFilter::Typed(TypedFilter::new(TypeFilter::Sorcery));
    let both = || TargetFilter::Or {
        filters: vec![instant(), sorcery()],
    };

    alt((
        value(both(), tag::<_, _, E>("instant and/or sorcery")),
        value(both(), tag("instant or sorcery")),
        value(both(), tag("sorcery and/or instant")),
        value(both(), tag("sorcery or instant")),
        value(instant(), tag("instant")),
        value(sorcery(), tag("sorcery")),
    ))
    .parse(input)
    .ok()
}

/// CR 601.2a: Parse the "from <zones>" tail of a free-cast window, returning the
/// controller-owned zones to draw candidates from. Accepts the graveyard/hand
/// union in either order plus the single-zone variants.
fn parse_free_cast_zone_tail(input: &str) -> Option<Vec<Zone>> {
    type E<'a> = OracleError<'a>;

    let (rest, _) = tag::<_, _, E>(" from your ").parse(input).ok()?;
    let (rest, first) = parse_free_cast_zone_word(rest).ok()?;
    let (_, second) = opt(preceded(
        alt((tag::<_, _, E>(" and/or "), tag(" or "))),
        preceded(opt(tag("your ")), parse_free_cast_zone_word),
    ))
    .parse(rest)
    .ok()?;

    if matches!(
        (&first, second.as_ref()),
        (Zone::Graveyard, Some(Zone::Hand)) | (Zone::Hand, Some(Zone::Graveyard))
    ) {
        return Some(vec![Zone::Graveyard, Zone::Hand]);
    }

    let mut zones = vec![first];
    if let Some(zone) = second {
        if !zones.contains(&zone) {
            zones.push(zone);
        }
    }
    Some(zones)
}

fn parse_free_cast_zone_word(input: &str) -> OracleResult<'_, Zone> {
    alt((
        value(Zone::Graveyard, tag("graveyard")),
        value(Zone::Hand, tag("hand")),
    ))
    .parse(input)
}

/// CR 614.1a: "If those spells would be put into your graveyard, exile them
/// instead" is not a standalone effect. It modifies the preceding free-cast
/// window so each spell cast through that window receives the replacement rider.
fn is_free_cast_exile_instead_rider(input: &str) -> bool {
    type E<'a> = OracleError<'a>;

    all_consuming((
        tag::<_, _, E>("if "),
        alt((
            tag("those spells"),
            tag("those cards"),
            tag("that spell"),
            tag("that card"),
            tag("it"),
        )),
        tag(" would be put into your graveyard, exile "),
        alt((tag("them"), tag("it"))),
        tag(" instead"),
        opt(tag(".")),
    ))
    .parse(input)
    .is_ok()
}

/// 1. Anaphoric — "cast it", "cast that spell", "cast those cards" — target is
///    `ParentTarget` (refers to the cards exiled / chosen by a prior effect).
/// 2. Constrained — "cast a [type-phrase] [from <zone>] [with mana value <bound>]
///    without paying its mana cost" — target is built from `parse_type_phrase` +
///    origin-zone inference. CR 118.9 + CR 601.2a + CR 120.3.
/// 3. Bare — fallback `TargetFilter::Any`.
fn try_parse_cast_effect(lower: &str) -> Option<Effect> {
    type E<'a> = OracleError<'a>;

    // CR 117.3a: Optional "you may " is peeled by `clause_shell` for generic
    // imperatives but left attached for specialized cast/play grants (Emry,
    // impulse-draw siblings). Strip here so "you may cast that card this
    // turn" reaches the anaphoric `CastFromZone` arms.
    let lower = opt(tag::<_, _, E>("you may "))
        .parse(lower)
        .ok()
        .map(|(rest, _)| rest)
        .unwrap_or(lower);

    // CR 305.1: "play" means cast if spell, play as land if land.
    let (rest, mode) = alt((
        value(CardPlayMode::Cast, tag::<_, _, E>("cast ")),
        value(CardPlayMode::Play, tag("play ")),
    ))
    .parse(lower)
    .ok()?;

    // CR 401.5 + CR 118.9 + CR 601.2a: Static-shaped "you may [play|cast] X
    // from the top of your library" lines (Realmwalker, Future Sight, Bolas's
    // Citadel) are routed to `parse_static_line` →
    // `StaticMode::TopOfLibraryCastPermission` by `is_static_compound_pattern`
    // before the imperative dispatcher runs, so this path does not see them.
    // Trigger sub-effects (Ziatora's Envoy combat-damage trigger, The
    // Belligerent attack trigger granting "until end of turn, you may play
    // lands and cast spells from the top of your library") are NOT classified
    // — they parse through the imperative path here and lower to
    // `Effect::CastFromZone`, the same shape the engine has long supported for
    // these cards. A blanket guard against the "from the top of your library"
    // anchor would silently regress those triggers to `Unimplemented`.

    let without_paying = scan_contains_phrase(rest, "without paying its mana cost")
        || scan_contains_phrase(rest, "without paying their mana cost");
    let constraint = parse_cast_permission_constraint(rest);

    // Branch 1: anaphoric forms. Order longer-first ("one of those cards"
    // before "those cards") so the prefix-match doesn't shadow the longer
    // anaphor.
    if alt((
        tag::<_, _, E>("one of those cards"),
        tag("the exiled card"),
        tag("those cards"),
        tag("cards exiled"),
        tag("that card"),
        tag("that spell"),
        tag("the copy"),
        tag("them"),
        tag("it"),
    ))
    .parse(rest)
    .is_ok()
    {
        let (_, dur) = strip_trailing_duration(lower);
        let duration = dur.or_else(|| {
            scan_contains_phrase(lower, "this turn").then_some(Duration::UntilEndOfTurn)
        });
        return Some(Effect::CastFromZone {
            target: TargetFilter::ParentTarget,
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }

    // CR 610.3 + CR 118.9 + CR 608.2c: "Cast [quantifier] [filter] from among
    // them/those cards" — the cards-exiled-by-this-resolution anaphor.
    // Improvisation Capstone, Etali (Primal Storm / Primal Conqueror),
    // Dream Pillager, Hatchery Spider, Genesis Hydra, etc. Following an
    // ExileFromTopUntil or ExileTop[N] resolver that publishes
    // `ExileLink::TrackedBySource`, the cast effect must bind to
    // `TargetFilter::ExiledBySource` so the runtime restricts the choice to
    // cards just exiled by this same resolution. Without the bind the parser
    // falls through to Branch 3 with `TargetFilter::Any`, and the cast
    // option lists every card in the game (semantically incorrect even
    // though `optional: true` prevents auto-misfire).
    //
    // Detection: a "from among them" / "from among those cards" anchor
    // anywhere in `rest` (post-"cast " prefix) is structurally diagnostic of
    // the per-resolution exile-set anaphor.
    if scan_contains_phrase(rest, "from among those nonland cards") {
        return Some(Effect::CastFromZone {
            target: TargetFilter::And {
                filters: vec![
                    TargetFilter::ExiledBySource,
                    TargetFilter::Typed(
                        TypedFilter::card().with_type(TypeFilter::Non(Box::new(TypeFilter::Land))),
                    ),
                ],
            },
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration: None,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }
    // CR 610.3 + CR 118.9 + CR 608.2c + CR 701.13a: "Cast [quantifier] [filter]
    // from among [the|those] [typed] cards exiled this way" — the article-`the`
    // + "exiled this way" surface form of the per-resolution exile-set anaphor.
    // Mirrors the "from among those nonland cards" arm above; suffix
    // "exiled this way" keeps the anchor disjoint from the bare anaphor arm
    // below ("from among the exiled cards" lacks this suffix and falls through).
    //
    // Unlocks the WotC-templated "exiled this way" family: Etali Primal
    // Conqueror, Etali Primal Storm, Crabomination, Gix Yawgmoth Praetor,
    // Hellcarver Demon, and similar.
    if let Some(target) = parse_from_among_exiled_this_way(rest) {
        return Some(Effect::CastFromZone {
            target,
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration: None,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }
    if scan_contains_phrase(rest, "from among them")
        || scan_contains_phrase(rest, "from among those cards")
        || scan_contains_phrase(rest, "from among those exiled cards")
        || scan_contains_phrase(rest, "from among the exiled cards")
    {
        return Some(Effect::CastFromZone {
            target: TargetFilter::ExiledBySource,
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration: None,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }

    // CR 406.6 + CR 603.10a: "[cast a <filter> spell] from among cards exiled
    // with [self-ref]" — the persistent per-source exile-link anaphor.
    // Distinct from Branch 1.5's per-resolution `from among them` anaphor:
    // Jeleva, Nephalia's Scourge / Mizzix's Mastery / Riku of Two Reflections
    // and the wider class of cards that exile cards on an earlier trigger
    // (ETB / cast / first-strike-damage) and reference those exiled cards
    // from a later, independent ability (attack trigger, sacrifice cost, etc.).
    // The exile link lives on the source object across resolutions, so
    // `TargetFilter::ExiledBySource` is the correct binding — the runtime
    // resolves it via `linked_exile_cards_for_source`, which scopes to the
    // permanent's persistent tracked-exile set.
    //
    // When a typed filter is present ("cast an instant or sorcery spell ..."),
    // AND it with `ExiledBySource` so the cast is restricted both by card
    // type and by the source-exile-link.
    if has_from_among_cards_exiled_with_self(rest) {
        // First try the disjunctive form ("an instant or sorcery spell ...")
        // since `parse_type_phrase` doesn't currently handle " or " between
        // bare core-type words. Then fall back to `parse_type_phrase` for
        // single-type forms.
        let typed_filter = parse_cast_type_disjunction(rest)
            .map(TargetFilter::Typed)
            .unwrap_or_else(|| super::oracle_target::parse_type_phrase(rest).0);
        let target = if let TargetFilter::Typed(mut tf) = typed_filter {
            // CR 406.1: source-linked exiled cards live in the Exile zone.
            // Make the zone explicit so target legality (CR 601.2c) restricts
            // the choice to exile-zone objects even before AND'ing with
            // ExiledBySource.
            if !tf
                .properties
                .iter()
                .any(|p| matches!(p, FilterProp::InZone { .. }))
            {
                tf.properties.push(FilterProp::InZone { zone: Zone::Exile });
            }
            TargetFilter::And {
                filters: vec![TargetFilter::Typed(tf), TargetFilter::ExiledBySource],
            }
        } else {
            TargetFilter::ExiledBySource
        };
        return Some(Effect::CastFromZone {
            target,
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration: None,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }

    // Branch 2: constrained-filter form (Buster Sword, FIN equipment cycle).
    // CR 118.9 + CR 601.2a: "cast a <filter> spell [from <zone>] [with mana
    // value <bound>] without paying its mana cost" — extract the constraint
    // by composing `parse_type_phrase` (handles "a [type-phrase]") with
    // origin-zone inference and a `with mana value` suffix scan over the
    // remainder. The suffix scan is necessary because `parse_type_phrase`'s
    // own internal `parse_mana_value_suffix` call runs before `parse_zone_suffix`,
    // so for inputs of the form "spell from your hand with mana value ..."
    // the mana-value clause is past the type-phrase pos when reached.
    let cast_target_rest = strip_cast_target_prefix(rest);
    let mut filter = parse_cast_type_disjunction(rest)
        .map(TargetFilter::Typed)
        .unwrap_or_else(|| super::oracle_target::parse_type_phrase(cast_target_rest).0);
    if cast_filter_has_typed_leaf(&filter) {
        apply_cast_target_suffixes(&mut filter, rest);
        return Some(Effect::CastFromZone {
            target: filter,
            without_paying_mana_cost: without_paying,
            mode,
            cast_transformed: false,
            alt_ability_cost: None,
            constraint,
            duration: None,
            driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
        });
    }

    // Branch 3: bare fallback.
    Some(Effect::CastFromZone {
        target: TargetFilter::Any,
        without_paying_mana_cost: without_paying,
        mode,
        cast_transformed: false,
        alt_ability_cost: None,
        constraint,
        duration: None,
        driver: crate::types::ability::CastFromZoneDriver::LingeringPermission,
    })
}

fn parse_cast_permission_constraint(lower: &str) -> Option<CastPermissionConstraint> {
    type E<'a> = OracleError<'a>;
    let (tail, _) = take_until::<_, _, E>("if that spell's mana value is ")
        .parse(lower)
        .ok()?;
    let (rest, _) = tag::<_, _, E>("if that spell's mana value is ")
        .parse(tail)
        .ok()?;
    let (after_value, value) = nom_quantity::parse_quantity_expr_number(rest).ok()?;
    let after_value = after_value.trim_start();
    let comparator = if tag::<_, _, E>("or less").parse(after_value).is_ok() {
        Comparator::LE
    } else if tag::<_, _, E>("or greater").parse(after_value).is_ok() {
        Comparator::GE
    } else {
        Comparator::EQ
    };
    Some(CastPermissionConstraint::ManaValue { comparator, value })
}

/// CR 118.9 + CR 119.4: Recognise an "alternative-cost rider" — text of the
/// form "[If you cast a spell this way,] pay <ability-cost> rather than
/// paying its mana cost". The body parses to an `AbilityCost` that the
/// runtime pays in lieu of the spell's mana cost when casting via a granted
/// `ExileWithAltAbilityCost` permission. Returns `Some(cost)` when the rider
/// shape is recognised; `None` otherwise. Currently handles the "pay life
/// equal to its mana value" form (Nashi, Moon Sage's Scion); the cost
/// parser will accept other `AbilityCost` shapes naturally as they are
/// added.
pub(crate) fn try_parse_alt_cost_rider(text: &str) -> Option<crate::types::ability::AbilityCost> {
    type Vbe<'a> = OracleError<'a>;
    let lower = text.to_lowercase();
    let trimmed_lower = lower.trim_end_matches('.').trim();
    // Accept the rider with or without an "if you cast a spell this way,"
    // conditional prefix (the conditional is folded into the runtime check
    // by the casting pipeline — the permission only fires for spells cast
    // through this grant). Both forms map to the same `AbilityCost`.
    let after_prefix = if let Ok((rest, _)) = alt((
        tag::<_, _, Vbe>("if you cast a spell this way, "),
        tag::<_, _, Vbe>("if you cast it this way, "),
    ))
    .parse(trimmed_lower)
    {
        rest
    } else {
        trimmed_lower
    };
    // Confirm the rider's tail. Without this guard, "pay life equal to its
    // mana value" alone (without the "rather than" clause) would also match —
    // but that form is a normal payment effect, not an alt-cost grant.
    if !nom_primitives::scan_contains(after_prefix, "rather than paying its mana cost")
        && !nom_primitives::scan_contains(after_prefix, "rather than pay its mana cost")
    {
        return None;
    }
    // CR 119.4: "pay life equal to its mana value" — the only currently-
    // supported rider body. Detect via nom prefix match; emit
    // `AbilityCost::PayLife { amount: SelfManaValue }` (CR 202.3 — "its mana
    // value" resolves against the spell-being-cast at cost-payment time).
    if let Ok((_, _)) = tag::<_, _, Vbe>("pay life equal to its mana value").parse(after_prefix) {
        return Some(crate::types::ability::AbilityCost::PayLife {
            amount: crate::types::ability::QuantityExpr::Ref {
                qty: crate::types::ability::QuantityRef::SelfManaValue,
            },
        });
    }
    None
}

/// CR 106.4 + CR 514.2: Recognise mana-retention riders that modify the mana
/// produced by the previous clause rather than creating a standalone effect.
fn try_parse_mana_retention_rider(text: &str) -> Option<ManaExpiry> {
    nom_on_lower(text, &text.to_lowercase(), |input| {
        let (input, _) = tag::<_, _, OracleError<'_>>("until end of turn, ").parse(input)?;
        let (input, _) = alt((tag("you "), tag("they "))).parse(input)?;
        let (input, _) = alt((tag("don't lose "), tag("don\u{2019}t lose "))).parse(input)?;
        let (input, _) = alt((
            value((), tag("this mana")),
            value((), tag("unspent mana")),
            value(
                (),
                preceded(
                    tag("unspent "),
                    preceded(nom_primitives::parse_color, tag(" mana")),
                ),
            ),
        ))
        .parse(input)?;
        let (input, _) = tag(" as steps and phases end").parse(input)?;
        let (input, _) = nom::combinator::opt(tag(".")).parse(input)?;
        nom::combinator::eof(input)?;
        Ok((input, ManaExpiry::EndOfTurn))
    })
    .map(|(expiry, _)| expiry)
}

/// CR 118.9: Walk `defs` from the back, descending into `sub_ability`
/// chains, and stamp `alt_ability_cost` onto the most recent `CastFromZone`
/// effect that does not already carry one. Returns `true` when a target
/// was found and stamped; `false` when no `CastFromZone` is in scope (the
/// caller should fall back to emitting the rider as an Unimplemented effect
/// to preserve coverage signal).
fn attach_alt_cost_to_prior_cast_from_zone(
    defs: &mut [AbilityDefinition],
    cost: crate::types::ability::AbilityCost,
) -> bool {
    fn walk(def: &mut AbilityDefinition, cost: &crate::types::ability::AbilityCost) -> bool {
        // Recurse into sub_ability first so we stamp the *most recent*
        // (deepest) CastFromZone in the chain — the rider attaches to the
        // immediately-preceding cast clause.
        if let Some(sub) = def.sub_ability.as_mut() {
            if walk(sub, cost) {
                return true;
            }
        }
        if let Effect::CastFromZone {
            alt_ability_cost: alt @ None,
            ..
        } = &mut *def.effect
        {
            *alt = Some(cost.clone());
            return true;
        }
        false
    }
    for def in defs.iter_mut().rev() {
        if walk(def, &cost) {
            return true;
        }
    }
    false
}

/// CR 106.4: Walk `defs` from the back, descending into `sub_ability` chains,
/// and stamp a mana-retention expiry onto the most recent Mana effect.
fn attach_mana_retention_to_prior_mana(defs: &mut [AbilityDefinition], expiry: ManaExpiry) -> bool {
    fn walk(def: &mut AbilityDefinition, expiry: ManaExpiry) -> bool {
        if let Some(sub) = def.sub_ability.as_mut() {
            if walk(sub, expiry) {
                return true;
            }
        }
        if let Effect::Mana {
            expiry: current @ None,
            ..
        } = &mut *def.effect
        {
            *current = Some(expiry);
            return true;
        }
        false
    }
    for def in defs.iter_mut().rev() {
        if walk(def, expiry) {
            return true;
        }
    }
    false
}

/// Swap every `Keyword` inside a `TargetFilter`'s `WithKeyword` properties to
/// `new_keyword`. Recurses through `Or`/`And` filter trees so a compound
/// affected filter is handled uniformly.
fn rewrite_filter_keyword(filter: &mut TargetFilter, new_keyword: &Keyword) {
    match filter {
        TargetFilter::Typed(typed) => {
            for prop in &mut typed.properties {
                if let FilterProp::WithKeyword { value } = prop {
                    *value = new_keyword.clone();
                }
            }
        }
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for f in filters {
                rewrite_filter_keyword(f, new_keyword);
            }
        }
        _ => {}
    }
}

/// Swap the granted keyword inside a `StaticCondition` to `new_keyword`.
fn rewrite_condition_keyword(condition: &mut StaticCondition, new_keyword: &Keyword) {
    match condition {
        StaticCondition::IsPresent {
            filter: Some(filter),
        } => rewrite_filter_keyword(filter, new_keyword),
        StaticCondition::And { conditions } | StaticCondition::Or { conditions } => {
            for c in conditions {
                rewrite_condition_keyword(c, new_keyword);
            }
        }
        StaticCondition::Not { condition } => rewrite_condition_keyword(condition, new_keyword),
        _ => {}
    }
}

/// CR 702: Apply a "The same is true for <keyword list>" continuation.
///
/// Walks `defs` from the back for the most recent `Effect::GenericEffect`, uses
/// its first `StaticDefinition` as a grant template, and appends one cloned
/// `StaticDefinition` per listed keyword — with both the granted keyword
/// (`AddKeyword` modification) and the gating condition's keyword swapped.
/// This keeps Odric's 13 keyword grants structurally identical: one
/// conditioned `StaticDefinition` each, all evaluated once at resolution time
/// (see `StaticDefinition.condition` dual-semantics doc).
fn attach_same_is_true_keywords(defs: &mut [AbilityDefinition], keywords: &[Keyword]) {
    for def in defs.iter_mut().rev() {
        if let Effect::GenericEffect {
            static_abilities, ..
        } = &mut *def.effect
        {
            let Some(template) = static_abilities.first().cloned() else {
                return;
            };
            for keyword in keywords {
                let mut new_def = template.clone();
                for modification in &mut new_def.modifications {
                    if let ContinuousModification::AddKeyword { keyword: kw } = modification {
                        *kw = keyword.clone();
                    }
                }
                if let Some(condition) = &mut new_def.condition {
                    rewrite_condition_keyword(condition, keyword);
                }
                static_abilities.push(new_def);
            }
            return;
        }
    }
}

/// CR 608.2c: Apply a "Repeat this process for <keyword list>" continuation
/// (Kathril, Aspect Warper). Walks `defs` from the back for the most recent
/// conditional keyword-counter placement (`PutCounter { counter_type:
/// Keyword(..) }` gated by a graveyard-keyword `condition`) and appends one
/// cloned sibling per listed keyword — swapping both the placed counter's
/// keyword and the gating condition's keyword. Each clone is an independent
/// sequential sibling, mirroring the antecedent's structure, so the engine
/// resolves all keyword counters during the trigger's one resolution. This is
/// the counters-class analogue of `attach_same_is_true_keywords` (static
/// grants); it covers the whole "repeat this process for <list>" class.
fn attach_repeat_process_keywords(defs: &mut Vec<AbilityDefinition>, keywords: &[Keyword]) {
    let Some(template) = defs
        .iter()
        .rev()
        .find(|d| {
            matches!(
                &*d.effect,
                Effect::PutCounter {
                    counter_type: CounterType::Keyword(_),
                    ..
                }
            )
        })
        .cloned()
    else {
        return;
    };
    for keyword in keywords {
        let mut new_def = template.clone();
        if let Effect::PutCounter { counter_type, .. } = &mut *new_def.effect {
            *counter_type = CounterType::Keyword(keyword.kind());
        }
        if let Some(condition) = &mut new_def.condition {
            rewrite_ability_condition_keyword(condition, keyword);
        }
        // Each replicated counter placement is its own sequential instruction.
        new_def.sub_link = SubAbilityLink::SequentialSibling;
        new_def.sub_ability = None;
        defs.push(new_def);
    }
}

/// Swap the gating keyword inside an `AbilityCondition` to `new_keyword`. Used
/// by `attach_repeat_process_keywords` to rewrite the "if a creature card in
/// your graveyard has <keyword>" gate of each replicated counter clause.
fn rewrite_ability_condition_keyword(condition: &mut AbilityCondition, new_keyword: &Keyword) {
    if let AbilityCondition::QuantityCheck { lhs, rhs, .. } = condition {
        rewrite_quantity_expr_keyword(lhs, new_keyword);
        rewrite_quantity_expr_keyword(rhs, new_keyword);
    }
}

/// Rewrite the keyword inside any `ObjectCount` filter carried by a
/// `QuantityExpr` (the count side of a graveyard-keyword condition).
fn rewrite_quantity_expr_keyword(expr: &mut QuantityExpr, new_keyword: &Keyword) {
    if let QuantityExpr::Ref {
        qty: QuantityRef::ObjectCount { filter },
    } = expr
    {
        rewrite_filter_keyword(filter, new_keyword);
    }
}

#[tracing::instrument(level = "debug")]
fn parse_imperative_effect(text: &str, ctx: &mut ParseContext) -> ParsedEffectClause {
    let lower = text.to_lowercase();
    let tp = TextPair::new(text, &lower);
    parse_imperative_effect_inner(tp, ctx)
}

fn parse_imperative_effect_inner(tp: TextPair, ctx: &mut ParseContext) -> ParsedEffectClause {
    if let Some(ast) = parse_imperative_family_ast(tp.original, tp.lower, ctx) {
        return lower_imperative_family_ast(ast);
    }

    // CR 114.1: "you get an emblem with "[static text]""
    if let Some(effect) = try_parse_emblem_creation(tp.lower, tp.original) {
        return parsed_clause(effect);
    }

    // Duration-scoped "play the exiled card" grants permission to the object
    // just exiled by the preceding clause. It is not an immediate cast/play
    // instruction, so it must win before the generic CastFromZone parser.
    if let Some(clause) = try_parse_play_from_exile(tp, ctx) {
        return clause;
    }

    // CR 601.3b + CR 702.8a: Flash-timing grants ("cast sorcery spells as though
    // they had flash") are not CastFromZone card picks — route before the cast
    // parser (issue #878).
    if let Some(clause) = try_parse_cast_as_though_flash_permission(tp) {
        return clause;
    }

    // CR 400.11 + CR 400.11a + CR 701.23j: "play/cast a … card you own from
    // outside the game [this turn]" (Wish, M19) draws from the sideboard /
    // wishboard pool, not from an in-game zone. Probe it before the generic
    // cast parser so it lowers to `Effect::SearchOutsideGame` instead of a
    // `CastFromZone` that would target an in-game permanent (issue #1976).
    if let Some(effect) = imperative::try_parse_play_from_outside_game(tp.lower, ctx) {
        return parsed_clause(effect);
    }

    // CR 608.2g + CR 601.2 + CR 118.9: "you may cast up to N ... without paying"
    // opens an interactive free-cast window, not a standing CastFromZone permission.
    // Keep this at the normal per-clause cast seam, before the generic cast parser.
    if let Some(effect) = try_parse_free_cast_from_zones(tp.lower) {
        return parsed_clause(effect);
    }

    // CR 601.2a + CR 118.9: "cast it/that card without paying its mana cost"
    if let Some(effect) = try_parse_cast_effect(tp.lower) {
        return parsed_clause(effect);
    }

    // CR 115.7: "change the target of" / "you may choose new targets for"
    if let Some(effect) = try_parse_change_targets(tp.lower) {
        return parsed_clause(effect);
    }

    // --- Fallback ---
    let verb = tp.lower.split_whitespace().next().unwrap_or("unknown");
    tracing::debug!(
        verb,
        oracle_text = tp.original,
        "imperative fallback to Unimplemented"
    );
    parsed_clause(Effect::Unimplemented {
        name: verb.to_string(),
        description: Some(tp.original.to_string()),
    })
}

/// Determines if text after "choose " is a targeting synonym rather than
/// a modal choice ("choose one —"), color choice, or creature type choice.
///
/// Returns true when the text contains "target" (indicating a targeting phrase)
/// or uses "a/an {type} you/opponent control(s)" (selection-as-targeting).
///
/// Returns false for:
///   - "card from it" — handled separately as RevealHand filter
///   - "a color" / "a creature type" / "a card type" / "a card name" — different mechanics
fn is_choose_as_targeting(rest: &str) -> bool {
    // Already handled elsewhere
    if scan_contains_phrase(rest, "card from it") {
        return false;
    }

    // If try_parse_named_choice would match "choose {rest}", it's a named choice, not targeting
    let as_full = format!("choose {rest}");
    if try_parse_named_choice(&as_full).is_some() {
        return false;
    }

    // Any phrase containing "target" is a targeting synonym
    if scan_contains_phrase(rest, "target") {
        return true;
    }

    // "choose up to N" without "target" (e.g. "choose up to two creatures"),
    // but NOT "choose up to N of them/those" which is anaphoric (handled separately).
    if tag::<_, _, OracleError<'_>>("up to ").parse(rest).is_ok()
        && !scan_contains_phrase(rest, "of them")
        && !scan_contains_phrase(rest, "of those")
    {
        return true;
    }

    // "choose a/an {type} ... you control / an opponent controls"
    if let Some(after_article) = nom_primitives::parse_article
        .parse(rest)
        .ok()
        .map(|(rest, _)| rest)
    {
        // Exclude patterns not yet in try_parse_named_choice but still not targeting
        if alt((
            tag::<_, _, OracleError<'_>>("nonbasic land type"),
            tag("number"),
        ))
        .parse(after_article)
        .is_ok()
        {
            return false;
        }
        // Must reference controller to be targeting-like.
        // "they control" covers "target opponent chooses a creature they control"
        // where "they" refers to the targeted player (CR 608.2d).
        // Exclude "from among" patterns (Cataclysm-family multi-category selection)
        // which require engine infrastructure not yet implemented.
        if !scan_contains_phrase(after_article, "from among")
            && (scan_contains_phrase(after_article, "you control")
                || scan_contains_phrase(after_article, "opponent controls")
                || scan_contains_phrase(after_article, "an opponent controls")
                || scan_contains_phrase(after_article, "they control"))
        {
            return true;
        }
    }

    // General controller-reference fallback for non-article patterns:
    // "six lands they control", "any number of creatures they control",
    // "three permanents they control", etc.
    // Exclude "from among" patterns (Cataclysm-family multi-category selection)
    // which require engine infrastructure not yet implemented.
    if !scan_contains_phrase(rest, "from among")
        && (scan_contains_phrase(rest, "they control") || scan_contains_phrase(rest, "you control"))
    {
        return true;
    }

    false
}

/// CR 205.2: Recognize the enumerated form of a "choose a card type" choice.
/// Older cards (e.g. Cloud Key) spell out the *complete* list of choosable card
/// types ("artifact, creature, enchantment, instant, or sorcery") instead of
/// the modern generic phrasing. A *partial* type list (e.g. "artifact, creature,
/// or land" — Storage Matrix, Turnabout, A Killer Among Us) is a restricted
/// modal selection, NOT a card-type chooser, and must remain `Labeled`. So this
/// matches only when `rest` (after an optional trailing period) is exactly the
/// canonical card-type set, in any order.
fn is_card_type_enumeration(rest: &str) -> bool {
    fn card_type_word(input: &str) -> nom::IResult<&str, &str, OracleError<'_>> {
        alt((
            tag("artifact"),
            tag("creature"),
            tag("enchantment"),
            tag("instant"),
            tag("sorcery"),
        ))
        .parse(input)
    }
    fn separator(input: &str) -> nom::IResult<&str, &str, OracleError<'_>> {
        alt((tag(", or "), tag(", "), tag(" or "))).parse(input)
    }
    let rest = rest.trim_end_matches('.').trim_end();
    match all_consuming(nom::multi::separated_list1(separator, card_type_word)).parse(rest) {
        Ok((_, mut items)) => {
            items.sort_unstable();
            items.dedup();
            // The complete canonical card-type set (alphabetical).
            items == ["artifact", "creature", "enchantment", "instant", "sorcery"]
        }
        Err(_) => false,
    }
}

/// Match "choose a creature type", "choose a color", "choose odd or even",
/// "choose a basic land type", "choose a card type" from lowercased Oracle text.
pub(crate) fn try_parse_named_choice(lower: &str) -> Option<ChoiceType> {
    let (rest, _) = alt((
        tag::<_, _, OracleError<'_>>("choose "),
        nom::sequence::preceded(tag("secretly "), tag("choose ")),
    ))
    .parse(lower)
    .ok()?;
    type E<'a> = OracleError<'a>;
    if tag::<_, _, E>("a creature type").parse(rest).is_ok() {
        Some(ChoiceType::CreatureType)
    } else if let Ok((_, excluded)) = preceded(
        tag::<_, _, E>("a color other than "),
        nom_primitives::parse_color,
    )
    .parse(rest)
    {
        Some(ChoiceType::color_excluding(vec![excluded]))
    } else if tag::<_, _, E>("a color").parse(rest).is_ok() {
        Some(ChoiceType::color())
    } else if tag::<_, _, E>("odd or even").parse(rest).is_ok() {
        Some(ChoiceType::OddOrEven)
    } else if tag::<_, _, E>("a basic land type").parse(rest).is_ok() {
        Some(ChoiceType::BasicLandType)
    } else if tag::<_, _, E>("a card type").parse(rest).is_ok() {
        Some(ChoiceType::CardType)
    } else if is_card_type_enumeration(rest) {
        // CR 205.2: Older "choose a card type" cards (Cloud Key) spell out the
        // options ("artifact, creature, enchantment, instant, or sorcery")
        // rather than using the modern generic phrasing. Treat the enumeration
        // as the same CardType choice so the chosen type persists for downstream
        // `IsChosenCardType` reads (cost reduction, protection from the chosen
        // type, etc.).
        Some(ChoiceType::CardType)
    } else if alt((
        tag::<_, _, E>("a card name"),
        tag("a nonland card name"),
        tag("a creature card name"),
        tag("a land card name"),
    ))
    .parse(rest)
    .is_ok()
    {
        Some(ChoiceType::CardName)
    } else if let Ok((range_rest, _)) = tag::<_, _, E>("a number between ").parse(rest) {
        // "choose a number between 0 and 13"
        let mut parts = range_rest.splitn(3, ' ');
        let min = parts.next().and_then(|s| s.parse::<u8>().ok()).unwrap_or(0);
        let and = parts.next();
        let max = parts
            .next()
            .and_then(|s| {
                s.trim_end_matches(|c: char| !c.is_ascii_digit())
                    .parse::<u8>()
                    .ok()
            })
            .unwrap_or(20);
        if and == Some("and") {
            Some(ChoiceType::NumberRange { min, max })
        } else {
            None
        }
    } else if let Ok((gt_rest, _)) = tag::<_, _, E>("a number greater than ").parse(rest) {
        // "choose a number greater than 0" — open-ended, cap at 20
        let n = gt_rest
            .split_whitespace()
            .next()
            .and_then(|s| s.parse::<u8>().ok())
            .unwrap_or(0);
        Some(ChoiceType::NumberRange {
            min: n + 1,
            max: 20,
        })
    } else if rest == "a number" || tag::<_, _, E>("a number ").parse(rest).is_ok() {
        // Generic "choose a number" — default range 0-20
        Some(ChoiceType::NumberRange { min: 0, max: 20 })
    } else if alt((tag::<_, _, E>("a land type"), tag("a nonbasic land type")))
        .parse(rest)
        .is_ok()
    {
        Some(ChoiceType::LandType)
    } else if tag::<_, _, E>("an opponent").parse(rest).is_ok() {
        // CR 800.4a: Choose an opponent from among players in the game.
        Some(ChoiceType::Opponent)
    } else if tag::<_, _, E>("a player").parse(rest).is_ok() {
        Some(ChoiceType::Player)
    } else if tag::<_, _, E>("two colors").parse(rest).is_ok() {
        Some(ChoiceType::TwoColors)
    } else if tag::<_, _, E>("a word").parse(rest).is_ok() {
        Some(ChoiceType::Word)
    } else if tag::<_, _, E>("an artist").parse(rest).is_ok() {
        Some(ChoiceType::Artist)
    } else {
        // Generic "X or Y" / "X, Y, or Z" / "W, X, Y, or Z" labeled choice —
        // must come AFTER all specific patterns above.
        try_parse_labeled_choice(rest).map(|options| ChoiceType::Labeled { options })
    }
}

/// Try to parse a labeled choice ("X or Y", "X, Y, or Z", "W, X, Y, or Z", ...) into
/// its option list. The Oxford-comma form is canonical in MTG Oracle text — every
/// printed N≥3 labeled choice (Master of Ceremonies, Storage Matrix, Turnabout,
/// Teferi's Realm, A Killer Among Us) uses ", or " before the last item.
///
/// Each label must be ≤2 whitespace-delimited words and must not contain
/// "target", "more", or "both" — these gates filter out clausal disjunctions
/// ("destroy target creature or land you control") that aren't real labeled
/// choices.
///
/// This must come AFTER all specific patterns in `try_parse_named_choice` to
/// avoid accidentally matching "choose left or right" against targeting
/// patterns.
fn try_parse_labeled_choice(rest: &str) -> Option<Vec<String>> {
    // N-ary Oxford-comma form first: split on the LAST ", or " (which `split_once_on`
    // finds as the first occurrence of the separator — there's only one in well-formed
    // Oracle text since middle items are joined by ", ").
    if let Ok((_, (head, tail))) = nom_primitives::split_once_on(rest, ", or ") {
        let mut labels: Vec<&str> = Vec::new();
        let mut remaining = head.trim();
        // Walk the comma-separated middle labels via the same nom combinator.
        while let Ok((_, (middle, next))) = nom_primitives::split_once_on(remaining, ", ") {
            labels.push(middle.trim());
            remaining = next.trim();
        }
        // Whatever's left of `remaining` after the loop is the last middle label
        // (or the only middle label if there were no inner commas — i.e. "X, or Y").
        if !remaining.is_empty() {
            labels.push(remaining);
        }
        labels.push(tail.trim());
        return validate_and_capitalize_labels(&labels);
    }

    // Binary form: "X or Y" with no comma before "or".
    let (_, (left, right)) = nom_primitives::split_once_on(rest, " or ").ok()?;
    validate_and_capitalize_labels(&[left.trim(), right.trim()])
}

/// Apply the per-label validation gates uniformly across all labels in a labeled
/// choice and return the capitalized result.
///
/// Gates:
/// - At least 2 labels (a single-element "list" isn't a choice).
/// - Each label is ≤2 whitespace-delimited words. Longer phrases are clauses,
///   not labels.
/// - No label contains "target" — distinguishes labeled choices from object
///   disjunctions like "creature or planeswalker".
/// - No label is "more" or "both" — these are quantifier/conjunction words,
///   not choice labels (e.g. "five or more", "one or both").
fn validate_and_capitalize_labels(labels: &[&str]) -> Option<Vec<String>> {
    if labels.len() < 2 {
        return None;
    }
    for label in labels {
        if label.is_empty() || label.split_whitespace().count() > 2 {
            return None;
        }
        if scan_contains_phrase(label, "target") {
            return None;
        }
        if *label == "more" || *label == "both" {
            return None;
        }
    }
    Some(labels.iter().map(|l| capitalize(l)).collect())
}

/// Refine a damage target based on remainder text left after `parse_target`.
/// Handles common patterns:
/// - "'s controller" → `ParentTargetController` (CR 608.2c)
/// - "or planeswalker" / "or blocking creature" → union with additional type
fn refine_damage_target_remainder(target: TargetFilter, remainder: &str) -> (TargetFilter, &str) {
    let trimmed = remainder.trim();
    // CR 608.2c: "'s controller" — redirect damage to the controller of the target
    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("'s controller").parse(trimmed) {
        return (TargetFilter::ParentTargetController, rest);
    }
    // "or <target>" — expand target to union: "creature or planeswalker",
    // "creature or blocking creature", "~ or enchanted creature", etc.
    // Uses parse_target (not parse_type_phrase) to handle special patterns
    // like "enchanted creature" that aren't plain type phrases.
    if let Ok((after_or, _)) = tag::<_, _, OracleError<'_>>("or ").parse(trimmed) {
        let (additional, type_rem) = parse_target(after_or);
        if !matches!(additional, TargetFilter::Any) {
            return (
                TargetFilter::Or {
                    filters: vec![target, additional],
                },
                type_rem,
            );
        }
    }
    (target, remainder)
}

/// Split a post-"choose" clause into the card-description phrase and any trailing
/// restriction suffix after `"from it"` (e.g. `"with mana value 2 or less"`).
/// CR 702.148a: cleave brackets are removed at build time, so the suffix here is
/// plain text — `combine_choose_filter_parts` merges it and relies on
/// `parse_search_filter`'s self-bounding terminator to drop any trailing sentence.
fn choose_filter_parts(text: &str) -> (&str, &str) {
    if let Ok((_, (before, suffix))) = nom_primitives::split_once_on(text, " card from among those")
    {
        return (before.trim(), suffix.trim());
    }
    if let Ok((_, (before, suffix))) = nom_primitives::split_once_on(text, " card from among them")
    {
        return (before.trim(), suffix.trim());
    }
    if let Ok((_, (before, suffix))) = nom_primitives::split_once_on(text, " card from it") {
        return (before.trim(), suffix.trim());
    }
    (text.trim(), "")
}

fn parse_choose_filter_leading_body(input: &str) -> &str {
    type E<'a> = OracleError<'a>;
    preceded(opt(alt((tag::<_, _, E>("a "), tag("an ")))), rest::<_, E>)
        .parse(input.trim())
        .map(|(_, body)| body.trim())
        .unwrap_or(input.trim())
}

fn trailing_bare_article_only(input: &str) -> bool {
    type E<'a> = OracleError<'a>;
    opt(alt((
        all_consuming(terminated(take_until::<_, _, E>(" an"), tag(" an"))),
        all_consuming(terminated(take_until::<_, _, E>(" a"), tag(" a"))),
    )))
    .parse(input.trim())
    .is_ok()
}

/// Merge the pre-`from it` card phrase with the plain trailing restriction
/// suffix that follows `"card from it"` (e.g. `"with mana value 2 or less"`).
///
/// CR 702.148a: Cleave's bracketed text is removed at build time before this
/// parse runs (the base parse sees the bracket *content* without the bracket
/// characters; the cleave-cost parse sees it removed entirely). So the suffix
/// here is plain text, not a bracketed span. The merged string is handed to
/// `parse_search_filter`, whose `search_filter_region` self-bounds at the first
/// `". "`/`"."`, so any trailing sentence (Dread Fugue's "That player discards
/// that card.") is naturally dropped without bracket-specific extraction.
fn combine_choose_filter_parts(filter_part: &str, suffix_part: &str) -> String {
    let filter_part = parse_choose_filter_leading_body(filter_part);
    let suffix = suffix_part.trim();
    if suffix.is_empty() {
        filter_part.to_string()
    } else if filter_part.is_empty() {
        suffix.to_string()
    } else {
        format!("{filter_part} {suffix}")
    }
}

fn parse_choose_filter(lower: &str, ctx: &mut ParseContext) -> TargetFilter {
    // Extract type info between "choose" and "card from it"
    // Handle both "choose X" and "you choose X" forms
    let after_choose = alt((
        tag::<_, _, OracleError<'_>>("you choose "),
        tag("you may choose "),
        tag("choose "),
    ))
    .parse(lower)
    .map(|(rest, _)| rest)
    .unwrap_or(lower);

    // "one of them/those [cards]" — selection reference to parent target set
    if tag::<_, _, OracleError<'_>>("one of th")
        .parse(after_choose)
        .is_ok()
    {
        return TargetFilter::ParentTarget;
    }

    let (filter_part, suffix_part) = choose_filter_parts(after_choose);
    let combined = combine_choose_filter_parts(filter_part, suffix_part);

    // Intentional: bare article "a [card]" or empty string means any card — not a parse failure
    if combined.is_empty() || combined == "a" {
        return TargetFilter::Any;
    }

    // CR 202.3: Delegate full card restrictions (type + mana value bounds, etc.) to the
    // shared search-filter parser — cleave bracket suffixes after "from it" are merged above.
    let search_filter = parse_search_filter(&combined, ctx);
    if !is_unrestricted_card_filter(&search_filter) {
        return search_filter;
    }

    let cleaned = filter_part;

    // structural: not dispatch — segmenting pre-extracted type string on comma separator
    // Comma-separated negation: "noncreature, nonland" → intersection of negations
    if cleaned.contains(", ") {
        let comma_parts: Vec<&str> = cleaned.split(", ").collect();
        let mut tf = TypedFilter::card();
        let mut all_resolved = true;
        for part in &comma_parts {
            if let Some(TargetFilter::Typed(part_tf)) = type_str_to_target_filter(part.trim()) {
                // Merge Non(...) type filters and properties, skip the Card base
                for t in part_tf.type_filters {
                    if !matches!(t, TypeFilter::Card) {
                        tf = tf.with_type(t);
                    }
                }
                for p in part_tf.properties {
                    tf.properties.push(p);
                }
            } else {
                all_resolved = false;
                break;
            }
        }
        if all_resolved {
            return TargetFilter::Typed(tf);
        }
    }

    // Try full type phrase parsing first — handles compound patterns like
    // "green or white creature", "nonland permanent", "spirit or arcane"
    let (phrase_filter, phrase_rem) = parse_type_phrase(cleaned);
    if !matches!(phrase_filter, TargetFilter::Any) && phrase_rem.trim().is_empty() {
        return phrase_filter;
    }

    let parts: Vec<&str> = cleaned.split(" or ").collect();
    if parts.len() > 1 {
        let filters: Vec<TargetFilter> = parts
            .iter()
            .filter_map(|p| type_str_to_target_filter(p.trim()))
            .collect();
        if filters.len() > 1 {
            return TargetFilter::Or { filters };
        }
        if let Some(f) = filters.into_iter().next() {
            return f;
        }
    }
    if let Some(f) = type_str_to_target_filter(cleaned) {
        return f;
    }
    ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
        context: "unrecognized type string".into(),
        text: cleaned.into(),
        line_index: 0,
    });
    TargetFilter::Any
}

fn type_str_to_target_filter(s: &str) -> Option<TargetFilter> {
    // Simple core types
    let card_type = match s {
        "artifact" => Some(TypeFilter::Artifact),
        "creature" => Some(TypeFilter::Creature),
        "enchantment" => Some(TypeFilter::Enchantment),
        "instant" => Some(TypeFilter::Instant),
        "sorcery" => Some(TypeFilter::Sorcery),
        "planeswalker" => Some(TypeFilter::Planeswalker),
        "land" => Some(TypeFilter::Land),
        "permanent" => Some(TypeFilter::Permanent),
        _ => None,
    };
    if let Some(ct) = card_type {
        return Some(TargetFilter::Typed(TypedFilter::new(ct)));
    }

    // CR 205.4b: Negated types — "nonland", "noncreature", etc.
    if let Some(negated) = s.strip_prefix("non") {
        // Card type negation
        let inner = match negated {
            "creature" => Some(TypeFilter::Creature),
            "land" => Some(TypeFilter::Land),
            "artifact" => Some(TypeFilter::Artifact),
            "enchantment" => Some(TypeFilter::Enchantment),
            "instant" => Some(TypeFilter::Instant),
            "sorcery" => Some(TypeFilter::Sorcery),
            "planeswalker" => Some(TypeFilter::Planeswalker),
            _ => None,
        };
        if let Some(inner) = inner {
            return Some(TargetFilter::Typed(
                TypedFilter::card().with_type(TypeFilter::Non(Box::new(inner))),
            ));
        }
        // CR 205.4a: Supertype negation — "nonbasic", "nonlegendary", "nonsnow"
        let super_prop = match negated {
            "basic" => Some(FilterProp::NotSupertype {
                value: Supertype::Basic,
            }),
            "legendary" => Some(FilterProp::NotSupertype {
                value: Supertype::Legendary,
            }),
            "snow" => Some(FilterProp::NotSupertype {
                value: Supertype::Snow,
            }),
            _ => None,
        };
        if let Some(prop) = super_prop {
            return Some(TargetFilter::Typed(
                TypedFilter::card().properties(vec![prop]),
            ));
        }
        return None;
    }

    // structural: not dispatch — splitting pre-extracted type string at word boundary
    // Compound: "nonland permanent", "nonbasic land"
    if let Some(pos) = s.find(' ') {
        let (first, rest) = s.split_at(pos);
        let rest = rest.trim();
        // Handle "nonbasic land", "nonlegendary" as supertype negation + type
        if let Some(negated_super) = first.strip_prefix("non") {
            let super_prop = match negated_super {
                "basic" => Some(FilterProp::NotSupertype {
                    value: Supertype::Basic,
                }),
                "legendary" => Some(FilterProp::NotSupertype {
                    value: Supertype::Legendary,
                }),
                "snow" => Some(FilterProp::NotSupertype {
                    value: Supertype::Snow,
                }),
                _ => None,
            };
            if let Some(prop) = super_prop {
                // Recurse for the base type
                if let Some(TargetFilter::Typed(base_tf)) = type_str_to_target_filter(rest) {
                    return Some(TargetFilter::Typed(base_tf.properties(vec![prop])));
                }
            }
        }
        // "nonland permanent" etc. — negated type modifier + base type
        // Only merge Non(...) filters from the negation part, not the Card base
        if let Some(TargetFilter::Typed(neg_tf)) = type_str_to_target_filter(first) {
            if let Some(TargetFilter::Typed(base_tf)) = type_str_to_target_filter(rest) {
                let mut combined = base_tf;
                for tf in neg_tf.type_filters {
                    if matches!(tf, TypeFilter::Non(_)) {
                        combined = combined.with_type(tf);
                    }
                }
                return Some(TargetFilter::Typed(combined));
            }
        }
    }

    None
}

/// True when a filter imposes no restriction beyond "any card" (including empty `Typed`).
fn is_unrestricted_card_filter(filter: &TargetFilter) -> bool {
    match filter {
        TargetFilter::Any => true,
        TargetFilter::Typed(tf) => {
            tf.type_filters.is_empty() && tf.properties.is_empty() && tf.controller.is_none()
        }
        _ => false,
    }
}

fn parse_article_type_phrase_suffix<'a>(
    input: &'a str,
) -> nom::IResult<&'a str, &'a str, OracleError<'a>> {
    alt((
        preceded(tag::<_, _, OracleError<'_>>(" an "), rest),
        preceded(tag(" a "), rest),
    ))
    .parse(input)
}

/// Type phrase after the last article in text that precedes `"card from"` (e.g. `"nonland"`,
/// `"creature with mana value 3 or less"`, or empty for bare `"a card from it"`).
fn type_phrase_before_card_from(before_card: &str) -> &str {
    let trimmed = before_card.trim();

    if trailing_bare_article_only(trimmed) {
        return "";
    }

    let mut last = trimmed;
    let mut cursor = 0;
    while cursor < trimmed.len() {
        let slice = &trimmed[cursor..];
        if let Some((_rel_before, phrase, _rest)) =
            nom_primitives::scan_preceded(slice, parse_article_type_phrase_suffix)
        {
            last = phrase.trim();
            cursor += 1;
        } else {
            break;
        }
    }
    last
}

fn choose_filter_search_text(phrase: &str) -> String {
    if nom_primitives::scan_contains(phrase, "card") {
        phrase.to_string()
    } else {
        format!("{phrase} card")
    }
}

/// Extract card type filter from a sub-ability sentence containing "card from it/among".
/// Handles forms like "exile a nonland card from it", "discard a creature card from it".
fn parse_choose_filter_from_sentence(lower: &str, ctx: &mut ParseContext) -> TargetFilter {
    let before_card = match take_until::<_, _, OracleError<'_>>("card from")
        .parse(lower)
        .ok()
    {
        Some((_, before)) => before,
        None => {
            ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
                context: "choose-from-sentence missing 'card from'".into(),
                text: lower.trim().into(),
                line_index: 0,
            });
            return TargetFilter::Any;
        }
    };
    // Use the full type phrase before "card from" (e.g. "nonland", "creature with mana
    // value 3 or less"), not only the last word.
    let phrase = type_phrase_before_card_from(before_card);
    if phrase.is_empty() || phrase == "a" {
        return TargetFilter::Any;
    }
    let search_text = choose_filter_search_text(phrase);
    let filter = parse_search_filter(&search_text, ctx);
    if !is_unrestricted_card_filter(&filter) {
        return filter;
    }
    // Legacy single-word fallback for short descriptors ("nonland", "creature").
    let word = phrase.rsplit(' ').next().unwrap_or(phrase);
    if let Some(negated) = word.strip_prefix("non") {
        if let Some(TargetFilter::Typed(tf)) = type_str_to_target_filter(negated) {
            if let Some(primary) = tf.get_primary_type().cloned() {
                return TargetFilter::Typed(
                    TypedFilter::card().with_type(TypeFilter::Non(Box::new(primary))),
                );
            }
        }
    }
    type_str_to_target_filter(word).unwrap_or_else(|| {
        ctx.push_diagnostic(OracleDiagnostic::TargetFallback {
            context: "unrecognized choose-from-sentence type".into(),
            text: phrase.into(),
            line_index: 0,
        });
        TargetFilter::Any
    })
}

/// Check if an effect exiles objects (candidate for tracked set recording).
/// Also looks inside `CreateDelayedTrigger` wrappers, since a previous clause's
/// exile may have already been wrapped by `strip_temporal_suffix`.
///
/// CR 406.1 + CR 603.7: `ExileTop` exiles the top N cards of a library — the
/// same library-to-exile zone transfer that `ChangeZone { destination: Exile }`
/// performs for a specifically-targeted card. Cross-clause anaphors like
/// "put that card into your hand at the beginning of your next end step"
/// (Necropotence, Bomat Courier, Asmodeus the Archfiend, Knowledge Vault — the
/// exile-top-then-recall class, ~16 cards) bind to the just-exiled cards via
/// the tracked-set pathway. Without including `ExileTop` here, follow-up
/// clauses against an `ExileTop` prior never publish a tracked set and the
/// delayed-trigger return resolves with `ParentTarget` pointing nowhere.
fn is_exile_effect(effect: &Effect) -> bool {
    match effect {
        Effect::ChangeZone {
            destination: Zone::Exile,
            ..
        }
        | Effect::ChangeZoneAll {
            destination: Zone::Exile,
            ..
        }
        | Effect::ExileTop { .. } => true,
        Effect::CreateDelayedTrigger { effect: inner, .. } => is_exile_effect(&inner.effect),
        _ => false,
    }
}

fn publishes_tracked_set_from_resolution(effect: &Effect) -> bool {
    is_exile_effect(effect)
        || is_token_creating_effect(effect)
        || matches!(
            effect,
            Effect::PutCounter { .. }
                | Effect::PutCounterAll { .. }
                | Effect::MultiplyCounter { .. }
                | Effect::MoveCounters { .. }
        )
}

/// CR 603.7: Detect explicit cross-clause pronouns ("those cards", "the exiled card").
/// `lower` must be the pre-lowered version of the text.
fn contains_explicit_tracked_set_pronoun(lower: &str) -> bool {
    scan_contains_phrase(lower, "those cards")
        || scan_contains_phrase(lower, "those permanents")
        || scan_contains_phrase(lower, "those creatures")
        || scan_contains_phrase(lower, "those tokens")
        || scan_contains_phrase(lower, "the exiled card")
        || scan_contains_phrase(lower, "the exiled permanent")
        || scan_contains_phrase(lower, "the exiled creature")
}

/// CR 603.7: Detect implicit anaphora when preceded by an exile effect.
/// Context-sensitive — only matches when the pronoun is in a recall
/// construction whose destination is one of the supported zones.
/// `lower` must be the pre-lowered version of the text.
///
/// Two recall shapes are recognized:
///   * "return it/them to the battlefield" — the Aetherling / Crackling Drake
///     class (exile-then-return-to-battlefield).
///   * "put that card/them/it into your hand" — the Necropotence / Bomat
///     Courier / Asmodeus class (exile-then-recall-to-hand). The hand-recall
///     branch is what unlocks Necropotence's "Pay 1 life: Exile the top card
///     of your library face down. Put that card into your hand at the
///     beginning of your next end step." pattern (~16 cards).
///   * "create a token that's a copy of that card" — the Sin, Spira's
///     Punishment class where the copy source is the card just exiled by the
///     previous instruction, not the trigger source.
fn contains_implicit_tracked_set_pronoun(lower: &str) -> bool {
    // Battlefield recall — "return it/them ... battlefield". Start-anchored
    // because cross-clause anaphors begin the recall clause.
    let battlefield_recall = alt((
        tag::<_, _, OracleError<'_>>("return it "),
        tag("return them "),
    ))
    .parse(lower)
    .is_ok()
        && scan_contains_phrase(lower, "battlefield");

    // Hand recall — "put {that card,them,it} into your hand". Composed via
    // nested `alt()` over the pronoun axis (CLAUDE.md "compose nom
    // combinators, don't enumerate permutations") within a shared "put …
    // into your hand" frame.
    let hand_recall = (
        tag::<_, _, OracleError<'_>>("put "),
        alt((
            tag::<_, _, OracleError<'_>>("that card"),
            tag("them"),
            tag("it"),
        )),
        tag(" into your hand"),
    )
        .parse(lower)
        .is_ok();

    let copy_token_recall = (
        take_until::<_, _, OracleError<'_>>("copy of "),
        tag("copy of "),
        tag("that card"),
    )
        .parse(lower)
        .is_ok();

    // CR 400.7i + CR 603.7: Play-from-exile grant — "[you may] play/cast {that
    // card, that spell, it, those cards, them} for as long as {it,that card,...}
    // remains exiled". The "that card" anaphor refers to the card the preceding
    // exile published into the tracked set. Gated on the "remains exiled"
    // duration phrase (the impulse-grant fingerprint) plus a play/cast verb so
    // it never matches an unrelated "that card" mention. This caller is itself
    // only consulted when the previous clause is an exile that publishes a
    // tracked set, so the gate is doubly scoped (Gonti, Canny Acquisitor).
    let play_from_exile_grant = (scan_contains_phrase(lower, "remains exiled")
        || scan_contains_phrase(lower, "remain exiled"))
        && (scan_contains_phrase(lower, "may play")
            || scan_contains_phrase(lower, "may cast")
            || tag::<_, _, OracleError<'_>>("play ").parse(lower).is_ok()
            || tag::<_, _, OracleError<'_>>("cast ").parse(lower).is_ok());

    // CR 603.7 + CR 400.7h + CR 118.9: cross-clause "you may play/cast that card
    // without paying its mana cost [until end of turn / this turn]" — the "that
    // card" anaphor refers to the card the preceding exile published into the
    // tracked set (Urza, Lord High Artificer's {5}; the "shuffle ..., then exile
    // the top card, you may play it for free until end of turn" class). Distinct
    // from the `play_from_exile_grant` "remains exiled" impulse grant (which is
    // PAID and permanent-duration); this is the FREE-cast, turn-scoped
    // fingerprint. Only consulted after a prior clause publishes a tracked set,
    // and triply scoped: anaphor (play/cast that card) + free-cast marker
    // (without paying) + turn duration (until end of turn / this turn).
    let free_cast_that_card_grant = (scan_contains_phrase(lower, "play that card")
        || scan_contains_phrase(lower, "cast that card"))
        && scan_contains_phrase(lower, "without paying")
        && (scan_contains_phrase(lower, "until end of turn")
            || scan_contains_phrase(lower, "this turn"));

    battlefield_recall
        || hand_recall
        || copy_token_recall
        || play_from_exile_grant
        || free_cast_that_card_grant
}

fn mark_uses_tracked_set(def: &mut AbilityDefinition) {
    if let Effect::CreateDelayedTrigger {
        uses_tracked_set, ..
    } = &mut *def.effect
    {
        *uses_tracked_set = true;
    }
}

fn tracked_set_filter() -> TargetFilter {
    TargetFilter::TrackedSet {
        id: TrackedSetId(0),
    }
}

fn rewrite_filter_parent_to_tracked_set(filter: &mut TargetFilter) {
    match filter {
        TargetFilter::ParentTarget => *filter = tracked_set_filter(),
        TargetFilter::Not { filter } => rewrite_filter_parent_to_tracked_set(filter),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for filter in filters {
                rewrite_filter_parent_to_tracked_set(filter);
            }
        }
        _ => {}
    }
}

fn fold_cast_copy_of_card_defs(defs: &mut Vec<AbilityDefinition>) {
    let mut index = 0;
    while index + 1 < defs.len() {
        let copies_parent_card = matches!(
            &*defs[index].effect,
            Effect::CopySpell {
                target: TargetFilter::ParentTarget,
                ..
            }
        );
        let casts_the_copy_without_paying = matches!(
            &*defs[index + 1].effect,
            Effect::CastFromZone {
                target: TargetFilter::ParentTarget,
                without_paying_mana_cost: true,
                mode: CardPlayMode::Cast,
                ..
            }
        );

        if copies_parent_card && casts_the_copy_without_paying {
            *defs[index].effect = Effect::CastCopyOfCard {
                target: tracked_set_filter(),
                cost: ManaCost::zero(),
            };
            defs[index].optional = false;
            defs[index].repeat_for = None;
            defs.remove(index + 1);
        } else {
            index += 1;
        }
    }
}

fn rewrite_parent_targets_to_tracked_set(effect: &mut Effect) {
    match effect {
        // CR 701.26a/b: only single-target tap/untap carries a rewritable target.
        Effect::SetTapState {
            scope: EffectScope::Single,
            target,
            ..
        }
        | Effect::Destroy { target, .. }
        | Effect::GainControl { target }
        | Effect::Fight { target, .. }
        | Effect::Bounce { target, .. }
        | Effect::DealDamage { target, .. }
        | Effect::Pump { target, .. }
        | Effect::Counter { target, .. }
        | Effect::Transform { target, .. }
        | Effect::Connive { target, .. }
        | Effect::PhaseOut { target }
        | Effect::ForceBlock { target }
        | Effect::ForceAttack { target, .. }
        | Effect::CastCopyOfCard { target, .. }
        | Effect::CopyTokenOf { target, .. }
        | Effect::PutCounter { target, .. }
        | Effect::RemoveCounter { target, .. }
        | Effect::ChangeZone { target, .. }
        | Effect::ChangeZoneAll { target, .. }
        // CR 603.7 + CR 608.2c: A cross-clause "cast/play that card / those
        // cards" anaphor following an exile resolves to the *tracked set*
        // (the cards exiled by the prior clause), not the trigger source.
        // Fallen Shinobi ("...you may play those cards without paying their
        // mana costs"), Daxos of Meletis ("...you may cast that card..."),
        // and similar cross-clause cast forms reach `try_parse_cast_effect`
        // with `target: ParentTarget`; this rewrite binds them to the
        // tracked exile set during chain stitching.
        | Effect::CastFromZone { target, .. } => rewrite_filter_parent_to_tracked_set(target),
        Effect::Attach { target, .. } => rewrite_filter_parent_to_tracked_set(target),
        Effect::UnattachAll { target, .. } => rewrite_filter_parent_to_tracked_set(target),
        Effect::GenericEffect {
            target,
            static_abilities,
            ..
        } => {
            if let Some(target) = target {
                rewrite_filter_parent_to_tracked_set(target);
            }
            for static_def in static_abilities {
                if let Some(affected) = &mut static_def.affected {
                    rewrite_filter_parent_to_tracked_set(affected);
                }
            }
        }
        // CR 603.7 + CR 400.7i: "You may play that card for as long as it
        // remains exiled" — the "that card" anaphor refers to the card the
        // preceding exile published into the tracked set. A bare
        // play-from-exile grant parses with `target: Any` (or `ParentTarget`),
        // which `grant_permission::resolve` would otherwise bind to the source
        // object rather than the exiled card. Re-target it to the tracked set so
        // the permission attaches to the just-exiled card (Gonti, Canny
        // Acquisitor). Scoped to `PlayFromExile` so non-impulse grants are
        // untouched.
        Effect::GrantCastingPermission {
            target,
            permission: CastingPermission::PlayFromExile { .. },
            ..
        } if matches!(target, TargetFilter::Any | TargetFilter::ParentTarget) => {
            *target = tracked_set_filter();
        }
        _ => {}
    }
}

/// CR 603.7c + CR 400.7 + CR 603.7a: A *delayed* triggered ability that returns a
/// snapshotted `ParentTarget` referent may only move it if it is still in the zone
/// the prior clause placed it in (the expected zone, fixed at delayed-trigger
/// creation per CR 603.7a). Walk the effect tree for `CreateDelayedTrigger`
/// wrappers ONLY — a non-delayed `ParentTarget` `ChangeZone` has no snapshot
/// semantics and must not be stamped (an intervening chain clause could
/// legitimately re-move the referent). Mirrors `rewrite_parent_targets_to_tracked_set`.
fn stamp_delayed_returns(effect: &mut Effect, expected: Zone) {
    if let Effect::CreateDelayedTrigger { effect, .. } = effect {
        stamp_inside_delayed(&mut effect.effect, expected);
    }
}

/// Stamps the expected origin zone onto every `ParentTarget`-targeted
/// `ChangeZone`/`ChangeZoneAll` reached inside a `CreateDelayedTrigger` subtree
/// whose `origin` is still unset, so the resolver's CR 400.7 `origin` guard
/// (`change_zone::resolve`) fires. Recurses into nested `CreateDelayedTrigger`.
fn stamp_inside_delayed(effect: &mut Effect, expected: Zone) {
    match effect {
        Effect::ChangeZone { target, origin, .. }
        | Effect::ChangeZoneAll { target, origin, .. }
            if origin.is_none() && matches!(target, TargetFilter::ParentTarget) =>
        {
            *origin = Some(expected);
        }
        Effect::CreateDelayedTrigger { effect, .. } => {
            stamp_inside_delayed(&mut effect.effect, expected);
        }
        _ => {}
    }
}

fn append_to_deepest_sub_ability(
    ability: &mut AbilityDefinition,
    tail: Option<Box<AbilityDefinition>>,
) {
    let Some(tail) = tail else {
        return;
    };

    let mut cursor = ability;
    while cursor.sub_ability.is_some() {
        cursor = cursor
            .sub_ability
            .as_mut()
            .expect("sub_ability checked above");
    }
    cursor.sub_ability = Some(tail);
}

fn intrinsic_continuation_effect(def: &AbilityDefinition) -> &Effect {
    if matches!(*def.effect, Effect::TargetOnly { .. }) {
        if let Some(sub_ability) = def.sub_ability.as_deref() {
            return &sub_ability.effect;
        }
    }
    &def.effect
}

/// CR 107.1a: Strip a trailing "Round down each time" / "Round up each time"
/// sentence from a chain of Oracle text, returning the stripped text and the
/// captured rounding mode. Used by `parse_effect_chain_ir` to consume the
/// chain-level rounding annotation (Pox Plague) before chunk splitting so
/// the phrase doesn't become an Unimplemented chunk. The captured mode is
/// re-applied to every `DivideRounded` in the built chain via
/// `rewrite_rounding_mode`.
fn strip_trailing_rounding_annotation(text: &str) -> (String, Option<RoundingMode>) {
    let trimmed = text.trim_end();
    let trimmed_no_dot = trimmed.trim_end_matches('.').trim_end();
    let lower = trimmed_no_dot.to_lowercase();
    for (phrase, mode) in [
        ("round down each time", RoundingMode::Down),
        ("round up each time", RoundingMode::Up),
    ] {
        if let Some(prefix_lower) = lower.strip_suffix(phrase) {
            // Require a sentence boundary before the phrase — either end of
            // text or a period followed by whitespace. Prevents matching
            // "when you round down each time" / similar mid-sentence usage.
            let before = &trimmed_no_dot[..prefix_lower.len()];
            let before_trimmed = before.trim_end();
            if before_trimmed.ends_with('.') {
                let without_phrase = before_trimmed.trim_end_matches('.').trim_end();
                return (without_phrase.to_string(), Some(mode));
            }
        }
    }
    (text.to_string(), None)
}

/// CR 602.5b: Activation instructions such as "Activate only once each turn"
/// restrict when an activated ability may be activated; they are not spell or
/// ability effects and must not become a chained `Unimplemented` effect.
fn strip_trailing_activation_restriction_sentence(text: &str) -> String {
    let trimmed = text.trim_end();
    let trimmed_no_dot = trimmed.trim_end_matches('.').trim_end();
    let lower = trimmed_no_dot.to_lowercase();
    for suffix in ["activate only once each turn", "activate only once"] {
        let Ok((rest, prefix_lower)) = terminated(
            take_until::<_, _, OracleError<'_>>(suffix),
            tag::<_, _, OracleError<'_>>(suffix),
        )
        .parse(lower.as_str()) else {
            continue;
        };
        if !rest.trim().is_empty() {
            continue;
        }
        let before = &trimmed_no_dot[..prefix_lower.len()];
        let before_trimmed = before.trim_end();
        if before_trimmed.ends_with('.') {
            return before_trimmed.trim_end_matches('.').trim_end().to_string();
        }
    }
    text.to_string()
}

/// CR 608.2c + CR 107.1a: Apply `f` to every `QuantityExpr` reachable through
/// the common quantity-bearing fields of an `Effect`. This is a pragmatic
/// visitor — it covers the subset of `Effect` variants whose counts /
/// amounts meaningfully reference player-scoped possessives ("their life",
/// "their hand") in Oracle text. Variants not listed here keep their
/// expressions untouched; add arms here when a new variant surfaces a
/// possessive quantity.
pub(crate) fn each_quantity_expr_mut(effect: &mut Effect, f: &mut impl FnMut(&mut QuantityExpr)) {
    match effect {
        Effect::LoseLife { amount, .. }
        | Effect::GainLife { amount, .. }
        | Effect::SetLifeTotal { amount, .. } => f(amount),
        Effect::DealDamage { amount, .. } => f(amount),
        Effect::Draw { count, .. }
        | Effect::Mill { count, .. }
        | Effect::Discard { count, .. }
        | Effect::Scry { count, .. }
        | Effect::Surveil { count, .. }
        | Effect::PutCounter { count, .. } => f(count),
        Effect::Sacrifice { count, .. } => f(count),
        _ => {}
    }
}

/// CR 109.4 + CR 608.2c: Apply `f` to every `TargetFilter` reachable through
/// the common target-bearing fields of an `Effect`. Companion to
/// `each_quantity_expr_mut`; used by callers that need to rewrite target slots
/// across an effect chain (e.g. the prevention follow-up call site rewrites
/// `ParentTargetController` → `PostReplacementSourceController` so "the source's
/// controller draws cards" resolves against the prevented event's damage source).
///
/// Pragmatic visitor — covers the subset of `Effect` variants whose target
/// slots are statically declared as `TargetFilter` or `Option<TargetFilter>`.
/// Variants not listed here keep their target slots untouched; **add an arm
/// when introducing a new target-bearing variant** so future rewrites cover it.
/// Variant list mirrors `replace_target_with_parent` plus a handful of
/// player-targetable effects (Draw, LoseLife, Discard, Mill, Scry, Surveil,
/// RevealFromHand) whose `target` field is a `TargetFilter` and can therefore
/// hold a player ref like `ParentTargetController`.
pub(crate) fn each_target_filter_mut(effect: &mut Effect, f: &mut impl FnMut(&mut TargetFilter)) {
    match effect {
        // CR 701.26a/b: only single-target tap/untap exposes a per-event target
        // filter; the mass (`All`) scope is a population filter and was never
        // visited here (it falls through to the no-op arm), matching the legacy
        // `TapAll`/`UntapAll`.
        Effect::SetTapState {
            scope: EffectScope::Single,
            target,
            ..
        }
        | Effect::Destroy { target, .. }
        | Effect::Regenerate { target, .. }
        | Effect::Sacrifice { target, .. }
        | Effect::GainControl { target }
        | Effect::Fight { target, .. }
        | Effect::Bounce { target, .. }
        | Effect::DealDamage { target, .. }
        | Effect::Pump { target, .. }
        | Effect::Attach { target, .. }
        | Effect::UnattachAll { target, .. }
        | Effect::Counter { target, .. }
        | Effect::Transform { target, .. }
        | Effect::Connive { target, .. }
        | Effect::PhaseOut { target }
        | Effect::ForceBlock { target }
        | Effect::ForceAttack { target, .. }
        | Effect::Draw { target, .. }
        | Effect::Discard { target, .. }
        | Effect::Mill { target, .. }
        | Effect::Scry { target, .. }
        | Effect::Surveil { target, .. }
        | Effect::Dig { player: target, .. }
        | Effect::RevealTop { player: target, .. }
        | Effect::ExileTop { player: target, .. }
        | Effect::Manifest { target, .. }
        | Effect::TargetOnly { target, .. } => f(target),
        Effect::PutCounter { target, .. } | Effect::RemoveCounter { target, .. } => f(target),
        Effect::ChangeZone { target, .. } | Effect::ChangeZoneAll { target, .. } => f(target),
        Effect::LoseLife {
            target: Some(target),
            ..
        } => f(target),
        Effect::GenericEffect {
            target: Some(target),
            ..
        } => f(target),
        _ => {}
    }
}

/// CR 608.2 + CR 107.2: Rewrite target-scoped `QuantityRef` variants to their
/// controller-scoped equivalents across an ability tree. Under
/// `player_scope: All` / `Opponent` / etc., the resolver rebinds
/// `scoped.controller = *pid` per iterating player, but `targets` remains
/// unchanged. `TargetLifeTotal` and `TargetZoneCardCount` resolve against
/// `targets`, returning 0 in the scoped context; the controller-scoped
/// `LifeTotal`, `HandSize`, `GraveyardSize`, and
/// `ZoneCardCount{scope:Controller}` variants read the rebound controller.
///
/// Walks the entire `AbilityDefinition` tree (ability → sub_ability → …) so
/// every chained clause under an each-player chain (Pox Plague:
/// "Each player loses half their life, then discards half the cards in their
/// hand, then sacrifices half the permanents they control") picks up the
/// rewrite uniformly. Only reached when the top-level `def.player_scope` is
/// set, so non-scoped abilities keep the target-scoped resolution path.
fn rewrite_filter_controller_to_scoped(filter: &mut TargetFilter) {
    match filter {
        TargetFilter::Typed(typed) if typed.controller == Some(ControllerRef::You) => {
            typed.controller = Some(ControllerRef::ScopedPlayer);
        }
        TargetFilter::Not { filter } => rewrite_filter_controller_to_scoped(filter),
        TargetFilter::Or { filters } | TargetFilter::And { filters } => {
            for filter in filters {
                rewrite_filter_controller_to_scoped(filter);
            }
        }
        _ => {}
    }
}

fn rewrite_condition_quantity_expr(expr: &mut QuantityExpr) {
    match expr {
        QuantityExpr::Ref { qty } => match qty {
            QuantityRef::LifeTotal { player }
            | QuantityRef::HandSize { player }
            | QuantityRef::LifeLostThisTurn { player }
            | QuantityRef::LifeGainedThisTurn { player }
            | QuantityRef::PartySize { player }
                if *player == PlayerScope::Controller =>
            {
                *player = PlayerScope::ScopedPlayer;
            }
            QuantityRef::ObjectCount { filter }
            | QuantityRef::ObjectCountBySharedQuality { filter, .. } => {
                rewrite_filter_controller_to_scoped(filter)
            }
            _ => {}
        },
        QuantityExpr::DivideRounded { inner, .. }
        | QuantityExpr::Multiply { inner, .. }
        | QuantityExpr::ClampMin { inner, .. }
        | QuantityExpr::Offset { inner, .. } => rewrite_condition_quantity_expr(inner),
        QuantityExpr::Sum { exprs } => {
            for inner in exprs {
                rewrite_condition_quantity_expr(inner);
            }
        }
        QuantityExpr::UpTo { max } => rewrite_condition_quantity_expr(max),
        QuantityExpr::Power { exponent, .. } => rewrite_condition_quantity_expr(exponent),
        QuantityExpr::Difference { left, right } => {
            rewrite_condition_quantity_expr(left);
            rewrite_condition_quantity_expr(right);
        }
        QuantityExpr::Fixed { .. } => {}
    }
}

fn rewrite_player_scope_refs(def: &mut AbilityDefinition) {
    fn rewrite_condition(condition: &mut AbilityCondition) {
        match condition {
            AbilityCondition::QuantityCheck { lhs, rhs, .. } => {
                rewrite_condition_quantity_expr(lhs);
                rewrite_condition_quantity_expr(rhs);
            }
            AbilityCondition::TargetMatchesFilter { filter, .. }
            | AbilityCondition::SourceMatchesFilter { filter }
            | AbilityCondition::ZoneChangeObjectMatchesFilter { filter, .. }
            | AbilityCondition::ControllerControlsMatching { filter }
            | AbilityCondition::ZoneChangedThisWay { filter }
            | AbilityCondition::CostPaidObjectMatchesFilter { filter } => {
                rewrite_filter_controller_to_scoped(filter);
            }
            AbilityCondition::Not { condition }
            | AbilityCondition::ConditionInstead { inner: condition } => {
                rewrite_condition(condition)
            }
            AbilityCondition::And { conditions } | AbilityCondition::Or { conditions } => {
                for condition in conditions {
                    rewrite_condition(condition);
                }
            }
            _ => {}
        }
    }

    fn rewrite_quantity_expr(expr: &mut QuantityExpr) {
        match expr {
            QuantityExpr::Ref { qty } => match qty {
                QuantityRef::LifeTotal {
                    player: PlayerScope::Target,
                } => {
                    *qty = QuantityRef::LifeTotal {
                        player: PlayerScope::ScopedPlayer,
                    }
                }
                QuantityRef::HandSize {
                    player: PlayerScope::Target,
                } => {
                    *qty = QuantityRef::HandSize {
                        player: PlayerScope::ScopedPlayer,
                    }
                }
                QuantityRef::TargetZoneCardCount { zone } => match zone {
                    crate::types::ability::ZoneRef::Hand => {
                        *qty = QuantityRef::HandSize {
                            player: PlayerScope::ScopedPlayer,
                        }
                    }
                    // CR 608.2 + CR 109.5 — Issue #310: "their library" inside
                    // an iterating `player_scope` resolves against the
                    // iterated player's library. Pre-fix this rewrite emitted
                    // `CountScope::Controller` (caster) which broke
                    // Maddening Cacophony's kicker mode. `CountScope::ScopedPlayer`
                    // falls back to Controller outside iteration, so non-scoped
                    // sites still resolve correctly.
                    crate::types::ability::ZoneRef::Library
                    | crate::types::ability::ZoneRef::Graveyard => {
                        *qty = QuantityRef::ZoneCardCount {
                            zone: zone.clone(),
                            card_types: Vec::new(),
                            scope: crate::types::ability::CountScope::ScopedPlayer,
                            filter: None,
                        };
                    }
                    // Exile has no clean controller-scoped equivalent in the
                    // current `QuantityRef` set. Leave untouched — the
                    // scoped-controller resolver path does not exist for
                    // exile card counts, so preserving the target-scoped
                    // form at least lets a targeting ability resolve
                    // correctly.
                    crate::types::ability::ZoneRef::Exile => {}
                },
                _ => {}
            },
            QuantityExpr::DivideRounded { inner, .. }
            | QuantityExpr::Multiply { inner, .. }
            | QuantityExpr::ClampMin { inner, .. }
            | QuantityExpr::Offset { inner, .. } => rewrite_quantity_expr(inner),
            QuantityExpr::Sum { exprs } => {
                for inner in exprs {
                    rewrite_quantity_expr(inner);
                }
            }
            QuantityExpr::UpTo { max } => rewrite_quantity_expr(max),
            QuantityExpr::Power { exponent, .. } => rewrite_quantity_expr(exponent),
            QuantityExpr::Difference { left, right } => {
                rewrite_quantity_expr(left);
                rewrite_quantity_expr(right);
            }
            QuantityExpr::Fixed { .. } => {}
        }
    }

    each_quantity_expr_mut(&mut def.effect, &mut rewrite_quantity_expr);
    if let Some(condition) = def.condition.as_mut() {
        rewrite_condition(condition);
    }
    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_player_scope_refs(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_player_scope_refs(else_branch);
    }
}

/// CR 608.2 + CR 109.5: Apply `rewrite_player_scope_refs` rooted at every def in
/// the chain that carries `player_scope` — not only the outermost one. A scoped
/// clause routinely appears NESTED as a sub-ability: Betor, Kin to All chains
/// "draw a card", "untap each creature you control", then "each opponent loses
/// half their life, rounded up", so `player_scope: Opponent` sits on the third
/// sub-ability while the outermost effect (Draw) has none. Gating the rewrite on
/// the outermost def's scope left the nested clause's "their life" as
/// `LifeTotal { Target }`, which resolves to 0 (no player target). Once a scoped
/// root is found, `rewrite_player_scope_refs` already recurses through its own
/// sub-chain, so we stop descending here to avoid rewriting it twice.
fn apply_player_scope_rewrites(def: &mut AbilityDefinition) {
    if def.player_scope.is_some() {
        rewrite_player_scope_refs(def);
        return;
    }
    if let Some(sub) = def.sub_ability.as_mut() {
        apply_player_scope_rewrites(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        apply_player_scope_rewrites(else_branch);
    }
}

/// CR 603.7c + CR 119.3 + CR 120.3: Rebind the event-bound player possessive
/// inside a "deals [combat] damage to a player" / "attacks a player" trigger
/// body from the *targeting* reading (`PlayerScope::Target`, emitted by the
/// generic "their life" / "their hand" possessive parser) to the
/// *event* reading (`PlayerScope::ScopedPlayer`).
///
/// These triggers are NOT targeted (CR 603.6f): "they"/"their" binds to the
/// damaged/attacked player carried on the triggering event, which the engine
/// stamps onto `ResolvedAbility::scoped_player` at resolution. Without this
/// rewrite, "they lose half their life" parses its amount as
/// `LifeTotal { Target }`, which reads an absent player target and resolves to
/// 0 (Unstoppable Slasher's silent no-op). Mirrors the each-player rewrite in
/// [`rewrite_player_scope_refs`] but is deliberately narrower — it touches only
/// quantity refs, never `You`-scoped filters, so "you draw a card" on the same
/// trigger still acts for the controller.
/// CR 613.1 + CR 503.1a: Rebind possessive player quantities in a trigger
/// whose condition names "the chosen player's" phase step (The Rack) to read
/// the source's persisted `ChosenAttribute::Player`.
pub(crate) fn rewrite_player_quantity_refs_to_source_chosen(def: &mut AbilityDefinition) {
    use crate::types::ability::{CountScope, PlayerScope, QuantityRef, ZoneRef};

    fn rewrite_qty(expr: &mut QuantityExpr) {
        match expr {
            QuantityExpr::Ref { qty } => match qty {
                QuantityRef::LifeTotal { player }
                | QuantityRef::HandSize { player }
                | QuantityRef::LifeLostThisTurn { player }
                | QuantityRef::LifeGainedThisTurn { player }
                | QuantityRef::PartySize { player }
                    if matches!(
                        *player,
                        PlayerScope::Target | PlayerScope::ScopedPlayer | PlayerScope::Controller
                    ) =>
                {
                    *player = PlayerScope::SourceChosenPlayer;
                }
                QuantityRef::TargetZoneCardCount { zone } => match zone {
                    ZoneRef::Hand => {
                        *qty = QuantityRef::HandSize {
                            player: PlayerScope::SourceChosenPlayer,
                        }
                    }
                    ZoneRef::Library | ZoneRef::Graveyard => {
                        *qty = QuantityRef::ZoneCardCount {
                            zone: zone.clone(),
                            card_types: Vec::new(),
                            scope: CountScope::SourceChosenPlayer,
                            filter: None,
                        };
                    }
                    ZoneRef::Exile => {}
                },
                _ => {}
            },
            QuantityExpr::DivideRounded { inner, .. }
            | QuantityExpr::Multiply { inner, .. }
            | QuantityExpr::ClampMin { inner, .. }
            | QuantityExpr::Offset { inner, .. } => rewrite_qty(inner),
            QuantityExpr::Sum { exprs } => {
                for inner in exprs {
                    rewrite_qty(inner);
                }
            }
            QuantityExpr::UpTo { max } => rewrite_qty(max),
            QuantityExpr::Power { exponent, .. } => rewrite_qty(exponent),
            QuantityExpr::Difference { left, right } => {
                rewrite_qty(left);
                rewrite_qty(right);
            }
            QuantityExpr::Fixed { .. } => {}
        }
    }

    each_quantity_expr_mut(&mut def.effect, &mut rewrite_qty);
    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_player_quantity_refs_to_source_chosen(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_player_quantity_refs_to_source_chosen(else_branch);
    }
}

pub(crate) fn rewrite_event_player_quantity_refs_to_scoped(def: &mut AbilityDefinition) {
    use crate::types::ability::{CountScope, PlayerScope, QuantityRef, ZoneRef};

    fn rewrite_qty(expr: &mut QuantityExpr) {
        match expr {
            QuantityExpr::Ref { qty } => match qty {
                QuantityRef::LifeTotal { player }
                | QuantityRef::HandSize { player }
                | QuantityRef::LifeLostThisTurn { player }
                | QuantityRef::LifeGainedThisTurn { player }
                | QuantityRef::PartySize { player }
                    if *player == PlayerScope::Target =>
                {
                    *player = PlayerScope::ScopedPlayer;
                }
                QuantityRef::TargetZoneCardCount { zone } => match zone {
                    ZoneRef::Hand => {
                        *qty = QuantityRef::HandSize {
                            player: PlayerScope::ScopedPlayer,
                        }
                    }
                    ZoneRef::Library | ZoneRef::Graveyard => {
                        *qty = QuantityRef::ZoneCardCount {
                            zone: zone.clone(),
                            card_types: Vec::new(),
                            scope: CountScope::ScopedPlayer,
                            filter: None,
                        };
                    }
                    // No scoped-player equivalent for exile counts; leave as-is.
                    ZoneRef::Exile => {}
                },
                _ => {}
            },
            QuantityExpr::DivideRounded { inner, .. }
            | QuantityExpr::Multiply { inner, .. }
            | QuantityExpr::ClampMin { inner, .. }
            | QuantityExpr::Offset { inner, .. } => rewrite_qty(inner),
            QuantityExpr::Sum { exprs } => {
                for inner in exprs {
                    rewrite_qty(inner);
                }
            }
            QuantityExpr::UpTo { max } => rewrite_qty(max),
            QuantityExpr::Power { exponent, .. } => rewrite_qty(exponent),
            QuantityExpr::Difference { left, right } => {
                rewrite_qty(left);
                rewrite_qty(right);
            }
            QuantityExpr::Fixed { .. } => {}
        }
    }

    each_quantity_expr_mut(&mut def.effect, &mut rewrite_qty);
    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_event_player_quantity_refs_to_scoped(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_event_player_quantity_refs_to_scoped(else_branch);
    }
}

/// True when a trigger's intervening-if references the controller gaining life
/// this turn (Lathiel / Ocelot Pride class).
pub(crate) fn trigger_condition_references_controller_life_gained(
    condition: &crate::types::ability::TriggerCondition,
) -> bool {
    use crate::types::ability::TriggerCondition;
    match condition {
        TriggerCondition::GainedLife { .. } => true,
        TriggerCondition::QuantityComparison { lhs, .. } => {
            quantity_expr_references_controller_life_gained(lhs)
        }
        TriggerCondition::And { conditions } | TriggerCondition::Or { conditions } => conditions
            .iter()
            .any(trigger_condition_references_controller_life_gained),
        TriggerCondition::Not { condition } => {
            trigger_condition_references_controller_life_gained(condition)
        }
        _ => false,
    }
}

fn quantity_expr_references_controller_life_gained(expr: &QuantityExpr) -> bool {
    use crate::types::ability::{PlayerScope, QuantityRef};
    match expr {
        QuantityExpr::Ref {
            qty:
                QuantityRef::LifeGainedThisTurn {
                    player: PlayerScope::Controller,
                },
        } => true,
        QuantityExpr::Offset { inner, .. }
        | QuantityExpr::ClampMin { inner, .. }
        | QuantityExpr::Multiply { inner, .. }
        | QuantityExpr::DivideRounded { inner, .. }
        | QuantityExpr::UpTo { max: inner }
        | QuantityExpr::Power {
            exponent: inner, ..
        } => quantity_expr_references_controller_life_gained(inner),
        QuantityExpr::Sum { exprs } => exprs
            .iter()
            .any(quantity_expr_references_controller_life_gained),
        QuantityExpr::Difference { left, right } => {
            quantity_expr_references_controller_life_gained(left)
                || quantity_expr_references_controller_life_gained(right)
        }
        _ => false,
    }
}

/// CR 609.3 + CR 119.3: "distribute up to that many ..." on end-step life-gain
/// triggers anaphorizes "that many" to life gained this turn, not
/// `EventContextAmount` (which has no scalar on a phase trigger).
pub(crate) fn rewrite_gained_life_that_many_distribution_refs(def: &mut AbilityDefinition) {
    use crate::types::ability::{PlayerScope, QuantityRef};
    if def.distribute.is_none() {
        if let Some(sub) = def.sub_ability.as_mut() {
            rewrite_gained_life_that_many_distribution_refs(sub);
        }
        if let Some(else_branch) = def.else_ability.as_mut() {
            rewrite_gained_life_that_many_distribution_refs(else_branch);
        }
        return;
    }

    fn rewrite_qty(expr: &mut QuantityExpr) {
        match expr {
            QuantityExpr::Ref { qty } if matches!(*qty, QuantityRef::EventContextAmount) => {
                *qty = QuantityRef::LifeGainedThisTurn {
                    player: PlayerScope::Controller,
                };
            }
            QuantityExpr::Offset { inner, .. }
            | QuantityExpr::ClampMin { inner, .. }
            | QuantityExpr::Multiply { inner, .. }
            | QuantityExpr::DivideRounded { inner, .. }
            | QuantityExpr::UpTo { max: inner }
            | QuantityExpr::Power {
                exponent: inner, ..
            } => rewrite_qty(inner),
            QuantityExpr::Sum { exprs } => {
                for inner in exprs {
                    rewrite_qty(inner);
                }
            }
            QuantityExpr::Difference { left, right } => {
                rewrite_qty(left);
                rewrite_qty(right);
            }
            _ => {}
        }
    }

    each_quantity_expr_mut(&mut def.effect, &mut rewrite_qty);
    if let Some(spec) = def.multi_target.as_mut() {
        rewrite_qty(&mut spec.min);
        if let Some(max) = spec.max.as_mut() {
            rewrite_qty(max);
        }
    }
    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_gained_life_that_many_distribution_refs(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_gained_life_that_many_distribution_refs(else_branch);
    }
}

/// CR 107.1a: Back-apply a rounding mode to every `DivideRounded` in an ability
/// tree. Used by `parse_effect_chain_ir` after stripping a trailing
/// "Round down each time" / "Round up each time" sentence (Pox Plague), so
/// earlier chunks that defaulted to `RoundingMode::Down` pick up an explicit
/// `Up` annotation that Oracle grammar places in a separate closing
/// sentence. Class-level: handles both the redundant-default case (Pox
/// Plague already has Down) and hypothetical "Round up each time" variants
/// without new types.
fn rewrite_rounding_mode(def: &mut AbilityDefinition, mode: RoundingMode) {
    fn rewrite_quantity_expr(expr: &mut QuantityExpr, mode: RoundingMode) {
        match expr {
            QuantityExpr::DivideRounded {
                inner,
                divisor: _,
                rounding,
            } => {
                *rounding = mode;
                rewrite_quantity_expr(inner, mode);
            }
            QuantityExpr::Multiply { inner, .. }
            | QuantityExpr::ClampMin { inner, .. }
            | QuantityExpr::Offset { inner, .. } => rewrite_quantity_expr(inner, mode),
            QuantityExpr::Sum { exprs } => {
                for inner in exprs {
                    rewrite_quantity_expr(inner, mode);
                }
            }
            QuantityExpr::UpTo { max } => rewrite_quantity_expr(max, mode),
            QuantityExpr::Power { exponent, .. } => rewrite_quantity_expr(exponent, mode),
            QuantityExpr::Difference { left, right } => {
                rewrite_quantity_expr(left, mode);
                rewrite_quantity_expr(right, mode);
            }
            QuantityExpr::Ref { .. } | QuantityExpr::Fixed { .. } => {}
        }
    }

    each_quantity_expr_mut(&mut def.effect, &mut |expr| {
        rewrite_quantity_expr(expr, mode)
    });
    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_rounding_mode(sub, mode);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_rounding_mode(else_branch, mode);
    }
}

fn lift_each_player_exile_top_scope(effect: &mut Effect, player_scope: &mut Option<PlayerFilter>) {
    if player_scope.is_some() {
        return;
    }
    if let Effect::ExileTop { player, .. } = effect {
        if matches!(player, TargetFilter::ScopedPlayer) {
            *player = TargetFilter::Controller;
            *player_scope = Some(PlayerFilter::All);
        }
    }
}

fn collapse_ephemeral_color_choice_mana(def: &mut AbilityDefinition) {
    if matches!(
        &*def.effect,
        Effect::Choose {
            choice_type: ChoiceType::Color { excluded },
            persist: false,
        } if excluded.is_empty()
    ) {
        let can_collapse = def.sub_ability.as_ref().is_some_and(|sub| {
            matches!(
                &*sub.effect,
                Effect::Mana {
                    produced: ManaProduction::ChosenColor { .. },
                    target: None,
                    ..
                }
            )
        });
        if can_collapse {
            let mut mana = *def.sub_ability.take().expect("sub_ability checked above");
            def.effect = mana.effect;
            def.sub_ability = mana.sub_ability.take();
        }
    }

    if let Some(sub) = def.sub_ability.as_mut() {
        collapse_ephemeral_color_choice_mana(sub);
    }
}

fn parse_that_type_mana_count(text: &str) -> Option<QuantityExpr> {
    let lower = text.to_lowercase();
    nom_on_lower(text, &lower, |input| {
        let (input, _) = tag("add ").parse(input)?;
        let (input, count) = nom_quantity::parse_quantity(input)?;
        let (input, _) = tag(" mana of that type").parse(input)?;
        let (input, _) = opt(tag(" instead")).parse(input)?;
        let (input, _) = opt(tag(".")).parse(input)?;
        eof(input)?;
        Ok((input, count))
    })
    .map(|(count, _)| count)
}

fn mana_production_with_count(
    produced: &ManaProduction,
    count: QuantityExpr,
) -> Option<ManaProduction> {
    match produced {
        ManaProduction::Colorless { .. } => Some(ManaProduction::Colorless { count }),
        ManaProduction::AnyOneColor {
            color_options,
            contribution,
            ..
        } => Some(ManaProduction::AnyOneColor {
            count,
            color_options: color_options.clone(),
            contribution: *contribution,
        }),
        ManaProduction::AnyCombination { color_options, .. } => {
            Some(ManaProduction::AnyCombination {
                count,
                color_options: color_options.clone(),
            })
        }
        ManaProduction::ChosenColor {
            contribution,
            fixed_alternative,
            ..
        } => Some(ManaProduction::ChosenColor {
            count,
            contribution: *contribution,
            fixed_alternative: *fixed_alternative,
        }),
        ManaProduction::OpponentLandColors { .. } => {
            Some(ManaProduction::OpponentLandColors { count })
        }
        ManaProduction::AnyTypeProduceableBy { land_filter, .. } => {
            Some(ManaProduction::AnyTypeProduceableBy {
                count,
                land_filter: land_filter.clone(),
            })
        }
        ManaProduction::AnyInCommandersColorIdentity { contribution, .. } => {
            Some(ManaProduction::AnyInCommandersColorIdentity {
                count,
                contribution: *contribution,
            })
        }
        ManaProduction::AnyOneColorAmongPermanents {
            filter,
            contribution,
            ..
        } => Some(ManaProduction::AnyOneColorAmongPermanents {
            count,
            filter: filter.clone(),
            contribution: *contribution,
        }),
        ManaProduction::Fixed { .. }
        | ManaProduction::Mixed { .. }
        | ManaProduction::ChoiceAmongExiledColors { .. }
        | ManaProduction::ChoiceAmongCombinations { .. }
        | ManaProduction::DistinctColorsAmongPermanents { .. }
        | ManaProduction::TriggerEventManaType => None,
    }
}

fn rewrite_that_type_mana_instead(def: &mut AbilityDefinition) {
    let replacement = match (&*def.effect, def.sub_ability.as_deref()) {
        (
            Effect::Mana {
                produced,
                restrictions,
                grants,
                expiry,
                target,
            },
            Some(sub),
        ) => match sub.effect.as_ref() {
            Effect::Unimplemented {
                name,
                description: Some(description),
            } if name == "add" => parse_that_type_mana_count(description).and_then(|count| {
                Some(Effect::Mana {
                    produced: mana_production_with_count(produced, count)?,
                    restrictions: restrictions.clone(),
                    grants: grants.clone(),
                    expiry: *expiry,
                    target: target.clone(),
                })
            }),
            _ => None,
        },
        _ => None,
    };

    if let Some(effect) = replacement {
        if let Some(sub) = def.sub_ability.as_mut() {
            *sub.effect = effect;
        }
    }

    if let Some(sub) = def.sub_ability.as_mut() {
        rewrite_that_type_mana_instead(sub);
    }
    if let Some(else_branch) = def.else_ability.as_mut() {
        rewrite_that_type_mana_instead(else_branch);
    }
}

fn wire_optional_cast_decline_fallback(def: &mut AbilityDefinition) {
    if def.optional
        && matches!(
            def.condition,
            Some(AbilityCondition::AdditionalCostPaid { .. })
        )
        && matches!(&*def.effect, Effect::CastFromZone { .. })
        && def.else_ability.is_none()
    {
        def.else_ability = def.sub_ability.take();
    }

    if let Some(sub) = def.sub_ability.as_mut() {
        wire_optional_cast_decline_fallback(sub);
    }
    if let Some(else_ability) = def.else_ability.as_mut() {
        wire_optional_cast_decline_fallback(else_ability);
    }
}

/// Parse a compound effect chain into an `AbilityDefinition` sub-ability chain.
///
/// Phase 1 keeps the existing clause/effect semantics but replaces the fragile
/// textual `replace(", then ", ". ").split(". ")` logic with a boundary-aware
/// splitter that preserves whether a chunk ended a sentence or was linked by
/// `, then`.
///
/// **Self-reference precondition:** this entry point takes no `card_name`
/// and performs no normalization. Callers must pass text whose card-name
/// self-references have already been rewritten to `~` — which is always the
/// case when reached via [`parse_oracle_text`] or any of the wrapper parsers
/// that invoke `normalize_card_name_refs` internally. External test callers
/// must pre-normalize via `normalize_card_name_refs` before invoking.
pub fn parse_effect_chain(text: &str, kind: AbilityKind) -> AbilityDefinition {
    if let Some(def) = try_parse_exile_top_each_library_with_collection_counter(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_balance_equalization(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_return_target_and_same_name_from_your_graveyard(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_for_each_attacker_copy_blocker(text, kind) {
        return def;
    }
    let ir = parse_effect_chain_ir(text, kind, &mut ParseContext::default());
    let mut def = lower_effect_chain_ir(&ir);
    fold_speed_floor_sentences(&mut def);
    def
}

/// Parse a compound effect chain with subject context for pronoun resolution.
/// CR 608.2k: Used by the trigger parser to thread the trigger subject so that
/// bare pronouns ("it") resolve to TriggeringSource instead of SelfRef.
pub(crate) fn parse_effect_chain_with_context(
    text: &str,
    kind: AbilityKind,
    ctx: &mut ParseContext,
) -> AbilityDefinition {
    if let Some(def) = try_parse_exile_top_each_library_with_collection_counter(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_balance_equalization(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_return_target_and_same_name_from_your_graveyard(text, kind) {
        return def;
    }
    if let Some(def) = try_parse_for_each_attacker_copy_blocker(text, kind) {
        return def;
    }
    let ir = parse_effect_chain_ir(text, kind, ctx);
    let mut def = lower_effect_chain_ir(&ir);
    fold_speed_floor_sentences(&mut def);
    def
}

/// CR 509.1g + CR 506.3e + CR 707.2 + CR 603.7: Mirror Match's whole-card idiom
/// — "For each creature attacking you[ or a planeswalker you control], create a
/// token that's a copy of that creature and that's blocking that creature.
/// Exile those tokens at end of combat."
///
/// Lowers to `Effect::CopyTokenBlockingAttacker` (the copy-and-block half, whose
/// resolver copies each matched attacker and puts the copy onto the battlefield
/// blocking it, CR 506.3e) chained via `sub_ability` to a delayed end-of-combat
/// exile of "those tokens" (`TargetFilter::LastCreated`, snapshotted at
/// creation by the delayed-trigger resolver, CR 603.7c). The casting
/// restriction ("only during the declare blockers step") is handled separately
/// by the casting-line parser; an optional leading copy of that sentence is
/// stripped here defensively in case it reaches this entry inline.
///
/// `FilterProp::AttackingController` matches every attacker whose defending
/// player is the controller — which the engine records as the controller of an
/// attacked planeswalker/battle too, so "attacking you" and "or a planeswalker
/// you control" collapse onto the one predicate.
fn try_parse_for_each_attacker_copy_blocker(
    text: &str,
    kind: AbilityKind,
) -> Option<AbilityDefinition> {
    let lower = text.to_ascii_lowercase();
    // Optional leading casting-restriction sentence, if not pre-stripped.
    let i = opt(tag::<_, _, OracleError<'_>>(
        "cast this spell only during the declare blockers step.",
    ))
    .parse(lower.as_str())
    .map(|(rest, _)| rest.trim_start())
    .unwrap_or(lower.as_str());

    // "for each creature attacking you[ or a planeswalker you control], "
    let (i, _) = tag::<_, _, OracleError<'_>>("for each creature attacking you")
        .parse(i)
        .ok()?;
    let (i, _) = opt(tag::<_, _, OracleError<'_>>(
        " or a planeswalker you control",
    ))
    .parse(i)
    .ok()?;
    let (i, _) = tag::<_, _, OracleError<'_>>(", ").parse(i).ok()?;

    // "create a token that's a copy of <anaphor> and that's blocking <anaphor>"
    let (i, _) = tag::<_, _, OracleError<'_>>("create a token that's a copy of ")
        .parse(i)
        .ok()?;
    let (i, _) = alt((tag::<_, _, OracleError<'_>>("that creature"), tag("it")))
        .parse(i)
        .ok()?;
    let (i, _) = tag::<_, _, OracleError<'_>>(" and that's blocking ")
        .parse(i)
        .ok()?;
    let (i, _) = alt((tag::<_, _, OracleError<'_>>("that creature"), tag("it")))
        .parse(i)
        .ok()?;
    let (i, _) = opt(tag::<_, _, OracleError<'_>>(".")).parse(i).ok()?;
    let i = i.trim_start();

    // Optional trailing "exile those tokens at end of combat." sentence. When
    // present, it chains a delayed end-of-combat exile of the created tokens;
    // when the body ends after the copy clause, the recognizer still matches
    // (the copy-and-block half alone). Any other trailing text disqualifies the
    // whole-card match so the generic pipeline can attempt it instead.
    let exiles_tokens = if i.is_empty() {
        false
    } else {
        let (rest, _) = tag::<_, _, OracleError<'_>>("exile those tokens at end of combat")
            .parse(i)
            .ok()?;
        let (rest, _) = opt(tag::<_, _, OracleError<'_>>(".")).parse(rest).ok()?;
        if !rest.trim().is_empty() {
            return None;
        }
        true
    };

    let source_filter = TargetFilter::Typed(
        TypedFilter::creature().properties(vec![FilterProp::AttackingController]),
    );
    let mut def = AbilityDefinition::new(
        kind,
        Effect::CopyTokenBlockingAttacker {
            source_filter,
            owner: TargetFilter::Controller,
        },
    );
    if exiles_tokens {
        // CR 603.7c + CR 701.36a: "those tokens" → the tokens created above,
        // snapshotted at delayed-trigger creation via `TargetFilter::LastCreated`.
        let exile = AbilityDefinition::new(
            kind,
            Effect::ChangeZone {
                origin: Some(Zone::Battlefield),
                destination: Zone::Exile,
                target: TargetFilter::LastCreated,
                owner_library: false,
                enter_transformed: false,
                enters_under: None,
                enter_tapped: crate::types::zones::EtbTapState::Unspecified,
                enters_attacking: false,
                up_to: false,
                enter_with_counters: vec![],
                face_down_profile: None,
            },
        );
        def.sub_ability = Some(Box::new(AbilityDefinition::new(
            kind,
            Effect::CreateDelayedTrigger {
                condition: DelayedTriggerCondition::AtNextPhase {
                    phase: Phase::EndCombat,
                },
                effect: Box::new(exile),
                uses_tracked_set: false,
            },
        )));
    }
    Some(def)
}

fn try_parse_return_target_and_same_name_from_your_graveyard(
    text: &str,
    kind: AbilityKind,
) -> Option<AbilityDefinition> {
    let lower = text.to_ascii_lowercase();
    let (_, rest) = nom_on_lower(text, &lower, |input| value((), tag("return ")).parse(input))?;
    let rest_lower = &lower[lower.len() - rest.len()..];
    let rest_tp = TextPair::new(rest, rest_lower);
    let marker =
        " and all other cards with the same name as that card from your graveyard to the battlefield";
    let (target_tp, after_marker) = rest_tp.split_around(marker)?;
    let (_, (enter_tapped, _)) = all_consuming((
        opt(value(true, tag::<_, _, OracleError<'_>>("tapped"))),
        opt(tag(".")),
    ))
    .parse(after_marker.lower.trim())
    .ok()?;

    let target_phrase = format!("{} in your graveyard", target_tp.original.trim());
    let (target, remainder) = parse_target(&target_phrase);
    if !remainder.trim().is_empty() {
        return None;
    }
    let target =
        add_inferred_origin_constraints_to_target(target, Some(Zone::Graveyard), rest_lower);
    let enter_tapped =
        crate::types::zones::EtbTapState::from_legacy_bool(enter_tapped.unwrap_or(false));
    let mut def = AbilityDefinition::new(
        kind,
        Effect::ChangeZone {
            origin: Some(Zone::Graveyard),
            destination: Zone::Battlefield,
            target,
            owner_library: false,
            enter_transformed: false,
            enters_under: None,
            enter_tapped,
            enters_attacking: false,
            up_to: false,
            enter_with_counters: vec![],
            face_down_profile: None,
        },
    );
    def.sub_ability = Some(Box::new(AbilityDefinition::new(
        kind,
        Effect::ChangeZoneAll {
            origin: Some(Zone::Graveyard),
            destination: Zone::Battlefield,
            target: TargetFilter::Typed(TypedFilter::default().properties(vec![
                FilterProp::InZone {
                    zone: Zone::Graveyard,
                },
                FilterProp::Owned {
                    controller: ControllerRef::You,
                },
                FilterProp::SameNameAsParentTarget,
            ])),
            enters_under: None,
            enter_tapped,
            face_down_profile: None,
        },
    )));
    Some(def)
}

/// CR 702.179c-d: Fold a trailing "This effect can't reduce their speed below
/// N" sub-ability sentence into the preceding `ChangeSpeed` effect's `floor`
/// field, then delete the now-redundant `Unimplemented` floor-sentence node.
///
/// The floor sentence parses as its own `Effect::Unimplemented { name: "this"
/// }` sub-ability; leaving it would surface a spurious unimplemented gap. This
/// pass walks the `sub_ability` chain and rewrites `ChangeSpeed →
/// Unimplemented(floor sentence)` into a single floored `ChangeSpeed`.
pub(crate) fn fold_speed_floor_sentences(def: &mut AbilityDefinition) {
    /// Parse "[this effect ]can't reduce <their|its> speed below N" → N.
    fn parse_floor_sentence(text: &str) -> Option<u8> {
        let lower = text.to_lowercase();
        let lower = lower.trim_end_matches('.').trim();
        let (rest, _) = opt(tag::<_, _, OracleError<'_>>("this effect "))
            .parse(lower)
            .ok()?;
        let (rest, _) = tag::<_, _, OracleError<'_>>("can't reduce ")
            .parse(rest)
            .ok()?;
        let (rest, _) = alt((
            tag::<_, _, OracleError<'_>>("their speed below "),
            tag("its speed below "),
        ))
        .parse(rest)
        .ok()?;
        let (rest, n) = nom_primitives::parse_number.parse(rest).ok()?;
        if !rest.trim().is_empty() {
            return None;
        }
        u8::try_from(n).ok()
    }

    // Walk the sub_ability chain. When the current node is a `ChangeSpeed`
    // decrease and its sub_ability is the floor sentence, fold and unlink.
    let mut cursor: &mut AbilityDefinition = def;
    loop {
        let floor_value = match (&*cursor.effect, &cursor.sub_ability) {
            (
                Effect::ChangeSpeed {
                    direction: crate::types::ability::SpeedDelta::Decrease,
                    ..
                },
                Some(child),
            ) => match &*child.effect {
                Effect::Unimplemented { description, .. } => {
                    description.as_deref().and_then(parse_floor_sentence)
                }
                _ => None,
            },
            _ => None,
        };
        if let Some(n) = floor_value {
            // Re-link past the floor sentence, then fold the value in.
            let grandchild = cursor
                .sub_ability
                .take()
                .and_then(|child| child.sub_ability);
            cursor.sub_ability = grandchild;
            if let Effect::ChangeSpeed { floor, .. } = &mut *cursor.effect {
                *floor = Some(n);
            }
        }
        match cursor.sub_ability.as_deref_mut() {
            Some(next) => cursor = next,
            None => break,
        }
    }
}

/// CR 109.4 + CR 608.2c: True when a clause's leading/suffix condition is an
/// anaphoric-control check on the subject — `TargetMatchesFilter` over a
/// controlled-by-`You` typed filter (the positive antecedent of an inverse
/// "if you don't control it, …" else-connector). Used to gate the inverse-
/// control "otherwise" routing so it only engages with a matching positive
/// antecedent. Accepts both `use_lki` tenses (present "control" / past
/// "controlled").
fn clause_has_anaphoric_control_condition(clause: &ClauseIr) -> bool {
    matches!(
        clause.condition.as_ref(),
        Some(AbilityCondition::TargetMatchesFilter {
            filter: TargetFilter::Typed(tf),
            ..
        }) if tf.controller == Some(ControllerRef::You)
    )
}

/// Produce an intermediate representation of an effect chain from Oracle text.
///
/// This is the IR-production half of the parse/lower split (Phase 48).
/// It runs the chunk loop — text splitting, strip cascade, per-chunk effect
/// parsing, continuation recognition — producing a flat `Vec<AbilityDefinition>`
/// (pre-assembled defs). Post-loop assembly (demoting Dig, sub_ability chaining,
/// anaphoric resolution, etc.) is handled by [`lower_effect_chain_ir`].
/// CR 701.42a: Build the single `ClauseIr` for an atomic meld effect clause.
/// All chain-assembly fields are inert (no condition/continuation/scope) — the
/// own/control gate rides the trigger's intervening-if, not the effect chain.
fn meld_single_clause(effect: Effect, source_text: &str) -> ClauseIr {
    ClauseIr {
        parsed: parsed_clause(effect),
        boundary: Some(ClauseBoundary::Sentence),
        condition: None,
        is_optional: false,
        opponent_may_scope: None,
        repeat_for: None,
        player_scope: None,
        starting_with: None,
        delayed_condition: None,
        prefix_delayed_condition: None,
        intrinsic_continuation: None,
        followup_continuation: None,
        absorbed_by_followup: false,
        multi_target: None,
        where_x_expression: None,
        is_otherwise: false,
        unless_pay: None,
        special: None,
        source_text: source_text.to_string(),
        target_selection_mode: TargetSelectionMode::Chosen,
        target_chooser: None,
    }
}

pub(crate) fn parse_effect_chain_ir(
    text: &str,
    kind: AbilityKind,
    ctx: &mut ParseContext,
) -> EffectChainIr {
    let text = strip_trailing_activation_restriction_sentence(text);
    // CR 107.1a: Strip a trailing "Round down each time" / "Round up each time"
    // sentence before chain splitting — it is a chain-level rounding annotation
    // (Pox Plague) that back-applies to every `DivideRounded` the chain contains.
    // Stripped here so it doesn't become an Unimplemented chunk; the captured
    // mode is re-applied to the built chain via `rewrite_rounding_mode`.
    let (text, chain_rounding) = strip_trailing_rounding_annotation(&text);
    let text = text.as_str();
    // CR 611.2b + CR 611.2a: A leading "For as long as <condition>," prefix that
    // resolves to UntilHostLeavesPlay (either "you control ~" or "~ remains on the
    // battlefield") scopes the ENTIRE following comma body, not just its first
    // clause. When that body is HETEROGENEOUS — its first clause is a distinct effect
    // (e.g. "gain control of that permanent") the single-clause arm cannot merge with
    // the trailing static/restriction riders — starts_prefix_clause ("for as long as")
    // would otherwise glue the body into one chunk and the single-clause arm would drop
    // every sibling after the first (Opportunistic Dragon: "it loses all abilities" lost).
    // Strip the prefix here so split_clause_sequence produces the sibling chunks; the
    // duration is restamped onto every clause after the chunk loop.
    //
    // Gate is deliberately narrow (only Opportunistic Dragon fires across the full
    // dataset): RESTRICTED to UntilHostLeavesPlay (excludes "until end of turn"
    // animations, which the single-clause arm MERGES into one GenericEffect) AND to
    // bodies whose first chunk is neither GenericEffect (homogeneous continuous-mod /
    // animate merge — Kitesail) nor GrantCastingPermission (play/mana permission merge
    // — Kotose), the two classes the single-clause arm merges across commas.
    let leading_host_lifetime_split = strip_leading_duration(text).and_then(|(dur, body)| {
        if !matches!(dur, Duration::UntilHostLeavesPlay) {
            return None;
        }
        let body_chunks = split_clause_sequence(body);
        if body_chunks.len() <= 1 {
            return None;
        }
        // Parser-as-detector: classify the first chunk's effect; only chain-route a
        // distinct, non-mergeable lead.
        let mut probe_ctx = ParseContext::default();
        let first = parse_effect_clause(body_chunks[0].text.trim(), &mut probe_ctx);
        if matches!(
            first.effect,
            Effect::GenericEffect { .. } | Effect::GrantCastingPermission { .. }
        ) {
            return None;
        }
        Some((dur, body))
    });
    let text = leading_host_lifetime_split
        .as_ref()
        .map_or(text, |(_, body)| *body);
    let full_text = text; // bind AFTER the strip so diagnostics track the parsed chunks
    ctx.effect_chain_full_lower = Some(full_text.to_ascii_lowercase());
    // CR 701.42a: The meld effect clause "exile them, then meld them into
    // [result]" is a single atomic instruction whose ", then " comma would
    // otherwise be split into two clauses by `split_clause_sequence`. Intercept
    // the bare clause BEFORE chunking and emit it as one `Effect::Meld`.
    //
    // Only the TRIGGERED forms (Gisela, Graf Rats) are handled here: their
    // own/control gate was already hoisted to the trigger's intervening-if (in
    // `oracle_trigger.rs`) and the partner staged in `ctx.pending_meld_partner`,
    // so `full_text` is the bare residual "exile them, then meld them into R".
    //
    // The ACTIVATED / inline-gate forms (Hanweir Battlements, Urza, Lord
    // Protector) are deliberately NOT handled here. Their text leads with the
    // inline "if you both own and control ..." gate, which `parse_meld_effect_clause`
    // cannot consume (its `tag("exile them, then meld them into ")` fails), so
    // they fall through to baseline parsing and remain `Unimplemented`. Swallowing
    // that inline `Condition_If` would be a coverage-honesty regression; an honest
    // activated-ability condition node for these is a follow-up.
    //
    // Cheap fast-reject: only the ~6 meld cards carry the meld signature, so a
    // byte-substring check on the lowercase form already computed above
    // (`effect_chain_full_lower`) gates the full nom parse. This is a perf
    // guard, not parsing dispatch — a positive hit still routes through the
    // nom-combinator `parse_meld_effect_clause`, which remains the sole
    // authority on whether the text forms a meld clause.
    if ctx
        .effect_chain_full_lower
        .as_deref()
        .is_some_and(|lower| lower.contains(meld::MELD_EFFECT_MARKER))
    {
        if let Some(effect) = meld::parse_meld_effect_clause(full_text.trim(), ctx) {
            return EffectChainIr {
                clauses: vec![meld_single_clause(effect, full_text)],
                kind,
                chain_rounding,
                actor: ctx.actor.clone(),
                repeat_until: None,
            };
        }
    }
    let chunks = split_clause_sequence(text);
    // CR 107.3i: "Normally, all instances of X on an object have the same value."
    // Build a per-chunk sentence-scoped `where X is <expr>` binding so that when
    // one clause in a sentence binds X ("... and you gain X life, where X is <expr>"),
    // sibling clauses in the same sentence ("Target player loses X life")
    // substitute X with the same expression. Delimited by ClauseBoundary::Sentence.
    let sentence_where_x = compute_sentence_where_x(&chunks);
    let mut clauses: Vec<ClauseIr> = Vec::new();

    // CR 608.2c + CR 117.3a: "Anchor subject" for chain-level anaphoric
    // inheritance. When a clause in the chain declares an explicit player-scope
    // subject other than the caster (e.g., "its controller may search their
    // library" → ParentTargetController), subsequent clauses in the same chain
    // that produce caster-defaulted player-scope effects (e.g., "then shuffle"
    // → `Shuffle { target: Controller }`) inherit this anchor so the correct
    // player performs the action. Only propagates within a single sentence /
    // chain; the anchor is reset at each top-level call.
    let mut anchor_subject: Option<TargetFilter> = None;
    let mut chunk_diagnostics: Vec<OracleDiagnostic> = Vec::new();
    // CR 608.2c: "Repeat the following process N times." appears as its own
    // sentence before the body clause. The count is stashed here and applied
    // to the immediately-following clause so the body executes N times.
    let mut pending_repeat_for: Option<QuantityExpr> = None;
    // CR 101.4 + CR 800.4: "Starting with you," is split by sequence boundary
    // into its own chunk when followed by a comma. Capture the override here
    // when that chunk is consumed standalone, so the next chunk (which holds
    // the actual `player_scope: All` payload) can stamp `starting_with`.
    let mut pending_starting_with: Option<ControllerRef> = None;
    // CR 101.4 + CR 608.2c + CR 608.2f: "Repeat the following process for
    // each {opponent,player} [in turn order]." — forward-carry the
    // per-player iteration scope to the next clause. Sibling of
    // `pending_repeat_for` / `pending_starting_with`; identical lifecycle.
    let mut pending_player_scope: Option<PlayerFilter> = None;
    // CR 608.2c + CR 107.1c: Chain-level "repeat this process" loop predicate.
    // A back-reference recognized as its own trailing sentence; applied to the
    // root `AbilityDefinition` during lowering.
    let mut pending_repeat_until: Option<crate::types::ability::RepeatContinuation> = None;
    // CR 608.2c + CR 109.4: Chain-spanning chosen-player state. The per-chunk
    // `chunk_ctx` is rebuilt fresh each iteration, so these loop-locals thread
    // the running `Choose(Player)` count and the active chosen-player scope
    // from one sentence to the next: "choose a player. They put counters …
    // choose a second player to draw" — the `ChosenPlayer { index }` index and
    // the "they"/"that player controls" anaphor scope both depend on choices
    // made in earlier chunks. Seeded into each `chunk_ctx` and read back after.
    let mut chain_chosen_player_count: u8 = 0;
    let mut chain_chosen_player_scope: Option<ControllerRef> = None;
    // CR 608.2e + CR 109.5: Sticky across chunks of a "For each opponent who
    // doesn't, <body>" decline-consequence sentence. Set true on the chunk that
    // carries the "for each opponent who doesn't" prefix; every chunk while
    // active has its recipient-bearing effects rebound ("that player" →
    // ScopedPlayer, "you" → OriginalController). Reset at the next `Sentence`
    // boundary, so a following independent instruction is unaffected.
    let mut decline_consequence_active = false;
    // CR 608.2c: Within one sentence, English can state a targeted player
    // subject once and then continue with conjugated predicates:
    // "target opponent sacrifices ..., discards ..., and loses ...". Carry the
    // targeted player subject so the bare conjugated continuations inherit the
    // same player target rather than falling back to the ability controller.
    let mut carried_targeted_player_subject: Option<SubjectApplication> = None;
    // CR 608.2c + CR 109.4: Chain-spanning "its controller" antecedent. Armed
    // when a chunk's leading subject is "its/their controller may <act>"
    // (SubjectApplication { affected: ParentTargetController, is_optional: true });
    // a later sentence's "that player" anaphor (Star Athlete) binds to it.
    // Unlike the Sentence-reset siblings, this MUST survive the sentence
    // boundary between "...sacrifice it." and "If they don't, ...", so it is
    // single-shot consumption-cleared (cleared once a downstream chunk binds a
    // recipient through it) rather than boundary-cleared, preventing leak into
    // an unrelated later sentence.
    let mut chain_parent_target_controller_scope: Option<ControllerRef> = None;

    for (chunk_idx, chunk) in chunks.iter().enumerate() {
        let normalized_text = strip_leading_sequence_connector(&chunk.text).trim();
        if normalized_text.is_empty() {
            continue;
        }

        // CR 101.4 + CR 800.4: "Starting with you," — turn-order override for
        // `player_scope` iteration (Join Forces: "Starting with you, each
        // player may pay any amount of mana"). `split_clause_sequence` may
        // split at the comma so the phrase lives in its own chunk; capture
        // it as `pending_starting_with` and apply on the NEXT non-empty
        // chunk. When the comma stays attached, strip the prefix in-place.
        // The lowering step stamps the captured override onto the produced
        // `AbilityDefinition.starting_with` so the iteration site in
        // `effects/mod.rs` reads it via
        // `players::apnap_order_from(state, starting_with, controller)`.
        let (normalized_text, starting_with) = {
            let temp_lower = normalized_text.to_lowercase();
            if tag::<_, _, OracleError<'_>>("starting with you")
                .parse(temp_lower.as_str())
                .is_ok_and(|(rest, _)| rest.trim().is_empty())
            {
                // Standalone "starting with you" chunk — stash the override
                // for the next body chunk and skip this empty marker.
                pending_starting_with = Some(ControllerRef::You);
                continue;
            }
            match nom_on_lower(normalized_text, &temp_lower, |i| {
                value((), tag("starting with you, ")).parse(i)
            }) {
                Some(((), rest)) => (rest, Some(ControllerRef::You)),
                None => (normalized_text, pending_starting_with.take()),
            }
        };

        // CR 614.1 + CR 614.12 + CR 303.4 + CR 613.1d + CR 613.1f + CR 113.10 +
        // CR 604.1: Return-as-Aura sub-effect (Old-Growth Troll [KHM],
        // Bronzehide Lion [THB], Harold and Bob, First Numens [FIN-precon]).
        // Detect the "It's an Aura enchantment with enchant <X> and \"<body>\""
        // sentence as its own emitted `Effect::ReturnAsAura` clause. Slotted
        // before the special-case riders because the prefix is highly
        // distinctive ("it's an aura enchantment with enchant ") and the body
        // contains nested apostrophe/quote sequences that could confuse later
        // generic dispatch. The companion `try_fold_loses_other_sibling` pass
        // (after the chunk loop) folds Bronzehide's pre-split
        // `GenericEffect(RemoveAllAbilities)` sibling into this clause's grants.
        {
            let chunk_lower = normalized_text.to_ascii_lowercase();
            if let Some((enchant_filter, mut grants, loses_other_in_chunk)) =
                crate::parser::oracle_nom::return_as_aura::try_parse(normalized_text, &chunk_lower)
            {
                if loses_other_in_chunk {
                    // CR 113.10 + CR 613.1f + CR 613.8: Layer-6
                    // RemoveAllAbilities dependency-orders before grants
                    // (CR 613.8a: a `Grant*` effect depends on the removal
                    // because removal changes the existence of the grant).
                    // Insert at index 0 so the resolver's grants Vec has
                    // RemoveAllAbilities first.
                    grants.insert(0, ContinuousModification::RemoveAllAbilities);
                }
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::ReturnAsAura {
                        enchant_filter,
                        grants,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: starting_with.clone(),
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: None,
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 118.9 + CR 119.4: Alternative-cost rider — "[If you cast a spell
        // this way,] pay <ability-cost> rather than paying its mana cost."
        // This is a *modifier* on the previous chain entry's `CastFromZone`
        // grant rather than its own effect. Fold the cost onto the most
        // recent `CastFromZone` def (walking sub_ability descendants) and
        // skip emitting a sibling Unimplemented chunk. Used by Nashi, Moon
        // Sage's Scion: the granted card is cast by paying life equal to its
        // mana value instead of paying its mana cost.
        if let Some(cost) = try_parse_alt_cost_rider(normalized_text) {
            clauses.push(ClauseIr {
                parsed: parsed_clause(Effect::Unimplemented {
                    name: "alt_cost_rider_placeholder".to_string(),
                    description: None,
                }),
                boundary: chunk.boundary_after,
                condition: None,
                is_optional: false,
                opponent_may_scope: None,
                repeat_for: None,
                player_scope: None,
                starting_with: None,
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: false,
                unless_pay: None,
                special: Some(SpecialClause::AltCostRider(cost)),
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        if let Some(expiry) = try_parse_mana_retention_rider(normalized_text) {
            if !clauses.is_empty() {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "mana_retention_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::ManaRetention(expiry)),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 109.4 + CR 608.2c: Inverse anaphoric-control "otherwise" connector —
        // "If you don't control it, [effect]" following a positively-control-gated
        // clause ("draw a card if you control that creature."). The negated second
        // sentence is the `else_ability` of the first over the SAME subject, not an
        // independent sibling instruction — without this routing the runtime would
        // either fire both branches or neither (issue #1510, Auntie Ool). Requires a
        // prior clause to carry an anaphoric-control condition so this only engages
        // as a genuine else over a matching positive antecedent.
        if clauses.iter().any(clause_has_anaphoric_control_condition) {
            if let Some(else_text) = strip_inverse_control_otherwise_connector(normalized_text) {
                let else_def = {
                    let ir = parse_effect_chain_ir(&else_text, kind, ctx);
                    lower_effect_chain_ir(&ir)
                };
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "otherwise_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: true,
                    unless_pay: None,
                    special: Some(SpecialClause::Otherwise(Box::new(else_def))),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 608.2c: "Otherwise, [effect]" — attach as else_ability on the
        // most recent conditional def in the chain.
        let lower_check = normalized_text.to_lowercase();
        let otherwise_rest = nom_on_lower(normalized_text, &lower_check, |i| {
            value(
                (),
                alt((
                    tag("otherwise, "),
                    tag("otherwise "),
                    tag("if not, "),
                    tag("if no player does, "),
                    tag("if no one does, "),
                )),
            )
            .parse(i)
        });
        if let Some((_, else_text)) = otherwise_rest {
            let else_def = {
                let ir = parse_effect_chain_ir(else_text, kind, ctx);
                lower_effect_chain_ir(&ir)
            };
            // Check whether a prior clause has a condition — lowering will attach as else_ability
            let has_condition = clauses.iter().any(|c| c.condition.is_some());
            let special = if has_condition {
                SpecialClause::Otherwise(Box::new(else_def))
            } else {
                SpecialClause::OtherwiseFallback(Box::new(else_def))
            };
            clauses.push(ClauseIr {
                parsed: parsed_clause(Effect::Unimplemented {
                    name: "otherwise_placeholder".to_string(),
                    description: None,
                }),
                boundary: chunk.boundary_after,
                condition: None,
                is_optional: false,
                opponent_may_scope: None,
                repeat_for: None,
                player_scope: None,
                starting_with: None,
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: true,
                unless_pay: None,
                special: Some(special),
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        // CR 702: "The same is true for <keyword list>." — Odric, Lunarch
        // Marshal. Extends the previous `GenericEffect` keyword grant to each
        // additional keyword. Recorded as a `SpecialClause`; lowering reads
        // the antecedent grant template and emits one `StaticDefinition` per
        // keyword. Requires a prior clause to attach to.
        if !clauses.is_empty() {
            if let Some(keywords) = try_parse_same_is_true_continuation(normalized_text) {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "same_is_true_for_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::SameIsTrueFor(keywords)),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 608.2c: "Repeat this process for <keyword list>." — Kathril, Aspect
        // Warper. Must precede the generic "repeat this process" directive below,
        // whose `tag("repeat this process")` would otherwise swallow the prefix
        // and discard the keyword list. Replicates the antecedent conditional
        // keyword-counter clause once per listed keyword during lowering.
        if !clauses.is_empty() {
            if let Some(keywords) = try_parse_repeat_process_for_keywords(normalized_text) {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "repeat_process_for_keywords_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::RepeatProcessForKeywords(keywords)),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 608.2c + CR 107.1c: "Repeat this process" — a loop-continuation
        // directive that doesn't produce an independent effect. It is a
        // back-reference applying to the process (chain) built so far.
        //
        //   - "you may repeat this process [any number of times]" → a
        //     per-iteration controller decision; recorded chain-level in
        //     `pending_repeat_until` and applied to the root
        //     `AbilityDefinition` during lowering (`ControllerChoice`).
        //   - "[if you do, ]repeat this process" — the game-state-predicate
        //     form (Primal Surge) is a deferred unit. It is still recognized
        //     here so the directive is consumed rather than producing an
        //     Unimplemented gap, but it sets no `repeat_until` predicate.
        if let Some((continuation, _)) = nom_on_lower(normalized_text, &lower_check, |i| {
            let (i, prefix) = nom::combinator::opt(alt((
                tag::<_, _, OracleError<'_>>("you may "),
                tag("if you do, "),
                tag("if you do "),
            )))
            .parse(i)?;
            let (i, _) = value((), tag("repeat this process")).parse(i)?;
            let continuation = (prefix == Some("you may "))
                .then_some(crate::types::ability::RepeatContinuation::ControllerChoice);
            Ok((i, continuation))
        }) {
            if continuation.is_some() {
                pending_repeat_until = continuation;
            }
            continue;
        }

        // CR 608.2f + CR 101.4 + CR 608.2c: "Repeat the following process …" —
        // forward-carry repeat directive. Unlike "repeat this process"
        // (back-reference), this announces that the NEXT clause executes
        // some number of times or once per matching player.
        //   - "… N times" → numeric repeat into `pending_repeat_for`.
        //   - "… for each {opponent,player} [in turn order]" → per-player
        //     iteration into `pending_player_scope` (CR 101.4 APNAP from
        //     the active player when no explicit "starting with <player>"
        //     prefix is present). The directive itself produces no clause.
        if let Some((player_scope_opt, _)) = nom_on_lower(normalized_text, &lower_check, |i| {
            let (i, _) = tag("repeat the following process").parse(i)?;
            let (i, player_scope) = opt(|i| {
                let (i, _) = tag(" for each ").parse(i)?;
                let (i, scope) = alt((
                    value(PlayerFilter::Opponent, tag("opponents")),
                    value(PlayerFilter::Opponent, tag("opponent")),
                    value(PlayerFilter::All, tag("players")),
                    value(PlayerFilter::All, tag("player")),
                ))
                .parse(i)?;
                // CR 101.4: optional "in turn order" — with no explicit
                // "starting with <player>" prefix, this is APNAP from the
                // active player.
                let (i, _) = opt(tag(" in turn order")).parse(i)?;
                Ok((i, scope))
            })
            .parse(i)?;
            let (i, _) = opt(tag(".")).parse(i)?;
            Ok((i, player_scope))
        }) {
            if let Some(scope) = player_scope_opt {
                pending_player_scope = Some(scope);
            } else {
                let (count, _) = strip_repeat_count_suffix(normalized_text);
                pending_repeat_for = count;
            }
            continue;
        }

        // CR 614.1a + CR 514.2: "If [target] would die this turn, exile it
        // instead." — damage-spell rider that registers a one-shot, EOT-scoped
        // replacement on the parent ability's target. Checked early because
        // the rider has its own complete grammar and shouldn't be subject to
        // the generic "if X, [effect]" conditional stripping or to "instead"
        // replacement-style clause matching. Attaches as sub_ability of the
        // previous def so it inherits the parent's resolved target via
        // ParentTarget at runtime.
        let rider_lower = normalized_text.to_lowercase();
        if let Some(rider_def) =
            try_parse_die_exile_rider(rider_lower.trim_end_matches('.').trim(), kind)
        {
            if !clauses.is_empty() {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "die_exile_rider_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::DieExileRider(Box::new(rider_def))),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        if is_free_cast_exile_instead_rider(rider_lower.trim_end_matches('.').trim()) {
            if let Some(previous) = clauses.iter_mut().rev().find(|clause| {
                !clause.absorbed_by_followup
                    && matches!(&clause.parsed.effect, Effect::FreeCastFromZones { .. })
            }) {
                if let Effect::FreeCastFromZones {
                    exile_instead_of_graveyard,
                    ..
                } = &mut previous.parsed.effect
                {
                    *exile_instead_of_graveyard = true;
                    continue;
                }
            }
        }

        if let Some(life_payment) =
            try_parse_drawn_this_turn_pay_or_topdeck_followup(normalized_text)
        {
            if !clauses.is_empty() {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "drawn_this_turn_pay_or_topdeck_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::DrawnThisTurnPayOrTopdeck { life_payment }),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 608.2c: "If <cond>, you may instead <reveal-N-from-among-body>" —
        // conditional alternative SELECTION parameters for the preceding Dig effect.
        // The alternative reuses the same top-N source but swaps keep_count/up_to/filter.
        // Checked before the generic "instead" clause because the body starts with
        // "you may instead ..." rather than a bare "instead ..." prefix/suffix and
        // carries no standalone effect — it patches the preceding Dig.
        {
            // Build a temporary AbilityDefinition from the last non-absorbed clause's
            // effect to pass to try_parse_dig_instead_alternative (which inspects the
            // previous effect to check it's a Dig). Must skip absorbed clauses — in the
            // old code, absorbed chunks are not in `defs`, so `defs.last()` is the Dig.
            let prev_clause = clauses.iter().rev().find(|c| !c.absorbed_by_followup);
            let prev_temp =
                prev_clause.map(|c| AbilityDefinition::new(kind, c.parsed.effect.clone()));
            let inherited_where_x_expression =
                prev_clause.and_then(|c| c.where_x_expression.clone());
            if let Some(alt_def) =
                try_parse_dig_instead_alternative(normalized_text, prev_temp.as_ref(), kind, ctx)
            {
                if !clauses.is_empty() {
                    // Store the alt_def's effect as `parsed.effect` so followup continuation
                    // matching (e.g., PutRest for "put the rest on the bottom") can see that
                    // the effective last clause is a Dig. In the old code, `defs.last()` was
                    // the alt_def (a Dig) after the DigInsteadAlt was processed.
                    clauses.push(ClauseIr {
                        parsed: parsed_clause((*alt_def.effect).clone()),
                        boundary: chunk.boundary_after,
                        condition: None,
                        is_optional: false,
                        opponent_may_scope: None,
                        repeat_for: None,
                        player_scope: None,
                        starting_with: None,
                        delayed_condition: None,
                        prefix_delayed_condition: None,
                        intrinsic_continuation: None,
                        followup_continuation: None,
                        absorbed_by_followup: false,
                        multi_target: None,
                        where_x_expression: inherited_where_x_expression,
                        is_otherwise: false,
                        unless_pay: None,
                        special: Some(SpecialClause::DigInsteadAlt(Box::new(alt_def))),
                        source_text: normalized_text.to_string(),
                        target_selection_mode: TargetSelectionMode::Chosen,
                        target_chooser: None,
                    });
                    continue;
                }
            }
        }

        if let Some((is_win, effect_text)) = imperative::try_parse_coin_flip_branch(normalized_text)
        {
            let branch_def = {
                let ir = parse_effect_chain_ir(effect_text, kind, ctx);
                lower_effect_chain_ir(&ir)
            };
            let flip_effect = if is_win {
                Effect::FlipCoin {
                    win_effect: Some(Box::new(branch_def)),
                    lose_effect: None,
                }
            } else {
                Effect::FlipCoin {
                    win_effect: None,
                    lose_effect: Some(Box::new(branch_def)),
                }
            };
            clauses.push(ClauseIr {
                parsed: parsed_clause(flip_effect),
                boundary: chunk.boundary_after,
                condition: None,
                is_optional: false,
                opponent_may_scope: None,
                repeat_for: None,
                player_scope: None,
                starting_with: None,
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: false,
                unless_pay: None,
                special: None,
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        // CR 615 + CR 514.2: "If damage would be dealt to <target> this turn,
        // prevent that damage [and put that many <kind> counter(s) on <target>]"
        // — sub-clause of a chain that already chose a target. Emits an
        // `Effect::PreventDamage { amount: All, target: ParentTarget }` with
        // `duration: UntilEndOfTurn` and (optionally) a counter rider sub-ability
        // that fires once per damage prevented this way. Gatta and Luzzu is the
        // motivating case; the same shape applies to any future card with this
        // antecedent.
        if let Some(parsed) = try_parse_conditional_damage_prevention_with_followup(normalized_text)
        {
            clauses.push(ClauseIr {
                parsed,
                boundary: chunk.boundary_after,
                condition: None,
                is_optional: false,
                opponent_may_scope: None,
                repeat_for: None,
                player_scope: None,
                starting_with: None,
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: false,
                unless_pay: None,
                special: None,
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        if let Some(effect) =
            try_parse_next_time_source_damage_replacement(&normalized_text.to_lowercase())
        {
            clauses.push(ClauseIr {
                parsed: parsed_clause(effect),
                boundary: chunk.boundary_after,
                condition: None,
                is_optional: false,
                opponent_may_scope: None,
                repeat_for: None,
                player_scope: None,
                starting_with: None,
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: false,
                unless_pay: None,
                special: None,
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        // CR 608.2e: "if [condition], [effect] instead" — the preceding ability's effect
        // is replaced when the condition holds. Keep the base effect as the root so
        // target collection stays anchored on the printed target-bearing clause.
        if let Some(instead_def) = try_parse_generic_instead_clause(normalized_text, kind, ctx) {
            if !clauses.is_empty() {
                clauses.push(ClauseIr {
                    parsed: parsed_clause(Effect::Unimplemented {
                        name: "instead_clause_placeholder".to_string(),
                        description: None,
                    }),
                    boundary: chunk.boundary_after,
                    condition: None,
                    is_optional: false,
                    opponent_may_scope: None,
                    repeat_for: None,
                    player_scope: None,
                    starting_with: None,
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target: None,
                    where_x_expression: None,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::InsteadClause(Box::new(instead_def))),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        let (condition, text) = strip_additional_cost_conditional(normalized_text);
        // CR 608.2c: General leading conditional — "if [condition], [effect]".
        // Runs only when no dedicated leading stripper matched. Handles patterns like
        // "if you control 3 or more creatures, draw a card".
        let (leading_cond, text) = if condition.is_none() {
            strip_leading_general_conditional(&text, ctx)
        } else {
            (None, text)
        };
        let condition = condition.or(leading_cond);
        // CR 608.2c: "[effect] a number of times equal to the difference" — when
        // a leading comparison condition was just stripped, a trailing
        // difference-repeat suffix repeats the effect by the unsigned magnitude
        // gap between the condition's operands (Expand the Sphere's "If you put
        // fewer than two lands onto the battlefield this way, proliferate a
        // number of times equal to the difference"). Detected here, where both
        // the parsed condition and the residual effect text are in scope; the
        // resulting count merges into `repeat_for` below.
        let (difference_repeat, text) =
            match (condition.as_ref(), split_difference_repeat_suffix(&text)) {
                (Some(cond), Some(head)) => (difference_expr(cond), head.to_string()),
                _ => (None, text),
            };
        let (if_you_do, text) = if condition.is_none() {
            strip_if_you_do_conditional(&text)
        } else {
            (None, text)
        };
        // CR 603.4 + CR 608.2c: Counter threshold condition — runs unconditionally
        // on the text output from strip_if_you_do_conditional. For compound
        // "when you do, if it has N counters" patterns, WhenYouDo is always true for
        // non-optional parents (CR 603.12), so the QuantityCheck is the meaningful gate.
        let (counter_cond, text) = strip_counter_conditional(&text);
        // CR 202.3 + CR 608.2c: Mana value threshold condition — same priority as counter_cond.
        let (mv_cond, text) = strip_mana_value_conditional(&text);
        let (target_supertype_cond, text) = strip_target_supertype_conditional(&text);
        let (cast_from_zone, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
        {
            strip_cast_from_zone_conditional(&text)
        } else {
            (None, text)
        };
        let (card_type_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
        {
            strip_card_type_conditional(&text)
        } else {
            (None, text)
        };
        let (property_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
            && card_type_cond.is_none()
        {
            strip_property_conditional(&text)
        } else {
            (None, text)
        };
        // CR 608.2c: player-property superlative-comparison conditional —
        // "if that opponent's speed is greater than each other player's speed, ..."
        let (player_property_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
            && card_type_cond.is_none()
            && property_cond.is_none()
        {
            strip_player_property_superlative_conditional(&text)
        } else {
            (None, text)
        };
        // CR 608.2c: "If it's your turn" / "If it's not your turn" — game-state condition
        let (turn_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
            && card_type_cond.is_none()
            && property_cond.is_none()
            && player_property_cond.is_none()
        {
            strip_turn_conditional(&text)
        } else {
            (None, text)
        };
        // CR 608.2e: "If that creature has [keyword], [effect] instead"
        let (keyword_instead_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
            && card_type_cond.is_none()
            && property_cond.is_none()
            && player_property_cond.is_none()
            && turn_cond.is_none()
        {
            strip_target_keyword_instead(&text)
        } else {
            (None, text)
        };
        // CR 608.2c: General suffix condition — "do Y if X" where X is a quantity comparison.
        // Runs only when no dedicated stripper matched; parse_condition_text is the safety net
        // (returns None for anything it can't parse).
        let (suffix_cond, text) = if condition.is_none()
            && if_you_do.is_none()
            && counter_cond.is_none()
            && mv_cond.is_none()
            && target_supertype_cond.is_none()
            && cast_from_zone.is_none()
            && card_type_cond.is_none()
            && property_cond.is_none()
            && player_property_cond.is_none()
            && turn_cond.is_none()
            && keyword_instead_cond.is_none()
        {
            strip_suffix_conditional(&text, ctx)
        } else {
            (None, text)
        };
        let condition = condition
            .or(counter_cond)
            .or(mv_cond)
            .or(target_supertype_cond)
            .or(if_you_do)
            .or(cast_from_zone)
            .or(card_type_cond)
            .or(property_cond)
            .or(player_property_cond)
            .or(turn_cond)
            .or(keyword_instead_cond)
            .or(suffix_cond);
        // CR 608.2c + CR 608.2d: When NO typed condition matched any pass above,
        // fall back to a structural-only strip that removes an unrepresentable
        // `If <X>, ` head ONLY when the body begins with `"you may "`. This
        // preserves the optional choice on patterns like Amareth ("If it shares
        // a card type with that permanent, you may reveal …") and Tithe ("If
        // target opponent controls more lands than you, you may search …"). The
        // condition is intentionally dropped — the Condition_If swallow detector
        // still flags it as unsupported. Issue #2277.
        let text = if condition.is_none() {
            strip_unrecognized_conditional_head_when_body_optional(&text)
        } else {
            text
        };
        // CR 608.2c + CR 400.7: "unless ~ entered this turn" — strip suffix and
        // replace condition with SourceDidNotEnterThisTurn. The IfYouDo condition
        // is redundant when the parent is optional (optional already gates the sub).
        let (unless_entered, text) = strip_unless_entered_suffix(&text, ctx);
        let condition = if unless_entered.is_some() {
            unless_entered
        } else {
            condition
        };
        // CR 608.2e: Strip leading "instead " when a condition was extracted.
        // The condition already encodes the replacement gate; "instead" is a
        // textual marker that the effect parser doesn't need.
        let text = if condition.is_some() {
            strip_leading_instead(&text)
        } else {
            text
        };
        // CR 608.2c: A leading "if [condition], ..." scopes over the whole
        // conditional instruction, including comma/then subclauses in the body.
        // Split the stripped body recursively so "If ..., exile it, then put it
        // ..." emits both guarded zone-change effects instead of letting the
        // first imperative parser swallow the tail.
        if let Some(ref outer_condition) = condition {
            let body_chunks = split_clause_sequence(&text);
            if body_chunks.len() > 1 {
                let mut body_ir = parse_effect_chain_ir(&text, kind, ctx);
                if let Some(last) = body_ir.clauses.last_mut() {
                    if last.boundary.is_none() {
                        last.boundary = chunk.boundary_after;
                    }
                }
                for clause in &mut body_ir.clauses {
                    apply_outer_condition_to_clause(outer_condition, clause);
                }
                clauses.extend(body_ir.clauses);
                continue;
            }
        }
        // CR 508.4 / CR 614.1: "If [condition], they/those tokens/it enter(s) tapped and
        // attacking" — conditional modifier on preceding Token/CopyTokenOf/ChangeZone.
        // Model as an "instead" swap: the modified Token (with tapped+attacking set)
        // replaces the original when the condition holds. Lowering handles the patching.
        {
            let enters_lower = text.to_lowercase();
            if condition.is_some()
                && nom_primitives::scan_contains(&enters_lower, "enter tapped and attacking")
            {
                if let Some(prev) = clauses.last() {
                    let can_patch = matches!(
                        prev.parsed.effect,
                        Effect::CopyTokenOf { .. }
                            | Effect::Token { .. }
                            | Effect::ChangeZone { .. }
                    );
                    if can_patch {
                        clauses.push(ClauseIr {
                            parsed: parsed_clause(Effect::Unimplemented {
                                name: "enters_tapped_attacking_placeholder".to_string(),
                                description: None,
                            }),
                            boundary: chunk.boundary_after,
                            condition,
                            is_optional: false,
                            opponent_may_scope: None,
                            repeat_for: None,
                            player_scope: None,
                            starting_with: None,
                            delayed_condition: None,
                            prefix_delayed_condition: None,
                            intrinsic_continuation: None,
                            followup_continuation: None,
                            absorbed_by_followup: false,
                            multi_target: None,
                            where_x_expression: None,
                            is_otherwise: false,
                            unless_pay: None,
                            special: Some(SpecialClause::EntersTappedAttacking),
                            source_text: normalized_text.to_string(),
                            target_selection_mode: TargetSelectionMode::Chosen,
                            target_chooser: None,
                        });
                        continue;
                    }
                }
            }
        }
        let (is_optional, opponent_may_scope, implicit_player_scope, text) =
            strip_optional_effect_prefix(&text);
        // CR 701.34a + CR 122.1: keep the whole "for each kind of counter on
        // target permanent or player, give … another counter of that kind"
        // clause intact so the targeted-proliferate recognizer in
        // `parse_effect_clause` claims it. The generic `for each` strip would
        // otherwise lift the counter-kind iteration into `repeat_for` and drop
        // the target, leaving an Unimplemented "give … counter" body.
        let (repeat_for, text, for_each_reference_target) =
            if try_parse_proliferate_target(&text).is_some() {
                (None, text, None)
            } else {
                let reference_target = for_each_clause_target_controller_filter(&text);
                let (repeat_for, text) = strip_for_each_prefix(&text);
                let reference_target = repeat_for.as_ref().and(reference_target);
                (repeat_for, text, reference_target)
            };
        let (text_without_where_x, local_where_x_expression) = {
            let text_where_x_lower = text.to_lowercase();
            let (without_where_x, where_x_expression) =
                strip_trailing_where_x(TextPair::new(&text, &text_where_x_lower));
            (without_where_x.original.to_string(), where_x_expression)
        };
        // CR 608.2c: "twice" / "N times" suffix — same mechanism as "for each" prefix.
        let (repeat_count, text) = if repeat_for.is_none() {
            let (repeat_count, stripped_text) = strip_repeat_count_suffix(&text_without_where_x);
            if repeat_count.is_some() {
                (repeat_count, stripped_text)
            } else {
                (None, text)
            }
        } else {
            (None, text)
        };
        let repeat_for = repeat_for
            .or(repeat_count)
            // CR 608.2c: difference-repeat count detected after the leading
            // conditional strip ("a number of times equal to the difference").
            .or(difference_repeat)
            .or_else(|| pending_repeat_for.take());
        let (player_scope, text) = strip_player_scope_subject(&text);
        let pending_player_scope_for_clause = pending_player_scope.take();
        let carried_player_scope = if player_scope.is_none()
            && !sequence::starts_clause_text(&text)
            && sequence::starts_clause_text_or_conjugated(&text)
        {
            clauses
                .iter()
                .rev()
                .find(|clause| !clause.absorbed_by_followup)
                .and_then(|clause| clause.player_scope.clone())
        } else {
            None
        };
        // CR 608.2d: When the optional prefix ("each opponent may") carries an
        // implicit per-player iteration, propagate it to the ability so the
        // OptionalEffectChoice is emitted once per matching player.
        let mut player_scope = player_scope
            .or(implicit_player_scope)
            .or(carried_player_scope)
            // CR 101.4 + CR 608.2f: forward-carry from a preceding
            // "Repeat the following process for each <scope> [in turn order]."
            .or(pending_player_scope_for_clause);

        // CR 608.2e + CR 608.2c + CR 101.3: A decline-tail strips one of four
        // shapes (prepositional vs subject-only × optional `doesn't` vs
        // mandatory `can't`) into a body that runs only when the parent's
        // per-iteration action did NOT happen. Track which quadrant dispatched
        // so the recipient-rebinding walker fires on the right axis. Both
        // paths share the single `rebind_clause_recipients_with` walker; the
        // per-quadrant mapping is the leaf rebinder:
        //   - Prepositional ("for each opponent who …, <body>") uses
        //     `rebind_decline_body_recipient` (Controller → OriginalController).
        //   - SubjectOnly ("each <scope> who can't, <body>") uses
        //     `rebind_subject_only_body_recipient` (Controller → ScopedPlayer).
        // Both leaf rebinders run on every chunk while the sticky
        // `decline_consequence_active` flag remains set, so only the kind
        // (which leaf rebinder) needs to be tracked — no head bit.
        #[derive(Copy, Clone)]
        enum DeclineDispatch {
            None,
            Prepositional,
            SubjectOnly,
        }
        let (text, condition, decline_dispatch) =
            if let Some((body, decline_condition)) = strip_for_each_opponent_who_doesnt(&text) {
                // CR 608.2e + CR 101.3: Do NOT stamp `player_scope` on the body
                // — it inherits the parent's `player_scope: Opponent` iteration
                // by being its `sub_ability` inside the scoped clone. The
                // `Not{...}` wrapper makes it the decline branch:
                //   - `Not{IfYouDo}` for "doesn't / does not" (Braids-class,
                //     optional parent — CR 118.12 optional-cost branch).
                //   - `Not{IfCurrentScopeSucceeded}` for "can't / cannot"
                //     (Refurbished-Familiar-class, mandatory parent — CR 101.3
                //     + CR 118.12 mandatory-cost branch).
                // Recipient rebinds resolve "that player"/"you".
                if let Some(prev) = clauses.last_mut() {
                    if prev.boundary == Some(ClauseBoundary::Sentence) {
                        prev.boundary = Some(ClauseBoundary::Then);
                    }
                }
                decline_consequence_active = true;
                (
                    body,
                    Some(AbilityCondition::Not {
                        condition: Box::new(decline_condition),
                    }),
                    DeclineDispatch::Prepositional,
                )
            } else if let Some((scope, body)) = strip_each_scope_who_cant_subject(&text) {
                // CR 608.2c + CR 101.3 + CR 118.12: subject-only
                // mandatory-impossible decline-tail (Plaguecrafter:
                // "each player sacrifices …. Each player who can't discards a
                // card."). Retarget the preceding clause's Sentence boundary
                // to Then so this clause lowers as a within-action
                // ContinuationStep, then stamp the And-of-two-conjuncts gate.
                //
                // Do NOT stamp `player_scope = Some(scope)` here — the body
                // inherits the parent's per-player iteration by being
                // attached as `sub_ability` inside the scoped clone. The
                // parent's first-sentence parse already stamps the matching
                // `player_scope` (e.g. `All` for "each player sacrifices …")
                // via `strip_player_scope_subject`, so a second stamp here
                // would start a nested per-player fan-out that resets
                // `cost_payment_failed_flag` for each inner iteration —
                // exactly the failure mode the second stamp is omitted to
                // avoid. Parallel to `strip_for_each_opponent_who_doesnt`
                // above.
                //
                // CR 101.3 + CR 109.5: The body's gate has TWO conjuncts:
                //   (a) `Not{IfCurrentScopeSucceeded}` — fires only on
                //       iterations whose mandatory parent action failed
                //       (the canonical "who can't" filter from CR 101.3).
                //   (b) `ScopedPlayerMatches { filter: scope }` — fires only
                //       on iterations whose scoped player matches the
                //       decline clause's OWN PlayerFilter, relative to the
                //       ability controller.
                //
                // Conjunct (b) is the cross-scope fix (Liliana, Waker of the
                // Dead: parent "each player discards a card" iterates `All`,
                // decline clause "each opponent who can't loses 3 life"
                // filters to `Opponent`; without (b) the controller would
                // lose 3 life if they couldn't discard, violating CR 109.5).
                // For same-scope cards (Plaguecrafter, Entropic Battlecruiser,
                // Skull Storm, Momentum Breaker, Lurking Spinecrawler — parent
                // and decline share the scope) the `ScopedPlayerMatches`
                // conjunct is trivially true for every iteration and acts as
                // a no-op, so this is uniformly safe for the whole class.
                if let Some(prev) = clauses.last_mut() {
                    if prev.boundary == Some(ClauseBoundary::Sentence) {
                        prev.boundary = Some(ClauseBoundary::Then);
                    }
                }
                let condition = AbilityCondition::And {
                    conditions: vec![
                        AbilityCondition::Not {
                            condition: Box::new(AbilityCondition::current_scope_succeeded()),
                        },
                        AbilityCondition::ScopedPlayerMatches { filter: scope },
                    ],
                };
                (body, Some(condition), DeclineDispatch::SubjectOnly)
            } else if let Some((_scope, body)) = strip_each_scope_who_doesnt_subject(&text) {
                // CR 118.12 + CR 608.2d + CR 109.5: subject-only OPTIONAL-decline
                // tail (Wernog, Rider's Chaplain: "each opponent may investigate.
                // Each opponent who doesn't loses 1 life."). Inverse of the
                // `who can't` arm above; the parent is OPTIONAL ("may"), so the
                // gate is Not{effect_performed()} (the CR 118.12 "doesn't" branch
                // reading OptionalEffectPerformed), NOT Not{current_scope_succeeded()}.
                //
                // CR 608.2e: retarget the preceding Sentence boundary → Then so
                // the body lowers as a within-action ContinuationStep — a
                // SequentialSibling would resolve even when the opponent ACCEPTS
                // (the current bug). Do NOT stamp `player_scope`: the body inherits
                // the parent's Opponent iteration via sub_ability attachment;
                // stamping it would start a nested fan-out and reset the
                // per-iteration flag. Parallel to the `who can't` arm above.
                //
                // Uses the BARE `Not{effect_performed()}` (no
                // `And{Not, ScopedPlayerMatches}` wrapper) to match the proven
                // prepositional `doesn't` arm (`strip_for_each_opponent_who_doesnt`)
                // exactly and hit the runtime decline fast-path. Dropping the
                // ScopedPlayerMatches conjunct is rules-correct for the same-scope
                // Wernog class: parent and decline both iterate `Opponent`, so the
                // scope conjunct would be a trivial no-op (CR 109.5).
                if let Some(prev) = clauses.last_mut() {
                    if prev.boundary == Some(ClauseBoundary::Sentence) {
                        prev.boundary = Some(ClauseBoundary::Then);
                    }
                }
                (
                    body,
                    Some(AbilityCondition::Not {
                        condition: Box::new(AbilityCondition::effect_performed()),
                    }),
                    DeclineDispatch::SubjectOnly,
                )
            } else {
                (text, condition, DeclineDispatch::None)
            };
        // Recipient rebinds apply to every chunk of the prepositional
        // decline-consequence sentence; the `Not{IfYouDo}` condition and
        // `player_scope` only to the head chunk that carried the "for each
        // opponent who doesn't" prefix. The subject-only quadrant rebinds
        // independently below via its own walker — see Step 4 site.
        let is_decline_consequence = matches!(decline_dispatch, DeclineDispatch::Prepositional)
            || decline_consequence_active;

        let (text, mut unless_pay) =
            extract_resolution_unless_pay_modifier(&text, player_scope.as_ref());

        // CR 701.21a + CR 608.2k: Derive the actor performing this chunk's effect
        // from any actor prefix that was just stripped ("you (may) ", "an
        // opponent (may) ", "each opponent ", "each player "). Threaded via
        // `ParseContext.actor` so targeted-action parsers can default
        // `TargetFilter::Typed.controller` to the actor when the target phrase
        // itself doesn't specify one (e.g. "you may sacrifice a non-Demon
        // creature" → controller defaults to You). Without this default, the
        // resolver would treat `controller: None` as Any and let the actor
        // sacrifice an opponent's permanent — violating CR 701.21a.
        let chunk_actor = match (is_optional, &opponent_may_scope, &player_scope) {
            (true, None, None) => Some(ControllerRef::You),
            (true, Some(_), _) => Some(ControllerRef::Opponent),
            (_, _, Some(PlayerFilter::Opponent)) => Some(ControllerRef::You),
            (_, _, Some(PlayerFilter::Controller)) => Some(ControllerRef::You),
            _ => None,
        }
        .or_else(|| ctx.actor.clone());
        let if_you_do_anchor = if_you_do_object_anchor(&clauses, &condition);
        let chunk_subject = if condition.as_ref().is_some_and(condition_refs_source_object) {
            Some(TargetFilter::SelfRef)
        } else {
            if_you_do_anchor.clone().or_else(|| ctx.subject.clone())
        };
        let parent_target_available =
            if_you_do_anchor.is_some() || chain_has_prior_typed_referent(&clauses);
        // CR 608.2c + CR 601.2a: a strict subset of `parent_target_available`
        // restricted to chosen-target referents (Emry), excluding impulse
        // publishers (Territorial Bruntar's `ExileFromTopUntil`). An "if you
        // do" object anchor is a created/tracked referent, not a target
        // selection, so it does not count here.
        let parent_target_is_chosen = chain_prior_referent_is_chosen_target(&clauses);
        // CR 608.2c (issue #1670): Consumption signal for the body "its
        // controller may" antecedent. True only when the rung ladder below
        // falls through to `chain_parent_target_controller_scope` for THIS
        // chunk (both higher-precedence rungs are None). Independent of the
        // lazy `.or_else` chain — pure Option inspection.
        let seeded_parent_target_controller_this_chunk = chain_chosen_player_scope.is_none()
            && ctx.relative_player_scope.is_none()
            && chain_parent_target_controller_scope.is_some();
        let mut chunk_ctx = ParseContext {
            subject: chunk_subject,
            card_name: ctx.card_name.clone(),
            // CR 707.9a + CR 603.1: propagate the trigger index from the parent
            // ctx — `current_trigger_index` is a property of the whole trigger
            // body, not of an individual chunk, so all chunks inside a trigger
            // share the same index for the BecomeCopy except-clause parser to
            // reference via `RetainPrintedTriggerFromSource`. Actor, by contrast,
            // is per-chunk (re-derived from each chunk's stripped prefix above).
            current_trigger_index: ctx.current_trigger_index,
            current_ability_index: ctx.current_ability_index,
            actor: chunk_actor,
            // CR 109.4 + CR 115.1 + CR 506.2: propagate relative-player scope
            // from the trigger condition so "that player controls" inside any
            // chunk resolves to TargetPlayer rather than defaulting to You.
            // CR 608.2c: a chosen-player scope set by an earlier "choose a
            // player" sentence (Gluntch) takes precedence — the "they"/"that
            // player controls" anaphor binds to the most recent choice.
            relative_player_scope: chain_chosen_player_scope
                .clone()
                .or_else(|| ctx.relative_player_scope.clone())
                // CR 608.2c (issue #1670): body "its controller may" antecedent
                // (Star Athlete). Placed BELOW ctx.relative_player_scope so a
                // trigger-CONDITION-derived scope keeps precedence — conservative
                // non-regressive ordering. No card today has BOTH a
                // condition-scoped player AND an independent body "its controller"
                // antecedent; this only supplies a scope when the condition set
                // none (e.g. "Whenever ~ attacks", where ctx.relative_player_scope
                // is None).
                .or_else(|| chain_parent_target_controller_scope.clone())
                .or_else(|| {
                    player_scope
                        .is_some()
                        .then_some(ControllerRef::ScopedPlayer)
                }),
            // CR 608.2c + CR 109.4: chain-spanning count of `Choose(Player)`
            // clauses already finalized — supplies the next `ChosenPlayer`
            // index.
            chosen_player_count: chain_chosen_player_count,
            // CR 303.4 + CR 702.103: propagate the enclosing card's typed host
            // self-reference so a `"that creature"` copy-token anaphor in any
            // chunk of an Aura/bestow card remaps to the enchanted host.
            host_self_reference: ctx.host_self_reference.clone(),
            // CR 608.2k: propagate the enclosing ability's exile-cost source
            // zone so a `"the exiled card"` anaphor in any effect chunk
            // disambiguates to `CostPaidObject` (Jhoira of the Ghitu).
            current_ability_exile_cost_zone: ctx.current_ability_exile_cost_zone,
            parent_target_available,
            effect_chain_full_lower: ctx.effect_chain_full_lower.clone(),
            parent_target_is_chosen,
            ..Default::default()
        };
        let ctx = &mut chunk_ctx;
        // CR 608.2c + CR 109.4 (issue #1670): Path-independent consumption-clear
        // of the single-shot "its controller" antecedent. The chunk consumed the
        // seeded scope above when `chunk_ctx.relative_player_scope` cloned
        // `chain_parent_target_controller_scope` (line ~15591); the loop-local
        // itself is not read again by this iteration's parse. Clearing it here —
        // immediately after `chunk_ctx` is built and BEFORE any special-clause
        // early `continue` (delayed-trigger, type-setting, instead-override,
        // search forms, etc.) — guarantees the antecedent cannot leak into a
        // later unrelated "that player" no matter which dispatch branch this
        // chunk takes. For an arming chunk (`seeded == false`, local was None at
        // start) this is a no-op, so it does not pre-empt the arm below that sets
        // the scope from `leading_subject_application`.
        if seeded_parent_target_controller_this_chunk {
            chain_parent_target_controller_scope = None;
        }
        let leading_subject_application = subject::parse_leading_subject_application(&text, ctx);
        let inherits_carried_targeted_player_subject = leading_subject_application.is_none()
            && player_scope.is_none()
            && !sequence::starts_clause_text(&text)
            && sequence::starts_clause_text_or_conjugated(&text);

        // CR 603.7a: Check for temporal prefix before suffix. When present, parse the
        // inner effect through the full pipeline and wrap in CreateDelayedTrigger.
        let (text_after_prefix, prefix_delayed) = strip_temporal_prefix(&text);
        // CR 107.3i: If this chunk has no local "where X is" but a sibling clause
        // in the same sentence binds X, propagate the sibling binding so "target
        // player loses X life" and "you gain X life" in the same sentence share
        // the same X expression (Essence Harvest, Debt to the Deathless, etc.).
        let where_x_expression = local_where_x_expression.or_else(|| {
            sentence_where_x
                .get(chunk_idx)
                .and_then(|expr| expr.clone())
        });
        if let Some(prefix_condition) = prefix_delayed {
            let (inner_text, inner_multi_target) = strip_any_number_quantifier(text_after_prefix);
            let inner_clause = parse_effect_clause(&inner_text, ctx);
            let mut inner_def = AbilityDefinition::new(kind, inner_clause.effect);
            if let Some(spec) = inner_multi_target.or(inner_clause.multi_target) {
                inner_def = inner_def.multi_target(spec);
            }
            if let Some(duration) = inner_clause.duration {
                inner_def = inner_def.duration(duration);
            }
            if let Some(sub) = inner_clause.sub_ability {
                inner_def.sub_ability = Some(sub);
            }
            apply_where_x_ability_expression(&mut inner_def, where_x_expression.as_deref());
            let delayed_effect = Effect::CreateDelayedTrigger {
                condition: prefix_condition.clone(),
                effect: Box::new(inner_def),
                uses_tracked_set: false,
            };
            let cascade_snap = super::swallow_check::CascadeSnapshot {
                is_optional,
                opponent_may_scope: opponent_may_scope.as_ref(),
                condition: condition.as_ref(),
                repeat_for: repeat_for.as_ref(),
                player_scope: player_scope.as_ref(),
                clause_duration: None,
            };
            let mut def = AbilityDefinition::new(kind, delayed_effect.clone());
            if is_optional {
                def.optional = true;
                def.optional_for = opponent_may_scope;
            }
            if let Some(ref condition) = condition {
                def = def.condition(condition.clone());
            }
            {
                let mut cascade_diags = Vec::new();
                super::swallow_check::check_cascade_diff(
                    &cascade_snap,
                    std::slice::from_ref(&def),
                    &mut cascade_diags,
                );
                for d in cascade_diags {
                    ctx.push_diagnostic(d);
                }
            }
            clauses.push(ClauseIr {
                parsed: parsed_clause(delayed_effect),
                boundary: chunk.boundary_after,
                condition: condition.clone(),
                is_optional,
                opponent_may_scope,
                repeat_for: repeat_for.clone(),
                player_scope,
                starting_with: starting_with.clone(),
                delayed_condition: None,
                prefix_delayed_condition: Some(prefix_condition),
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: where_x_expression.clone(),
                is_otherwise: false,
                unless_pay: None,
                special: None,
                source_text: normalized_text.to_string(),
                target_selection_mode: chunk_ctx.target_selection_mode,
                target_chooser: chunk_ctx.target_chooser.clone(),
            });
            continue;
        }

        // CR 205.1a: "it's a/an [type]" — type-setting effect for returned permanents
        // (e.g., Glimmer cycle "It's an enchantment."). Intercept before parse_effect_clause.
        if let Some(animate_def) = try_parse_type_setting(&text) {
            let cascade_snap = super::swallow_check::CascadeSnapshot {
                is_optional,
                opponent_may_scope: opponent_may_scope.as_ref(),
                condition: condition.as_ref(),
                repeat_for: repeat_for.as_ref(),
                player_scope: player_scope.as_ref(),
                clause_duration: None,
            };
            let mut def = animate_def.clone();
            if let Some(ref condition) = condition {
                def = def.condition(condition.clone());
            }
            {
                let mut cascade_diags = Vec::new();
                super::swallow_check::check_cascade_diff(
                    &cascade_snap,
                    std::slice::from_ref(&def),
                    &mut cascade_diags,
                );
                for d in cascade_diags {
                    ctx.push_diagnostic(d);
                }
            }
            clauses.push(ClauseIr {
                parsed: ParsedEffectClause {
                    effect: (*animate_def.effect).clone(),
                    duration: animate_def.duration.clone(),
                    sub_ability: animate_def.sub_ability.clone(),
                    distribute: animate_def.distribute,
                    multi_target: animate_def.multi_target.clone(),
                    condition: animate_def.condition.clone(),
                    optional: animate_def.optional,
                    unless_pay: animate_def.unless_pay.clone(),
                },
                boundary: chunk.boundary_after,
                condition: condition.clone(),
                is_optional,
                opponent_may_scope,
                repeat_for: repeat_for.clone(),
                player_scope,
                starting_with: starting_with.clone(),
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target: None,
                where_x_expression: None,
                is_otherwise: false,
                unless_pay: None,
                special: None,
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        let (text_no_temporal, delayed_condition) = strip_temporal_suffix(&text);
        let (text_no_qty, mut multi_target) = strip_any_number_quantifier(text_no_temporal);
        // CR 121.1 + CR 609.3: "draw cards equal to the difference" — anaphoric draw
        // count. When a leading QuantityCheck condition establishes two operands (e.g.
        // "if you have fewer than seven cards in hand"), "the difference" draws the
        // unsigned gap between them. Resolved here, in scope of both operands, to
        // QuantityExpr::Difference { left, right }. Cards: Kozilek the Great Distortion,
        // Iymrith Desert Doom, Damia Sage of Stone, Slithermuse, Balance of Power.
        let difference_draw = condition.as_ref().and_then(|cond| {
            let lower = text_no_qty.to_lowercase();
            let clean = lower.trim().trim_end_matches('.');
            if clean == "draw cards equal to the difference" {
                conditions::difference_expr(cond).map(|diff| {
                    parsed_clause(Effect::Draw {
                        count: diff,
                        target: TargetFilter::Controller,
                    })
                })
            } else {
                None
            }
        });
        let (clause, repeat_for) = if let Some(draw) = difference_draw {
            (draw, repeat_for)
        } else {
            let (suffix_repeat_for, stripped_text_no_qty) =
                strip_for_each_repeat_suffix(&text_no_qty);
            let stripped_clause = parse_effect_clause(&stripped_text_no_qty, ctx);
            if suffix_repeat_for.is_some()
                && matches!(stripped_clause.effect, Effect::CopySpell { .. })
            {
                (stripped_clause, repeat_for.or(suffix_repeat_for))
            } else if let Some((fanout_clause, fanout_spec, fanout_ctx)) =
                parse_for_each_opponent_target_fanout_clause(
                    &text_no_qty,
                    repeat_for.as_ref(),
                    multi_target.as_ref(),
                    ctx,
                )
            {
                *ctx = fanout_ctx;
                multi_target = Some(fanout_spec);
                (fanout_clause, None)
            } else {
                (parse_effect_clause(&text_no_qty, ctx), repeat_for)
            }
        };

        // CR 608.2c + CR 109.4: After a `Choose(Player)` clause is finalized,
        // advance the chain's chosen-player counter exactly once. The index is
        // read (not mutated) inside `try_parse_choose_player_to_verb`, which is
        // called speculatively (the trial parse above + the real parse). Doing
        // the increment here — once per finalized chunk — keeps the next
        // `ChosenPlayer { index }` correct under that double-parse.
        if matches!(
            clause.effect,
            Effect::Choose {
                choice_type: ChoiceType::Player | ChoiceType::Opponent,
                ..
            }
        ) {
            ctx.chosen_player_count = ctx.chosen_player_count.saturating_add(1);
        }

        // CR 118.12: After parsing the effect clause, the lowering for
        // `Effect::Counter` carries its own `unless_pay` modifier on the
        // produced `ParsedEffectClause` (post-2026-05-09 fold). Merge it into
        // the chunk-level `unless_pay` so it propagates into the ClauseIr.
        // The resolution-time extractor (`extract_resolution_unless_pay_modifier`)
        // catches "[verb] [target] unless [player] pays [cost]" patterns at
        // the chunk-text level; the AST intercept catches Counter-specific
        // shapes that survive into the lowered effect.
        if unless_pay.is_none() {
            unless_pay = clause.unless_pay.clone();
        }

        // CR 608.2c: Verb carry-forward for bare "target X" clauses in multi-target
        // conjunctions. When a clause parses as Unimplemented and starts with "target",
        // inherit the verb from the previous successfully-parsed effect and re-parse.
        // Handles patterns like "destroy target artifact, target creature, ..." (Decimate).
        let text_no_qty_lower = text_no_qty.to_lowercase();
        let clause = if matches!(clause.effect, Effect::Unimplemented { .. })
            && tag::<_, _, OracleError<'_>>("target ")
                .parse(text_no_qty_lower.as_str())
                .is_ok()
        {
            if let Some(verb) = clauses
                .last()
                .and_then(|prev| extract_effect_verb(&prev.parsed.effect))
            {
                let reparsed_text = format!("{verb} {text_no_qty}");
                let reparsed = parse_effect_clause(&reparsed_text, ctx);
                if !matches!(reparsed.effect, Effect::Unimplemented { .. }) {
                    reparsed
                } else {
                    clause
                }
            } else {
                clause
            }
        } else {
            clause
        };

        // CR 608.2c + CR 117.3a: Anchor-subject inheritance. Before this chunk is
        // stored in the IR, check whether a caster-defaulted player-scope effect
        // should inherit a previously-declared subject (e.g., "then shuffle" after
        // "its controller may search their library" → Shuffle inherits the
        // ParentTargetController anchor). Only overrides when the effect still
        // carries the caster default (Controller). Per D-04, this is parse-time
        // pronoun resolution that belongs in IR production.
        let mut clause = clause;
        if let Some(target) = &for_each_reference_target {
            bind_search_library_for_each_antecedent(&mut clause.effect, target, &text_no_qty_lower);
        }
        // CR 608.2: `parse_exile_ast` uses `ScopedPlayer` as the structural
        // marker for "each player's library". Lower it into the same
        // player_scope-driven shape used by Evelyn/Jeleva-class effects:
        // the resolver iterates all players and `Controller` reads the
        // rebound per-player controller.
        lift_each_player_exile_top_scope(&mut clause.effect, &mut player_scope);
        // CR 109.5: Rebind recipient-bearing nodes inside a decline body so the
        // body's "you"/"that player" anaphors resolve relative to the surrounding
        // per-player iteration. The two walkers are parallel inverses:
        //   - Prepositional ("for each opponent who …, you draw …"): rebinds
        //     Controller → OriginalController so "you" stays the printed
        //     controller inside the Opponent-scoped iteration; also covers the
        //     sticky continuation chunks via `decline_consequence_active`.
        //   - SubjectOnly ("each player who can't discards a card"): rebinds
        //     Controller → ScopedPlayer so the body's implicit recipient binds
        //     to the per-iteration player who couldn't perform the predicate.
        if matches!(decline_dispatch, DeclineDispatch::SubjectOnly) {
            rebind_clause_recipients_with(&mut clause, rebind_subject_only_body_recipient);
        }
        if is_decline_consequence {
            rebind_clause_recipients_with(&mut clause, rebind_decline_body_recipient);
        }
        if inherits_carried_targeted_player_subject {
            if let Some(subject) = carried_targeted_player_subject.as_ref() {
                // CR 601.2c: a single "target opponent" governs the whole verb
                // list ("sacrifices …, discards …, and loses 3 life") — the
                // target is chosen ONCE at announcement and every conjugated
                // continuation applies to that same player. Inject
                // `ParentTarget` (inherit the leading verb's chosen player) and
                // NOT a fresh copy of the player filter, which would surface a
                // second target slot and prompt the player again (#2344).
                let subject = SubjectPhraseAst {
                    affected: TargetFilter::ParentTarget,
                    target: Some(TargetFilter::ParentTarget),
                    multi_target: None,
                    inherits_parent: true,
                    is_optional: subject.is_optional,
                };
                inject_subject_target(&mut clause.effect, &subject);
            }
        }
        if nom_primitives::scan_contains(&text.to_lowercase(), "villainous choice") {
            if let (Effect::ChooseOneOf { chooser, .. }, Some(scope)) =
                (&mut clause.effect, player_scope.clone())
            {
                *chooser = scope;
                player_scope = None;
            }
        }
        if let Some(ref anchor) = anchor_subject {
            apply_anchor_subject(&mut clause.effect, anchor);
        }

        // Update anchor from this clause's subject (e.g., SearchLibrary.target_player
        // set to a non-caster player-scope filter).
        if let Some(extracted) = extract_player_anchor(&clause.effect) {
            anchor_subject = Some(extracted);
        }

        // Anaphoric resolution: parse-time pronoun→parent-target rewrites.
        // These modify the parsed effect based on text analysis and previous
        // clause context — parse-time work that belongs in IR production.
        // CR 608.2k carve-out (issue #319): in typed-trigger-subject context,
        // bare pronouns have already been correctly bound to TriggeringSource by
        // `resolve_pronoun_target` — preserve that binding so cards like
        // Ancestral Katana ("Whenever a Samurai or Warrior … attach ~ to it")
        // attach to the triggering creature, not the parent target.
        let text_lower = text.to_lowercase();
        let typed_trigger_subject = ctx_has_typed_trigger_subject(ctx);
        // CR 109.5 + CR 608.2c: A compound-subject distribution chunk ("~ and
        // that creature each ...") has already had an explicit recipient bound
        // on EVERY link by `try_parse_compound_subject_each` — the distributor
        // is the authority for that chain. The anaphoric "it"/"that creature"
        // rewriters below operate only on the head link (`clause.effect`) and
        // would clobber the distributor's leading recipient (Gogo's head
        // `SelfRef` → `ParentTarget`), so they must be skipped for distributed
        // chunks. The deeper links are never visited by these rewriters anyway,
        // which is exactly why a head-only rewrite corrupts the chain.
        let is_distributed_chunk = text_is_compound_subject_distribution(&text);
        // Kicker clauses referencing "that creature"/"it" inherit the parent's target.
        if condition.is_some()
            && !is_distributed_chunk
            && !condition.as_ref().is_some_and(condition_refs_source_object)
            && !clauses.is_empty()
            && has_anaphoric_reference(&text_lower)
            && !matches!(if_you_do_anchor, Some(TargetFilter::SelfRef))
            && !typed_trigger_subject
            && !explicit_any_target_clause(&clause.effect, &text_lower)
            && !replace_fight_subject_with_parent_if_anaphoric_subject(
                &text_lower,
                &mut clause.effect,
            )
        {
            replace_target_with_parent(&mut clause.effect);
        }
        // CR 608.2c: Pronoun clause following a conditional targeted effect.
        if condition.is_none()
            && !is_distributed_chunk
            && clauses.last().is_some_and(|prev| {
                prev.condition.is_some() && has_typed_target(&prev.parsed.effect)
            })
            && has_anaphoric_reference(&text_lower)
            && !typed_trigger_subject
            && !explicit_any_target_clause(&clause.effect, &text_lower)
            && !replace_fight_subject_with_parent_if_anaphoric_subject(
                &text_lower,
                &mut clause.effect,
            )
        {
            replace_target_with_parent(&mut clause.effect);
        }
        // CR 608.2c: Pronoun clause following an unconditional targeted effect.
        // Transitive across `ParentTarget`-carrier clauses so an intervening
        // anaphor ("Untap it.") doesn't hide the originating typed target
        // (Nissa, Who Shakes the World).
        if condition.is_none()
            && !is_distributed_chunk
            && chain_has_prior_typed_referent(&clauses)
            && has_anaphoric_reference(&text_lower)
            && !typed_trigger_subject
            && !explicit_any_target_clause(&clause.effect, &text_lower)
            && !replace_fight_subject_with_parent_if_anaphoric_subject(
                &text_lower,
                &mut clause.effect,
            )
        {
            replace_target_with_parent(&mut clause.effect);
        }
        if chain_has_prior_player_target_referent(&clauses)
            && has_player_anaphoric_reference(&text_lower)
        {
            replace_player_anaphor_with_parent_target(&mut clause.effect);
        }
        if clauses
            .last()
            .is_some_and(|prev| matches!(&prev.parsed.effect, Effect::Counter { .. }))
        {
            rewrite_triggering_spell_controller_to_parent_target_controller(&mut clause.effect);
        }
        // CR 614.1a + CR 701.5 + CR 608.2c: "Exile-after-cast/counter rider"
        // class — Toshiro Umezawa, Dire Fleet Daredevil's chained cousins,
        // Defabricate-class. When the previous clause is a CastFromZone or
        // Counter with a typed target, the rider clause's bare "it" must bind
        // to the cast/countered spell (the parent target), even when the outer
        // trigger has a typed subject (Toshiro: subject = "a creature an
        // opponent controls"). Without this rewrite the pronoun would bind to
        // the triggering source (the dying creature) per CR 608.2k. The
        // trailing rider is recognised structurally via
        // `is_exile_after_spell_rider_clause` so the relaxation is precise.
        if typed_trigger_subject
            && !is_distributed_chunk
            && is_exile_after_spell_rider_clause(&text_lower)
            && clauses.last().is_some_and(|prev| {
                matches!(
                    &prev.parsed.effect,
                    Effect::CastFromZone { .. } | Effect::Counter { .. }
                )
            })
        {
            replace_target_with_parent(&mut clause.effect);
        }
        // CR 608.2c: A clause whose bare pronoun ("it"/"him"/"her") follows an
        // earlier clause that named the source object via `~` (parsed as a
        // SelfRef-targeted zone change — "exile ~, then return him transformed",
        // Ajani, Nacatl Pariah) must bind that pronoun to the source, not the
        // typed trigger subject. Mirrors the Toshiro exile-after-spell rider
        // above: a rewrite that fires even under a typed trigger subject because
        // the antecedent is a *named clause*, not the trigger condition. The
        // SelfRef prior-clause test is a typed `matches!` on the parsed Effect
        // AST — the parser's own output is the detector, no string heuristic.
        if typed_trigger_subject
            && has_anaphoric_reference(&text_lower)
            && clauses.last().is_some_and(|prev| {
                matches!(
                    &prev.parsed.effect,
                    Effect::ChangeZone {
                        target: TargetFilter::SelfRef,
                        ..
                    }
                )
            })
        {
            replace_target_with_self(&mut clause.effect);
        }

        if condition
            .as_ref()
            .is_some_and(condition_refs_cost_paid_object)
        {
            rewrite_cost_paid_object_quantities(&mut clause.effect);
        }
        // CR 608.2g + CR 601.2: The "may" in a free-cast window belongs to the
        // interactive CastOffer itself ("up to N" includes choosing zero casts),
        // not to the generic OptionalEffectChoice wrapper around the whole
        // effect. Keep the actor context derived from the printed "you may", but
        // lower the effect as mandatory so resolution opens the FreeCastWindow.
        let is_optional = if matches!(&clause.effect, Effect::FreeCastFromZones { .. }) {
            false
        } else {
            is_optional
        };

        // CR 608.2e: "Instead" overrides — marker for lowering to attach as
        // sub_ability on the previous def.
        if matches!(
            condition,
            Some(AbilityCondition::TargetHasKeywordInstead { .. })
        ) {
            // Build the def that lowering will attach — apply condition + effect
            let mut instead_def = AbilityDefinition::new(kind, clause.effect.clone());
            if let Some(ref cond) = condition {
                instead_def = instead_def.condition(cond.clone());
            }
            clauses.push(ClauseIr {
                parsed: clause,
                boundary: chunk.boundary_after,
                condition,
                is_optional,
                opponent_may_scope,
                repeat_for,
                player_scope,
                starting_with: starting_with.clone(),
                delayed_condition: None,
                prefix_delayed_condition: None,
                intrinsic_continuation: None,
                followup_continuation: None,
                absorbed_by_followup: false,
                multi_target,
                where_x_expression,
                is_otherwise: false,
                unless_pay: None,
                special: Some(SpecialClause::KeywordInsteadOverride),
                source_text: normalized_text.to_string(),
                target_selection_mode: TargetSelectionMode::Chosen,
                target_chooser: None,
            });
            continue;
        }

        // CR 608.2e: AdditionalCostPaidInstead + SearchLibrary pattern.
        // In the old code, the trailing ChangeZone was an explicit def produced by the
        // SearchDestination intrinsic continuation. In the IR, the ChangeZone is implicit
        // in the SearchLibrary clause's intrinsic_continuation field. We check for either:
        // (a) a separate ChangeZone clause (shouldn't happen in new code), or
        // (b) a SearchLibrary clause with a SearchDestination { destination: Hand } continuation.
        let effective_condition = condition.as_ref().or(clause.condition.as_ref());
        if matches!(
            effective_condition,
            Some(AbilityCondition::AdditionalCostPaidInstead)
        ) && matches!(clause.effect, Effect::SearchLibrary { .. })
            && !clauses.is_empty()
        {
            // Find the last non-absorbed clause — it should be a SearchLibrary with
            // a SearchDestination(Hand) intrinsic continuation.
            let prev_non_absorbed = clauses.iter().rev().find(|c| !c.absorbed_by_followup);
            let previous_is_search_with_hand_dest = prev_non_absorbed.is_some_and(|c| {
                matches!(c.parsed.effect, Effect::SearchLibrary { .. })
                    && matches!(
                        c.intrinsic_continuation,
                        Some(ContinuationAst::SearchDestination {
                            destination: Zone::Hand,
                            ..
                        })
                    )
            });
            if previous_is_search_with_hand_dest {
                // Compute intrinsic continuation for this SearchLibrary too —
                // it needs its own SearchDestination.
                let temp_def = AbilityDefinition::new(kind, clause.effect.clone());
                let ic = parse_intrinsic_continuation_ast(
                    normalized_text,
                    intrinsic_continuation_effect(&temp_def),
                    full_text,
                );
                clauses.push(ClauseIr {
                    parsed: clause,
                    boundary: chunk.boundary_after,
                    condition,
                    is_optional,
                    opponent_may_scope,
                    repeat_for,
                    player_scope,
                    starting_with: starting_with.clone(),
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: ic,
                    followup_continuation: None,
                    absorbed_by_followup: false,
                    multi_target,
                    where_x_expression,
                    is_otherwise: false,
                    unless_pay: None,
                    special: Some(SpecialClause::AdditionalCostInsteadSearch),
                    source_text: normalized_text.to_string(),
                    target_selection_mode: TargetSelectionMode::Chosen,
                    target_chooser: None,
                });
                continue;
            }
        }

        // CR 603.7: Cross-clause pronoun → mark uses_tracked_set flag.
        // This needs to check whether the previous clause publishes an affected
        // object set (zone changes, token creation, counter placement, etc.).
        let needs_tracked_set = clauses
            .iter()
            .rev()
            .find(|c| !c.absorbed_by_followup)
            .is_some_and(|previous| {
                publishes_tracked_set_from_resolution(&previous.parsed.effect)
                    && (contains_explicit_tracked_set_pronoun(&lower_check)
                        || contains_implicit_tracked_set_pronoun(&lower_check))
            });

        // Continuation recognition — store on ClauseIr, application moves to lowering.
        //
        // The followup continuation check needs the "effective last effect" — i.e., what
        // `defs.last()` would look like in the old code after intrinsic/followup continuation
        // application. Two adjustments are needed vs. simply using `clauses.last().parsed.effect`:
        //
        // 1. Skip absorbed clauses: in the old code, absorbed chunks are not pushed to `defs`,
        //    so `defs.last()` remains the clause that absorbed them. In our IR, absorbed clauses
        //    ARE stored (for lowering), so we must skip them when finding the "effective previous."
        //
        // 2. Simulate intrinsic continuation: when the previous clause has an intrinsic
        //    continuation (e.g., SearchDestination), the continuation adds new defs (e.g.,
        //    ChangeZone) that become `defs.last()`. We must simulate this to match followup
        //    patterns that absorb paraphrase chunks (e.g., "put it onto the battlefield"
        //    after SearchLibrary).
        let absorbed_choice_prev = clauses.last().and_then(|previous| {
            if previous.absorbed_by_followup {
                match previous.followup_continuation.as_ref() {
                    Some(ContinuationAst::ChooseFromExile { count, chooser }) => {
                        Some(Effect::ChooseFromZone {
                            count: *count,
                            zone: Zone::Exile,
                            additional_zones: Vec::new(),
                            zone_owner: crate::types::ability::ZoneOwner::Controller,
                            filter: None,
                            chooser: *chooser,
                            up_to: false,
                            constraint: None,
                        })
                    }
                    _ => None,
                }
            } else {
                None
            }
        });
        // "Effective effect" of a non-absorbed clause — what `defs.last()` would
        // be after intrinsic/followup continuation application. Shared by the
        // nearest-clause lookback and the CR 608.2c deeper-clause lookback.
        let effective_effect_of = |previous: &ClauseIr| -> Effect {
            if let Some(ref ic) = previous.intrinsic_continuation {
                // Build a temporary defs list, apply the continuation, and use the last effect.
                let mut temp_defs =
                    vec![AbilityDefinition::new(kind, previous.parsed.effect.clone())];
                apply_clause_continuation(&mut temp_defs, ic.clone(), kind);
                (*temp_defs.last().unwrap().effect).clone()
            } else if let Some(ref _fc) = previous.followup_continuation {
                // A non-absorbed clause with a followup continuation means the continuation
                // was applied to the clause BEFORE it. Simulate to get patched effect.
                // Find the clause before `previous` (skip absorbed), apply the followup.
                match previous.followup_continuation.as_ref() {
                    Some(ContinuationAst::ChooseFromExile { count, chooser }) => {
                        Effect::ChooseFromZone {
                            count: *count,
                            zone: Zone::Exile,
                            additional_zones: Vec::new(),
                            zone_owner: crate::types::ability::ZoneOwner::Controller,
                            filter: None,
                            chooser: *chooser,
                            up_to: false,
                            constraint: None,
                        }
                    }
                    // Simple patch-in-place continuations leave the previous
                    // effect type as the effective lookback target.
                    _ => previous.parsed.effect.clone(),
                }
            } else {
                previous.parsed.effect.clone()
            }
        };
        // Non-absorbed clauses, nearest-first — the lookback search space.
        let non_absorbed: Vec<&ClauseIr> = clauses
            .iter()
            .rev()
            .filter(|c| !c.absorbed_by_followup)
            .collect();
        let effective_prev_effect =
            absorbed_choice_prev.or_else(|| non_absorbed.first().map(|c| effective_effect_of(c)));
        let followup_continuation = effective_prev_effect
            .as_ref()
            .and_then(|eff| parse_followup_continuation_ast(normalized_text, eff, ctx))
            .or_else(|| {
                // CR 608.2c: when the nearest non-absorbed clause is
                // lookback-transparent (e.g. `Sacrifice` — Birthing Ritual),
                // continue searching deeper for a `Dig`/`Mill` antecedent. The
                // parser is the detector: only redirect if a deeper clause
                // actually yields a `Dig`-patching continuation. Both arms
                // patch the same `Dig`: `DigFromAmong` is the "put N from
                // among those cards" selection (clause 3), `PutRest` is the
                // trailing "put the rest on the bottom" remainder placement
                // (clause 4). Both must reach back past the intervening
                // `Sacrifice` to the `Dig`.
                let nearest = effective_prev_effect.as_ref()?;
                if !clause_is_dig_lookback_transparent(nearest) {
                    return None;
                }
                non_absorbed.iter().skip(1).find_map(|c| {
                    let deeper = effective_effect_of(c);
                    match parse_followup_continuation_ast(normalized_text, &deeper, ctx) {
                        Some(
                            continuation @ (ContinuationAst::DigFromAmong { .. }
                            | ContinuationAst::PutRest { .. }),
                        ) => Some(continuation),
                        _ => None,
                    }
                })
            });
        let absorb_followup = followup_continuation
            .as_ref()
            .is_some_and(|continuation| continuation_absorbs_current(continuation, &clause.effect));

        // Build a temporary def for intrinsic continuation detection and cascade check.
        // The intrinsic continuation parser needs the assembled effect to determine
        // what continuation pattern applies.
        let mut temp_def = AbilityDefinition::new(kind, clause.effect.clone());
        // Wire sub_ability for TargetOnly unwrapping in intrinsic_continuation_effect.
        if matches!(clause.effect, Effect::TargetOnly { .. }) {
            temp_def.sub_ability = clause.sub_ability.clone();
        }
        let intrinsic_continuation = parse_intrinsic_continuation_ast(
            normalized_text,
            intrinsic_continuation_effect(&temp_def),
            full_text,
        );

        // Phase 1.5: cascade-vs-AST structural diff.
        {
            let cascade_snap = super::swallow_check::CascadeSnapshot {
                is_optional,
                opponent_may_scope: opponent_may_scope.as_ref(),
                condition: condition.as_ref().or(clause.condition.as_ref()),
                repeat_for: repeat_for.as_ref(),
                player_scope: player_scope.as_ref(),
                clause_duration: clause.duration.as_ref(),
            };
            // Build temporary defs for the cascade check
            let mut check_def = AbilityDefinition::new(kind, clause.effect.clone());
            if is_optional {
                check_def.optional = true;
                check_def.optional_for = opponent_may_scope;
            }
            if clause.optional {
                check_def.optional = true;
            }
            if let Some(ref qty) = repeat_for {
                check_def.repeat_for = Some(qty.clone());
            }
            if let Some(ref scope) = player_scope {
                check_def.player_scope = Some(scope.clone());
            }
            if let Some(ref duration) = clause.duration {
                check_def = check_def.duration(duration.clone());
            }
            if let Some(cond) = condition.as_ref().or(clause.condition.as_ref()) {
                check_def = check_def.condition(cond.clone());
            }
            if let Some(ref spec) = multi_target {
                check_def = check_def.multi_target(spec.clone());
            } else if let Some(ref spec) = clause.multi_target {
                check_def = check_def.multi_target(spec.clone());
            }
            if let Some(ref unit) = clause.distribute {
                check_def = check_def.distribute(unit.clone());
            }
            if let Some(ref modifier) = unless_pay {
                check_def = check_def.unless_pay(modifier.clone());
            }
            // Include delayed_condition wrapping for accurate cascade check
            if let Some(ref delayed_cond) = delayed_condition {
                let inner = check_def;
                let lifted_condition = inner.condition.clone();
                let lifted_optional = inner.optional;
                let lifted_optional_for = inner.optional_for;
                let lifted_repeat_for = inner.repeat_for.clone();
                let lifted_player_scope = inner.player_scope.clone();
                check_def = AbilityDefinition::new(
                    kind,
                    Effect::CreateDelayedTrigger {
                        condition: delayed_cond.clone(),
                        effect: Box::new(inner),
                        uses_tracked_set: needs_tracked_set,
                    },
                );
                check_def.condition = lifted_condition;
                check_def.optional = lifted_optional;
                check_def.optional_for = lifted_optional_for;
                check_def.repeat_for = lifted_repeat_for;
                check_def.player_scope = lifted_player_scope;
            }
            if needs_tracked_set {
                rewrite_parent_targets_to_tracked_set(&mut check_def.effect);
            }
            let mut check_defs = vec![check_def];
            let is_target_only = matches!(clause.effect, Effect::TargetOnly { .. });
            if !is_target_only {
                if let Some(ref sub) = clause.sub_ability {
                    check_defs.push(*sub.clone());
                }
            }
            {
                let mut cascade_diags = Vec::new();
                super::swallow_check::check_cascade_diff(
                    &cascade_snap,
                    &check_defs,
                    &mut cascade_diags,
                );
                for d in cascade_diags {
                    ctx.push_diagnostic(d);
                }
            }
        }

        // If this clause is absorbed by a followup continuation from the previous
        // clause, mark it and store the continuation on the PREVIOUS clause.
        if absorb_followup {
            // Store the followup continuation — it applies to the previous clause.
            // We handle this by pushing an absorbed marker clause.
            if let Some(continuation) = followup_continuation {
                clauses.push(ClauseIr {
                    parsed: clause,
                    boundary: chunk.boundary_after,
                    condition,
                    is_optional,
                    opponent_may_scope,
                    repeat_for,
                    player_scope,
                    starting_with: starting_with.clone(),
                    delayed_condition: None,
                    prefix_delayed_condition: None,
                    intrinsic_continuation: None,
                    followup_continuation: Some(continuation),
                    absorbed_by_followup: true,
                    multi_target,
                    where_x_expression,
                    is_otherwise: false,
                    unless_pay: None,
                    special: None,
                    source_text: normalized_text.to_string(),
                    target_selection_mode: chunk_ctx.target_selection_mode,
                    target_chooser: chunk_ctx.target_chooser.clone(),
                });
            }
            continue;
        }

        // Non-absorbed followup continuation — store on the current clause
        // (it applies to the PREVIOUS clause in lowering).
        let followup_for_this = if followup_continuation.is_some() && !absorb_followup {
            followup_continuation
        } else {
            None
        };

        clauses.push(ClauseIr {
            parsed: clause,
            boundary: chunk.boundary_after,
            condition,
            is_optional,
            opponent_may_scope,
            repeat_for,
            player_scope,
            starting_with: starting_with.clone(),
            delayed_condition,
            prefix_delayed_condition: None,
            intrinsic_continuation,
            followup_continuation: followup_for_this,
            absorbed_by_followup: false,
            multi_target,
            where_x_expression,
            is_otherwise: false,
            unless_pay,
            special: None,
            source_text: normalized_text.to_string(),
            // CR 115.1 + CR 701.9b: snapshot the parser's per-chunk selection
            // mode. Set to `Random` by `parse_target_with_ctx` when "random "
            // was stripped from this chunk's target phrase.
            target_selection_mode: chunk_ctx.target_selection_mode,
            target_chooser: chunk_ctx.target_chooser.clone(),
        });

        // Drain chunk-ctx diagnostics into the accumulator (the outer `ctx` is
        // shadowed inside the loop, so we collect here and extend after the loop).
        chunk_diagnostics.append(&mut chunk_ctx.diagnostics);

        // CR 608.2c + CR 109.4: Carry the chosen-player state forward to the
        // next chunk. The per-chunk loop body advanced `chosen_player_count`
        // (once per finalized `Choose(Player)` clause) and set
        // `relative_player_scope` to the chosen scope; thread both into the
        // chain-spanning loop-locals so the following sentence sees them.
        chain_chosen_player_count = chunk_ctx.chosen_player_count;
        if let Some(scope @ ControllerRef::ChosenPlayer { .. }) = &chunk_ctx.relative_player_scope {
            chain_chosen_player_scope = Some(scope.clone());
        }

        // CR 608.2c + CR 109.4 (issue #1670): Arm the chain-spanning "its
        // controller" antecedent. The consuming-chunk CLEAR was hoisted above to
        // a path-independent location (immediately after `chunk_ctx` is built) so
        // it runs on every iteration regardless of early `continue`; this block
        // only ARMS. The arming chunk (leading subject "its controller may
        // <act>") has `seeded == false` (the local was None at its start), so the
        // hoisted clear was a no-op for it and this arm fires unimpeded. Read
        // `leading_subject_application` via `.as_ref()` because it is MOVED
        // below in the `carried_targeted_player_subject` update.
        if matches!(
            leading_subject_application.as_ref(),
            Some(app) if app.is_optional && app.affected == TargetFilter::ParentTargetController
        ) {
            chain_parent_target_controller_scope = Some(ControllerRef::ParentTargetController);
        }

        // CR 608.2e: The decline-consequence rebind scope ends at the sentence
        // boundary — a following independent instruction is not part of the
        // "for each opponent who doesn't" body.
        if chunk.boundary_after == Some(ClauseBoundary::Sentence) {
            decline_consequence_active = false;
        }
        if chunk.boundary_after == Some(ClauseBoundary::Sentence) {
            carried_targeted_player_subject = None;
        } else if let Some(application) = leading_subject_application {
            carried_targeted_player_subject = application
                .target
                .as_ref()
                .is_some_and(target_filter_can_target_player)
                .then_some(application);
        } else if !inherits_carried_targeted_player_subject {
            carried_targeted_player_subject = None;
        }
    }

    // Merge per-chunk diagnostics and any pre-loop diagnostics into the outer ctx.
    ctx.diagnostics.extend(chunk_diagnostics);

    // CR 113.10 + chunk-splitter normalization: Bronzehide Lion's "and it loses
    // all other abilities" was pre-split by
    // `sequence.rs::starts_bare_and_clause` into a sibling `GenericEffect`
    // clause. Fold it into the preceding `Effect::ReturnAsAura.grants` so the
    // single resolver registers ONE `TransientContinuousEffect` under
    // `Duration::UntilHostLeavesPlay` rather than a stray sibling that would
    // default to `Duration::UntilEndOfTurn` (engine convention for
    // `GenericEffect` whose duration field is `None`; the CR baseline per
    // CR 611.2a is "until end of the game", which is not what we want either).
    try_fold_loses_other_sibling(&mut clauses);

    // CR 611.2b: stamp the stripped leading "for as long as" duration onto every
    // sibling clause of the heterogeneous body (gain control, "it loses all abilities"
    // -> RemoveAllAbilities, "can't attack or block"). with_clause_duration patches
    // both the clause-level duration and any inner GenericEffect.duration.
    if let Some((dur, _)) = leading_host_lifetime_split {
        for clause in clauses.iter_mut() {
            clause.parsed = with_clause_duration(clause.parsed.clone(), dur.clone());
        }
    }

    EffectChainIr {
        clauses,
        kind,
        chain_rounding,
        actor: ctx.actor.clone(),
        repeat_until: pending_repeat_until,
    }
}

/// CR 113.10 + CR 613.1f + CR 613.8: IR-layer fold helper.
///
/// Walks `clauses` and, for each `Effect::ReturnAsAura` whose IMMEDIATE
/// following sibling is exactly the shape produced by the chunk-splitter for
/// "and it loses all other abilities" — a `ClauseIr` with `Effect::GenericEffect`
/// carrying a single `StaticDefinition { mode: Continuous, affected:
/// Some(TargetFilter::SelfRef), modifications: [RemoveAllAbilities], condition:
/// None }` and `duration: None`, `target: None` — prepends
/// `ContinuousModification::RemoveAllAbilities` to the `ReturnAsAura`'s grants
/// list and removes the sibling clause.
///
/// This consolidates Bronzehide Lion's pre-split decomposition into a single
/// `TransientContinuousEffect` so the layer system runs `RemoveAllAbilities`
/// (CR 613.1f, Layer 6) under the same `Duration::UntilHostLeavesPlay` as the
/// rest of the Aura's continuous effect (CR 400.7 + CR 611.2a). Without the
/// fold, the sibling `GenericEffect` resolver would default to
/// `Duration::UntilEndOfTurn` (engine convention for `GenericEffect.duration ==
/// None`; the CR baseline per CR 611.2a is "until end of the game", but the
/// engine uses end-of-turn as a more conservative default for unannotated
/// continuous effects). Either default is wrong for an Aura's installed
/// effect, which is anchored to the host object's lifetime per CR 400.7.
///
/// Old-Growth Troll and Harold and Bob don't trigger the fold (Old-Growth has
/// no loses-clause; Harold's loses-clause lives in the same chunk and is
/// handled by `parse_loses_clause` in `oracle_nom::return_as_aura`).
fn try_fold_loses_other_sibling(clauses: &mut Vec<ClauseIr>) {
    let mut i = 0;
    while i + 1 < clauses.len() {
        let is_return_as_aura = matches!(&clauses[i].parsed.effect, Effect::ReturnAsAura { .. });
        if !is_return_as_aura {
            i += 1;
            continue;
        }
        let sibling_is_loses_all = match &clauses[i + 1].parsed.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                target,
            } => {
                duration.is_none() && target.is_none() && static_abilities.len() == 1 && {
                    let s = &static_abilities[0];
                    s.mode == StaticMode::Continuous
                        && s.affected == Some(TargetFilter::SelfRef)
                        && s.condition.is_none()
                        && s.modifications.len() == 1
                        && matches!(
                            s.modifications[0],
                            ContinuousModification::RemoveAllAbilities
                        )
                }
            }
            _ => false,
        };
        if !sibling_is_loses_all {
            i += 1;
            continue;
        }
        // Fold: prepend RemoveAllAbilities into the ReturnAsAura's grants,
        // then drop the sibling clause.
        if let Effect::ReturnAsAura { grants, .. } = &mut clauses[i].parsed.effect {
            grants.insert(0, ContinuousModification::RemoveAllAbilities);
        }
        clauses.remove(i + 1);
        i += 1;
    }
}

/// CR 111.1 + CR 616.1: "For each X, create a [token]" creates all the tokens
/// as a SINGLE event, not one event per iteration. When the repeated
/// body is a bare token creation, fold the per-iteration quantity into the
/// token's `count` so the runtime emits one `CreateToken` event. This makes
/// token doublers (Doubling Season, Primal Vigor) and additive token
/// replacements (Xorn) apply once to the whole batch under a single CR 616.1
/// ordering choice, instead of re-prompting and re-doubling per iteration
/// (Brass's Bounty, Hei Bai, Turn Stones).
///
/// "Bare" is enforced by the caller (no chained `sub_ability`) plus the checks
/// here: a token attached to the iteration's object (`attach_to`, e.g. Asinine
/// Antics' per-creature Roles) is per-iteration and must NOT fold. Only the
/// canonical single-per-iteration `count` is folded; "create N per iteration"
/// would need a product expression that no bare-token card uses, so it falls
/// through to the existing `repeat_for` loop.
fn try_fold_token_repeat_into_count(effect: &mut Effect, qty: &QuantityExpr) -> bool {
    if let Effect::Token {
        count, attach_to, ..
    } = effect
    {
        if attach_to.is_none() && matches!(count, QuantityExpr::Fixed { value: 1 }) {
            *count = qty.clone();
            return true;
        }
    }
    false
}

#[cfg(test)]
fn try_parse_put_zone_change(lower: &str, text: &str) -> Option<Effect> {
    try_parse_put_zone_change_parts(lower, text).map(|(effect, _)| effect)
}

fn try_parse_put_zone_change_parts(
    lower: &str,
    text: &str,
) -> Option<(Effect, Option<MultiTargetSpec>)> {
    let tp = TextPair::new(text, lower);
    let (_, after_put_tp) = tp.split_at(4);

    for (needle, destination) in [
        (" onto the battlefield", Zone::Battlefield),
        (" into your hand", Zone::Hand),
        (" into their hand", Zone::Hand),
        (" into its owner's hand", Zone::Hand),
        (" into their owner's hand", Zone::Hand),
        (" into your graveyard", Zone::Graveyard),
        (" into its owner's graveyard", Zone::Graveyard),
        (" into their owner's graveyard", Zone::Graveyard),
        // CR 701.14: "into that player's graveyard" — "that player" refers back to the owner
        // named earlier in the clause (e.g. Eldrazi Processors: "a card an opponent owns").
        (" into that player's graveyard", Zone::Graveyard),
        (" into their graveyard", Zone::Graveyard),
        (" on the bottom of", Zone::Library),
        (" on top of", Zone::Library),
    ] {
        if let Some((before, after)) = after_put_tp.split_around(needle) {
            let target_text = before.original.trim();
            if target_text.is_empty() {
                return None;
            }
            // CR 701.20e + CR 608.2c: "from among those cards" / "from among
            // them" / "from among the milled cards" is a prior-selection
            // anaphor — the card is chosen from the set produced by an earlier
            // Dig/Mill/Reveal in the same instruction, not from any zone. When
            // it appears, the type filter is everything BEFORE the anaphor
            // ("a creature card with mana value X or less"); the anaphor and
            // the milled/those-cards noun must NOT be fed to `parse_target`.
            // The selection set is bound at resolution via the sentinel
            // `TrackedSetId(0)`.
            let from_among_anaphor = ["from among those cards", "from among them"]
                .iter()
                .chain(["from among the milled cards"].iter())
                .find_map(|phrase| {
                    take_until::<_, _, OracleError<'_>>(*phrase)
                        .parse(before.lower)
                        .ok()
                        .map(|(_, prefix): (&str, &str)| prefix.len())
                });
            let target_text = match from_among_anaphor {
                Some(prefix_len) => before.original[..prefix_len].trim(),
                None => target_text,
            };
            let (target_text, choice_count) = strip_put_resolution_choice_quantifier(target_text);
            // CR 202.3: An interior "with total mana value <X|N> or less" phrase
            // (Ancient Brass Dragon: "creature cards with total mana value X or
            // less from graveyards") sits between the type phrase and the zone
            // suffix, breaking the contiguous "<type> cards from graveyards"
            // parse that `parse_zone_suffix_nom` needs. Strip it here so the
            // remaining text is contiguous; the cap itself is recovered as a
            // `TargetSelectionConstraint::TotalManaValue` on the lowering path
            // (see `parse_total_mana_value_target_constraint` in `lower.rs`).
            let stripped_mv = strip_total_mana_value_target_phrase(target_text);
            let target_text: &str = stripped_mv.as_deref().unwrap_or(target_text);
            // CR 400.7 + CR 110.2a: Mass put-onto-battlefield text moves every
            // matching object from the origin zone. Strip the mass quantifier
            // before target parsing so the filter mirrors the `return all`
            // dispatcher instead of relying on parse_target to re-strip it.
            let (is_mass, target_text) = if let Some((_, rest)) =
                nom_on_lower(target_text, &target_text.to_ascii_lowercase(), |input| {
                    value((), alt((tag("all "), tag("each ")))).parse(input)
                }) {
                (true, rest)
            } else {
                (false, target_text)
            };
            let up_to = parse_up_to_one_target_prefix(before.lower) || choice_count.is_some();
            let (target, _) = parse_target(target_text);
            // CR 202.3 + CR 107.3i: A trailing "where X is <expression>"
            // defining clause (Birthing Ritual: "...with mana value X or less
            // ..., where X is 1 plus the sacrificed creature's mana value")
            // binds the literal X in the type filter's `Cmc` bound. Without
            // this substitution the bound stays `QuantityRef::Variable("X")`
            // with no defining expression and the filter is effectively
            // unbounded. The expression is parsed by the shared
            // `parse_where_x_quantity_expression` building block.
            let where_x_expression = strip_trailing_where_x(after_put_tp).1;
            let target = apply_where_x_to_filter(target, where_x_expression.as_deref());
            // CR 608.2c: Restrict the target to objects affected by the
            // preceding effect when a "this way" result phrase appears in the
            // target text. The relevant resolvers publish `state.tracked_object_sets`
            // with the affected objects; `TargetFilter::TrackedSetFiltered`
            // reads that set and intersects it with the original type filter.
            // `TrackedSetId(0)` is a sentinel resolved to the most recent
            // tracked set (via the existing `bind_tracked_set_to_effect` pass
            // for delayed triggers; direct sub_abilities observe the latest
            // set via `filter_inner`'s lookup). Used by Zimone's Experiment:
            // "Put all land cards revealed this way onto the battlefield
            // tapped and put all creature cards revealed this way into your
            // hand", and Mind Roots: "Put up to one land card discarded this
            // way onto the battlefield tapped under your control."
            let target = if from_among_anaphor.is_some()
                || [
                    "revealed this way",
                    "discarded this way",
                    "milled this way",
                    "exiled this way",
                    "sacrificed this way",
                    "destroyed this way",
                ]
                .iter()
                .any(|phrase| scan_contains_phrase(before.lower, phrase))
            {
                TargetFilter::TrackedSetFiltered {
                    id: crate::types::identifiers::TrackedSetId(0),
                    filter: Box::new(target),
                }
            } else {
                target
            };
            // CR 110.2a: "under your control" overrides the entering object's controller.
            let enters_under = scan_contains_phrase(after_put_tp.lower, "under your control")
                .then_some(ControllerRef::You);
            // CR 122.1 + CR 614.1c: Detect a trailing "with [N] [type] counter(s)
            // on it" clause and stamp it onto `enter_with_counters`. This covers
            // The Darkness Crystal's "with two additional +1/+1 counters on it"
            // and the broader class of put-onto-battlefield-with-counters
            // activated abilities. The combinator scans the post-destination
            // remainder so the suffix is consumed only when present.
            let enter_with_counters = parse_with_counters_suffix(after_put_tp.lower);
            // CR 508.4 + CR 614.1: The post-destination tail may carry inline
            // entry-qualifier clauses ("tapped" / "tapped and attacking
            // [<player_phrase>]") that propagate flags onto the produced
            // `Effect::ChangeZone`. The combinator inspects the immediate tail
            // (the slice starting right after the destination needle) so the
            // single-sentence Kaalia/Ilharg pattern — where the qualifiers
            // trail the destination in the same clause — sets both flags in
            // one pass. The separate-sentence form ("It enters tapped and
            // attacking") is handled by the `EntersTappedAttacking`
            // continuation patcher in `oracle_effect/sequence.rs`.
            let (enter_tapped, enters_attacking) = if destination == Zone::Battlefield {
                parse_battlefield_entry_qualifiers(after.lower)
            } else {
                (false, false)
            };
            let enter_transformed = destination == Zone::Battlefield
                && parse_battlefield_transformed_qualifier(after.lower);
            if is_mass && enter_with_counters.is_empty() {
                // No printed mass put-onto-battlefield card currently combines
                // `all`/`each` with transformed, attacking, or up-to qualifiers;
                // those remain on the single-object ChangeZone path until a
                // real card needs corresponding ChangeZoneAll fields.
                return Some((
                    Effect::ChangeZoneAll {
                        origin: infer_origin_zone(after_put_tp.lower),
                        destination,
                        target,
                        enters_under,
                        enter_tapped: crate::types::zones::EtbTapState::from_legacy_bool(
                            enter_tapped,
                        ),
                        face_down_profile: None,
                    },
                    choice_count,
                ));
            }
            return Some((
                Effect::ChangeZone {
                    origin: infer_origin_zone(after_put_tp.lower),
                    destination,
                    target,
                    owner_library: false,
                    enter_transformed,
                    enters_under,
                    enter_tapped: crate::types::zones::EtbTapState::from_legacy_bool(enter_tapped),
                    enters_attacking,
                    up_to,
                    enter_with_counters,
                    face_down_profile: None,
                },
                choice_count,
            ));
        }
    }

    None
}

fn strip_put_resolution_choice_quantifier(target_text: &str) -> (&str, Option<MultiTargetSpec>) {
    let lower = target_text.to_ascii_lowercase();
    let target_starts_with_target = |text: &str| {
        alt((
            tag::<_, _, OracleError<'_>>("target "),
            tag("other target "),
            tag("another target "),
        ))
        .parse(text.trim_start())
        .is_ok()
    };

    if let Ok((rest, _)) = tag::<_, _, OracleError<'_>>("any number of ").parse(lower.as_str()) {
        let consumed = lower.len() - rest.len();
        let stripped = target_text[consumed..].trim_start();
        // CR 601.2c + CR 115.1: "any number of target [type] …" is a
        // variable-count *targeted* selection. Strip only the "any number of "
        // quantifier so `parse_target` still sees the "target …" phrase (and
        // builds the proper `Typed` filter + zone suffix), while returning the
        // unlimited multi-target spec. The non-target form ("any number of
        // [type] cards") strips the same prefix but feeds a bare type phrase.
        return (stripped, Some(MultiTargetSpec::unlimited(0)));
    }

    if let Ok((after_up_to, _)) = tag::<_, _, OracleError<'_>>("up to ").parse(lower.as_str()) {
        if let Ok((remainder, max)) = parse_multi_target_count_expr(after_up_to) {
            let consumed = lower.len() - remainder.len();
            let stripped = target_text[consumed..].trim_start();
            if !target_starts_with_target(&stripped.to_ascii_lowercase()) {
                return (stripped, Some(MultiTargetSpec::up_to(max)));
            }
        }
    }

    (target_text, None)
}

/// CR 202.3: Strip an interior "with total mana value <N|X> or less" phrase from
/// a put-clause target text so the type phrase and the zone suffix remain
/// contiguous for `parse_target` / `parse_zone_suffix_nom`. Returns the
/// reconstructed text (phrase removed, surrounding whitespace normalized to a
/// single space) when the phrase is found with an "or less" (LE) comparator;
/// `None` otherwise (leaving `target_text` borrowed unchanged).
///
/// Only the LE comparator is stripped here: `validate_target_constraints` runs
/// during target-set enumeration where prefix pruning of an over-cap partial
/// set is only monotonic-safe for LE (mana value is non-negative), so the
/// target-side parser never emits GE (no GE target card exists). The matched
/// comparator value is discarded — the cap is recovered as a typed
/// `TargetSelectionConstraint::TotalManaValue` on the lowering path.
fn strip_total_mana_value_target_phrase(target_text: &str) -> Option<String> {
    let lower = target_text.to_ascii_lowercase();
    let (before, (comparator, _value), rest) =
        nom_primitives::scan_preceded(lower.as_str(), |input| {
            preceded(
                tag::<_, _, OracleError<'_>>("with total mana value "),
                parse_total_mana_value_comparator,
            )
            .parse(input)
        })?;
    if comparator != Comparator::LE {
        return None;
    }
    // Slice the original-case text using the byte offsets from the (length-
    // preserving, ASCII) lowercase scan: everything before the phrase plus
    // everything after it.
    let before_len = before.len();
    let after_start = lower.len() - rest.len();
    let before_orig = target_text[..before_len].trim_end();
    let after_orig = target_text[after_start..].trim_start();
    Some(format!("{before_orig} {after_orig}").trim().to_string())
}

fn parse_up_to_one_target_prefix(input: &str) -> bool {
    let trimmed = input.trim_start();
    tag::<_, _, OracleError<'_>>("up to one ")
        .parse(trimmed)
        .is_ok()
}

fn parse_battlefield_transformed_qualifier(tail_lower: &str) -> bool {
    fn transformed_boundary(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
        alt((
            value((), nom::combinator::eof),
            value((), tag(" ")),
            value((), tag(",")),
            value((), tag(".")),
        ))
        .parse(input)
    }

    fn transformed_clause(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
        preceded(tag(" transformed"), transformed_boundary).parse(input)
    }

    (0..tail_lower.len()).any(|pos| {
        tail_lower.as_bytes().get(pos) == Some(&b' ')
            && transformed_clause(&tail_lower[pos..]).is_ok()
    })
}

/// CR 508.4 + CR 614.1: Detect inline entry-qualifier clauses ("tapped" or
/// "tapped and attacking [<player_phrase>]") immediately following a "put X
/// onto the battlefield" destination needle. Returns
/// `(enter_tapped, enters_attacking)`.
///
/// The single-sentence "tapped and attacking" pattern is the Kaalia / Ilharg
/// class: 25+ commander/legacy cards whose Oracle text reads
/// "...onto the battlefield tapped and attacking[ that opponent | that player |
/// defending player or a planeswalker they control | during your declare
/// attackers step | , where X is ... | and the rest ...]." Without this
/// inline-tail patcher, `enters_attacking` was silently dropped and the
/// summoned creature entered tapped but not attacking (CR 508.4 violation).
///
/// The bare "tapped" branch preserves the prior behavior for the
/// "onto the battlefield tapped" tutor / reanimation class (Coming Attraction,
/// Dance of the Dead, Hunting Wilds, etc.).
///
/// `tail_lower` is the lowercase slice starting *immediately after* the
/// destination needle (e.g. `" tapped and attacking that opponent."`); the
/// leading space is part of the needle's word-boundary contract.
fn parse_battlefield_entry_qualifiers(tail_lower: &str) -> (bool, bool) {
    // Word-boundary anchor for the qualifier clause: the qualifier must end at
    // a real boundary so " tapped" doesn't accidentally consume " tappedly".
    // EOF, whitespace, or sentence punctuation all qualify.
    fn qualifier_boundary(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
        alt((
            value((), nom::combinator::eof),
            value((), tag(" ")),
            value((), tag(",")),
            value((), tag(".")),
        ))
        .parse(input)
    }

    // Combinator for the most-specific "tapped and attacking" form. The
    // boundary check absorbs the trailing player phrase ("that opponent",
    // "defending player ...") or sentence terminator without consuming it.
    fn tapped_and_attacking_clause(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
        preceded(tag(" tapped and attacking"), qualifier_boundary).parse(input)
    }

    // Combinator for the bare "tapped" form (no "and attacking"). Preserves
    // existing tutor / reanimation behavior (Coming Attraction, Dance of the
    // Dead, Hunting Wilds, etc.).
    fn tapped_clause(input: &str) -> nom::IResult<&str, (), OracleError<'_>> {
        preceded(tag(" tapped"), qualifier_boundary).parse(input)
    }

    // CR 508.4 + CR 614.1: Scan every word-boundary position in the tail for
    // the qualifier clause. This handles word-ordering variants where
    // "under your control" or other phrasing appears between the destination
    // and the qualifier (Chorale of the Void, The Grim Captain, Zara
    // Renegade Recruiter: "...onto the battlefield under your control tapped
    // and attacking..."). The scanner mirrors `oracle_effect/token.rs:195`
    // which scans byte positions for the first leading-space match. Try the
    // more-specific "tapped and attacking" combinator at every boundary
    // first; if no boundary matches, fall back to the bare "tapped" form.
    let scan_at_boundaries = |clause: fn(&str) -> nom::IResult<&str, (), OracleError<'_>>| {
        (0..tail_lower.len()).any(|pos| {
            tail_lower.as_bytes().get(pos) == Some(&b' ') && clause(&tail_lower[pos..]).is_ok()
        })
    };
    if scan_at_boundaries(tapped_and_attacking_clause) {
        return (true, true);
    }
    if scan_at_boundaries(tapped_clause) {
        return (true, false);
    }
    (false, false)
}

/// CR 118.12: Wrap a parsed counter unless-cost into the unified
/// `UnlessPayModifier`. The payer is `TargetFilter::ParentTargetController`,
/// which at runtime resolves to "controller of the spell/ability targeted by
/// this counter effect" — matching the bespoke stack-search the pre-fold
/// `effects/counter.rs` did.
pub(super) fn counter_unless_pay_modifier(cost: AbilityCost) -> UnlessPayModifier {
    UnlessPayModifier {
        cost,
        payer: TargetFilter::ParentTargetController,
    }
}

/// CR 118.12: Parse "unless its controller pays {X}" from counter/trigger text.
/// Returns `AbilityCost::Mana` for static costs ({3}, {1}{U}),
/// `AbilityCost::ManaDynamic` for "pays {X}, where X is this creature's power",
/// and `AbilityCost::PayEnergy` for "{E}{E}" patterns.
pub(super) fn parse_unless_payment(lower: &str) -> Option<AbilityCost> {
    // Find "unless" followed by a subject and "pays {cost}"
    let after_unless = strip_after(lower, "unless ")?;
    // Skip the subject ("its controller", "that player", "he or she", etc.)
    let cost_str = strip_after(after_unless, "pays ")?;
    // CR 107.14 + CR 202.3: dynamic energy unless-cost — checked before the
    // brace-run truncation below, which collapses "an amount of {e} …" to "an".
    if let Some(amount) = parse_dynamic_energy_unless_cost(cost_str) {
        return Some(AbilityCost::PayEnergy { amount });
    }
    // Extract the mana cost (brace-delimited symbols)
    let cost_end = cost_str
        .find(|c: char| c != '{' && c != '}' && !c.is_alphanumeric())
        .unwrap_or(cost_str.len());
    let cost_text = cost_str[..cost_end].trim();
    if cost_text.is_empty() || !cost_text.contains('{') {
        return None;
    }
    if let Some((amount, rest)) = parse_fixed_energy_unless_cost(cost_text) {
        if rest.trim().is_empty() {
            return Some(AbilityCost::PayEnergy {
                amount: QuantityExpr::Fixed {
                    value: amount as i32,
                },
            });
        }
    }
    // Check for dynamic {X} with "where X is" clause
    if cost_text == "{X}" || cost_text == "{x}" {
        let after_cost = &cost_str[cost_end..];
        if let Some(quantity) = parse_where_x_is(after_cost) {
            return Some(AbilityCost::ManaDynamic { quantity });
        }
        // CR 107.3a + CR 118.12: bare {X} unless-cost references the announced X
        // of the spell carrying this counter.
        return Some(AbilityCost::ManaDynamic {
            quantity: QuantityExpr::Ref {
                qty: QuantityRef::Variable {
                    name: "X".to_string(),
                },
            },
        });
    }
    let cost = parse_mtgjson_mana_cost(cost_text);
    if let Some(unless_cost) = parse_unless_for_each_payment(&cost_str[cost_end..], &cost) {
        return Some(unless_cost);
    }
    if cost == ManaCost::NoCost || cost == ManaCost::zero() {
        return None;
    }
    Some(AbilityCost::Mana { cost })
}

/// CR 118.12a: Tail of "deal N damage to them" unless-cost alternatives.
fn parse_deal_damage_to_them_tail(input: &str) -> Option<()> {
    all_consuming(terminated(
        (
            tag::<_, _, OracleError<'_>>("damage to "),
            tag::<_, _, OracleError<'_>>("them"),
        ),
        opt(tag::<_, _, OracleError<'_>>(".")),
    ))
    .parse(input)
    .ok()
    .map(|_| ())
}

/// CR 118.12a: "unless that creature's controller has [~] deal N damage to them"
/// (Blazing Salvo) — the controller may take the damage instead of the creature.
fn parse_unless_have_deal_damage_cost(after_unless: &str) -> Option<AbilityCost> {
    let (rest, _) = tag::<_, _, OracleError<'_>>("that creature's controller has ")
        .parse(after_unless)
        .ok()?;
    let (rest, _) = take_until::<_, _, OracleError<'_>>(" deal ")
        .parse(rest)
        .ok()?;
    // `take_until` leaves the matched delimiter on the input (" deal N ...").
    let (rest, _) = tag::<_, _, OracleError<'_>>(" deal ").parse(rest).ok()?;
    let (amount, tail) = super::oracle_util::parse_count_expr(rest)?;
    parse_deal_damage_to_them_tail(tail)?;
    Some(AbilityCost::EffectCost {
        effect: Box::new(Effect::DealDamage {
            amount,
            target: TargetFilter::Player,
            damage_source: None,
        }),
    })
}

fn extract_resolution_unless_pay_modifier(
    text: &str,
    player_scope: Option<&PlayerFilter>,
) -> (String, Option<UnlessPayModifier>) {
    let lower = text.to_lowercase();
    if tag::<_, _, OracleError<'_>>("counter ")
        .parse(lower.trim_start())
        .is_ok()
    {
        return (text.to_string(), None);
    }

    // CR 118.12a: "[Effect] unless a player has [~] deal N to them" (Barbarian
    // Bully). Checked before the generic "unless " scan so the player-have-deal
    // shape is not misclassified as a mana-payment unless.
    if let Some((before_unless, _, after_unless_lower)) =
        nom_primitives::scan_preceded(&lower, |i| tag("unless a player has ").parse(i))
    {
        if let Some(cost) = parse_unless_player_have_deal_damage_cost(after_unless_lower) {
            let cleaned = text[..before_unless.trim_end().len()].trim().to_string();
            return (
                cleaned,
                Some(UnlessPayModifier {
                    cost,
                    payer: TargetFilter::AllPlayers,
                }),
            );
        }
    }

    // CR 118.12a: "[Effect] unless they X [or Y]" — the targeted player is
    // the payer (`TargetFilter::Player`), the alternative payment is one
    // (or one of several) non-mana action(s). Tergrid's Lantern is the
    // canonical case: "Target player loses 3 life unless they sacrifice a
    // nonland permanent of their choice or discard a card." Routes through
    // the trigger-side `parse_unless_they_alt_cost_chain` building block
    // (single authority for non-mana unless-cost shapes — see
    // `crate::parser::oracle_trigger`).
    if let Some((before_unless, _, after_unless_lower)) =
        nom_primitives::scan_preceded(&lower, |i| tag::<_, _, OracleError<'_>>("unless ").parse(i))
    {
        if let Some(cost) = parse_unless_have_deal_damage_cost(after_unless_lower) {
            let cleaned = text[..before_unless.trim_end().len()].trim().to_string();
            return (
                cleaned,
                Some(UnlessPayModifier {
                    cost,
                    payer: TargetFilter::ParentTargetController,
                }),
            );
        }
        if let Some(cost) =
            crate::parser::oracle_trigger::parse_unless_they_alt_cost_chain(after_unless_lower)
        {
            // Strip the entire " unless ..." tail from the cleaned effect
            // text. `before_unless` is the lowercase prefix slice ending
            // just before " unless "; trim trailing whitespace there to
            // produce the cleaned effect.
            let cleaned = text[..before_unless.trim_end().len()].trim().to_string();
            // CR 118.12a + CR 608.2f: select the payer for "they X". A
            // permanent's controller in the pre-"unless" text (Fade Away)
            // takes precedence. Otherwise, when this chunk carries a
            // `player_scope` ("each opponent/each player ... unless they X"),
            // the payer is the per-iteration scoped player (`ScopedPlayer`,
            // bound by the fan-out) rather than a chosen player target.
            // Non-scoped punishers (Tergrid's Lantern) keep `Player`.
            let payer = if nom_primitives::scan_contains(before_unless, "controller") {
                TargetFilter::ParentTargetController
            } else if player_scope.is_some() {
                TargetFilter::ScopedPlayer
            } else {
                TargetFilter::Player
            };
            return (cleaned, Some(UnlessPayModifier { cost, payer }));
        }
    }

    let Some((before, payer, cost_text)) =
        nom_primitives::scan_preceded(&lower, parse_resolution_unless_payer)
    else {
        return (text.to_string(), None);
    };

    let Some(cost) = parse_resolution_unless_cost(cost_text) else {
        return (text.to_string(), None);
    };

    // CR 118.12a + CR 608.2f: "unless they pay ..." surfaces `they` as
    // `TargetFilter::Player` provisionally. When the effect text before "unless"
    // taxes a permanent's controller ("its controller", "that land's controller"
    // — Fade Away, Stench of Evil) rather than a player target (Flay), `they`
    // resolves to that controller. Otherwise, when this chunk carries a
    // `player_scope` ("each opponent/each player ... unless they pay"), the payer
    // is the per-iteration scoped player (`ScopedPlayer`) rather than a chosen
    // player target. Non-scoped punishers keep `Player`. `Player` is unique to
    // the "they pay" arm, so these rewrites are unambiguous.
    let payer = if payer == TargetFilter::Player {
        if nom_primitives::scan_contains(before, "controller") {
            TargetFilter::ParentTargetController
        } else if player_scope.is_some() {
            TargetFilter::ScopedPlayer
        } else {
            TargetFilter::Player
        }
    } else {
        payer
    };

    let cleaned = text[..before.trim_end().len()].trim().to_string();
    (cleaned, Some(UnlessPayModifier { cost, payer }))
}

fn parse_resolution_unless_payer(input: &str) -> OracleResult<'_, TargetFilter> {
    preceded(
        tag("unless "),
        alt((
            value(
                TargetFilter::ParentTargetController,
                (
                    alt((
                        // CR 115.1 + CR 118.12: "any target" effects (Rhystic
                        // Lightning) restate the payer as a disjunctive
                        // "[permanent's controller] or [that player]" — both
                        // arms collapse to `ParentTargetController` because
                        // that filter already unifies object-target controller
                        // and player-target self-reference.
                        tag("that permanent's controller or that player "),
                        tag("its controller "),
                        tag("that artifact's controller "),
                        tag("that creature's controller "),
                        tag("that permanent's controller "),
                        tag("that spell's controller "),
                    )),
                    tag("pays "),
                ),
            ),
            value(TargetFilter::Controller, tag("you pay ")),
            // CR 118.12a: "unless they pay ..." — `they` is anaphoric to the
            // effect's player subject. Emitted as `Player` provisionally;
            // `extract_resolution_unless_pay_modifier` resolves it to
            // `ParentTargetController` when the effect taxes a permanent's
            // controller (Stench of Evil, Fade Away) rather than a player
            // target (Flay).
            value(TargetFilter::Player, tag("they pay ")),
            // CR 118.12a: "unless any player pays ..." — every player is polled
            // in APNAP order; the first to pay prevents the effect (Cleansing,
            // the Rhystic cycle, Soul Strings).
            value(TargetFilter::AllPlayers, tag("any player pays ")),
        )),
    )
    .parse(input)
}

fn parse_resolution_unless_cost(cost_text: &str) -> Option<AbilityCost> {
    // CR 107.14 + CR 202.3: dynamic energy unless-cost ("an amount of {e}
    // equal to <quantity>"). `cost_text` arrives untruncated here, so this
    // check precedes the fixed-energy brace-run path.
    if let Some(amount) = parse_dynamic_energy_unless_cost(cost_text) {
        return Some(AbilityCost::PayEnergy { amount });
    }
    if let Some((amount, rest)) = parse_fixed_energy_unless_cost(cost_text.trim_start()) {
        if rest.trim().is_empty() {
            return Some(AbilityCost::PayEnergy {
                amount: QuantityExpr::Fixed {
                    value: amount as i32,
                },
            });
        }
    }

    // CR 107.3a: extract_resolution_unless_pay_modifier lowercased the text; the
    // case-sensitive X mana symbol no longer matches, so handle bare {x}
    // explicitly. The announced X of the carrying effect drives the cost.
    if tag::<_, _, OracleError<'_>>("{x}")
        .parse(cost_text.trim_start())
        .is_ok()
    {
        return Some(AbilityCost::ManaDynamic {
            quantity: QuantityExpr::Ref {
                qty: QuantityRef::Variable {
                    name: "X".to_string(),
                },
            },
        });
    }

    if let Ok((rest, cost)) = nom_primitives::parse_mana_cost(cost_text.trim_start()) {
        if let Some(unless_cost) = parse_unless_for_each_payment(rest, &cost) {
            return Some(unless_cost);
        }
        if cost != ManaCost::NoCost && cost != ManaCost::zero() {
            return Some(AbilityCost::Mana { cost });
        }
    }

    let (amount, after_amount) = parse_number(cost_text.trim_start())?;
    if tag::<_, _, OracleError<'_>>("life")
        .parse(after_amount.trim_start())
        .is_ok()
    {
        return Some(AbilityCost::PayLife {
            amount: QuantityExpr::Fixed {
                value: amount as i32,
            },
        });
    }

    None
}

pub(crate) fn parse_fixed_energy_unless_cost(input: &str) -> Option<(u32, &str)> {
    let (rest, symbols) = many1(tag::<_, _, OracleError<'_>>("{e}"))
        .parse(input)
        .ok()?;
    Some((u32::try_from(symbols.len()).ok()?, rest))
}

/// CR 107.14 + CR 202.3: Parse "an amount of {e} equal to <quantity>" → a
/// dynamic energy amount. Shared by the trigger-side unless-cost detector
/// (`extract_unless_pay_modifier`), the resolution-side detectors
/// (`parse_resolution_unless_cost` / `parse_unless_payment`), and the
/// imperative cost-resource path. Single authority for this grammar.
pub(crate) fn parse_dynamic_energy_unless_cost(input: &str) -> Option<QuantityExpr> {
    let (rest, _) = tag::<_, _, OracleError<'_>>("an amount of {e} equal to ")
        .parse(input.trim_start())
        .ok()?;
    let qty_text = rest.trim().trim_end_matches('.');
    let qty = crate::parser::oracle_quantity::parse_quantity_ref(qty_text)?;
    Some(QuantityExpr::Ref { qty })
}

pub(crate) fn parse_unless_for_each_payment(
    after_cost: &str,
    cost: &ManaCost,
) -> Option<AbilityCost> {
    let ManaCost::Cost { shards, generic } = cost else {
        return None;
    };
    if !shards.is_empty() || *generic == 0 {
        return None;
    }

    let (_, clause) = preceded(
        tag::<_, _, OracleError<'_>>(" for each "),
        nom::combinator::rest,
    )
    .parse(after_cost)
    .ok()?;
    let qty = parse_for_each_clause(clause.trim())?;
    let quantity = if *generic == 1 {
        QuantityExpr::Ref { qty }
    } else {
        QuantityExpr::Multiply {
            factor: i32::try_from(*generic).ok()?,
            inner: Box::new(QuantityExpr::Ref { qty }),
        }
    };
    Some(AbilityCost::ManaDynamic { quantity })
}

/// Parse "where X is this creature's power" and similar dynamic quantity clauses.
fn parse_where_x_is(text: &str) -> Option<QuantityExpr> {
    let trimmed = text.trim().trim_start_matches(',').trim();
    let (rest, _) = tag::<_, _, OracleError<'_>>("where x is ")
        .parse(trimmed)
        .ok()?;
    let qty_text = rest.trim_end_matches('.').trim();
    if let Some(qty) = crate::parser::oracle_quantity::parse_quantity_ref(qty_text) {
        return Some(QuantityExpr::Ref { qty });
    }
    if scan_contains_phrase(rest, "power") {
        Some(QuantityExpr::Ref {
            qty: QuantityRef::Power {
                scope: crate::types::ability::ObjectScope::Source,
            },
        })
    } else if scan_contains_phrase(rest, "toughness") {
        Some(QuantityExpr::Ref {
            qty: QuantityRef::Toughness {
                scope: crate::types::ability::ObjectScope::Source,
            },
        })
    } else {
        None
    }
}

fn infer_origin_zone(lower: &str) -> Option<Zone> {
    // CR 400.7: An object that moves from one zone to another becomes a new
    // object — the "from" prepositional phrase identifies that origin zone.
    // Adjective-qualified indefinite forms ("a single graveyard", "a random
    // graveyard") share the same semantic origin as bare "a graveyard"; the
    // qualifier constrains *which* instance, not which zone.
    if contains_possessive(lower, "from", "graveyard")
        || scan_contains_phrase(lower, "from a graveyard")
        || scan_contains_phrase(lower, "from a single graveyard")
        || scan_contains_phrase(lower, "from a random graveyard")
        || scan_contains_phrase(lower, "from all graveyards")
        || scan_contains_phrase(lower, "from each graveyard")
    {
        Some(Zone::Graveyard)
    } else if scan_contains_phrase(lower, "from exile")
        // CR 406.6: "[card] exiled with [source]" identifies the card via the
        // exile-link from a prior linked exile ability — the implicit origin
        // is the exile zone. Used by reanimation/return effects on cards that
        // previously exiled their target (Darkness Crystal, Mimeoplasm, etc.).
        || scan_contains_phrase(lower, "exiled with")
    {
        Some(Zone::Exile)
    } else if contains_possessive(lower, "from", "hand") {
        Some(Zone::Hand)
    } else if scan_contains_phrase(lower, "from the top of your library")
        || contains_possessive(lower, "from", "library")
    {
        Some(Zone::Library)
    } else if scan_contains_phrase(lower, "graveyard") && !scan_contains_phrase(lower, "from") {
        // CR 404.1: Possessive graveyard references without "from" — e.g.,
        // "exile each opponent's graveyard", "exile target player's graveyard"
        Some(Zone::Graveyard)
    } else {
        None
    }
}

fn add_inferred_origin_constraints_to_target(
    target: TargetFilter,
    origin: Option<Zone>,
    lower: &str,
) -> TargetFilter {
    let Some(zone) = origin else {
        return target;
    };
    if target.extract_in_zone().is_some() && origin_is_your_zone(lower, zone) {
        return add_filter_props(
            target,
            &[FilterProp::Owned {
                controller: ControllerRef::You,
            }],
        );
    }
    if target.extract_in_zone().is_some() {
        return target;
    }
    let mut props = vec![FilterProp::InZone { zone }];
    if origin_is_your_zone(lower, zone) {
        props.push(FilterProp::Owned {
            controller: ControllerRef::You,
        });
    }
    add_filter_props(target, &props)
}

fn origin_is_your_zone(lower: &str, zone: Zone) -> bool {
    match zone {
        Zone::Graveyard => scan_contains_phrase(lower, "from your graveyard"),
        Zone::Hand => scan_contains_phrase(lower, "from your hand"),
        Zone::Library => {
            scan_contains_phrase(lower, "from your library")
                || scan_contains_phrase(lower, "from the top of your library")
        }
        Zone::Exile => scan_contains_phrase(lower, "from your exile"),
        _ => false,
    }
}

fn add_filter_props(target: TargetFilter, props: &[FilterProp]) -> TargetFilter {
    match target {
        TargetFilter::Typed(mut typed) => {
            for prop in props {
                if !typed.properties.contains(prop) {
                    typed.properties.push(prop.clone());
                }
            }
            TargetFilter::Typed(typed)
        }
        TargetFilter::Or { filters } => TargetFilter::Or {
            filters: filters
                .into_iter()
                .map(|filter| add_filter_props(filter, props))
                .collect(),
        },
        TargetFilter::And { mut filters } => {
            filters.push(TargetFilter::Typed(
                TypedFilter::default().properties(props.to_vec()),
            ));
            TargetFilter::And { filters }
        }
        other => TargetFilter::And {
            filters: vec![
                other,
                TargetFilter::Typed(TypedFilter::default().properties(props.to_vec())),
            ],
        },
    }
}

pub(crate) fn normalize_verb_token(token: &str) -> String {
    let token = token.trim_matches(|c: char| !c.is_alphabetic());
    match token {
        "does" => "do".to_string(),
        "has" => "have".to_string(),
        "is" => "be".to_string(),
        // English consonant-y → ies plural (copy→copies, scry→scries, try→tries).
        // Vowel-y verbs (play→plays) take regular -s and fall through. Result is
        // checked against `PREDICATE_VERBS`; false positives like "series→sery"
        // are silent (no allowlist hit, no behavior change).
        // allow-noncombinator: verb-morphology suffix check on pre-tokenized word (PATTERNS.md §9)
        _ if token.ends_with("ies") && token.len() > 3 => {
            format!("{}y", &token[..token.len() - 3])
        }
        // English orthographic rule (parser-internal, no game-rule annotation):
        // verbs ending in /ʃ/, /tʃ/, /s/, /z/, /ks/ take "-es" instead of "-s"
        // for third-person singular (search→searches, wash→washes,
        // watch→watches, fix→fixes, buzz→buzzes). Strip "es" only when the
        // resulting stem is a known predicate verb — without this validator
        // the rule over-strips real `-eze`/`-eeze` words like "freezes",
        // "breezes", "sneezes" into nonsense stems ("freez", "breez", "sneez")
        // that no downstream lookup recognizes. The PREDICATE_VERBS guard
        // ensures unknown words pass through unchanged ("parser must not
        // swallow"); only registered verbs are de-conjugated.
        // allow-noncombinator: verb-morphology suffix check on pre-tokenized word
        _ if token.ends_with("es") && token.len() > 2 && {
            let stem = &token[..token.len() - 2];
            crate::parser::oracle_effect::subject::PREDICATE_VERBS.contains(&stem)
        } =>
        {
            token[..token.len() - 2].to_string()
        }
        // allow-noncombinator: verb-morphology suffix check on pre-tokenized word
        _ if token.ends_with('s') && !token.ends_with("ss") => token[..token.len() - 1].to_string(),
        _ => token.to_string(),
    }
}

fn constrain_filter_to_stack(filter: TargetFilter) -> TargetFilter {
    match filter {
        TargetFilter::Typed(TypedFilter {
            type_filters,
            controller,
            mut properties,
        }) => {
            if !properties
                .iter()
                .any(|p| matches!(p, FilterProp::InZone { zone: Zone::Stack }))
            {
                properties.push(FilterProp::InZone { zone: Zone::Stack });
            }
            TargetFilter::Typed(TypedFilter {
                type_filters,
                controller,
                properties,
            })
        }
        TargetFilter::Or { filters } => TargetFilter::Or {
            filters: filters.into_iter().map(constrain_filter_to_stack).collect(),
        },
        TargetFilter::And { filters } => TargetFilter::And {
            filters: filters.into_iter().map(constrain_filter_to_stack).collect(),
        },
        other => other,
    }
}

/// CR 115.7: Parse "change the/a target of [spell]" and "you may choose new targets for [spell]".
///
/// Covers Oracle text patterns:
/// - "change the target of [spell phrase]" → scope: `Single` (CR 115.7a)
/// - "change a target of [spell phrase]" → scope: `Single` (CR 115.7b — Spellskite, Phyresis)
/// - "you may choose new targets for [spell phrase]" → scope: `All` (CR 115.7d)
///
/// An optional trailing "to [target phrase]" sets `forced_to`.
fn try_parse_change_targets(lower: &str) -> Option<Effect> {
    type E<'a> = OracleError<'a>;

    let (rest, scope) = alt((
        value(
            RetargetScope::Single,
            tag::<_, _, E>("change the target of "),
        ),
        value(RetargetScope::Single, tag("change a target of ")),
        value(RetargetScope::All, tag("you may choose new targets for ")),
        // Peeled form when `strip_optional_effect_prefix` correctly declined to
        // strip a specialized "you may choose new targets" retarget clause.
        value(RetargetScope::All, tag("choose new targets for ")),
    ))
    .parse(lower)
    .ok()?;

    // Split off trailing "to [target]" — forced retarget destination.
    let (spell_phrase, forced_to) =
        if let Ok((_, (before, after))) = nom_primitives::split_once_on(rest, " to ") {
            let (filter, _) = parse_target(after);
            (before, Some(filter))
        } else {
            (rest, None)
        };

    // CR 115.7: Parse the spell phrase to extract a stack-entry filter.
    // Strip "with a single target" qualifier before parsing the type.
    let has_single_target = scan_contains_phrase(spell_phrase, "with a single target");
    // CR 115.9c: "that targets only [X]" is handled by parse_that_clause_suffix via
    // parse_type_phrase, producing FilterProp::TargetsOnly — no manual stripping needed.
    let spell_phrase_clean = spell_phrase.replace(" with a single target", "");
    let spell_phrase_clean = spell_phrase_clean.trim();

    // Handle "spell or ability" specially since "ability" is not a card type in parse_target.
    // CR 115.7: "spell or ability" matches any spell or any activated/triggered ability on the stack.
    let mut target = if scan_contains_phrase(spell_phrase_clean, "spell or ability")
        || scan_contains_phrase(spell_phrase_clean, "spell and/or ability")
    {
        // Both spells and abilities on the stack
        TargetFilter::Or {
            filters: vec![
                TargetFilter::StackSpell,
                TargetFilter::StackAbility {
                    controller: None,
                    tag: None,
                },
            ],
        }
    } else if scan_contains_phrase(spell_phrase_clean, "activated or triggered ability")
        || scan_contains_phrase(spell_phrase_clean, "activated ability")
    {
        TargetFilter::StackAbility {
            controller: None,
            tag: None,
        }
    } else if scan_contains_phrase(spell_phrase_clean, "spell") {
        // Parse with parse_target for type-specific spells (e.g. "instant or sorcery spell")
        let (parsed, _) = parse_target(spell_phrase_clean);
        constrain_filter_to_stack(parsed)
    } else {
        let (parsed, _) = parse_target(spell_phrase_clean);
        parsed
    };

    // Add HasSingleTarget property if "with a single target" was specified
    if has_single_target {
        target = add_single_target_constraint(target);
    }

    Some(Effect::ChangeTargets {
        target,
        scope,
        forced_to,
    })
}

/// Add a `HasSingleTarget` property to a stack-entry filter.
/// CR 115.7: "with a single target" constrains which stack entries can be retargeted.
fn add_single_target_constraint(filter: TargetFilter) -> TargetFilter {
    match filter {
        TargetFilter::Typed(mut tf) => {
            tf.properties.push(FilterProp::HasSingleTarget);
            TargetFilter::Typed(tf)
        }
        TargetFilter::Or { filters } => TargetFilter::Or {
            filters: filters
                .into_iter()
                .map(add_single_target_constraint)
                .collect(),
        },
        // For non-typed filters (StackAbility, StackSpell), wrap in And with a typed filter
        other => TargetFilter::And {
            filters: vec![
                other,
                TargetFilter::Typed(TypedFilter {
                    properties: vec![FilterProp::HasSingleTarget],
                    ..TypedFilter::default()
                }),
            ],
        },
    }
}

/// Extract the imperative verb keyword from an effect for verb carry-forward
/// in multi-target conjunctions. Returns the verb string that, when prepended
/// to a bare "target X" clause, allows re-parsing as the same effect type.
fn extract_effect_verb(effect: &Effect) -> Option<&'static str> {
    match effect {
        Effect::Destroy { .. } | Effect::DestroyAll { .. } => Some("destroy"),
        Effect::ChangeZone {
            destination: Zone::Exile,
            ..
        } => Some("exile"),
        Effect::ChangeZone {
            destination: Zone::Hand,
            origin: Some(Zone::Battlefield),
            ..
        } => Some("return"),
        Effect::Bounce { .. } | Effect::BounceAll { .. } => Some("return"),
        Effect::Sacrifice { .. } => Some("sacrifice"),
        // CR 701.26a: the carry-forward verb depends on tap/untap polarity only;
        // both scopes share the same verb.
        Effect::SetTapState {
            state: TapStateChange::Tap,
            ..
        } => Some("tap"),
        Effect::SetTapState {
            state: TapStateChange::Untap,
            ..
        } => Some("untap"),
        // CR 608.2c: distributive "put" carries forward to a verbless trailing
        // counter conjunct ("...and a loyalty counter on each planeswalker...").
        Effect::PutCounter { .. } | Effect::PutCounterAll { .. } => Some("put"),
        _ => None,
    }
}

