    use crate::types::zones::Zone;

    fn typed_leg(filter: &TargetFilter) -> Option<&TypedFilter> {
        match filter {
            TargetFilter::Typed(tf) => Some(tf),
            TargetFilter::And { filters } => filters.iter().find_map(typed_leg),
            _ => None,
        }
    }

    fn is_stack_spell_leg(filter: &TargetFilter) -> bool {
        match filter {
            TargetFilter::StackSpell => true,
            TargetFilter::And { filters } => filters.iter().any(is_stack_spell_leg),
            _ => false,
        }
    }

    fn has_type(tf: &TypedFilter, ty: TypeFilter) -> bool {
        tf.type_filters.iter().any(|candidate| candidate == &ty)
    }

    fn assert_minus_counter_node(
        def: &AbilityDefinition,
        count: i32,
        another: bool,
    ) -> Option<&AbilityDefinition> {
        match def.effect.as_ref() {
            Effect::PutCounter {
                counter_type,
                count: QuantityExpr::Fixed { value },
                target,
            } => {
                assert_eq!(*counter_type, CounterType::Minus1Minus1);
                assert_eq!(*value, count);
                let tf = typed_leg(target).expect("counter target should be typed");
                assert!(has_type(tf, TypeFilter::Creature));
                assert_eq!(
                    tf.properties.contains(&FilterProp::Another),
                    another,
                    "unexpected Another property on {tf:?}",
                );
            }
            other => panic!("expected PutCounter, got {other:?}"),
        }
        def.sub_ability.as_deref()
    }

    /// Issue #943: comma-separated counter placements with bare count-led
    /// continuations inherit the `put` verb and stay as ordered sub-abilities.
    #[test]
    fn multi_target_counter_chain_incremental_blight_shape() {
        let def = parse_effect_chain(
            "Put a -1/-1 counter on target creature, two -1/-1 counters on another target creature, and three -1/-1 counters on a third target creature.",
            AbilityKind::Spell,
        );

        let second = assert_minus_counter_node(&def, 1, false).expect("second counter node");
        let third = assert_minus_counter_node(second, 2, true).expect("third counter node");
        assert!(
            assert_minus_counter_node(third, 3, false).is_none(),
            "counter chain should contain exactly three nodes",
        );
    }

    /// Issue #445 (Brokers Ascendancy): a compound counter clause whose FIRST
    /// conjunct is itself a mass placement ("on each") must keep the primary
    /// effect as `PutCounterAll`, and the verbless trailing conjunct must carry
    /// the "put" verb forward and resolve to its own `PutCounterAll`.
    #[test]
    fn compound_mass_counter_first_conjunct_stays_put_counter_all() {
        let clause = parse_effect_clause(
            "put a +1/+1 counter on each creature you control and a loyalty \
             counter on each planeswalker you control",
            &mut ParseContext::default(),
        );
        // Primary: +1/+1 on each creature you control.
        match &clause.effect {
            Effect::PutCounterAll {
                counter_type,
                target,
                ..
            } => {
                assert_eq!(*counter_type, CounterType::Plus1Plus1);
                let tf = typed_leg(target).expect("primary target should be typed");
                assert!(has_type(tf, TypeFilter::Creature));
                assert_eq!(tf.controller, Some(ControllerRef::You));
            }
            other => panic!("expected primary PutCounterAll, got {other:?}"),
        }
        // Sub: loyalty on each planeswalker you control.
        let sub = clause.sub_ability.expect("expected a trailing sub_ability");
        match &*sub.effect {
            Effect::PutCounterAll {
                counter_type,
                target,
                ..
            } => {
                assert_eq!(*counter_type, CounterType::Loyalty);
                let tf = typed_leg(target).expect("sub target should be typed");
                assert!(has_type(tf, TypeFilter::Planeswalker));
                assert_eq!(tf.controller, Some(ControllerRef::You));
            }
            other => panic!("expected sub PutCounterAll, got {other:?}"),
        }
        assert!(!matches!(*sub.effect, Effect::Unimplemented { .. }));
    }

    /// CR 608.2c + CR 611.2a + CR 613.1f: Nalia de'Arnise's full-party trigger
    /// body. The "and those creatures gain deathtouch until end of turn"
    /// conjunct must split at the chain level so the anaphoric back-reference
    /// subject reaches `try_parse_subject_continuous_clause` and lowers to a
    /// `GenericEffect` carrying `AddKeyword(Deathtouch)` (a layer-6
    /// ability-adding effect, CR 613.1f) with a CR 611.2a "until end of turn"
    /// continuous-effect duration.
    /// Because `PutCounterAll` publishes a tracked set at resolution time
    /// (`publishes_tracked_set_from_resolution`), the chain assembler then
    /// rewrites the static's `ParentTarget` filter to `TrackedSet(0)` so the
    /// runtime resolver binds the deathtouch grant to the exact set of
    /// creatures the counters were placed on. Before the splitter recognized
    /// "those creatures gain ..." as a clause start, the conjunct degraded to
    /// `Effect::Unimplemented { name: "those", ... }` and Nalia did nothing
    /// past the counter placement.
    #[test]
    fn nalia_de_arnise_counters_then_deathtouch_lowers_correctly() {
        let def = parse_effect_chain(
            "put a +1/+1 counter on each creature you control and those creatures gain deathtouch until end of turn",
            AbilityKind::Spell,
        );

        // Primary clause: +1/+1 counter on each creature you control. Counters
        // are permanent (CR 122.1), so no duration must leak onto this leg.
        match &*def.effect {
            Effect::PutCounterAll {
                counter_type,
                target,
                ..
            } => {
                assert_eq!(*counter_type, CounterType::Plus1Plus1);
                match target {
                    TargetFilter::Typed(tf) => {
                        assert!(tf.type_filters.contains(&TypeFilter::Creature));
                        assert_eq!(tf.controller, Some(ControllerRef::You));
                    }
                    other => {
                        panic!("primary target should be Typed creature you control, got {other:?}")
                    }
                }
            }
            other => panic!("expected primary PutCounterAll, got {other:?}"),
        }
        assert!(
            def.duration.is_none(),
            "primary PutCounterAll must not carry a duration — counters persist (CR 122.1), got {:?}",
            def.duration
        );

        // Sub-clause: continuous deathtouch grant on the same creature set.
        let sub = def
            .sub_ability
            .as_ref()
            .expect("'and those creatures gain deathtouch ...' must attach as sub_ability");
        assert!(
            !matches!(*sub.effect, Effect::Unimplemented { .. }),
            "deathtouch conjunct must not degrade to Unimplemented, got {:?}",
            sub.effect
        );
        match &*sub.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(
                    *duration,
                    Some(Duration::UntilEndOfTurn),
                    "deathtouch grant must be UntilEndOfTurn"
                );
                // CR 603.7: "those creatures" lowers to `ParentTarget` in the
                // subject-predicate parser, then the chain assembler rewrites
                // it to `TrackedSet(0)` because the prior clause
                // (`PutCounterAll`) publishes a tracked set at resolution.
                let static_def = static_abilities
                    .first()
                    .expect("deathtouch grant must produce a continuous StaticDefinition");
                assert!(
                    matches!(
                        static_def.affected,
                        Some(TargetFilter::TrackedSet {
                            id: TrackedSetId(0)
                        })
                    ),
                    "static `affected` must be TrackedSet(0) (anaphor to the counter set published by PutCounterAll), got {:?}",
                    static_def.affected
                );
                assert!(
                    static_def.modifications.iter().any(|m| matches!(
                        m,
                        ContinuousModification::AddKeyword {
                            keyword: Keyword::Deathtouch
                        }
                    )),
                    "modifications must include AddKeyword(Deathtouch), got {:?}",
                    static_def.modifications
                );
            }
            other => panic!("expected GenericEffect for deathtouch grant, got {other:?}"),
        }
    }

    /// Scoping regression for issue #445: a TARGETED primary counter clause must
    /// NOT be promoted to `PutCounterAll` just because a TRAILING conjunct is a
    /// mass placement. Mass detection must run against the primary clause only.
    #[test]
    fn compound_targeted_counter_primary_not_promoted_by_trailing_mass() {
        let clause = parse_effect_clause(
            "put a +1/+1 counter on target creature and a +1/+1 counter on \
             each creature you control",
            &mut ParseContext::default(),
        );
        assert!(
            matches!(clause.effect, Effect::PutCounter { .. }),
            "primary clause is single-target — must stay PutCounter, got {:?}",
            clause.effect
        );
    }

    /// CR 608.2c: Verb carry-forward for "up to N [other] target X" in compound actions.
    /// Relic Crush: "Destroy target artifact or enchantment and up to one other target
    /// artifact or enchantment." The sub-clause starts with "up to" — the verb must be
    /// carried forward from the primary clause.
    #[test]
    fn compound_verb_carry_forward_up_to_prefix() {
        let clause = parse_effect_clause(
            "Destroy target artifact or enchantment and up to one other target artifact or enchantment",
            &mut ParseContext::default(),
        );
        assert!(
            matches!(clause.effect, Effect::Destroy { .. }),
            "primary clause must be Destroy, got {:?}",
            clause.effect
        );
        let sub = clause
            .sub_ability
            .expect("must have sub_ability for compound");
        assert!(
            matches!(*sub.effect, Effect::Destroy { .. }),
            "sub-clause must also be Destroy, got {:?}",
            sub.effect
        );
        // CR 115.6: "up to one" must propagate as multi_target on the sub-ability.
        assert_eq!(
            sub.multi_target,
            Some(MultiTargetSpec::up_to(QuantityExpr::Fixed { value: 1 })),
            "sub-ability must carry up-to-one multi_target spec",
        );
        // CR 608.2c: "other" must appear as FilterProp::Another in the sub-effect target.
        match sub.effect.as_ref() {
            Effect::Destroy { target, .. } => {
                // Target may be Typed or Or { filters: [Typed, Typed] } for
                // "artifact or enchantment".
                let typed_filters: Vec<_> = match target {
                    TargetFilter::Typed(tf) => vec![tf],
                    TargetFilter::Or { filters } => filters
                        .iter()
                        .map(|f| match f {
                            TargetFilter::Typed(tf) => tf,
                            other => panic!("expected Typed in Or, got {:?}", other),
                        })
                        .collect(),
                    other => panic!("expected Typed or Or target, got {:?}", other),
                };
                assert!(
                    typed_filters
                        .iter()
                        .all(|tf| tf.properties.contains(&FilterProp::Another)),
                    "all sub-clause target filters must have Another property, got {:?}",
                    typed_filters,
                );
            }
            other => panic!("expected Destroy, got {:?}", other),
        }
    }

    #[test]
    fn compound_verb_carry_forward_return_target_only_tail_aether_tradewinds() {
        let clause = parse_effect_clause(
            "Return target permanent you control and target permanent you don't control to their owners' hands.",
            &mut ParseContext::default(),
        );

        match &clause.effect {
            Effect::Bounce { target, .. } => {
                let tf = typed_leg(target).expect("primary return target should be typed");
                assert_eq!(
                    tf.controller,
                    Some(ControllerRef::You),
                    "primary return target should remain 'you control'",
                );
            }
            other => panic!("primary clause must be Bounce, got {:?}", other),
        }

        let sub = clause
            .sub_ability
            .expect("must have sub_ability for compound return");
        match sub.effect.as_ref() {
            Effect::Bounce { target, .. } => {
                let tf = typed_leg(target).expect("sub return target should be typed");
                assert_eq!(
                    tf.controller,
                    Some(ControllerRef::Opponent),
                    "sub return target should resolve to 'you don't control'",
                );
            }
            other => panic!("sub-clause must be Bounce, got {:?}", other),
        }
    }

    /// CR 608.2c: Verb carry-forward for mass-object continuations.
    /// Godo, Bandit Warlord: "untap it and all Samurai you control" must parse
    /// the second conjunct as UntapAll rather than dropping the bare noun phrase.
    #[test]
    fn compound_verb_carry_forward_all_prefix() {
        let clause = parse_effect_clause(
            "untap it and all Samurai you control",
            &mut ParseContext::default(),
        );
        assert!(
            matches!(
                clause.effect,
                Effect::SetTapState {
                    scope: EffectScope::Single,
                    state: TapStateChange::Untap,
                    ..
                }
            ),
            "primary clause must be single Untap, got {:?}",
            clause.effect
        );
        let sub = clause
            .sub_ability
            .expect("must have sub_ability for mass continuation");
        match sub.effect.as_ref() {
            Effect::SetTapState {
                target,
                scope: EffectScope::All,
                state: TapStateChange::Untap,
            } => {
                let tf = typed_leg(target).expect("mass untap target should be typed");
                assert!(has_type(tf, TypeFilter::Subtype("Samurai".to_string())));
                assert_eq!(tf.controller, Some(ControllerRef::You));
            }
            other => panic!("sub-clause must be mass Untap, got {:?}", other),
        }
    }

    /// CR 608.2c + CR 701.8a: Verb carry-forward for self-reference "~" in compound
