    /// CR 608.2c: `extract_effect_verb` carries "put" forward for both the
    /// single-target and mass counter-placement effects.
    #[test]
    fn extract_effect_verb_put_counter_returns_put() {
        let single = Effect::PutCounter {
            counter_type: CounterType::Plus1Plus1,
            count: QuantityExpr::Fixed { value: 1 },
            target: TargetFilter::Typed(TypedFilter::creature()),
        };
        let mass = Effect::PutCounterAll {
            counter_type: CounterType::Loyalty,
            count: QuantityExpr::Fixed { value: 1 },
            target: TargetFilter::Typed(TypedFilter::new(TypeFilter::Planeswalker)),
        };
        assert_eq!(extract_effect_verb(&single), Some("put"));
        assert_eq!(extract_effect_verb(&mass), Some("put"));
    }

    fn has_prop(tf: &TypedFilter, prop: FilterProp) -> bool {
        tf.properties.iter().any(|candidate| candidate == &prop)
    }

    /// Parser must not invent verb stems for unknown words. The "-es" stripping
    /// rule in `normalize_verb_token` was previously triggered purely by
    /// orthographic suffix (stem ends in `ch`/`sh`/`ss`/`x`/`z`), which
    /// produced nonsense stems like `freez`/`breez`/`sneez` for the `-eze`/
    /// `-eeze` family. The narrowed rule only strips when the result is a
    /// known `PREDICATE_VERBS` member, so unrecognized verbs pass through
    /// unchanged ("parser must not swallow").
    #[test]
    fn normalize_verb_token_does_not_invent_stems_for_unknown_verbs() {
        // -eze / -eeze words must NOT be over-stripped. The actual stem
        // ("freeze", "breeze", "sneeze") is not in PREDICATE_VERBS, so the
        // -es branch must reject the strip and fall through to the -s branch
        // (which strips a single trailing 's' but only if the word doesn't
        // end in 'ss' — these end in 'es', not 'ss', so 's' strip applies and
        // yields "freeze"/"breeze"/"sneeze"). The critical assertion is the
        // negative: we never produce "freez"/"breez"/"sneez".
        for token in ["freezes", "breezes", "sneezes"] {
            let normalized = normalize_verb_token(token);
            assert_ne!(
                normalized,
                &token[..token.len() - 2],
                "normalize_verb_token({token:?}) must not produce the invented stem {:?}",
                &token[..token.len() - 2]
            );
        }

        // Sanity check: the registered "search" verb still de-conjugates so
        // the Winds of Abandon-class chain ("its controller searches their
        // library") continues to dispatch through the predicate path.
        assert_eq!(normalize_verb_token("searches"), "search");
    }

    /// CR 104.2b + CR 117.1 + CR 201.2 + CR 603.4 + CR 608.2c:
    /// Approach prints "If this spell was cast from your hand and you've cast
    /// another spell named Approach of the Second Sun this game, you win the
    /// game.  Otherwise, put Approach of the Second Sun into its owner's
    /// library seventh from the top and you gain 7 life."
    /// The parser must:
    ///   1. Recognise the compound `And { CastFromZone(Hand),
    ///      QuantityCheck(SpellsCastThisGame{filter=Named} >= 2) }` so the
    ///      win effect fires only on the second cast (CR 117.1 — at
    ///      resolution time the currently-resolving spell is already in
    ///      `spells_cast_this_game_by_player`, so "another" maps to >= 2).
    ///   2. Route the otherwise branch (PutAtLibraryPosition then GainLife
    ///      7) onto `else_ability`, keeping the "and you gain 7 life"
    ///      inside the Otherwise body rather than chaining it onto the win
    ///      effect.
    ///
    /// Feeds the parser the un-tilde'd "named X" text the way production
    /// sees it after `normalize_card_name_refs`' `"named ~"` → `"named
    /// CardName"` restore (`oracle_util.rs:1553`). Asserting the literal
    /// `FilterProp::Named { name }` value catches a regression in that
    /// restore step, which would otherwise produce `name: "~"` at parse
    /// time and silently mis-match against records whose `name` is the
    /// printed card name at resolution time.
    #[test]
    fn approach_of_the_second_sun_parses_compound_condition_and_otherwise_branch() {
        let def = parse_effect_chain(
            "If this spell was cast from your hand and you've cast another spell named Approach of the Second Sun this game, you win the game.\nOtherwise, put ~ into its owner's library seventh from the top and you gain 7 life.",
            AbilityKind::Spell,
        );

        assert!(
            matches!(*def.effect, Effect::WinTheGame { .. }),
            "top-level effect must be WinTheGame, got: {:?}",
            def.effect
        );

        let condition = def
            .condition
            .as_ref()
            .expect("WinTheGame must be gated by the printed compound condition");
        let AbilityCondition::And { conditions } = condition else {
            panic!("expected And condition, got: {condition:?}");
        };
        assert_eq!(conditions.len(), 2);
        assert!(
            matches!(
                &conditions[0],
                AbilityCondition::CastFromZone { zone: Zone::Hand }
            ),
            "first conjunct must be CastFromZone(Hand), got: {:?}",
            conditions[0]
        );
        match &conditions[1] {
            AbilityCondition::QuantityCheck {
                lhs:
                    QuantityExpr::Ref {
                        qty:
                            QuantityRef::SpellsCastThisGame {
                                scope: CountScope::Controller,
                                filter: Some(TargetFilter::Typed(tf)),
                            },
                    },
                comparator: Comparator::GE,
                rhs: QuantityExpr::Fixed { value: 2 },
            } => {
                // CR 201.2: name compare is case-insensitive — the parser
                // lowercases input before extraction, so the stored name is
                // lowercase. Runtime matches against `record.name` (printed
                // case) via `eq_ignore_ascii_case`.
                let printed_name_match = tf.properties.iter().any(|p| {
                    matches!(p, FilterProp::Named { name } if name == "approach of the second sun")
                });
                assert!(
                    printed_name_match,
                    "Named filter must carry the printed card name (lowercased), got properties: {:?}",
                    tf.properties
                );
            }
            other => panic!(
                "second conjunct must be SpellsCastThisGame filtered by Named >= 2, got: {other:?}"
            ),
        }

        let else_ab = def
            .else_ability
            .as_ref()
            .expect("Otherwise must attach as else_ability");
        assert!(
            matches!(*else_ab.effect, Effect::PutAtLibraryPosition { .. }),
            "else_ability head must be PutAtLibraryPosition, got: {:?}",
            else_ab.effect
        );
        let gain = else_ab
            .sub_ability
            .as_ref()
            .expect("Otherwise body must continue with `and you gain 7 life`");
        assert!(
            matches!(
                *gain.effect,
                Effect::GainLife {
                    amount: QuantityExpr::Fixed { value: 7 },
                    ..
                }
            ),
            "Otherwise body must end with GainLife(7), got: {:?}",
            gain.effect
        );
        assert!(
            def.sub_ability.is_none(),
            "WinTheGame must not carry a sub_ability (the gain-life clause belongs to the Otherwise branch), got: {:?}",
            def.sub_ability
        );
    }

    /// CR 608.2c: "If <cond>, you may instead <reveal-N-from-among>" must produce
    /// a conditional Dig alternative where the `else_ability` is the base Dig
    /// (with its patched filter) and the outer Dig carries the alternative's
    /// selection parameters. Class coverage: any Dig-followed-by-conditional-reveal
    /// pattern ("Follow the Lumarets" is the exemplar card).
    #[test]
    fn dig_conditional_instead_alternative_preserves_both_branches() {
        let def = parse_effect_chain(
            "Look at the top four cards of your library. You may reveal a creature or land card from among them and put it into your hand. If you gained life this turn, you may instead reveal two creature and/or land cards from among them and put them into your hand. Put the rest on the bottom of your library in a random order.",
            AbilityKind::Spell,
        );

        // Outer Dig: alternative (condition true) — keep 2 exactly, Or[Creature, Land].
        let Effect::Dig {
            count,
            keep_count,
            up_to,
            filter,
            rest_destination,
            destination,
            ..
        } = &*def.effect
        else {
            panic!("expected outer Effect::Dig, got {:?}", def.effect);
        };
        assert!(
            matches!(count, QuantityExpr::Fixed { value: 4 }),
            "alt branch should see top 4"
        );
        assert_eq!(*keep_count, Some(2), "alt branch keeps exactly 2");
        assert!(!*up_to, "alt branch is exact-2 (not up-to)");
        assert_eq!(*destination, Some(Zone::Hand));
        assert_eq!(*rest_destination, Some(Zone::Library));
        let TargetFilter::Or { filters } = filter else {
            panic!("alt filter should be Or, got {:?}", filter);
        };
        assert_eq!(filters.len(), 2);

        // Condition is life-gained-this-turn.
        let Some(AbilityCondition::QuantityCheck {
            lhs,
            comparator,
            rhs,
        }) = &def.condition
        else {
            panic!("expected QuantityCheck condition, got {:?}", def.condition);
        };
        assert!(matches!(
            lhs,
            QuantityExpr::Ref {
                qty: QuantityRef::LifeGainedThisTurn { .. }
            }
        ));
        assert_eq!(*comparator, Comparator::GE);
        assert!(matches!(rhs, QuantityExpr::Fixed { value: 1 }));

        // else_ability carries the base Dig (condition false) — keep up_to 1.
        let base = def
            .else_ability
            .as_deref()
            .expect("base Dig must be stored as else_ability");
        let Effect::Dig {
            player: TargetFilter::Controller,
            count: base_count,
            keep_count: base_keep,
            up_to: base_up_to,
            filter: base_filter,
            rest_destination: base_rest,
            ..
        } = &*base.effect
        else {
            panic!("expected base Effect::Dig, got {:?}", base.effect);
        };
        assert!(matches!(base_count, QuantityExpr::Fixed { value: 4 }));
        assert_eq!(*base_keep, Some(1));
        assert!(*base_up_to, "base branch is up-to 1");
        assert_eq!(*base_rest, Some(Zone::Library), "PutRest must recurse");
        let TargetFilter::Or {
            filters: base_filters,
        } = base_filter
        else {
            panic!("base filter should be Or, got {:?}", base_filter);
        };
        assert_eq!(base_filters.len(), 2);
    }

    #[test]
    fn flow_state_conditionally_keeps_two_for_instant_and_sorcery_in_graveyard() {
        let def = parse_effect_chain(
            "Look at the top three cards of your library. Put one of them into your hand and the rest on the bottom of your library in any order. If there is an instant card and a sorcery card in your graveyard, instead put two of them into your hand and the rest on the bottom of your library in any order.",
            AbilityKind::Spell,
        );

        let Effect::Dig {
            count,
            keep_count,
            up_to,
            filter,
            destination,
            rest_destination,
            ..
        } = &*def.effect
        else {
            panic!("expected conditional Flow State Dig, got {:?}", def.effect);
        };
        assert_eq!(*count, QuantityExpr::Fixed { value: 3 });
        assert_eq!(*keep_count, Some(2));
        assert!(!*up_to);
        assert_eq!(*filter, TargetFilter::Any);
        assert_eq!(*destination, Some(Zone::Hand));
        assert_eq!(*rest_destination, Some(Zone::Library));

        let Some(AbilityCondition::And { conditions }) = &def.condition else {
            panic!(
                "expected instant+sorcery graveyard condition, got {:?}",
                def.condition
            );
        };
        assert_eq!(conditions.len(), 2);
        assert_graveyard_card_count_condition(&conditions[0], TypeFilter::Instant);
        assert_graveyard_card_count_condition(&conditions[1], TypeFilter::Sorcery);

        let base = def
            .else_ability
            .as_deref()
            .expect("base Flow State Dig must be stored as else_ability");
        let Effect::Dig {
            keep_count: base_keep_count,
            up_to: base_up_to,
            rest_destination: base_rest_destination,
            ..
        } = &*base.effect
        else {
            panic!("expected base Flow State Dig, got {:?}", base.effect);
        };
        assert_eq!(*base_keep_count, Some(1));
        assert!(!*base_up_to);
        assert_eq!(*base_rest_destination, Some(Zone::Library));
    }

