    #[test]
    fn effect_bounce_counted_half_target_player_creatures() {
        let e = parse_effect(
            "Return half the creatures they control to their owner's hand, rounded up",
        );
        match e {
            Effect::BounceAll {
                target: TargetFilter::Typed(filter),
                destination,
                count:
                    Some(QuantityExpr::DivideRounded {
                        inner,
                        divisor,
                        rounding,
                    }),
            } => {
                assert!(destination.is_none(), "default destination = owner's hand");
                assert_eq!(filter.type_filters, vec![TypeFilter::Creature]);
                assert_eq!(filter.controller, Some(ControllerRef::ScopedPlayer));
                assert_eq!(divisor, 2);
                assert_eq!(rounding, crate::types::ability::RoundingMode::Up);
                match *inner {
                    QuantityExpr::Ref {
                        qty:
                            QuantityRef::ObjectCount {
                                filter: TargetFilter::Typed(count_filter),
                            },
                    } => {
                        assert_eq!(count_filter.type_filters, vec![TypeFilter::Creature]);
                        assert_eq!(count_filter.controller, Some(ControllerRef::ScopedPlayer));
                    }
                    other => panic!("expected ObjectCount inner quantity, got {other:?}"),
                }
            }
            other => panic!("expected counted BounceAll, got {other:?}"),
        }
    }

    /// Desynchronization (#2410): "that's not historic" must negate CR 700.6
    /// historic, not degrade to `Non(Subtype("Historic"))` which matches every
    /// permanent.
    #[test]
    fn effect_bounce_all_nonhistoric_nonland_permanents_desynchronization() {
        let e =
            parse_effect("Return each nonland permanent that's not historic to its owner's hand.");
        match e {
            Effect::BounceAll {
                target: TargetFilter::Typed(filter),
                ..
            } => {
                assert!(
                    filter.type_filters.iter().any(|t| matches!(
                        t,
                        TypeFilter::Non(inner) if matches!(**inner, TypeFilter::Land)
                    )),
                    "nonland exclusion present, got {:?}",
                    filter.type_filters
                );
                assert!(
                    filter.properties.contains(&FilterProp::NotHistoric),
                    "nonhistoric filter must be NotHistoric, got {:?}",
                    filter.properties
                );
            }
            other => {
                panic!("expected BounceAll {{ Permanent, Non(Land), NotHistoric }}, got {other:?}")
            }
        }
    }

