    #[test]
    fn expand_the_sphere_difference_repeat_threads_onto_proliferate_sub() {
        // CR 609.3: "If you put fewer than two lands onto the battlefield this
        // way, proliferate a number of times equal to the difference." — the
        // leading comparison condition AND the difference-repeat count must
        // both thread onto the Proliferate sub-ability.
        let def = parse_effect_chain(
            "Look at the top six cards of your library. Put up to two land cards from among \
             them onto the battlefield tapped and the rest on the bottom of your library in a \
             random order. If you put fewer than two lands onto the battlefield this way, \
             proliferate a number of times equal to the difference.",
            AbilityKind::Spell,
        );
        assert!(matches!(*def.effect, Effect::Dig { .. }));
        let sub = def.sub_ability.expect("proliferate sub-ability");
        assert!(matches!(*sub.effect, Effect::Proliferate));
        assert_eq!(
            sub.condition,
            Some(AbilityCondition::QuantityCheck {
                lhs: QuantityExpr::Ref {
                    qty: QuantityRef::TrackedSetSize,
                },
                comparator: Comparator::LT,
                rhs: QuantityExpr::Fixed { value: 2 },
            }),
        );
        assert_eq!(
            sub.repeat_for,
            Some(QuantityExpr::Difference {
                left: Box::new(QuantityExpr::Ref {
                    qty: QuantityRef::TrackedSetSize,
                }),
                right: Box::new(QuantityExpr::Fixed { value: 2 }),
            }),
        );
    }

    /// CR 121.1 + CR 402: "if you have fewer than N cards in hand, draw cards equal to
    /// the difference" — the draw count is `Difference(Fixed(N), HandSize(Controller))`.
    /// Anchor card: Kozilek, the Great Distortion. Same infrastructure fixes Iymrith
    /// Desert Doom (N=3), Damia Sage of Stone (N=7).
    #[test]
    fn draw_cards_equal_to_hand_difference_from_limit() {
        let def = parse_effect_chain(
            "If you have fewer than seven cards in hand, draw cards equal to the difference.",
            AbilityKind::Spell,
        );
        assert!(
            matches!(
                *def.effect,
                Effect::Draw {
                    target: TargetFilter::Controller,
                    ..
                }
            ),
            "expected Draw(Controller), got {:?}",
            def.effect
        );
        assert_eq!(
            def.condition,
            Some(AbilityCondition::QuantityCheck {
                lhs: QuantityExpr::Ref {
                    qty: QuantityRef::HandSize {
                        player: PlayerScope::Controller,
                    },
                },
                comparator: Comparator::LT,
                rhs: QuantityExpr::Fixed { value: 7 },
            }),
            "condition must be HandSize(Controller) LT 7"
        );
        if let Effect::Draw { ref count, .. } = *def.effect {
            assert_eq!(
                *count,
                QuantityExpr::Difference {
                    left: Box::new(QuantityExpr::Ref {
                        qty: QuantityRef::HandSize {
                            player: PlayerScope::Controller,
                        },
                    }),
                    right: Box::new(QuantityExpr::Fixed { value: 7 }),
                },
                "draw count must be Difference(HandSize(Controller), Fixed(7))"
            );
        }
    }

    /// CR 121.1 + CR 402: "if that player has more cards in hand than you, draw cards
