    // Remaining tests truncated for space — they are identical to the original file.
    // Including a representative subset to verify compilation.

    // CR 608.2c + CR 117.3a + CR 701.23a: Assassin's Trophy-shape —
    // "Destroy target permanent an opponent controls. Its controller may
    // search their library for a basic land card, put it onto the
    // battlefield, then shuffle." The subject "its controller" anchors the
    // subsequent "put it onto the battlefield, then shuffle" clauses so the
    // destroyed permanent's controller (a) searches their own library,
    // (b) receives the found land onto the battlefield (as `ParentTarget`),
    // and (c) shuffles their library. No spurious Library→Hand step emitted.
    #[test]
    fn assassins_trophy_its_controller_may_search_chain() {
        use crate::types::ability::AbilityKind;
        let def = parse_effect_chain(
            "Destroy target permanent an opponent controls. Its controller may search their library for a basic land card, put it onto the battlefield, then shuffle.",
            AbilityKind::Spell,
        );
        // Top-level: Destroy
        assert!(
            matches!(&*def.effect, Effect::Destroy { .. }),
            "top-level should be Destroy, got {:?}",
            def.effect
        );
        // First sub: SearchLibrary with ParentTargetController target_player + optional
        let search = def
            .sub_ability
            .as_deref()
            .expect("should chain SearchLibrary");
        match &*search.effect {
            Effect::SearchLibrary { target_player, .. } => {
                assert_eq!(
                    target_player.as_ref(),
                    Some(&TargetFilter::ParentTargetController),
                    "SearchLibrary must target the destroyed permanent's controller",
                );
            }
            other => panic!("expected SearchLibrary, got {:?}", other),
        }
        assert!(search.optional, "SearchLibrary must be optional ('may')");
        // Second sub: ChangeZone Library→Battlefield (NOT Hand)
        let put = search
            .sub_ability
            .as_deref()
            .expect("should chain put-step");
        match &*put.effect {
            Effect::ChangeZone {
                origin,
                destination,
                ..
            } => {
                assert_eq!(*origin, Some(Zone::Library));
                assert_eq!(
                    *destination,
                    Zone::Battlefield,
                    "put-step destination must be Battlefield — no spurious Library→Hand"
                );
            }
            other => panic!("expected ChangeZone, got {:?}", other),
        }
        // Third sub: Shuffle with ParentTargetController (the acting player)
        let shuffle = put.sub_ability.as_deref().expect("should chain Shuffle");
        match &*shuffle.effect {
            Effect::Shuffle { target } => {
                assert_eq!(
                    *target,
                    TargetFilter::ParentTargetController,
                    "Shuffle must target the acting player (its controller), not the caster"
                );
            }
            other => panic!("expected Shuffle, got {:?}", other),
        }
        // Chain must end there — no Library→Hand tail.
        assert!(
            shuffle.sub_ability.is_none(),
            "chain must end after Shuffle; got extra: {:?}",
            shuffle.sub_ability
        );
    }

    /// CR 608.2c + CR 117.3a + CR 701.23a + CR 609.3 + CR 603.7: Winds of
    /// Abandon — iterated subject-anchored search. The structure mirrors
    /// Assassin's Trophy but the search step carries `repeat_for:
    /// TrackedSetSize` so each exiled creature's controller searches their own
    /// library. The tracked-set anchor is published by the leading exile step;
    /// the per-iteration parent-target rebind in `repeat_for` execution
    /// (game/effects/mod.rs) ensures `ParentTargetController` resolves to a
    /// different exiled creature per iteration.
    #[test]
    fn winds_of_abandon_iterated_subject_search_chain() {
        use crate::types::ability::AbilityKind;
        let def = parse_effect_chain(
            "Exile target creature you don't control. For each creature exiled this way, its controller searches their library for a basic land card. Those players put those cards onto the battlefield tapped, then shuffle.",
            AbilityKind::Spell,
        );
        // Top-level: ChangeZone(exile target opponent's creature)
        match &*def.effect {
            Effect::ChangeZone {
                destination,
                target,
                ..
            } => {
                assert_eq!(*destination, Zone::Exile);
                assert!(
                    matches!(target, TargetFilter::Typed(_)),
                    "exile target should be a typed filter, got {:?}",
                    target
                );
            }
            other => panic!("expected top-level ChangeZone(Exile), got {:?}", other),
        }
        // Sub: SearchLibrary { target_player: ParentTargetController, basic land,
        //                     repeat_for: TrackedSetSize }
        let search = def
            .sub_ability
            .as_deref()
            .expect("chain must continue into SearchLibrary");
        match &*search.effect {
            Effect::SearchLibrary {
                filter,
                target_player,
                ..
            } => {
                assert_eq!(
                    target_player.as_ref(),
                    Some(&TargetFilter::ParentTargetController),
                    "search must route to the parent target's controller"
                );
                if let TargetFilter::Typed(tf) = filter {
                    assert!(tf.type_filters.contains(&TypeFilter::Land));
                    assert!(
                        tf.properties.iter().any(|p| matches!(
                            p,
                            FilterProp::HasSupertype {
                                value: crate::types::card_type::Supertype::Basic
                            }
                        )),
                        "search filter must require Basic supertype"
                    );
                } else {
                    panic!("search filter must be Typed, got {:?}", filter);
                }
            }
            other => panic!("expected SearchLibrary, got {:?}", other),
        }
        assert_eq!(
            search.repeat_for,
            Some(QuantityExpr::Ref {
                qty: QuantityRef::TrackedSetSize
            }),
            "SearchLibrary must iterate over the tracked-set size"
        );
        // Sub-sub: ChangeZone(Library→Battlefield, enter_tapped=true)
        let put = search
            .sub_ability
            .as_deref()
            .expect("search must chain a put-step");
        match &*put.effect {
            Effect::ChangeZone {
                origin,
                destination,
                enter_tapped,
                ..
            } => {
                assert_eq!(*origin, Some(Zone::Library));
                assert_eq!(*destination, Zone::Battlefield);
                assert!(
                    enter_tapped.is_tapped(),
                    "put-step must set enter_tapped (Oracle: 'onto the battlefield tapped')"
                );
            }
            other => panic!("expected ChangeZone Library→Battlefield, got {:?}", other),
        }
        // Sub-sub-sub: Shuffle with ParentTargetController so each searching
        // player shuffles their own library (CR 701.23i).
        let shuffle = put.sub_ability.as_deref().expect("must chain Shuffle");
        match &*shuffle.effect {
            Effect::Shuffle { target } => {
                assert_eq!(
                    *target,
                    TargetFilter::ParentTargetController,
                    "Shuffle must target the searching player, not the caster"
                );
            }
            other => panic!("expected Shuffle, got {:?}", other),
        }
        // No spurious tail — the third Oracle clause must have been absorbed.
        assert!(
            shuffle.sub_ability.is_none(),
            "chain must end at Shuffle; got extra: {:?}",
            shuffle.sub_ability
        );
    }

    #[test]
    fn parse_search_basic_land_to_hand() {
        let e = parse_effect(
            "Search your library for a basic land card, reveal it, put it into your hand",
        );
        match e {
            Effect::SearchLibrary {
                filter,
                count,
                reveal,
                ..
            } => {
                assert_eq!(count, QuantityExpr::Fixed { value: 1 });
                assert!(reveal);
                match filter {
                    TargetFilter::Typed(tf) => {
                        assert!(tf.type_filters.contains(&TypeFilter::Land));
                        assert!(tf.properties.iter().any(
                            |p| matches!(p, FilterProp::HasSupertype { value } if *value == crate::types::card_type::Supertype::Basic)
                        ));
                    }
                    other => panic!("Expected Typed filter, got {:?}", other),
                }
            }
            other => panic!("Expected SearchLibrary, got {:?}", other),
        }
    }

    #[test]
    fn parse_search_aura_with_mana_value_and_different_name() {
        // Light-Paws, Emperor's Voice search filter
        let e = parse_effect(
            "Search your library for an Aura card with mana value less than or equal to that Aura and with a different name than each Aura you control, put that card onto the battlefield attached to Light-Paws, then shuffle",
        );
        match e {
            Effect::SearchLibrary { filter, .. } => match filter {
                TargetFilter::Typed(tf) => {
                    assert!(tf.type_filters.contains(&TypeFilter::Enchantment));
                    assert_eq!(tf.get_subtype(), Some("Aura"));
                    let properties = &tf.properties;
                    assert!(
                        properties.iter().any(|p| matches!(
                            p,
                            FilterProp::Cmc {
                                comparator: Comparator::LE,
                                value: QuantityExpr::Ref {
                                    qty: QuantityRef::ObjectManaValue {
                                        scope: crate::types::ability::ObjectScope::CostPaidObject
                                    }
                                }
                            }
                        )),
                        "Should have CmcLE with ObjectManaValue {{ CostPaidObject }}, got {:?}",
                        properties
                    );
                    assert!(
                        properties
                            .iter()
                            .any(|p| matches!(p, FilterProp::DifferentNameFrom { .. })),
                        "Should have DifferentNameFrom, got {:?}",
                        properties
                    );
                }
                other => panic!("Expected Typed filter, got {:?}", other),
            },
            other => panic!("Expected SearchLibrary, got {:?}", other),
        }
    }

