    #[test]
    fn shared_target_untap_or_tap_reversed_ordering_parses() {
        // The reversed verb ordering maps to the same shared-target choice; the
        // generic "A or B" splitter must not swallow the second instruction.
        let def = parse_effect_chain("Untap or tap target permanent", AbilityKind::Spell);
        assert!(
            matches!(&*def.effect, Effect::TargetOnly { .. }),
            "expected TargetOnly head, got {:?}",
            def.effect
        );
        let choice = def
            .sub_ability
            .as_deref()
            .expect("untap-or-tap must chain a resolution choice");
        let Effect::ChooseOneOf { branches, .. } = &*choice.effect else {
            panic!("expected ChooseOneOf sub-ability, got {:?}", choice.effect);
        };
        assert_eq!(branches.len(), 2);
    }

    /// Issue #501 FOLLOW-UP — ROOT CAUSE A building-block test. A "gains
    /// suspend" continuous keyword grant carries `Duration::Permanent` (CR
    /// 702.62b + CR 611.2a): the suspend mechanic owns the card's lifetime, so
    /// the grant has no turn-scoped expiry. Keyed on the typed `Keyword::Suspend`
    /// variant in `build_continuous_clause`.
    ///
    /// NOTE: The parsed `SourceLacksKeyword { Suspend }` condition on this clause
    /// resolves against the activating object (Jhoira / The Tenth Doctor), not
    /// the exiled card. For these two cards this is inert — neither granter ever
    /// has Suspend, so the grant fires unconditionally. A future "if it doesn't
    /// have X" pattern whose subject is the cost-paid object will need a typed
    /// `CostPaidObjectLacksKeyword` variant; flag and skip here.
    #[test]
    fn suspend_keyword_grant_carries_permanent_duration() {
        use crate::types::keywords::Keyword;
        let def = parse_effect_chain(
            "If it doesn't have suspend, it gains suspend",
            AbilityKind::Spell,
        );
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(
                    *duration,
                    Some(Duration::Permanent),
                    "suspend grant's GenericEffect must be Permanent, not turn-scoped"
                );
                assert!(
                    static_abilities
                        .iter()
                        .any(|s| s.modifications.iter().any(|m| matches!(
                            m,
                            ContinuousModification::AddKeyword {
                                keyword: Keyword::Suspend { .. }
                            }
                        ))),
                    "the grant must add the Suspend keyword"
                );
            }
            other => panic!("suspend grant must be a GenericEffect, got {other:?}"),
        }
        assert_eq!(
            def.duration,
            Some(Duration::Permanent),
            "the ParsedEffectClause duration must also be Permanent"
        );
    }

    /// Issue #501 FOLLOW-UP — negative sibling for Root Cause A. The
    /// `Duration::Permanent` override is keyed strictly on `Keyword::Suspend`:
    /// an ordinary "gains flying" combat trick still parses to
    /// `Some(UntilEndOfTurn)` (recovered from the explicit duration suffix), so
    /// the suspend-specific override does not leak to other keyword grants.
    #[test]
    fn non_suspend_keyword_grant_is_not_made_permanent() {
        let e = parse_effect("Target creature gains flying until end of turn");
        match e {
            Effect::GenericEffect { duration, .. } => {
                assert_eq!(
                    duration,
                    Some(Duration::UntilEndOfTurn),
                    "ordinary keyword grants must stay turn-scoped"
                );
            }
            other => panic!("expected GenericEffect, got {other:?}"),
        }
    }

    /// CR 508.1d / CR 509.1c: Deadly Allure — "Target creature gains deathtouch
    /// until end of turn and must be blocked this turn if able." The trailing
    /// combat-requirement conjunct splits into a second chained `GenericEffect`,
    /// each carrying its own duration. def#1 = the keyword grant; def#2 = the
    /// MustBeBlocked requirement, whose `affected` resolves to `ParentTarget`
    /// (the same chosen creature, not a second target slot).
    #[test]
    fn effect_gain_keyword_and_must_be_blocked_splits_into_chained_generic_effects() {
        use crate::types::keywords::Keyword;
        use crate::types::statics::StaticMode;
        let def = parse_effect_chain(
            "Target creature gains deathtouch until end of turn and must be blocked this turn if able",
            AbilityKind::Spell,
        );
        // def#1 — keyword grant with recovered UntilEndOfTurn duration.
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
                assert!(static_abilities.iter().any(|s| s.modifications.contains(
                    &ContinuousModification::AddKeyword {
                        keyword: Keyword::Deathtouch
                    }
                )));
            }
            other => panic!("def#1 must be GenericEffect, got {other:?}"),
        }
        // def#2 — the MustBeBlocked requirement conjunct.
        let sub = def
            .sub_ability
            .as_deref()
            .expect("combat requirement must become a chained sub_ability");
        match &*sub.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(static_abilities[0].mode, StaticMode::MustBeBlocked);
                assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
                assert_eq!(
                    static_abilities[0].affected,
                    Some(TargetFilter::ParentTarget),
                    "conjunct 2 must reuse conjunct 1's target, not a new slot"
                );
            }
            other => panic!("def#2 must be GenericEffect, got {other:?}"),
        }
    }

    /// CR 508.1d: Impulsive Charge — "all Revelers gain haste until end of turn
    /// and attack this combat if able." The divergent-duration assertion:
    /// def#1 keeps `UntilEndOfTurn`, def#2 (MustAttack) carries
    /// `UntilEndOfCombat` — proving the requirement does NOT wrongly persist
    /// past combat.
    #[test]
    fn effect_gain_keyword_and_attack_if_able_splits_with_divergent_durations() {
        use crate::types::keywords::Keyword;
        use crate::types::statics::StaticMode;
        let def = parse_effect_chain(
            "all Revelers gain haste until end of turn and attack this combat if able",
            AbilityKind::Spell,
        );
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
                assert!(static_abilities.iter().any(|s| s.modifications.contains(
                    &ContinuousModification::AddKeyword {
                        keyword: Keyword::Haste
                    }
                )));
            }
            other => panic!("def#1 must be GenericEffect, got {other:?}"),
        }
        let sub = def
            .sub_ability
            .as_deref()
            .expect("combat requirement must become a chained sub_ability");
        match &*sub.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(static_abilities[0].mode, StaticMode::MustAttack);
                assert_eq!(
                    *duration,
                    Some(Duration::UntilEndOfCombat),
                    "MustAttack must carry its own UntilEndOfCombat, not inherit UntilEndOfTurn"
                );
                // Non-targeted set subject — the typed filter, not SelfRef.
                assert!(
                    !matches!(static_abilities[0].affected, Some(TargetFilter::SelfRef)),
                    "non-targeted subject must thread the typed filter, got {:?}",
                    static_abilities[0].affected
                );
            }
            other => panic!("def#2 must be GenericEffect, got {other:?}"),
        }
    }

    /// GAP-4 regression: "Target creature gains flying and haste until end of
    /// turn" is a multi-keyword list — NOT a combat requirement — so the
    /// combat-requirement-gated split must NOT fire. Stays one `GenericEffect`.
    #[test]
    fn effect_gain_multiple_keywords_does_not_split() {
        use crate::types::keywords::Keyword;
        let def = parse_effect_chain(
            "Target creature gains flying and haste until end of turn",
            AbilityKind::Spell,
        );
        assert!(
            def.sub_ability.is_none(),
            "multi-keyword list must not split, got chained sub_ability"
        );
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities, ..
            } => {
                let mods: Vec<_> = static_abilities
                    .iter()
                    .flat_map(|s| s.modifications.iter())
                    .collect();
                assert!(mods.contains(&&ContinuousModification::AddKeyword {
                    keyword: Keyword::Flying
                }));
                assert!(mods.contains(&&ContinuousModification::AddKeyword {
                    keyword: Keyword::Haste
                }));
            }
            other => panic!("expected single GenericEffect, got {other:?}"),
        }
    }

    /// CR 613.1d + CR 613.4b: Vedalken Humiliator — "lose all abilities and
    /// have base power and toughness 1/1 until end of turn" must parse as a
    /// single GenericEffect with RemoveAllAbilities + SetPower(1) + SetToughness(1)
    /// on the same StaticDefinition. The sequence splitter must NOT split at
    /// " and have base power and toughness" because the base-PT phrase is a
    /// layer-7b continuous modification, not an imperative clause starter.
    #[test]
    fn lose_abilities_and_have_base_pt_parses_as_single_generic_effect() {
        let def = parse_effect_chain(
            "creatures your opponents control lose all abilities and have base power and toughness 1/1 until end of turn",
            AbilityKind::Spell,
        );
        assert!(
            def.sub_ability.is_none(),
            "must parse as a single clause, not split into sub_ability"
        );
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
                let mods: Vec<_> = static_abilities
                    .iter()
                    .flat_map(|s| s.modifications.iter())
                    .collect();
                assert!(
                    mods.iter()
                        .any(|m| matches!(m, ContinuousModification::RemoveAllAbilities)),
                    "must contain RemoveAllAbilities"
                );
                assert!(
                    mods.iter()
                        .any(|m| matches!(m, ContinuousModification::SetPower { value: 1 })),
                    "must contain SetPower(1)"
                );
                assert!(
                    mods.iter()
                        .any(|m| matches!(m, ContinuousModification::SetToughness { value: 1 })),
                    "must contain SetToughness(1)"
                );
            }
            other => panic!("expected single GenericEffect, got {other:?}"),
        }
    }

    /// CR 509.1b + CR 613.4b: Atomic Microsizer — anaphoric subject with a
    /// restriction conjunct and a trailing "has base power and toughness" conjunct
    /// must stay one GenericEffect (sequence splitter recognizes "has" as well as
    /// "have").
    #[test]
    fn that_creature_cant_be_blocked_and_has_base_pt_parses_as_single_generic_effect() {
        let def = parse_effect_chain(
            "That creature can't be blocked this turn and has base power and toughness 1/1 until end of turn",
            AbilityKind::Spell,
        );
        assert!(
            def.sub_ability.is_none(),
            "must parse as a single clause, not split into sub_ability: {:?}",
            def.sub_ability
        );
        match &*def.effect {
            Effect::GenericEffect {
                static_abilities,
                duration,
                ..
            } => {
                assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
                let mods: Vec<_> = static_abilities
                    .iter()
                    .flat_map(|s| s.modifications.iter())
                    .collect();
                assert!(
                    mods.iter().any(|m| matches!(
                        m,
                        ContinuousModification::AddStaticMode {
                            mode: StaticMode::CantBeBlocked
                        }
                    )),
                    "must contain CantBeBlocked: {mods:?}"
                );
                assert!(
                    mods.iter()
                        .any(|m| matches!(m, ContinuousModification::SetPower { value: 1 })),
                    "must contain SetPower(1): {mods:?}"
                );
                assert!(
                    mods.iter()
                        .any(|m| matches!(m, ContinuousModification::SetToughness { value: 1 })),
                    "must contain SetToughness(1): {mods:?}"
                );
            }
            other => panic!("expected single GenericEffect, got {other:?}"),
        }
    }

