    /// CR 107.1a class-level regression — "Target opponent loses half their
    /// life, rounded up." The `try_parse_half_life_amount` path must now
    /// produce a typed DivideRounded `amount` on `LoseLife`, not `Fixed { 1 }`.
    #[test]
    fn blood_tribute_lose_half_their_life_rounded_up() {
        use crate::types::ability::RoundingMode;
        let def = parse_effect_chain(
            "Target opponent loses half their life, rounded up.",
            AbilityKind::Spell,
        );
        match &*def.effect {
            Effect::LoseLife { amount, .. } => {
                assert_eq!(
                    *amount,
                    QuantityExpr::DivideRounded {
                        inner: Box::new(QuantityExpr::Ref {
                            qty: QuantityRef::LifeTotal {
                                player: PlayerScope::Target
                            },
                        }),
                        divisor: 2,
                        rounding: RoundingMode::Up,
                    },
                    "Expected DivideRounded(TargetLifeTotal, Up), got {amount:?}",
                );
            }
            other => panic!("Expected LoseLife, got {other:?}"),
        }
    }

    /// CR 107.1a + CR 109.5 regression (Betor, Kin to All): an "each opponent
    /// loses half their life, rounded up" clause NESTED as a sub-ability (not
    /// the outermost effect) must still pick up the player-scope rewrite, so
    /// "their life" binds to each iterating opponent (`ScopedPlayer`). Before
    /// the fix the rewrite only ran when the OUTERMOST def carried
    /// `player_scope`, so the nested clause kept `LifeTotal { Target }` — which
    /// resolves to 0 (no player target), making the life loss a no-op.
    #[test]
    fn nested_each_opponent_loses_half_life_uses_scoped_player() {
        use crate::types::ability::{PlayerFilter, RoundingMode};
        let def = parse_effect_chain(
            "Draw a card. Then each opponent loses half their life, rounded up.",
            AbilityKind::Spell,
        );
        // Walk the sub_ability chain to the LoseLife clause.
        let mut node = &def;
        let lose = loop {
            if matches!(&*node.effect, Effect::LoseLife { .. }) {
                break node;
            }
            node = node
                .sub_ability
                .as_deref()
                .expect("LoseLife present in chain");
        };
        assert_eq!(lose.player_scope, Some(PlayerFilter::Opponent));
        let Effect::LoseLife { amount, .. } = &*lose.effect else {
            unreachable!()
        };
        assert_eq!(
            *amount,
            QuantityExpr::DivideRounded {
                inner: Box::new(QuantityExpr::Ref {
                    qty: QuantityRef::LifeTotal {
                        player: PlayerScope::ScopedPlayer
                    },
                }),
                divisor: 2,
                rounding: RoundingMode::Up,
            },
            "nested each-opponent 'their life' must rebind to ScopedPlayer, got {amount:?}",
        );
    }

    /// CR 107.1a: Cut Your Losses — "Target player mills half their library,
    /// rounded down." Regression test for the Mill effect picking up the
    /// fractional quantity primitive (previously defaulted to `Fixed { 1 }`).
    #[test]
    fn cut_your_losses_mill_half_their_library_rounded_down() {
        use crate::types::ability::{RoundingMode, ZoneRef};
        let def = parse_effect_chain(
            "Target player mills half their library, rounded down.",
            AbilityKind::Spell,
        );
        match &*def.effect {
            Effect::Mill {
                count,
                target,
                destination,
            } => {
                assert!(
                    matches!(target, TargetFilter::Player),
                    "Expected Player target, got {0:?}",
                    target,
                );
                assert_eq!(*destination, crate::types::zones::Zone::Graveyard);
                assert_eq!(
                    *count,
                    QuantityExpr::DivideRounded {
                        inner: Box::new(QuantityExpr::Ref {
                            qty: QuantityRef::TargetZoneCardCount {
                                zone: ZoneRef::Library,
                            },
                        }),
                        divisor: 2,
                        rounding: RoundingMode::Down,
                    },
                );
            }
            other => panic!("Expected Mill, got {other:?}"),
        }
    }

    #[test]
    fn coiling_oracle_reveal_conditional_with_otherwise() {
        // Spawned thread with 32MB stack — AbilityDefinition is very large in
        // debug builds and the parser + assertions + Drop exhaust the default
        // test thread stack.
        std::thread::Builder::new()
            .name("coiling-oracle".into())
            .stack_size(32 * 1024 * 1024)
            .spawn(|| {
                let def = parse_effect_chain(
                    "reveal the top card of your library. If it's a land card, put it onto the battlefield. Otherwise, put that card into your hand.",
                    AbilityKind::Spell,
                );
                assert!(matches!(*def.effect, Effect::RevealTop { .. }));
                let sub = def.sub_ability.as_deref().unwrap();
                assert!(sub.condition == Some(AbilityCondition::RevealedHasCardType {
                    card_types: vec![CoreType::Land],
                    additional_filter: None,
                    subtype_filter: None,
                }));
                assert!(matches!(
                    *sub.effect,
                    Effect::ChangeZone { destination: Zone::Battlefield, .. }
                ));
                assert!(sub.else_ability.is_some(), "sub should have else_ability");
                let else_ab = sub.else_ability.as_deref().unwrap();
                assert!(matches!(
                    *else_ab.effect,
                    Effect::ChangeZone { destination: Zone::Hand, .. }
                ));
            })
            .unwrap()
            .join()
            .unwrap();
    }

    /// CR 608.2c + CR 205.3a: "If it's a [subtype], A. Otherwise, B." — the subtype
    /// guard must parse to a non-None condition so the existing if/otherwise lowering
    /// attaches the else-branch. Pre-fix the subtype dropped to `None`, so the
    /// "Otherwise" became an unconditional `OtherwiseFallback` and the destroy ran
    /// unconditionally (the drain). Mirror of `coiling_oracle_...` for the subtype arm.
    #[test]
    fn if_its_a_subtype_otherwise_attaches_else_branch() {
        let def = parse_effect_chain(
            "Choose target creature. If it's a Goblin, destroy it. Otherwise, tap it.",
            AbilityKind::Spell,
        );
        let sub = def
            .sub_ability
            .as_deref()
            .expect("expected conditional destroy sub-ability");
        let Some(AbilityCondition::TargetMatchesFilter { filter, .. }) = &sub.condition else {
            panic!(
                "expected subtype condition on destroy, got {:?}",
                sub.condition
            );
        };
        let TargetFilter::Typed(tf) = filter else {
            panic!("expected Typed subtype filter");
        };
        assert!(
            tf.type_filters
                .contains(&TypeFilter::Subtype("Goblin".to_string())),
            "expected Goblin subtype, got {:?}",
            tf.type_filters
        );
        assert!(matches!(*sub.effect, Effect::Destroy { .. }));
        let else_ab = sub
            .else_ability
            .as_deref()
            .expect("else-branch must attach when the subtype condition parses");
        assert!(
            matches!(
                *else_ab.effect,
                Effect::SetTapState {
                    scope: EffectScope::Single,
                    state: TapStateChange::Tap,
                    ..
                }
            ),
            "expected Tap else-branch, got {:?}",
            else_ab.effect
        );
    }

    /// CR 608.2c + CR 702.1: "If it has [keyword], A. Otherwise, B." — affirmative
    /// keyword guard parses to FilterProp::WithKeyword and attaches the else-branch.
    #[test]
    fn if_it_has_keyword_otherwise_attaches_else_branch() {
        let def = parse_effect_chain(
            "Choose target creature. If it has flying, destroy it. Otherwise, tap it.",
            AbilityKind::Spell,
        );
        let sub = def
            .sub_ability
            .as_deref()
            .expect("expected conditional destroy sub-ability");
        let Some(AbilityCondition::TargetMatchesFilter { filter, .. }) = &sub.condition else {
            panic!(
                "expected keyword condition on destroy, got {:?}",
                sub.condition
            );
        };
        let TargetFilter::Typed(tf) = filter else {
            panic!("expected Typed keyword filter");
        };
        assert!(
            tf.properties.contains(&FilterProp::WithKeyword {
                value: Keyword::Flying
            }),
            "expected WithKeyword(Flying), got {:?}",
            tf.properties
        );
        assert!(matches!(*sub.effect, Effect::Destroy { .. }));
        let else_ab = sub
            .else_ability
            .as_deref()
            .expect("else-branch must attach when the keyword condition parses");
        assert!(matches!(
            *else_ab.effect,
            Effect::SetTapState {
                scope: EffectScope::Single,
                state: TapStateChange::Tap,
                ..
            }
        ));
    }

