    /// CR 603.7 + CR 107.3 + CR 202.1: "When you next cast a spell with {X} in
    /// its mana cost this turn, ..." — delayed triggered ability. The embedded
    /// `SpellCast` trigger must carry a `HasXInManaCost` filter on
    /// `valid_card`. Target card: Brass Infiniscope.
    #[test]
    fn when_next_cast_spell_with_x_in_cost_parses() {
        use crate::types::ability::{DelayedTriggerCondition, FilterProp, TypedFilter};
        let def = parse_effect_chain(
            "When you next cast a spell with {X} in its mana cost this turn, draw a card.",
            AbilityKind::Activated,
        );
        let Effect::CreateDelayedTrigger {
            condition, effect, ..
        } = &*def.effect
        else {
            panic!("expected CreateDelayedTrigger, got {:?}", def.effect);
        };
        let DelayedTriggerCondition::WhenNextEvent { trigger } = condition else {
            panic!("expected WhenNextEvent, got {:?}", condition);
        };
        assert_eq!(
            trigger.mode,
            crate::types::triggers::TriggerMode::SpellCast,
            "delayed trigger mode must be SpellCast"
        );
        let expected = TargetFilter::Typed(
            TypedFilter::default().properties(vec![FilterProp::HasXInManaCost]),
        );
        assert_eq!(
            trigger.valid_card.as_ref(),
            Some(&expected),
            "valid_card must carry HasXInManaCost filter"
        );
        // Scoped to the source's controller — "when YOU next cast".
        assert_eq!(trigger.valid_target, Some(TargetFilter::Controller));
        // Inner effect should parse as a draw.
        assert!(matches!(&*effect.effect, Effect::Draw { .. }));
    }

    /// CR 201.2: "Destroy target nonland permanent and all other permanents
    /// with the same name as that permanent" (Maelstrom Pulse, and the Echoing
    /// cycle, Bile Blight, Homing Lightning, Detention Sphere class). The
    /// secondary mass effect must filter to permanents whose name matches the
    /// targeted permanent (`SameNameAsParentTarget`) — without it the effect
    /// degrades into an unconditional board wipe.
    #[test]
    fn maelstrom_pulse_destroys_only_same_named_permanents() {
        let def = parse_effect_chain(
            "Destroy target nonland permanent and all other permanents with the same name as that permanent.",
            AbilityKind::Spell,
        );
        assert!(matches!(&*def.effect, Effect::Destroy { .. }));
        let sub = def.sub_ability.as_ref().expect("DestroyAll continuation");
        let Effect::DestroyAll { target, .. } = &*sub.effect else {
            panic!("expected DestroyAll, got {:?}", sub.effect);
        };
        let TargetFilter::Typed(typed) = target else {
            panic!("expected Typed filter, got {0:?}", target);
        };
        assert!(
            typed
                .properties
                .contains(&FilterProp::SameNameAsParentTarget),
            "DestroyAll must restrict to the parent target's name, got {:?}",
            typed.properties
        );
        assert!(
            typed.properties.contains(&FilterProp::Another),
            "DestroyAll must exclude the targeted permanent itself, got {:?}",
            typed.properties
        );
    }

    /// CR 701.12a: Tree of Perdition / Tree of Redemption / Evra — "exchange
    /// <player>'s life total with ~'s power/toughness" parses to
    /// `ExchangeLifeWithStat` with the right player filter and stat, not the
    /// previous `Unimplemented { name: "exchange" }` (which surfaced no target
    /// slot, so the player could never be chosen).
    #[test]
    fn exchange_life_with_stat_parses_tree_and_evra() {
        use crate::types::ability::{ControllerRef, PtStat, TypedFilter};

        // Tree of Perdition: target opponent's life ↔ source toughness.
        let perdition = parse_effect_chain(
            "Exchange target opponent's life total with ~'s toughness.",
            AbilityKind::Activated,
        );
        assert_eq!(
            *perdition.effect,
            Effect::ExchangeLifeWithStat {
                player: TargetFilter::Typed(
                    TypedFilter::default().controller(ControllerRef::Opponent)
                ),
                stat: PtStat::Toughness,
            }
        );

        // Tree of Redemption: your life ↔ source toughness (no target).
        let redemption = parse_effect_chain(
            "Exchange your life total with ~'s toughness.",
            AbilityKind::Activated,
        );
        assert_eq!(
            *redemption.effect,
            Effect::ExchangeLifeWithStat {
                player: TargetFilter::Controller,
                stat: PtStat::Toughness,
            }
        );

        // Evra, Halcyon Witness: your life ↔ source power.
        let evra = parse_effect_chain(
            "Exchange your life total with ~'s power.",
            AbilityKind::Activated,
        );
        assert_eq!(
            *evra.effect,
            Effect::ExchangeLifeWithStat {
                player: TargetFilter::Controller,
                stat: PtStat::Power,
            }
        );
    }

    #[test]
    fn kindred_dominance_excludes_chosen_creature_type() {
        use crate::types::ability::{ChoiceType, TypedFilter};

        let def = parse_effect_chain(
            "Choose a creature type. Destroy all creatures that aren't of the chosen type.",
            AbilityKind::Spell,
        );
        let Effect::Choose {
            choice_type,
            persist,
        } = &*def.effect
        else {
            panic!("expected Choose, got {:?}", def.effect);
        };
        assert_eq!(*choice_type, ChoiceType::CreatureType);
        assert!(*persist);

        let destroy = def.sub_ability.as_ref().expect("destroy continuation");
        let Effect::DestroyAll { target, .. } = &*destroy.effect else {
            panic!("expected DestroyAll, got {:?}", destroy.effect);
        };
        let expected = TargetFilter::And {
            filters: vec![
                TargetFilter::Typed(TypedFilter::creature()),
                TargetFilter::Not {
                    filter: Box::new(TargetFilter::Typed(
                        TypedFilter::default().properties(vec![FilterProp::IsChosenCreatureType]),
                    )),
                },
            ],
        };
        assert_eq!(target, &expected);
    }

    // ------------------------------------------------------------------
    // CR 700.2 + CR 608.2d: ChooseOneOf inline binary-choice regression.
    // ------------------------------------------------------------------

    /// Highway Robbery's spell text "You may discard a card or sacrifice a
    /// land" produces a `ChooseOneOf` with two branches (Discard + Sacrifice),
    /// wrapped in an optional outer ability.
    #[test]
    fn choose_one_of_detects_highway_robbery_pattern() {
        let ability = parse_effect_chain(
            "You may discard a card or sacrifice a land.",
            AbilityKind::Spell,
        );
        assert!(
            ability.optional,
            "outer 'you may' must mark ability optional"
        );
        match &*ability.effect {
            Effect::ChooseOneOf { branches, .. } => {
                assert_eq!(branches.len(), 2, "Highway Robbery has exactly 2 branches");
                assert!(
                    matches!(&*branches[0].effect, Effect::Discard { .. }),
                    "first branch is Discard"
                );
                assert!(
                    matches!(&*branches[1].effect, Effect::Sacrifice { .. }),
                    "second branch is Sacrifice"
                );
            }
            other => panic!("expected ChooseOneOf, got {other:?}"),
        }
    }

