    /// Disambiguation regression: when the populate-specific qualifier
    /// "the token created this way " is present, it MUST win over the
    /// shorter "the token " prefix. The longest-first strip_prefix order
    /// is the guard. If "the token " were tried first, the qualifier text
    /// would leak into the parsed verb-phrase (`parse_continuous_modifications`
    /// would receive "created this way gains haste"), producing an empty
    /// modification set and silently dropping the rewrite.
    #[test]
    fn populate_qualifier_takes_precedence_over_plain_the_token() {
        let ability = parse_effect_chain(
            "populate. the token created this way gains haste",
            AbilityKind::Spell,
        );
        assert!(
            matches!(&*ability.effect, Effect::Populate),
            "outer effect should be Populate, got {:?}",
            ability.effect
        );
        let sub = ability
            .sub_ability
            .as_deref()
            .expect("anaphor sub-ability missing");
        match &*sub.effect {
            Effect::GenericEffect {
                static_abilities,
                target,
                ..
            } => {
                assert_eq!(*target, Some(TargetFilter::LastCreated));
                assert!(
                    static_abilities[0].modifications.iter().any(|m| matches!(
                        m,
                        ContinuousModification::AddKeyword {
                            keyword: Keyword::Haste,
                        }
                    )),
                    "qualifier-form should still parse to AddKeyword(Haste); got {:?}",
                    static_abilities[0].modifications
                );
            }
            other => panic!("expected GenericEffect anaphor rewrite, got {other:?}"),
        }
    }

    /// Negative gate: without a preceding token-creating effect, plain
    /// "the token gains haste" must NOT be rewritten — there is no
    /// antecedent for `LastCreated` to bind to. The outer
    /// `resolve_populated_token_anaphors` walk gates on
    /// `is_token_creating_effect` in the chain prefix.
    #[test]
    fn plain_anaphor_without_token_creator_is_not_rewritten() {
        // Chain has no Token / Populate / CopyTokenOf — just a Pump and
        // a dangling anaphor. The dangling clause must remain Unimplemented.
        let ability = parse_effect_chain(
            "target creature gets +1/+1. the token gains haste",
            AbilityKind::Spell,
        );
        // Walk the chain's sub-ability tail; assert no GenericEffect with
        // LastCreated target was produced.
        fn contains_last_created_rewrite(def: &AbilityDefinition) -> bool {
            if let Effect::GenericEffect {
                target: Some(TargetFilter::LastCreated),
                ..
            } = &*def.effect
            {
                return true;
            }
            def.sub_ability
                .as_deref()
                .is_some_and(contains_last_created_rewrite)
        }
        assert!(
            !contains_last_created_rewrite(&ability),
            "no token creator preceded — must not produce LastCreated rewrite"
        );
    }

    /// CR 608.2k + CR 603.7c: Inalla-style "Exile it at the beginning of
    /// the next end step" inside a delayed trigger after a token-creating
    /// effect must rewrite the inner `ChangeZone { target: ParentTarget }`
    /// to `LastCreated`. Coverage gap before B11: `ChangeZone` was missing
    /// from `rewrite_parent_target_to_last_created`'s effect-list, so
    /// Inalla's exile-the-token delayed trigger leaked `ParentTarget`.
    #[test]
    fn delayed_trigger_change_zone_after_token_creator_rewrites_to_last_created() {
        let ability = parse_effect_chain(
            "create a token that's a copy of that creature. the token gains haste. exile it at the beginning of the next end step",
            AbilityKind::Spell,
        );
        // Outermost is CopyTokenOf.
        assert!(
            matches!(&*ability.effect, Effect::CopyTokenOf { .. }),
            "expected CopyTokenOf, got {:?}",
            ability.effect
        );
        // Walk to the CreateDelayedTrigger and inspect its inner ChangeZone.
        fn find_delayed_change_zone_target(def: &AbilityDefinition) -> Option<TargetFilter> {
            if let Effect::CreateDelayedTrigger { effect: inner, .. } = &*def.effect {
                if let Effect::ChangeZone { target, .. } = &*inner.effect {
                    return Some(target.clone());
                }
            }
            def.sub_ability
                .as_deref()
                .and_then(find_delayed_change_zone_target)
        }
        let target = find_delayed_change_zone_target(&ability)
            .expect("expected CreateDelayedTrigger { ChangeZone } in chain");
        assert_eq!(
            target,
            TargetFilter::LastCreated,
            "ChangeZone target must be rewritten from ParentTarget to LastCreated"
        );
    }

    /// CR 614.1a + CR 614.6: Whip-style "If it would leave the battlefield,
    /// exile it instead of putting it anywhere else" is a replacement effect
    /// installed on the returned object, not an immediate follow-up exile.
    #[test]
    fn leave_battlefield_exile_rider_adds_replacement() {
        fn contains_direct_parent_target_exile(def: &AbilityDefinition) -> bool {
            if matches!(
                &*def.effect,
                Effect::ChangeZone {
                    destination: Zone::Exile,
                    target: TargetFilter::ParentTarget,
                    ..
                }
            ) {
                return true;
            }
            def.sub_ability
                .as_deref()
                .is_some_and(contains_direct_parent_target_exile)
        }

        fn find_added_replacement(def: &AbilityDefinition) -> Option<&ReplacementDefinition> {
            if let Effect::AddTargetReplacement {
                replacement,
                target,
            } = &*def.effect
            {
                assert_eq!(*target, TargetFilter::Any);
                return Some(replacement);
            }
            def.sub_ability.as_deref().and_then(find_added_replacement)
        }

        for rider in [
            "if it would leave the battlefield, exile it instead of putting it anywhere else",
            "if that creature would leave the battlefield, exile that creature instead of putting that creature anywhere else",
            "if this permanent would leave the battlefield, exile this permanent instead of putting this permanent anywhere else",
        ] {
            let text = format!(
                "return target creature card from your graveyard to the battlefield. it gains haste. exile it at the beginning of the next end step. {rider}"
            );
            let ability = parse_effect_chain(&text, AbilityKind::Activated);

            assert!(
                !contains_direct_parent_target_exile(&ability),
                "{rider} must not parse as an immediate exile"
            );
            let replacement =
                find_added_replacement(&ability).expect("expected exile replacement");
            assert_eq!(replacement.event, ReplacementEvent::Moved);
            assert_eq!(replacement.valid_card, Some(TargetFilter::SelfRef));
            assert_eq!(replacement.destination_zone, None);

            let execute = replacement
                .execute
                .as_deref()
                .expect("replacement should carry redirect effect");
            match &*execute.effect {
                Effect::ChangeZone {
                    origin,
                    destination,
                    target,
                    ..
                } => {
                    assert_eq!(*origin, Some(Zone::Battlefield));
                    assert_eq!(*destination, Zone::Exile);
                    assert_eq!(*target, TargetFilter::SelfRef);
                }
                other => panic!("expected ChangeZone redirect, got {other:?}"),
            }
        }
    }

    /// CR 701.57a + CR 702.85a: `Effect::ExileFromTopUntil` must accept the
    /// second-person possessive form ("your library" / "you exile").
    /// Regression-protection for the pre-existing path Etali's parser
    /// extension was layered onto. Now exercises the
    /// `UntilCondition::NextMatches` arm of the parameterised stop condition.
    #[test]
    fn exile_from_top_until_second_person_nonland_filter() {
        let e =
            parse_effect("exile cards from the top of your library until you exile a nonland card");
        let Effect::ExileFromTopUntil { player: _, until } = e else {
            panic!("expected ExileFromTopUntil, got {:?}", e);
        };
        let UntilCondition::NextMatches { filter } = until else {
            panic!("expected NextMatches arm, got {:?}", until);
        };
        // Filter is `Typed { type_filters: [Non(Land)] }`.
        let TargetFilter::Typed(typed) = filter else {
            panic!("expected Typed filter");
        };
        assert!(typed
            .type_filters
            .iter()
            .any(|t| matches!(t, TypeFilter::Non(inner) if matches!(**inner, TypeFilter::Land))));
    }

    /// CR 701.57a + CR 702.85a: Etali, Primal Conqueror's trigger body uses
    /// the third-person possessive form ("their library" / "they exile") that
    /// `strip_each_player_subject` produces after stripping "each player ".
    /// Without the third-person prefix arms, the parser falls through to a
    /// flat `ChangeZone` lowering and silently drops both the
    /// "until …" loop semantic and the nonland filter.
    #[test]
    fn exile_from_top_until_third_person_possessive_etali_form() {
        let e = parse_effect(
            "exile cards from the top of their library until they exile a nonland card",
        );
        let Effect::ExileFromTopUntil { player: _, until } = e else {
            panic!("expected ExileFromTopUntil, got {:?}", e);
        };
        let UntilCondition::NextMatches { filter } = until else {
            panic!("expected NextMatches arm, got {:?}", until);
        };
        let TargetFilter::Typed(typed) = filter else {
            panic!("expected Typed filter");
        };
        assert!(typed
            .type_filters
            .iter()
            .any(|t| matches!(t, TypeFilter::Non(inner) if matches!(**inner, TypeFilter::Land))));
    }

    /// CR 701.13a + CR 601.2 + CR 118.9 + CR 401.4: Chaos Wand is a
    /// targeted-player exile-until loop followed by an optional free-cast
    /// branch and cleanup of cards still linked as exiled this way.
    #[test]
    fn chaos_wand_lowers_to_targeted_exile_until_optional_cast_and_cleanup() {
        let def = parse_effect_chain(
            "Target opponent exiles cards from the top of their library until they exile an instant or sorcery card. You may cast that card without paying its mana cost. Then put the exiled cards that weren't cast this way on the bottom of that library in a random order.",
            AbilityKind::Activated,
        );

        let Effect::ExileFromTopUntil { player, until } = &*def.effect else {
            panic!("expected ExileFromTopUntil, got {:?}", def.effect);
        };
        assert_eq!(
            *player,
            TargetFilter::Typed(TypedFilter::default().controller(ControllerRef::Opponent))
        );
        let UntilCondition::NextMatches { filter } = until else {
            panic!("expected NextMatches, got {until:?}");
        };
        let TargetFilter::Or { filters } = filter else {
            panic!("expected instant/sorcery OR filter, got {filter:?}");
        };
        assert!(filters.iter().any(
            |filter| matches!(filter, TargetFilter::Typed(typed) if typed.type_filters.contains(&TypeFilter::Instant))
        ));
        assert!(filters.iter().any(
            |filter| matches!(filter, TargetFilter::Typed(typed) if typed.type_filters.contains(&TypeFilter::Sorcery))
        ));

        let cast = def
            .sub_ability
            .as_deref()
            .expect("cast branch should be chained");
        let Effect::CastFromZone {
            target,
            without_paying_mana_cost,
            ..
        } = &*cast.effect
        else {
            panic!("expected CastFromZone, got {:?}", cast.effect);
        };
        assert_eq!(*target, TargetFilter::ParentTarget);
        assert!(*without_paying_mana_cost);
        assert!(cast.optional);

        for cleanup in [cast.sub_ability.as_deref(), cast.else_ability.as_deref()] {
            let cleanup = cleanup.expect("cleanup should run after accept or decline");
            let Effect::PutAtLibraryPosition {
                target,
                count,
                position,
            } = &*cleanup.effect
            else {
                panic!(
                    "expected PutAtLibraryPosition cleanup, got {:?}",
                    cleanup.effect
                );
            };
            assert_eq!(*target, TargetFilter::ExiledBySource);
            assert_eq!(*count, QuantityExpr::Fixed { value: 0 });
            assert_eq!(*position, LibraryPosition::Bottom);
        }
    }

    /// Issue #501 FOLLOW-UP — ROOT CAUSE B building-block test. After an
    /// `ExileFromTopUntil { NextMatches }` clause, a following sibling clause's
    /// bare anaphor "it" ("Put three time counters on it") binds to the
    /// exiled hit card. The `has_typed_target` arm for `ExileFromTopUntil
    /// { NextMatches }` routes the `PutCounter` clause through
    /// `replace_target_with_parent`, rewriting `target` SelfRef → ParentTarget
    /// (CR 608.2c). Without the arm the `PutCounter` keeps `SelfRef`.
    #[test]
    fn put_counter_it_after_exile_from_top_until_resolves_to_parent_target() {
        let def = parse_effect_chain(
            "Exile cards from the top of your library until you exile a nonland card. Put three time counters on it.",
            AbilityKind::Spell,
        );
        let Effect::ExileFromTopUntil { until, .. } = &*def.effect else {
            panic!("expected ExileFromTopUntil, got {:?}", def.effect);
        };
        assert!(matches!(until, UntilCondition::NextMatches { .. }));
        let put_counter = def
            .sub_ability
            .as_deref()
            .expect("the 'put counters on it' clause must chain as a sub_ability");
        let Effect::PutCounter { target, .. } = &*put_counter.effect else {
            panic!(
                "expected PutCounter sub-ability, got {:?}",
                put_counter.effect
            );
        };
        assert_eq!(
            *target,
            TargetFilter::ParentTarget,
            "'it' after an ExileFromTopUntil must bind to the exiled card, not SelfRef"
        );
    }

    /// Issue #501 FOLLOW-UP — negative sibling for Root Cause B. The
    /// `has_typed_target` arm is scoped to the `ExileFromTopUntil { NextMatches }`
    /// prior-sibling case: an ordinary self-trigger "put a +1/+1 counter on it"
    /// (no object-introducing prior clause) still resolves "it" to `SelfRef`,
    /// so the new arm does not capture ordinary self-trigger anaphora.
    #[test]
    fn put_counter_it_without_exile_prior_clause_stays_self_ref() {
        let def = parse_effect_chain("Put a +1/+1 counter on it", AbilityKind::Spell);
        let Effect::PutCounter { target, .. } = &*def.effect else {
            panic!("expected PutCounter, got {:?}", def.effect);
        };
        assert_eq!(
            *target,
            TargetFilter::SelfRef,
            "a bare 'it' with no object-introducing prior clause must stay SelfRef"
        );
    }

    /// CR 603.2 + CR 701.57a + CR 702.85a + CR 608.2: Etali's outer ETB trigger
    /// sentence — the "each player " subject phrase routes through
    /// `strip_each_player_subject` which strips the subject and deconjugates
    /// "exiles" → "exile", then the third-person possessive arm of
    /// `try_parse_exile_from_top_until` finalizes the lowering. Outer ability
    /// must carry `player_scope: All` so the resolver iterates per player;
    /// outer effect must be `ExileFromTopUntil { until: NextMatches { filter: Non(Land) } }`. (The
    /// follow-up `cast any number of spells from among …` sub-sentence is a
    /// separate parser path — not asserted here; see the runtime tests in
    /// `game::effects::exile_from_top_until::tests` for per-resolution exile
    /// linkage that the future sub-ability filter will consume.)
    #[test]
    fn each_player_exiles_outer_effect_lowers_to_exile_from_top_until() {
        let def = parse_effect_chain(
            "each player exiles cards from the top of their library until they exile a nonland card.",
            AbilityKind::Spell,
        );

        assert_eq!(
            def.player_scope,
            Some(PlayerFilter::All),
            "player_scope must propagate from \"each player\" subject"
        );
        let Effect::ExileFromTopUntil { ref until, .. } = *def.effect else {
            panic!("expected outer ExileFromTopUntil, got {:?}", def.effect);
        };
        let UntilCondition::NextMatches { filter } = until else {
            panic!("expected NextMatches arm, got {:?}", until);
        };
        let TargetFilter::Typed(typed) = filter else {
            panic!("expected Typed filter, got {:?}", filter);
        };
        assert!(
            typed.type_filters.iter().any(
                |t| matches!(t, TypeFilter::Non(inner) if matches!(**inner, TypeFilter::Land))
            ),
            "filter must be Non(Land)"
        );
    }

    #[test]
    fn parser_shape_evelyn_exiles_each_library_with_collection_counter_and_permission() {
        let def = parse_effect_chain(
            "Exile the top card of each player's library with a collection counter on it.",
            AbilityKind::Spell,
        );

        assert_eq!(def.player_scope, Some(PlayerFilter::All));
        let Effect::ExileTop {
            player: TargetFilter::Controller,
            count: QuantityExpr::Fixed { value: 1 },
            face_down: false,
        } = *def.effect
        else {
            panic!("expected all-player ExileTop, got {:?}", def.effect);
        };
        let counter = def.sub_ability.expect("counter sub ability");
        let Effect::PutCounterAll {
            counter_type,
            target,
            ..
        } = counter.effect.as_ref()
        else {
            panic!(
                "expected PutCounterAll sub ability, got {:?}",
                counter.effect
            );
        };
        assert_eq!(
            counter_type,
            &CounterType::Generic("collection".to_string())
        );
        assert_eq!(
            target,
            &TargetFilter::TrackedSet {
                id: TrackedSetId(0)
            }
        );
        let grant = counter.sub_ability.expect("permission sub ability");
        let Effect::GrantCastingPermission {
            permission, target, ..
        } = grant.effect.as_ref()
        else {
            panic!("expected GrantCastingPermission, got {:?}", grant.effect);
        };
        let CastingPermission::PlayFromExile {
            frequency,
            mana_spend_permission,
            ..
        } = permission
        else {
            panic!("expected PlayFromExile permission, got {permission:?}");
        };
        assert_eq!(*frequency, CastFrequency::OncePerTurn);
        assert_eq!(
            *mana_spend_permission,
            Some(ManaSpendPermission::AnyTypeOrColor)
        );
        assert_eq!(
            target,
            &TargetFilter::TrackedSet {
                id: TrackedSetId(0)
            }
        );
    }

    /// CR 202.3 + CR 107.3e: Tasha's Hideous Laughter — "Each opponent exiles
    /// cards from the top of their library until that player has exiled cards
    /// with total mana value 20 or greater." After `strip_each_player_subject`
    /// strips "each opponent " and binds `player_scope: Opponent`, the body
    /// reads "exile cards from the top of their library until that player has
    /// exiled cards with total mana value 20 or greater" — which the parser
    /// must lower to `ExileFromTopUntil { until: CumulativeThreshold { ManaValue, GE, 20 } }`,
    /// not to the misparsed flat `ChangeZone` that originally prompted the
    /// user for a permanent target (issue #316).
    #[test]
    fn tashas_hideous_laughter_lowers_to_cumulative_threshold() {
        let def = parse_effect_chain(
            "Each opponent exiles cards from the top of their library until that player has exiled cards with total mana value 20 or greater.",
            AbilityKind::Spell,
        );

        assert_eq!(
            def.player_scope,
            Some(PlayerFilter::Opponent),
            "player_scope must be Opponent (from \"each opponent\" subject)"
        );

        let Effect::ExileFromTopUntil { ref until, .. } = *def.effect else {
            panic!(
                "expected ExileFromTopUntil, got {:?} — issue #316 regression",
                def.effect
            );
        };
        let UntilCondition::CumulativeThreshold {
            property,
            comparator,
            threshold,
        } = until
        else {
            panic!("expected CumulativeThreshold arm, got {:?}", until);
        };
        assert_eq!(*property, ObjectProperty::ManaValue);
        assert_eq!(*comparator, Comparator::GE);
        assert_eq!(*threshold, QuantityExpr::Fixed { value: 20 });
    }

