    // -------------------------------------------------------------------
    // L9-43 + L9-44: attach-the-just-moved-card primitive.
    //
    // CR 303.4f + CR 301.5b + CR 603.7d + CR 608.2c: when the chain is
    // `Dig|ChangeZone(destination=Battlefield)` → `Attach` with a
    // `ZoneChangedThisWay` condition, the parent must carry
    // `forward_result: true` so the runtime forwards the just-moved card
    // as the Attach's `source_id` instead of the trigger source / Saga /
    // searcher.
    // -------------------------------------------------------------------

    /// Armored Skyhunter's attack trigger: Dig(6, Battlefield) →
    /// Attach(creature you control) with the "If an Equipment is put onto
    /// the battlefield this way" condition. Asserts the `forward_result`
    /// rewire fires AND the condition is recognized AND the Attach target
    /// slot is preserved.
    #[test]
    fn attach_just_moved_armored_skyhunter_dig_with_zone_changed_this_way() {
        let def = parse_effect_chain(
            "Look at the top six cards of your library. You may put an Aura or Equipment card from among them onto the battlefield. If an Equipment is put onto the battlefield this way, you may attach it to a creature you control. Put the rest of those cards on the bottom of your library in a random order.",
            AbilityKind::Spell,
        );

        // Parent: Dig{destination: Battlefield} with forward_result: true.
        match &*def.effect {
            Effect::Dig { destination, .. } => {
                assert_eq!(*destination, Some(Zone::Battlefield));
            }
            other => panic!("expected outer Dig, got {other:?}"),
        }
        assert!(
            def.forward_result,
            "Dig parent must forward the just-moved card to the Attach sub_ability"
        );

        // Walk the sub_ability chain: Attach with ZoneChangedThisWay condition.
        let attach = def
            .sub_ability
            .as_ref()
            .expect("expected Attach sub_ability");
        match &*attach.effect {
            Effect::Attach { target, .. } => {
                // Target slot must not be vacuous (Any) — either a typed
                // "creature you control" filter or `ParentTarget` (chain
                // composition routes the player-chosen target through the
                // parent's slot). Both are valid post-assembly shapes; what
                // matters is that the runtime has a target binding to fill.
                assert!(
                    !matches!(target, TargetFilter::Any),
                    "Attach target slot must not be Any, got {0:?}",
                    target
                );
                if let TargetFilter::Typed(t) = target {
                    assert_eq!(t.controller, Some(ControllerRef::You));
                    assert!(
                        t.type_filters
                            .iter()
                            .any(|f| matches!(f, TypeFilter::Creature)),
                        "expected Creature type_filter, got {:?}",
                        t.type_filters
                    );
                }
            }
            other => panic!("expected Attach sub_ability, got {other:?}"),
        }
        match &attach.condition {
            Some(AbilityCondition::ZoneChangedThisWay { filter }) => match filter {
                TargetFilter::Typed(t) => assert!(
                    t.type_filters
                        .iter()
                        .any(|f| matches!(f, TypeFilter::Subtype(s) if s.eq_ignore_ascii_case("Equipment"))),
                    "expected Equipment subtype filter on ZoneChangedThisWay, got {:?}",
                    t.type_filters
                ),
                other => panic!("expected Typed Equipment filter, got {other:?}"),
            },
            other => panic!("expected ZoneChangedThisWay condition on Attach, got {other:?}"),
        }
    }

    /// Quest for the Holy Relic / Stonehewer Giant pattern:
    /// SearchLibrary → ChangeZone(destination=Battlefield) → Attach. The
    /// rewire detects the ChangeZone-to-battlefield parent and sets
    /// forward_result regardless of how many shuffles / cleanups follow.
    #[test]
    fn attach_just_moved_change_zone_to_battlefield_attach_sub() {
        // Synthetic minimal pattern that exercises the same chain shape as
        // Stonehewer Giant ("you may search your library for an Equipment
        // card, put it onto the battlefield, then shuffle. If that
        // Equipment is put onto the battlefield this way, attach it to a
        // creature you control."). Phrased with present-tense "is put"
        // because that's the new pattern the combinator must recognize.
        let def = parse_effect_chain(
            "Search your library for an Equipment card and put it onto the battlefield. If an Equipment is put onto the battlefield this way, attach it to a creature you control. Then shuffle.",
            AbilityKind::Spell,
        );

        // Walk the chain to find the ChangeZone(Battlefield) node — the
        // outermost effect may be SearchLibrary depending on parser
        // composition. The post-pass recurses, so any Dig/ChangeZone-to-
        // Battlefield parent in the tree should be marked.
        fn find_battlefield_change_zone_with_attach_sub(
            def: &AbilityDefinition,
        ) -> Option<&AbilityDefinition> {
            let dest_is_bf = matches!(
                &*def.effect,
                Effect::ChangeZone {
                    destination: Zone::Battlefield,
                    ..
                } | Effect::Dig {
                    destination: Some(Zone::Battlefield),
                    ..
                }
            );
            if dest_is_bf {
                if let Some(sub) = def.sub_ability.as_ref() {
                    if matches!(*sub.effect, Effect::Attach { .. })
                        && matches!(
                            sub.condition,
                            Some(AbilityCondition::ZoneChangedThisWay { .. })
                        )
                    {
                        return Some(def);
                    }
                }
            }
            if let Some(sub) = def.sub_ability.as_ref() {
                if let Some(found) = find_battlefield_change_zone_with_attach_sub(sub) {
                    return Some(found);
                }
            }
            None
        }

        let parent = find_battlefield_change_zone_with_attach_sub(&def).expect(
            "expected a ChangeZone|Dig to Battlefield with an Attach sub gated by ZoneChangedThisWay",
        );
        assert!(
            parent.forward_result,
            "battlefield-bound parent of conditional Attach must have forward_result: true"
        );
    }

    /// Negative regression: Stoneforge Mystic-style "put an Equipment from
    /// your hand onto the battlefield" must NOT receive `forward_result:
    /// true` because the pattern has no Attach sub-ability — it's just a
    /// ChangeZone, no chained attach. Guards against the rewire over-firing.
    #[test]
    fn attach_just_moved_negative_no_attach_sub_no_rewire() {
        let def = parse_effect_chain(
            "You may put an Equipment card from your hand onto the battlefield.",
            AbilityKind::Spell,
        );
        // The chain may be wrapped (optional / target) but no descendant
        // should carry forward_result: true since there's no Attach.
        fn any_forward_result(def: &AbilityDefinition) -> bool {
            if def.forward_result {
                return true;
            }
            if let Some(sub) = def.sub_ability.as_ref() {
                if any_forward_result(sub) {
                    return true;
                }
            }
            if let Some(else_branch) = def.else_ability.as_ref() {
                if any_forward_result(else_branch) {
                    return true;
                }
            }
            false
        }
        assert!(
            !any_forward_result(&def),
            "ChangeZone-only (no Attach sub) must not be marked forward_result"
        );
    }

    /// CR 608.2c: Emperor of Bones class — a ChangeZone-to-Battlefield
    /// followed by sibling clauses that anaphorically reference the just-
    /// moved card ("it gains haste. sacrifice it ...") must mark
    /// `forward_result: true` on the ChangeZone parent so the runtime
    /// rewrites the sub-chain's `source_id` to the moved card. Without
    /// this, the trailing GenericEffect/Pump and CreateDelayedTrigger
    /// subs target Emperor itself (via `SelfRef`) instead of the
    /// returned creature.
    ///
    /// Building-block test: the same pattern covers any
    /// "[move a card to the battlefield]. it gains [keyword].
    /// sacrifice it at the beginning of the next end step." chain
    /// (Emperor of Bones plus any future card with the same shape).
    #[test]
    fn change_zone_to_battlefield_anaphor_subchain_sets_forward_result() {
        let def = parse_effect_chain(
            "put a creature card exiled with this creature onto the battlefield under your control with a finality counter on it. it gains haste. sacrifice it at the beginning of the next end step.",
            AbilityKind::Spell,
        );

        // Find the outer ChangeZone-to-Battlefield node (the post-pass
        // recurses, so the rewire may sit on any descendant of the root).
        fn find_change_zone_to_battlefield(def: &AbilityDefinition) -> Option<&AbilityDefinition> {
            if matches!(
                &*def.effect,
                Effect::ChangeZone {
                    destination: Zone::Battlefield,
                    ..
                } | Effect::Dig {
                    destination: Some(Zone::Battlefield),
                    ..
                }
            ) {
                return Some(def);
            }
            if let Some(sub) = def.sub_ability.as_ref() {
                if let Some(found) = find_change_zone_to_battlefield(sub) {
                    return Some(found);
                }
            }
            if let Some(else_branch) = def.else_ability.as_ref() {
                if let Some(found) = find_change_zone_to_battlefield(else_branch) {
                    return Some(found);
                }
            }
            None
        }

        let parent = find_change_zone_to_battlefield(&def)
            .expect("expected a ChangeZone|Dig to Battlefield parent in the parsed chain");

        // CR 608.2c: the bare-"it" anaphor sub-chain must trigger the
        // rewire, so the runtime rebinds the sub's source_id to the
        // moved card.
        assert!(
            parent.forward_result,
            "ChangeZone-to-Battlefield with bare-\"it\" sub-chain must mark forward_result"
        );

        // Discriminating sub-shape check: the sub-chain must contain a
        // haste-granting clause (GenericEffect/Pump granting Haste, or
        // GainKeyword) AND a deeper CreateDelayedTrigger whose inner
        // effect is a Sacrifice. Both must be present so we know the
        // rewire was set for the right reason (an anaphor sub-chain).
        fn finds_haste_grant_and_delayed_sacrifice(def: &AbilityDefinition) -> (bool, bool) {
            let mut found_haste = false;
            let mut found_delayed_sacrifice = false;
            fn walk(
                def: &AbilityDefinition,
                found_haste: &mut bool,
                found_delayed_sacrifice: &mut bool,
            ) {
                match &*def.effect {
                    Effect::GenericEffect {
                        static_abilities, ..
                    } if static_abilities.iter().any(|s| {
                        s.modifications.iter().any(|m| {
                            matches!(
                                m,
                                ContinuousModification::AddKeyword { keyword }
                                    if matches!(keyword, Keyword::Haste)
                            )
                        })
                    }) =>
                    {
                        *found_haste = true;
                    }
                    Effect::CreateDelayedTrigger { effect, .. } => {
                        if matches!(&*effect.effect, Effect::Sacrifice { .. }) {
                            *found_delayed_sacrifice = true;
                        }
                        walk(effect, found_haste, found_delayed_sacrifice);
                    }
                    _ => {}
                }
                if let Some(sub) = def.sub_ability.as_ref() {
                    walk(sub, found_haste, found_delayed_sacrifice);
                }
                if let Some(else_branch) = def.else_ability.as_ref() {
                    walk(else_branch, found_haste, found_delayed_sacrifice);
                }
            }
            walk(def, &mut found_haste, &mut found_delayed_sacrifice);
            (found_haste, found_delayed_sacrifice)
        }

        let (haste, delayed_sacrifice) = finds_haste_grant_and_delayed_sacrifice(&def);
        assert!(
            haste,
            "expected a haste-granting sub-clause in the parsed chain"
        );
        assert!(
            delayed_sacrifice,
            "expected a CreateDelayedTrigger with Sacrifice inside in the parsed chain"
        );

        fn delayed_sacrifice_targets_parent(def: &AbilityDefinition) -> bool {
            match &*def.effect {
                Effect::CreateDelayedTrigger { effect, .. } => match &*effect.effect {
                    Effect::Sacrifice {
                        target: TargetFilter::ParentTarget,
                        ..
                    } => true,
                    other => delayed_sacrifice_targets_parent(&AbilityDefinition::new(
                        AbilityKind::Spell,
                        other.clone(),
                    )),
                },
                _ => def
                    .sub_ability
                    .as_deref()
                    .is_some_and(delayed_sacrifice_targets_parent),
            }
        }
        assert!(
            delayed_sacrifice_targets_parent(&def),
            "delayed Sacrifice must target ParentTarget (the returned creature), not SelfRef"
        );
    }

    #[test]
    fn replace_target_with_parent_recurses_delayed_trigger_sub_ability() {
        let mut effect = Effect::CreateDelayedTrigger {
            condition: DelayedTriggerCondition::AtNextPhase { phase: Phase::End },
            effect: Box::new(
                AbilityDefinition::new(
                    AbilityKind::Spell,
                    Effect::Draw {
                        count: QuantityExpr::Fixed { value: 1 },
                        target: TargetFilter::Controller,
                    },
                )
                .sub_ability(AbilityDefinition::new(
                    AbilityKind::Spell,
                    Effect::Sacrifice {
                        target: TargetFilter::SelfRef,
                        count: QuantityExpr::Fixed { value: 1 },
                        min_count: 0,
                    },
                )),
            ),
            uses_tracked_set: false,
        };

        replace_target_with_parent(&mut effect);

        let Effect::CreateDelayedTrigger { effect, .. } = effect else {
            panic!("expected delayed trigger");
        };
        let sacrifice = effect
            .sub_ability
            .as_ref()
            .expect("expected delayed trigger sub-ability");
        assert!(
            matches!(
                &*sacrifice.effect,
                Effect::Sacrifice {
                    target: TargetFilter::ParentTarget,
                    ..
                }
            ),
            "delayed trigger sub-ability Sacrifice must target ParentTarget"
        );
    }

    /// Issue #2424: Goryo's Vengeance — "That creature gains haste. Exile it at
    /// the beginning of the next end step." must bind to the returned legendary
    /// creature, not the spell source.
    #[test]
    fn goryos_vengeance_reanimation_haste_and_delayed_exile() {
        let def = parse_effect_chain(
            "return target legendary creature card from your graveyard to the battlefield. that creature gains haste. exile it at the beginning of the next end step.",
            AbilityKind::Spell,
        );

        fn find_change_zone_to_battlefield(def: &AbilityDefinition) -> Option<&AbilityDefinition> {
            if matches!(
                &*def.effect,
                Effect::ChangeZone {
                    destination: Zone::Battlefield,
                    ..
                }
            ) {
                return Some(def);
            }
            if let Some(sub) = def.sub_ability.as_ref() {
                if let Some(found) = find_change_zone_to_battlefield(sub) {
                    return Some(found);
                }
            }
            None
        }

        let parent = find_change_zone_to_battlefield(&def)
            .expect("expected ChangeZone to Battlefield parent");
        assert!(
            parent.forward_result,
            "Goryo's-style anaphor sub-chain must set forward_result"
        );

        fn haste_targets_parent(def: &AbilityDefinition) -> bool {
            match &*def.effect {
                Effect::GenericEffect {
                    target,
                    static_abilities,
                    ..
                } => {
                    let outer = matches!(target, Some(TargetFilter::ParentTarget));
                    let inner = static_abilities.iter().any(|s| {
                        matches!(s.affected.as_ref(), Some(TargetFilter::ParentTarget))
                            && s.modifications.iter().any(|m| {
                                matches!(
                                    m,
                                    ContinuousModification::AddKeyword { keyword }
                                        if matches!(keyword, Keyword::Haste)
                                )
                            })
                    });
                    outer || inner
                }
                Effect::CreateDelayedTrigger { effect, .. } => haste_targets_parent(effect),
                _ => def.sub_ability.as_deref().is_some_and(haste_targets_parent),
            }
        }

        fn delayed_exile_targets_parent(def: &AbilityDefinition) -> bool {
            match &*def.effect {
                Effect::CreateDelayedTrigger { effect, .. } => match &*effect.effect {
                    Effect::ChangeZone {
                        destination: Zone::Exile,
                        target: TargetFilter::ParentTarget,
                        ..
                    } => true,
                    other => delayed_exile_targets_parent(&AbilityDefinition::new(
                        AbilityKind::Spell,
                        other.clone(),
                    )),
                },
                _ => def
                    .sub_ability
                    .as_deref()
                    .is_some_and(delayed_exile_targets_parent),
            }
        }

        assert!(
            haste_targets_parent(&def),
            "haste grant must target ParentTarget (the returned creature)"
        );
        assert!(
            delayed_exile_targets_parent(&def),
            "delayed exile must target ParentTarget (the returned creature)"
        );
    }

    // ── L9-20 + L8-1: cast-from-zone constraints + alt-ability-cost rider ──

    /// CR 118.9 + CR 120.3: Buster Sword's "cast a spell from your hand with
    /// mana value less than or equal to that damage without paying its mana
    /// cost" must produce a `CastFromZone` whose target is constrained to a
    /// `Card` filter with `InZone { Hand }` + `CmcLE { EventContextAmount }`.
    /// Building-block test: covers the entire FIN equipment-cycle class
    /// (~10–15 cards) by exercising the type-phrase + origin-zone +
    /// mana-value-suffix composition in `try_parse_cast_effect`.
    #[test]
    fn cast_from_zone_with_filter_and_damage_bound() {
        let effect = super::parse_effect(
            "cast a spell from your hand with mana value less than or equal to that damage without paying its mana cost",
        );
        match &effect {
            Effect::CastFromZone {
                target: TargetFilter::Typed(tf),
                without_paying_mana_cost: true,
                mode: crate::types::ability::CardPlayMode::Cast,
                alt_ability_cost: None,
                ..
            } => {
                assert_eq!(tf.type_filters, vec![TypeFilter::Card]);
                assert_eq!(tf.controller, Some(ControllerRef::You));
                // structural: not dispatch — Vec membership assertion in test
                assert!(tf
                    .properties
                    .contains(&FilterProp::InZone { zone: Zone::Hand }));
                let has_cmc_le_damage = tf.properties.iter().any(|p| {
                    matches!(
                        p,
                        FilterProp::Cmc {
                            comparator: Comparator::LE,
                            value: crate::types::ability::QuantityExpr::Ref {
                                qty: crate::types::ability::QuantityRef::EventContextAmount,
                            },
                        }
                    )
                });
                assert!(
                    has_cmc_le_damage,
                    "expected CmcLE bound on EventContextAmount, got {:?}",
                    tf.properties
                );
            }
            _ => panic!("expected constrained CastFromZone, got {effect:?}"),
        }
    }

    /// CR 202.3 + CR 608.2k: "with mana value less than or equal to that
    /// creature" — preserves the `ObjectManaValue { CostPaidObject }`
    /// semantic for the type-word arm; only "that damage" routes to
    /// `EventContextAmount`. Regression test for the `try_dynamic` factoring
